// ─── After render hooks ────────────────────────────────────

function _wizAfterRender(step) {
  if (step === 'date') {
    var el = document.getElementById('wizDate');
    if (el) setTimeout(function() { el.focus(); }, 50);
  }
  if (step === 'why_trade' || step === 'why_entry' || step === 'pm_lessons') {
    var ta = document.querySelector('#wizBody textarea');
    if (ta) setTimeout(function() { ta.focus(); ta.setSelectionRange(ta.value.length, ta.value.length); }, 50);
  }
  if (step === 'why_stop_tp') {
    var stop = document.getElementById('wizWhyStop');
    if (stop) setTimeout(function() { stop.focus(); }, 50);
  }
  if (step === 'levels') {
    var entry = document.getElementById('wizEntry');
    if (entry) setTimeout(function() { entry.focus(); }, 50);
  }
  if (step === 'screenshots') {
    _wizBindScreenshots();
  }
  if (step === 'direction') {
    var dirBtns = document.querySelectorAll('.wiz-dir-btn');
    if (dirBtns.length) setTimeout(function() { dirBtns[0].focus(); }, 50);
  }
  if (step === 'result') {
    var exitInput = document.getElementById('wizExitPrice');
    if (exitInput) setTimeout(function() { exitInput.focus(); }, 50);
  }
  if (step === 'recap') {
    var missingTa = document.getElementById('wizMissingChat');
    if (missingTa && !(wizState.data.missing_chat_text || '').trim()) {
      setTimeout(function() { missingTa.focus(); }, 50);
    }
  }
}

// ─── Screenshot drag-drop ──────────────────────────────────

function _wizBindScreenshots() {
  var zone  = document.getElementById('wizDropZone');
  var input = document.getElementById('wizFileInput');
  if (!zone || !input) return;

  zone.ondragover  = function(e) { e.preventDefault(); zone.classList.add('dragover'); };
  zone.ondragleave = function()  { zone.classList.remove('dragover'); };
  zone.ondrop      = function(e) {
    e.preventDefault();
    zone.classList.remove('dragover');
    _wizHandleFiles(e.dataTransfer.files);
  };
  input.onchange = function(e) { _wizHandleFiles(e.target.files); };
}

// ─── Direction step ─────────────────────────────────────────

function _wizStepDirection() {
  var d = wizState.data;
  var isLong  = d.direction === 'long';
  var isShort = d.direction === 'short';
  return '<div class="wiz-question">Direction</div>'
    
    + '<div class="wiz-direction-toggle">'
    +   '<button class="wiz-dir-btn' + (isLong?' active-long':'') + '" data-dir="long" onclick="wizSetDir(this)">'
    +     '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="18 15 12 9 6 15"/></svg>Long</button>'
    +   '<button class="wiz-dir-btn' + (isShort?' active-short':'') + '" data-dir="short" onclick="wizSetDir(this)">'
    +     '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="6 9 12 15 18 9"/></svg>Short</button>'
    + '</div>';
}

// ─── Result step ────────────────────────────────────────────

function _wizStepResult() {
  var d = wizState.data;
  var dir = d.direction || 'long';
  var pnl = '';
  if (d.entry_price && d.exit_price) {
    var pnlVal = dir === 'long' ? (Number(d.exit_price) - Number(d.entry_price)) : (Number(d.entry_price) - Number(d.exit_price));
    pnl = '<div class="wiz-rr-preview" style="color:' + (pnlVal >= 0 ? 'var(--win)' : 'var(--rose)') + '">PnL: ' + pnlVal.toFixed(2) + '$</div>';
  }
  return '<div class="wiz-question">Resultat</div>'
    + '<div class="wiz-hint">Prix de sortie et PnL calcule automatiquement.</div>'
    + '<div class="wiz-field">'
    +   '<label class="wiz-label">Prix de sortie</label>'
    +   '<input type="number" class="wiz-level-input" id="wizExitPrice" value="' + (d.exit_price||'') + '" placeholder="0.00" step="0.25" oninput="wizUpdateResult()">'
    + '</div>'
    + '<div id="wizResultPreview">' + pnl + '</div>';
}

function wizUpdateResult() {
  var exit = document.getElementById('wizExitPrice')?.value;
  if (!wizState) return;
  wizState.data.exit_price = exit;
  var dir = wizState.data.direction || 'long';
  var entry = wizState.data.entry_price;
  var preview = document.getElementById('wizResultPreview');
  if (!preview) return;
  if (entry && exit) {
    var pnlVal = dir === 'long' ? (Number(exit) - Number(entry)) : (Number(entry) - Number(exit));
    preview.innerHTML = '<div class="wiz-rr-preview" style="color:' + (pnlVal >= 0 ? 'var(--win)' : 'var(--rose)') + '">PnL: ' + pnlVal.toFixed(2) + '$</div>';
  } else {
    preview.innerHTML = '';
  }
}

// ---- 044_wizreadfileasdataurl.js ----
function _wizReadFileAsDataUrl(file) {
  return new Promise(function(resolve, reject) {
    var reader = new FileReader();
    reader.onload = function(e) { resolve(e.target.result); };
    reader.onerror = function() { reject(new Error('Lecture image impossible')); };
    reader.readAsDataURL(file);
  });
}

async function _wizHandleFiles(files) {
  if (!wizState || !files || files.length === 0) return;
  var imageFiles = Array.from(files).filter(function(file) {
    return !!file && file.type && file.type.startsWith('image/');
  });
  if (!imageFiles.length) return;

  for (const file of imageFiles) {
    try {
      const dataUrl = await _wizReadFileAsDataUrl(file);
      if (!wizState) return;
      wizState.data.screenshots.push({ dataUrl: dataUrl, name: file.name });
    } catch (_err) {}
  }

  if (wizState && wizState.steps[wizState.stepIdx] === 'screenshots') {
    _wizRender();
  }
}

function _wizFollowUpQuestionsFromParse(data) {
  var raw = Array.isArray(data?._follow_up_questions) ? data._follow_up_questions : [];
  return raw.map(function(item) {
    if (typeof item === 'string') return { field: '', question: item };
    return {
      field: String(item?.field || ''),
      question: String(item?.question || ''),
    };
  }).filter(function(item) { return !!item.question.trim(); });
}

function _wizApplyParseResult(data) {
  if (!wizState || !data) return;
  var d = wizState.data;

  if (data.strategy) d.strategy = String(data.strategy);
  if (data.direction) d.direction = String(data.direction);
  if (data._htf_bias) d.htf_bias = String(data._htf_bias);

  if (data.why_trade) d.why_trade = String(data.why_trade);
  if (data.why_entry) d.why_entry = String(data.why_entry);
  if (data.scenario) d.scenario = String(data.scenario);
  if (data.why_stop) d.why_stop = String(data.why_stop);
  if (data.why_tp) d.why_tp = String(data.why_tp);

  if (data.entry_price != null) d.entry_price = String(data.entry_price);
  if (data.stop_loss != null) d.stop_loss = String(data.stop_loss);
  if (data.take_profit != null) d.take_profit = String(data.take_profit);
  if (data.stdv_level != null) d.stdv_level = String(data.stdv_level);
  if (data.pnl != null) d.pnl = String(data.pnl);
  if (data.rr != null) d.rr = String(data.rr);
  if (data.is_win != null) d.is_win = data.is_win ? '1' : '0';

  d.missing_followups = _wizFollowUpQuestionsFromParse(data);
}

async function wizAnalyzeMissingChat() {
  if (!wizState) return;
  _wizSaveCurrentStep();

  var textarea = document.getElementById('wizMissingChat');
  var analyzeBtn = document.getElementById('wizMissingAnalyzeBtn');
  var text = String(textarea?.value || '').trim();
  if (!text) {
    if (typeof toast === 'function') toast("Ecris ta reponse avant l'application", "error");
    return;
  }

  if (analyzeBtn) {
    analyzeBtn.disabled = true;
    analyzeBtn.textContent = "Application...";
  }

  try {
    var parsed = await api('/api/parse-trade', {
      method: 'POST',
      body: JSON.stringify({ text: text }),
    });
    _wizApplyParseResult(parsed);
    _wizSaveDraft();
    _wizRender();
    var followUps = _wizFollowUpQuestionsFromParse(parsed);
    if (followUps.length) {
      if (typeof toast === 'function') toast("Challenge rapide partiel: complete les points restants si besoin", "error");
    } else if (typeof toast === 'function') {
      toast("Reponse appliquee a la fiche", "success");
    }
  } catch (err) {
    if (typeof toast === 'function') toast("Erreur analyse : " + err.message, "error");
  } finally {
    if (analyzeBtn) {
      analyzeBtn.disabled = false;
      analyzeBtn.textContent = "Appliquer ma reponse";
    }
  }
}

// ─── Submit ────────────────────────────────────────────────

async function _wizSubmit() {
  _wizSaveCurrentStep();

  if (wizState.mode === 'postmortem') {
    return _wizSubmitPM();
  }

  var d = wizState.data;
  if (!d.date) d.date = todayKey();
  var instrument = wizCanonicalInstrument(d.instrument) || wizDefaultInstrument();
  if (!INSTRUMENTS.includes(instrument)) {
    instrument = wizDefaultInstrument();
  }
  d.instrument = instrument;

  try {
    // 1. Find or create day
    var dayId = d.dayId;
    if (!dayId) {
      var lookupRes = await fetch('/api/days/lookup?date=' + d.date + '&instrument=' + encodeURIComponent(instrument));
      if (lookupRes.ok) {
        var existing = await lookupRes.json();
        if (existing && existing.id) dayId = existing.id;
      }
    }

    if (!dayId) {
      var dayRes = await fetch('/api/days', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          date:          d.date,
          instrument:    instrument,
          htf_bias:      d.htf_bias,
          htf_context:   d.htf_context,
          daily_notes:   d.daily_notes,
          tags:          d.tags,
        })
      });
      if (!dayRes.ok) throw new Error('Erreur creation du jour');
      var day = await dayRes.json();
      dayId = day.id;
    } else if (d.htf_bias || d.htf_context || d.daily_notes) {
      await fetch('/api/days/' + dayId, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          htf_bias: d.htf_bias,
          htf_context: d.htf_context,
          daily_notes: d.daily_notes,
        })
      });
    }

    // 2. Create trade
    var tradeRes = await fetch('/api/days/' + dayId + '/trades', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        strategy:     d.strategy,
        direction:    d.direction,
        entry_price:  d.entry_price  ? +d.entry_price  : null,
        stop_loss:    d.stop_loss    ? +d.stop_loss    : null,
        take_profit:  d.take_profit  ? +d.take_profit  : null,
        stdv_level:   d.stdv_level   ? +d.stdv_level   : null,
        scenario:     d.scenario,
        why_trade:    d.why_trade,
        why_entry:    d.why_entry,
        why_stop:     d.why_stop,
        why_tp:       d.why_tp,
      })
    });
    if (!tradeRes.ok) throw new Error('Erreur creation du trade');
    var trade   = await tradeRes.json();
    var tradeId = trade.id;

    // 3. Upload screenshots
    for (var si = 0; si < (d.screenshots || []).length; si++) {
      var s = d.screenshots[si];
      if (!s.dataUrl) continue;
      var blob = await (await fetch(s.dataUrl)).blob();
      var form = new FormData();
      form.append('file', blob, s.name || 'screenshot.png');
      await fetch('/api/trades/' + tradeId + '/screenshots', { method: 'POST', body: form });
    }

    _wizClearDraft();
    wizClose();
    if (typeof toast    === 'function') toast("Trade enregistre", "success");
    if (typeof loadAll === 'function') loadAll();

  } catch(err) {
    console.error(err);
    if (typeof toast === 'function') toast("Erreur : " + err.message, "error");
  }
}

async function _wizSubmitPM() {
  var d = wizState.data;
  if (!d.tradeId) {
    if (typeof toast === 'function') toast("Trade introuvable", "error");
    return;
  }
  try {
    var res = await fetch('/api/trades/' + d.tradeId, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        exit_price:        d.exit_price   ? +d.exit_price : null,

        execution_quality: d.exit_quality || null,
        lessons_learned:   d.lessons,
      })
    });
    if (!res.ok) throw new Error('Erreur mise a jour trade');
    wizClose();
    if (typeof toast    === 'function') toast("Post-mortem enregistre", "success");
    if (typeof loadAll === 'function') loadAll();
  } catch(err) {
    if (typeof toast === 'function') toast("Erreur : " + err.message, "error");
  }
}

// ─── Keyboard ──────────────────────────────────────────────

function _wizKeydown(e) {
  if (!wizState) return;
  if (e.key === 'Escape') { e.preventDefault(); wizBack(); return; }
  if (e.key === 'Enter') {
    var activeEl = document.activeElement;
    var isTextarea = activeEl && activeEl.tagName === 'TEXTAREA';
    if (isTextarea && !e.ctrlKey) return;
    e.preventDefault();
    wizNext();
  }
}

// ─── Bind ──────────────────────────────────────────────────

// ---- 045_bindwizard.js ----
function bindWizard() {
  console.log('[WIZARD] bindWizard() called');
  var wiz = document.getElementById('wiz');
  if (!wiz) { console.log('[WIZARD] #wiz NOT found'); return; }
  console.log('[WIZARD] #wiz found');

  // Focus trap pour le wizard
  document.addEventListener('keydown', function _wizTrap(e) {
    if (e.key !== 'Tab') return;
    var el = document.getElementById('wiz');
    if (!el || el.classList.contains('hidden')) return;
    var f = el.querySelectorAll('button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"]), a[href]');
    if (f.length === 0) return;
    if (e.shiftKey && document.activeElement === f[0]) { e.preventDefault(); f[f.length - 1].focus(); }
    else if (!e.shiftKey && document.activeElement === f[f.length - 1]) { e.preventDefault(); f[0].focus(); }
  });

  // Diagnostic clic — capturer TOUT clic dans la wizard
  wiz.addEventListener('click', function(e) {
    console.log('[WIZ] CLICK target=' + e.target.tagName + (e.target.id ? '#'+e.target.id : '') + (e.target.className ? '.'+e.target.className.slice(0,30) : '') + ' phase=' + e.eventPhase);
  }, true); // capture=true pour intercepter TOUS les clics
  wiz.addEventListener('click', function(e) {
    if (e.target === wiz) { console.log('[WIZARD] backdrop click'); wizClose(); }
  });

  var closeBtn = document.getElementById('wizCloseBtn');
  var backBtn  = document.getElementById('wizBackBtn');
  var nextBtn  = document.getElementById('wizNextBtn');
  var skipBtn  = document.getElementById('wizSkipBtn');

  console.log('[WIZARD] closeBtn:', !!closeBtn, 'backBtn:', !!backBtn, 'nextBtn:', !!nextBtn, 'skipBtn:', !!skipBtn);
  if (closeBtn) closeBtn.addEventListener('click', function(e) { console.log('[WIZARD] closeBtn clicked'); wizClose(); });
  if (backBtn)  backBtn.addEventListener('click',  wizBack);
  if (nextBtn)  nextBtn.addEventListener('click',  wizNext);
  if (skipBtn)  skipBtn.addEventListener('click',  wizSkip);

  document.addEventListener('keydown', _wizKeydown);
}

// ---- 046_ai_panel.js ----
// ---------- AI panel ----------

const AI_PANEL_OPEN_KEY = "cockpit:aiPanelOpen:v1";

function setAiPanelOpen(open, persist = true) {
  document.body.classList.toggle("ai-panel-open", !!open);
  const btn = $("#aiPanelToggle");
  if (btn) btn.setAttribute("aria-expanded", open ? "true" : "false");
  if (persist) {
    try { localStorage.setItem(AI_PANEL_OPEN_KEY, open ? "1" : "0"); } catch (_) {}
  }
}

function bindAiPanelToggle() {
  const btn = $("#aiPanelToggle");
  if (!btn) return;
  let saved = null;
  try { saved = localStorage.getItem(AI_PANEL_OPEN_KEY); } catch (_) {}
  setAiPanelOpen(saved === "1", false);
  btn.addEventListener("click", () => {
    const next = !document.body.classList.contains("ai-panel-open");
    setAiPanelOpen(next, true);
  });
}

// ---- 047_today_widget_board.js ----
// ---------- Widget boards ----------

const WIDGET_ORDER_PREFIX = "cockpit:widgetOrder:";
const WIDGET_VIS_PREFIX = "cockpit:widgetVis:";
const WIDGET_POS_PREFIX = "cockpit:widgetPos:";

var WIDGET_REGISTRY = {
  kpi_total_pnl:      { label: "Net PnL",          icon: "dollar",  kind: "kpi",    size: "sm" },
  kpi_winrate:         { label: "Winrate",           icon: "clock",  kind: "kpi",    size: "sm" },
  kpi_average_rr:      { label: "Avg R",            icon: "trend",  kind: "kpi",    size: "sm" },
  kpi_trades:          { label: "Trades",            icon: "list",  kind: "kpi",    size: "sm" },
  kpi_profit_factor:   { label: "Profit Factor",    icon: "scale", kind: "kpi",    size: "sm" },
  kpi_expectancy:      { label: "Expectancy",        icon: "chart", kind: "kpi",    size: "sm" },
  today_context:       { label: "Contexte du jour",  icon: "globe", kind: "panel",  size: "full" },
  today_log:           { label: "Recap",             icon: "log",   kind: "panel",  size: "md" },
  today_activity:      { label: "Activite",          icon: "bolt",  kind: "panel",  size: "tall" },
  today_calendar:      { label: "Calendrier",        icon: "cal",   kind: "panel",  size: "md" },
  today_streak:        { label: "Streak",            icon: "bolt",  kind: "kpi",    size: "sm" },
  btc_chart:           { label: "BTC Chart",         icon: "chart", kind: "panel",  size: "xl" },
  hyperliquid_markets: { label: "HL Markets",        icon: "exchange", kind: "panel", size: "xl" },
  hyperliquid_wallets: { label: "HL Wallets",        icon: "wallet", kind: "panel", size: "xl" },
  favorites_carousel:  { label: "Favoris",           icon: "heart", kind: "panel",  size: "xl" },
};

var WIDGET_DEFAULTS = {
  "today": ["kpi_total_pnl", "kpi_winrate", "kpi_average_rr", "kpi_trades", "kpi_profit_factor", "kpi_expectancy", "today_context", "today_log", "today_activity", "today_calendar", "today_streak", "btc_chart", "hyperliquid_markets", "hyperliquid_wallets", "favorites_carousel"],
};

function readWidgetOrder(boardKey) {
  try {
    var raw = localStorage.getItem(WIDGET_ORDER_PREFIX + boardKey);
    var parsed = JSON.parse(raw || "[]");
    return Array.isArray(parsed) ? parsed.filter(function(x) { return typeof x === "string" && x; }) : [];
  } catch (_) { return []; }
}

function writeWidgetOrder(boardKey, keys) {
  try { localStorage.setItem(WIDGET_ORDER_PREFIX + boardKey, JSON.stringify(keys)); } catch (_) {}
}

function readWidgetPositions(boardKey) {
  try {
    var raw = localStorage.getItem(WIDGET_POS_PREFIX + boardKey);
    var parsed = JSON.parse(raw || "{}");
    return (typeof parsed === "object" && parsed !== null) ? parsed : {};
  } catch (_) { return {}; }
}

function writeWidgetPositions(boardKey, pos) {
  try { localStorage.setItem(WIDGET_POS_PREFIX + boardKey, JSON.stringify(pos)); } catch (_) {}
}

function readWidgetVisibility() {
  try {
    var raw = localStorage.getItem(WIDGET_VIS_PREFIX + "today");
    var parsed = JSON.parse(raw || "{}");
    return typeof parsed === "object" && parsed !== null ? parsed : {};
  } catch (_) { return {}; }
}

function writeWidgetVisibility(map) {
  try { localStorage.setItem(WIDGET_VIS_PREFIX + "today", JSON.stringify(map)); } catch (_) {}
}

function getWidgetDefaults() {
  var vis = {};
  Object.keys(WIDGET_REGISTRY).forEach(function(key) { vis[key] = true; });
  return vis;
}

function applyWidgetBoardOrder(board) {
  var boardKey = board && board.dataset && board.dataset.widgetBoard;
  if (!boardKey) return;
  var desired = readWidgetOrder(boardKey);
  var nodes = Array.from(board.children).filter(function(el) { return el && el.dataset && el.dataset.widgetKey; });
  var byKey = new Map(nodes.map(function(el) { return [el.dataset.widgetKey, el]; }));
  desired.forEach(function(key) {
    var node = byKey.get(key);
    if (node) board.appendChild(node);
  });
  var finalKeys = Array.from(board.children).map(function(el) { return el && el.dataset && el.dataset.widgetKey; }).filter(Boolean);
  writeWidgetOrder(boardKey, finalKeys);

  var pos = readWidgetPositions(boardKey);
  Array.from(board.children).forEach(function(el) {
    var key = el.dataset && el.dataset.widgetKey;
    if (!key) return;
    var p = pos[key];
    if (p && p.col && p.row) {
      el.style.gridColumnStart = p.col;
      el.style.gridRowStart = p.row;
    } else {
      el.style.gridColumnStart = "";
      el.style.gridRowStart = "";
    }
  });

  board.dataset.widgetReady = "1";
}

function applyWidgetVisibility() {
  var vis = readWidgetVisibility();
  Object.keys(WIDGET_REGISTRY).forEach(function(key) {
    var visible = vis[key] !== undefined ? vis[key] : true;
    var el = document.querySelector('[data-widget-key="' + key + '"]');
    if (!el) return;
    if (visible) { el.classList.remove("widget-hidden"); el.style.display = ""; }
    else { el.classList.add("widget-hidden"); el.style.display = "none"; }
  });
  updateDashboardLayout();
  refreshDragHandles();
}

function updateDashboardLayout() {
  var board = document.querySelector('[data-widget-board="today"]');
  if (board) {
    var visible = Array.from(board.children).filter(function(el) {
      return el.dataset && el.dataset.widgetKey && !el.classList.contains("widget-hidden");
    }).length;
    board.dataset.visibleCount = visible;
    board.classList.toggle("today-empty", visible === 0);
  }
}

function initWidgetBoards() {
  document.querySelectorAll(".widget-board[data-widget-board]").forEach(applyWidgetBoardOrder);
  applyWidgetVisibility();
  bindWidgetConfig();
  initWidgetDragDrop();
}

function initTodayWidgetBoards() { initWidgetBoards(); }

function toggleWidgetVisibility(key) {
  var vis = readWidgetVisibility();
  vis[key] = vis[key] === undefined ? false : !vis[key];
  writeWidgetVisibility(vis);
  applyWidgetVisibility();
  renderWidgetConfigItems();
  if (state.currentPage === "today" && typeof renderToday === "function") renderToday();
  if (typeof renderKPIs === "function" && state._stats) renderKPIs(state._stats);
}

function resetWidgetVisibility() {
  if (!confirm("Réinitialiser tous les widgets à leur état par défaut ?")) return;
  writeWidgetVisibility(getWidgetDefaults());
  writeWidgetOrder("today", WIDGET_DEFAULTS["today"]);
  writeWidgetPositions("today", {});
  applyWidgetVisibility();
  applyWidgetBoardOrder(document.querySelector('[data-widget-board="today"]'));
  renderWidgetConfigItems();
  if (state.currentPage === "today" && typeof renderToday === "function") renderToday();
  if (typeof renderKPIs === "function" && state._stats) renderKPIs(state._stats);
}

// ---- Dropdown config ----

function widgetIconSvg(icon) {
  var svgs = {
    dollar: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>',
    clock: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>',
    trend: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polyline points="22 7 13.5 15.5 8.5 10.5 2 17"/><polyline points="16 7 22 7 22 13"/></svg>',
    list: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><line x1="4" y1="9" x2="20" y2="9"/><line x1="4" y1="15" x2="20" y2="15"/><line x1="10" y1="3" x2="8" y2="21"/><line x1="16" y1="3" x2="14" y2="21"/></svg>',
    scale: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M3 12h18"/><path d="M8 7l-5 5 5 5"/><path d="M16 17l5-5-5-5"/></svg>',
    chart: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M4 19h16"/><path d="M6 15l4-4 3 3 5-6"/></svg>',
    globe: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><line x1="2" y1="12" x2="22" y2="12"/><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z"/></svg>',
    log: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>',
    bolt: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/></svg>',
    cal: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="17" rx="3"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>',
    wallet: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M19 7V6a2 2 0 0 0-2-2H5a2 2 0 0 0 0 4h14a2 2 0 0 1 2 2v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V6"/><path d="M16 13h.01"/></svg>',
    exchange: '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M7 7h11l-3-3"/><path d="M17 17H6l3 3"/><path d="M18 7l-4 4"/><path d="M6 17l4-4"/></svg>',
  };
  return svgs[icon] || svgs.list;
}

function renderWidgetConfigItems() {
  var container = document.getElementById("widgetConfigItems");
  if (!container) return;
  var vis = readWidgetVisibility();
  var order = readWidgetOrder("today");
  if (!order.length) order = WIDGET_DEFAULTS["today"];
  Object.keys(WIDGET_REGISTRY).forEach(function(key) {
    if (order.indexOf(key) < 0) order.push(key);
  });
  function renderItem(key) {
    var meta = WIDGET_REGISTRY[key];
    if (!meta) return "";
    var isOn = vis[key] !== false;
    return '<div class="widget-config-item' + (isOn ? " is-on" : "") + '" data-widget-toggle="' + key + '">' +
      '<div class="widget-config-item-icon">' + widgetIconSvg(meta.icon) + '</div>' +
      '<div class="widget-config-item-info">' +
        '<span class="widget-config-item-label">' + escapeHtml(meta.label) + '</span>' +
        '<span class="widget-config-item-kind">' + (meta.kind === "kpi" ? "KPI" : "Panneau") + '</span>' +
      '</div>' +
      '<div class="widget-config-item-toggle">' +
        '<div class="toggle-track' + (isOn ? " is-on" : "") + '"><div class="toggle-thumb"></div></div>' +
      '</div>' +
    '</div>';
  }
  container.innerHTML = order.map(renderItem).join("");
}

function positionDropdown(dropdown, btn) {
  if (!dropdown || !btn) return;
  var rect = btn.getBoundingClientRect();
  var top = rect.bottom + 6;
  var left = rect.right - 280;
  if (left < 8) left = 8;
  if (top + 400 > window.innerHeight) { top = rect.top - 6 - 400; if (top < 8) top = 8; }
  dropdown.style.top = top + "px";
  dropdown.style.left = left + "px";
}

function bindWidgetConfig() {
  var dropdown = document.getElementById("widgetDropdown");
  var btn = document.getElementById("widgetConfigBtn");
  var resetBtn = document.getElementById("widgetConfigReset");
  var itemsC = document.getElementById("widgetConfigItems");
  if (!dropdown || !btn) return;

  btn.addEventListener("click", function(e) {
    e.stopPropagation();
    if (dropdown.classList.contains("is-open")) { dropdown.classList.remove("is-open"); return; }
    renderWidgetConfigItems();
    positionDropdown(dropdown, btn);
    dropdown.classList.add("is-open");
  });
  dropdown.addEventListener("click", function(e) { e.stopPropagation(); });
  document.addEventListener("click", function(e) {
    if (!dropdown.contains(e.target) && e.target !== btn && !btn.contains(e.target)) dropdown.classList.remove("is-open");
  });
  document.addEventListener("keydown", function(e) { if (e.key === "Escape") dropdown.classList.remove("is-open"); });
  window.addEventListener("scroll", function() { if (dropdown.classList.contains("is-open")) dropdown.classList.remove("is-open"); }, { passive: true });
  resetBtn.addEventListener("click", function() { resetWidgetVisibility(); });
  function handleToggle(e) {
    var item = e.target.closest("[data-widget-toggle]");
    if (!item) return;
    e.preventDefault();
    toggleWidgetVisibility(item.dataset.widgetToggle);
  }
  itemsC.addEventListener("click", handleToggle);
  applyWidgetVisibility();
}

// ============================================================
// Drag & Drop v12 — swap-based with overlap-normalized hit test
// ============================================================

var _dnd = null;
var _dndRaf = 0;
var DND_LONG_PRESS = ('ontouchstart' in window) ? 120 : 180;

function initWidgetDragDrop() {
  refreshDragHandles();
  document.addEventListener("pointermove", onDndPointerMove, { passive: false });
  document.addEventListener("pointerup",   onDndPointerUp);
  document.addEventListener("pointercancel", onDndPointerUp);
}

function refreshDragHandles() {
  if (_dnd) return;
  document.querySelectorAll(".widget-board[data-widget-board] .widget[data-widget-key]").forEach(function(el) {
    if (el.classList.contains("widget-hidden")) return;
    if (el._dndBound) return;
    el._dndBound = true;

    var pressTimer = null;
    var pressStartX = 0, pressStartY = 0;

    el.addEventListener("pointerdown", function(e) {
      if (e.button && e.button !== 0) return;
      if (e.target.closest("input,textarea,button,a,select,[contenteditable],[draggable],[role=\"button\"],.journal-flip-card,.fav-carousel-arrow")) return;
      if (_dnd) return;
      var widget = el;
      var board = widget.closest(".widget-board[data-widget-board]");
      if (!board) return;

      el.setPointerCapture(e.pointerId);

      pressStartX = e.clientX;
      pressStartY = e.clientY;
      widget.classList.add("is-press-pending");

      pressTimer = setTimeout(function() {
        pressTimer = null;
        if (navigator.vibrate) navigator.vibrate(18);
        widget.classList.remove("is-press-pending");
        var rect = widget.getBoundingClientRect();
        var rawOffsetX = pressStartX - rect.left;
        var rawOffsetY = pressStartY - rect.top;
        var centerX = rect.width / 2;
        var centerY = rect.height / 2;
        var SNAP_TO_CENTER = 0.40;

        // Cibles fantomes sur les cellules vides de la grille
        var holes = _createWidgetHoles(board);

        _dnd = {
          el: widget, board: board,
          offsetX: rawOffsetX + (centerX - rawOffsetX) * SNAP_TO_CENTER,
          offsetY: rawOffsetY + (centerY - rawOffsetY) * SNAP_TO_CENTER,
          width: rect.width, height: rect.height,
          ghost: null,
          active: false,
          dropRef: null,
          holes: holes,
        };
        dndStart(pressStartX, pressStartY);
      }, DND_LONG_PRESS);
    });

    el.addEventListener("pointerup", function() {
      if (pressTimer) { clearTimeout(pressTimer); pressTimer = null; }
      el.classList.remove("is-press-pending");
    });
    el.addEventListener("pointercancel", function() {
      if (pressTimer) { clearTimeout(pressTimer); pressTimer = null; }
      el.classList.remove("is-press-pending");
    });
    el.addEventListener("pointermove", function(e) {
      if (!pressTimer) return;
      var dx = e.clientX - pressStartX, dy = e.clientY - pressStartY;
      if (dx*dx + dy*dy > 100) {
        clearTimeout(pressTimer); pressTimer = null;
        el.classList.remove("is-press-pending");
      }
    }, { passive: true });
  });
}

function onDndPointerMove(e) {
  if (!_dnd || !_dnd.active) return;
  e.preventDefault();
  if (_dndRaf) cancelAnimationFrame(_dndRaf);
  var cx = e.clientX, cy = e.clientY;
  _dndRaf = requestAnimationFrame(function() {
    _dndRaf = 0;
    if (_dnd && _dnd.active) dndMove(cx, cy);
  });
}

function onDndPointerUp() {
  if (_dndRaf) { cancelAnimationFrame(_dndRaf); _dndRaf = 0; }
  if (!_dnd) return;
  if (_dnd.active) dndEnd(); // dndEnd nettoie les holes + met _dnd = null
  else {
    // Drag pas encore actif — nettoyer les trous manuellement
    if (_dnd.holes) { _dnd.holes.forEach(function(h) { h.remove(); }); }
    _dnd = null;
  }
}

function dndStart(cx, cy) {
  _dnd.active = true;
  var el = _dnd.el;

  el.classList.add("widget-dragging");

  var ghost = el.cloneNode(true);
  ghost.classList.remove("is-press-pending", "widget-dragging");
  ghost.removeAttribute("data-widget-key");
  ghost.classList.add("widget-drag-ghost");
  ghost.style.cssText = [
    "position:fixed","z-index:10000","left:0","top:0",
    "width:"  + _dnd.width  + "px",
    "height:" + _dnd.height + "px",
    "margin:0","pointer-events:none","will-change:transform",
    "transform:translate(" + (cx - _dnd.offsetX) + "px," + (cy - _dnd.offsetY) + "px) scale(0.97)",
    "opacity:0.75",
    "transition:opacity 120ms ease,box-shadow 120ms ease"
  ].join(";");
  document.body.appendChild(ghost);
  _dnd.ghost = ghost;

  requestAnimationFrame(function() {
    if (!_dnd || !_dnd.ghost) return;
    _dnd.ghost.style.opacity   = "0.97";
    _dnd.ghost.style.transform = "translate(" + (cx - _dnd.offsetX) + "px," + (cy - _dnd.offsetY) + "px) scale(1.04)";
    _dnd.ghost.style.boxShadow = "0 28px 80px rgba(0,0,0,0.65),0 0 0 1.5px rgba(0,229,255,0.4)";
    _dnd.ghost.style.transition = "opacity 120ms ease,box-shadow 120ms ease";
  });

  document.body.classList.add("is-dragging");
  _dnd.dropRef = null;
}

function dndMove(cx, cy) {
  if (!_dnd) return;

  _dnd.ghost.style.transition = "none";
  _dnd.ghost.style.transform  = "translate(" + (cx - _dnd.offsetX) + "px," + (cy - _dnd.offsetY) + "px) scale(1.04)";

  var items = dndItems(_dnd.board);
  var ghostLeft   = cx - _dnd.offsetX;
  var ghostTop    = cy - _dnd.offsetY;
  var ghostRight  = ghostLeft + _dnd.width;
  var ghostBottom = ghostTop  + _dnd.height;
  var ghostCX     = ghostLeft + _dnd.width  / 2;
  var ghostCY     = ghostTop  + _dnd.height / 2;

  var dropIdx = dndHitTest(items, ghostLeft, ghostTop, ghostRight, ghostBottom, ghostCX, ghostCY, _dnd.el);
  var dropRef = dropIdx >= 0 && dropIdx < items.length ? items[dropIdx] : null;

  if (dropRef === _dnd.dropRef) return;

  if (_dnd.dropRef) _dnd.dropRef.classList.remove("widget-drop-target");
  _dnd.dropRef = dropRef;
  if (dropRef) dropRef.classList.add("widget-drop-target");
}

function dndEnd() {
  if (!_dnd) return;
  var el = _dnd.el, board = _dnd.board;

  if (_dnd.dropRef && _dnd.dropRef !== el) {
    _dnd.dropRef.classList.remove("widget-drop-target");

    var target = _dnd.dropRef;
    var targetBoard = _dnd.targetBoard || target.closest(".widget-board[data-widget-board]");

    if (targetBoard === board) {
      if (target.classList.contains("widget-hole")) {
        // Déplacer le widget dans le trou — pas de swap DOM
        var holeCol = parseInt(target.style.gridColumnStart, 10);
        var holeRow = parseInt(target.style.gridRowStart, 10);
        el.style.gridColumnStart = holeCol;
        el.style.gridRowStart    = holeRow;
      } else {
        // Swap DOM
        var placeholder = document.createElement("div");
        board.insertBefore(placeholder, el);
        board.insertBefore(el, target);
        board.insertBefore(target, placeholder);
        placeholder.remove();
      }
    } else {
      // Cross-board
      var ph = document.createComment("swap");
      board.insertBefore(ph, el);
      targetBoard.insertBefore(el, target);
      board.insertBefore(target, ph);
      ph.remove();
    }
  }

  el.classList.remove("widget-dragging");
  el.style.transition = ""; el.style.transform = "";

  requestAnimationFrame(function() {
    el.style.transition = "transform 220ms cubic-bezier(0.34,1.56,0.64,1)";
    el.style.transform  = "scale(1.03)";
    setTimeout(function() {
      el.style.transform = "scale(1)";
      setTimeout(function() { el.style.transition = ""; el.style.transform = ""; }, 220);
    }, 30);
  });

  if (_dnd.ghost) _dnd.ghost.remove();
  document.body.classList.remove("is-dragging");

  var affectedBoards = [board];
  if (_dnd.targetBoard && _dnd.targetBoard !== board) affectedBoards.push(_dnd.targetBoard);

  affectedBoards.forEach(function(b) {
    var bKey = b.dataset.widgetBoard;
    var order = Array.from(b.children)
      .map(function(c) { return c.dataset && c.dataset.widgetKey; }).filter(Boolean);
    writeWidgetOrder(bKey, order);

    // Snapshot direct des styles inline — PAS de clear, PAS de getComputedStyle
    var pos = {};
    Array.from(b.children).forEach(function(child) {
      var key = child.dataset && child.dataset.widgetKey;
      if (!key || child.classList.contains("widget-hidden")) return;
      var col = parseInt(child.style.gridColumnStart, 10);
      var row = parseInt(child.style.gridRowStart, 10);
      if (!isNaN(col) && col > 0 && !isNaN(row) && row > 0) {
        pos[key] = { col: col, row: row };
      }
    });
    writeWidgetPositions(bKey, pos);
  });

  updateDashboardLayout();

  // Nettoyer les trous
  if (_dnd.holes) { _dnd.holes.forEach(function(h) { h.remove(); }); _dnd.holes = null; }

  setTimeout(refreshDragHandles, 300);
  _dnd = null;
}

function dndItems(board) {
  var items = Array.from(board.children).filter(function(el) {
    return el && el.dataset && el.dataset.widgetKey
      && !el.classList.contains("widget-hidden");
  });
  if (_dnd && _dnd.holes) {
    _dnd.holes.forEach(function(h) {
      if (h.parentNode === board) items.push(h);
    });
  }
  return items;
}

function _createWidgetHoles(board) {
  var holes = [];
  var children = Array.from(board.children).filter(function(c) {
    return c.dataset && c.dataset.widgetKey && !c.classList.contains("widget-hidden");
  });
  if (children.length === 0) return holes;

  // Lire la grille actuelle via computed style
  var boardStyle = window.getComputedStyle(board);
  var cols = (boardStyle.gridTemplateColumns || "").split(/\s+/).filter(Boolean).length;
  if (cols === 0) return holes;

  // Collecter les cellules occupees via data-size (plus fiable que gridRowEnd/computed)
  var occupied = new Set();
  children.forEach(function(c) {
    var cs = window.getComputedStyle(c);
    var col = parseInt(cs.gridColumnStart, 10);
    var row = parseInt(cs.gridRowStart, 10);
    if (isNaN(col) || isNaN(row) || col < 1 || row < 1) return;

    var size = c.dataset.size || "";
    var colSpan = size === "full" ? cols : size === "wide" ? 2 : 1;
    var rowSpan = size === "tall" ? 2 : 1;

    for (var r = row; r < row + rowSpan; r++) {
      for (var co = col; co < col + colSpan; co++) {
        occupied.add(r + ":" + co);
      }
    }
  });

  // Hauteur max = row la plus haute occupee
  var maxRow = 0;
  occupied.forEach(function(cell) { var rr = parseInt(cell, 10); if (rr > maxRow) maxRow = rr; });
  if (maxRow === 0) return holes;

  // Creer un trou pour chaque cellule vide
  for (var r = 1; r <= maxRow; r++) {
    for (var co = 1; co <= cols; co++) {
      if (!occupied.has(r + ":" + co)) {
        var hole = document.createElement("div");
        hole.className = "widget-hole";
        hole.style.gridColumnStart = co;
        hole.style.gridRowStart = r;
        hole.style.pointerEvents = "none";
        board.appendChild(hole);
        holes.push(hole);
      }
    }
  }
  return holes;
}

function dndHitTest(items, ghostLeft, ghostTop, ghostRight, ghostBottom, ghostCX, ghostCY, draggedEl) {
  var bestScore = 0, bestIdx = -1;

  for (var i = 0; i < items.length; i++) {
    if (items[i] === draggedEl) continue;
    var r = items[i].getBoundingClientRect();
    var ox = Math.max(0, Math.min(ghostRight, r.right) - Math.max(ghostLeft, r.left));
    var oy = Math.max(0, Math.min(ghostBottom, r.bottom) - Math.max(ghostTop, r.top));
    var overlap = ox * oy;
    if (overlap <= 0) continue;
    var targetArea = r.width * r.height;
    var score = overlap / targetArea;
    if (score > bestScore) {
      bestScore = score;
      bestIdx = i;
    }
  }

  if (bestIdx >= 0) {
    return bestIdx;
  }

  var nearest = -1, nearestDist = Infinity;
  for (var j = 0; j < items.length; j++) {
    if (items[j] === draggedEl) continue;
    var rj = items[j].getBoundingClientRect();
    var dx = ghostCX - (rj.left + rj.width / 2);
    var dy = ghostCY - (rj.top + rj.height / 2);
    var dist = dx * dx + dy * dy;
    if (dist < nearestDist) { nearestDist = dist; nearest = j; }
  }

  return nearest < 0 ? -1 : nearest;
}

// ---------- Today calendar (mini vue mois courant) ----------

function renderTodayCalendar() {
  var grid = $("#todayCalendarGrid");
  var monthEl = $("#todayCalendarMonth");
  if (!grid) return;

  var now = new Date();
  var year = now.getFullYear();
  var month = now.getMonth();

  if (monthEl) monthEl.textContent = (MONTHS_FR[month] || "") + " " + year;

  var byDay = buildCalendarByDay(state.days || []);

  var prevMode = state.calendarMetricMode;
  state.calendarMetricMode = state.calendarMetricMode || "pnl";

  var first = new Date(year, month, 1);
  var firstIdx = (first.getDay() + 6) % 7;
  var daysInMonth = new Date(year, month + 1, 0).getDate();
  var tk = todayKey();
  var frag = document.createDocumentFragment();

  for (var i = 0; i < firstIdx; i++) {
    var spacer = document.createElement("div");
    spacer.className = "day other-month";
    spacer.style.visibility = "hidden";
    frag.appendChild(spacer);
  }
  for (var d = 1; d <= daysInMonth; d++) {
    frag.appendChild(dayCell(new Date(year, month, d), byDay, false, tk));
  }

  state.calendarMetricMode = prevMode;
  grid.replaceChildren(frag);
  grid.dataset.metricMode = state.calendarMetricMode || "pnl";
  grid.dataset.viewMode = "month";

  if (!grid.dataset.bound) {
    grid.dataset.bound = "1";
    // Delegation document-level pour garantir la capture
    document.addEventListener("click", function _todayCalClick(e) {
      var dayEl = e.target.closest("#todayCalendarGrid .day");
      if (!dayEl) return;
      // other-month: navigation vers le mois clique uniquement (pas d'ouverture de jour)
      var isOther = dayEl.dataset.otherMonth === "1";
      if (isOther) {
        var otherKey = dayEl.dataset.date;
        if (otherKey && typeof goPage === "function") {
          state.journalFocusDate = otherKey;
          goPage("journal");
        }
        return;
      }
      var key = dayEl.dataset.date;
      if (!key) return;
      if (typeof wizOpen === "function") {
        wizOpen({ date: key });
      }
    });
    grid.addEventListener("keydown", function(e) {
      if (e.key !== "Enter" && e.key !== " ") return;
      var dayEl = e.target.closest(".day");
      if (!dayEl || dayEl.dataset.otherMonth === "1") return;
      e.preventDefault();
      dayEl.click();
    });
  }
}

// ---- 048_ai_chat.js ----
// ---------- AI Chat — frontend ----------
// State : window.aiChatHistory (session only, not persisted)
// Uses : api(), toast()
// Integration : wizard (wizOpen), day editor (openExistingDay)

/* Markdown rendering helpers (lightweight — no external lib needed) */

function _aiSafeHref(url) {
  try {
    var u = new URL(url, window.location.origin);
    if (u.protocol === 'http:' || u.protocol === 'https:' || u.protocol === 'mailto:') {
      return u.href;
    }
  } catch (_) {}
  return '#';
}

function _aiRenderInline(text) {
  var s = escapeHtml(text);
  // Bold
  s = s.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  // Italic
  s = s.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, '<em>$1</em>');
  // Inline code
  s = s.replace(/`([^`]+)`/g, '<code>$1</code>');
  // Links — sanitize href to prevent javascript: / data: injection
  s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, function (_, label, href) {
    return '<a href="' + escapeHtml(_aiSafeHref(href)) + '" target="_blank" rel="noopener noreferrer">' + label + '</a>';
  });
  return s;
}

function _aiRenderMarkdown(text) {
  if (!text) return '';
  var lines = text.split('\n');
  var html = '';
  var inCodeBlock = false;
  var codeContent = '';

  for (var i = 0; i < lines.length; i++) {
    var line = lines[i];

    // Code block fences
    if (/^```/.test(line)) {
      if (inCodeBlock) {
        html += '<pre><code>' + escapeHtml(codeContent.replace(/\n$/, '')) + '</code></pre>';
        codeContent = '';
        inCodeBlock = false;
      } else {
        inCodeBlock = true;
        codeContent = '';
      }
      continue;
    }

    if (inCodeBlock) {
      codeContent += line + '\n';
      continue;
    }

    var trimmed = line.trim();

    // Headings
    if (/^#{1,4}\s/.test(trimmed)) {
      var level = trimmed.match(/^#{1,4}/)[0].length;
      var hContent = _aiRenderInline(trimmed.replace(/^#+\s*/, ''));
      html += '<h' + level + '>' + hContent + '</h' + level + '>';
      continue;
    }

    // Blockquote
    if (/^>\s/.test(trimmed)) {
      html += '<blockquote>' + _aiRenderInline(trimmed.replace(/^>\s*/, '')) + '</blockquote>';
      continue;
    }

    // Horizontal rule
    if (/^---+\s*$/.test(trimmed)) {
      html += '<hr>';
      continue;
    }

    // Unordered list
    if (/^[-*+]\s/.test(trimmed)) {
      html += '<li>' + _aiRenderInline(trimmed.replace(/^[-*+]\s*/, '')) + '</li>';
      continue;
    }

    // Ordered list
    if (/^\d+\.\s/.test(trimmed)) {
      html += '<li value="' + trimmed.match(/^\d+/)[0] + '">' + _aiRenderInline(trimmed.replace(/^\d+\.\s*/, '')) + '</li>';
      continue;
    }

    // Empty line = paragraph break
    if (trimmed === '') {
      html += '</p><p>';
      continue;
    }

    // Regular text
    html += _aiRenderInline(line) + ' ';
  }

  if (inCodeBlock) {
    html += '<pre><code>' + escapeHtml(codeContent.replace(/\n$/, '')) + '</code></pre>';
  }

  // Wrap list items
  html = html.replace(/(<li[^>]*>.*?<\/li>)((?!<\/?li|<pre|<code|<\/p>).)*/gs, function(m) {
    var items = m.match(/<li[^>]*>.*?<\/li>/g);
    if (items && items.length > 1) {
      return '<ul>' + items.join('') + '</ul>';
    }
    return m;
  });

  // Wrap ordered list items
  html = html.replace(/((?:<li value="\d+".*?<\/li>)+)/g, function(m) {
    return '<ol>' + m + '</ol>';
  });

  // Trim and wrap
  html = html.trim();
  html = '<p>' + html + '</p>';
  // Clean double paragraph wraps
  html = html.replace(/<\/p>\s*<p>/g, '</p><p>');
  // Remove empty paragraphs
  html = html.replace(/<p>\s*<\/p>/g, '');
  return html;
}

/* Parse action markers from AI response */

function _aiParseActions(text) {
  var actions = [];
  var regex = /\[(wizOpen|openDay):\s*(\{[^}]+\})\]/g;
  var match;
  while ((match = regex.exec(text)) !== null) {
    try {
      var data = JSON.parse(match[2]);
      actions.push({ type: match[1], data: data });
    } catch (_) {}
  }
  return actions;
}

/* Strip action markers from display text */

function _aiStripActions(text) {
  return text.replace(/\[(wizOpen|openDay):\s*\{[^}]+\}\]/g, '').trim();
}

/* Render action buttons */

var _aiActionStore = {};
var _aiActionId = 0;

function _aiRenderActions(actions) {
  if (!actions || actions.length === 0) return '';
  var html = '<div class="ai-chat-actions">';
  for (var i = 0; i < actions.length; i++) {
    var a = actions[i];
    var label = '';
    var icon = '';
    switch (a.type) {
      case 'wizOpen':
        label = 'Ouvrir le wizard';
        icon = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"/></svg>';
        break;
      case 'openDay':
        label = 'Ouvrir le jour';
        icon = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>';
        break;
    }
    _aiActionId++;
    _aiActionStore[_aiActionId] = { type: a.type, data: a.data };
    html += '<button type="button" class="ai-chat-action-btn" data-ai-action-id="' + _aiActionId + '">' + icon + label + '</button>';
  }
  html += '</div>';
  return html;
}

/* Handle action button click */

function _aiHandleActionClick(e) {
  var btn = e.currentTarget;
  var id = parseInt(btn.getAttribute('data-ai-action-id'));
  var stored = _aiActionStore[id];
  if (!stored) return;
  var type = stored.type;
  var data = stored.data;

  switch (type) {
    case 'wizOpen':
      if (typeof wizOpen === 'function') {
        wizOpen(data);
      }
      break;
    case 'openDay':
      if (typeof openExistingDay === 'function' && data.id) {
        // Fetch the day by ID
        api('/api/days/' + data.id).then(function(day) {
          openExistingDay(day);
        }).catch(function() {
          toast('Impossible de charger ce jour', 'error');
        });
      } else if (data.date && data.instrument) {
        api('/api/days/lookup?date=' + encodeURIComponent(data.date) + '&instrument=' + encodeURIComponent(data.instrument)).then(function(day) {
          if (day) {
            openExistingDay(day);
          } else {
            toast('Jour introuvable pour cette date', 'error');
          }
        }).catch(function() {
          toast('Impossible de charger ce jour', 'error');
        });
      }
      break;
  }
}

/* --- Core chat functions --- */

function aiChatInit() {
  window.aiChatHistory = [];

  var messages = document.getElementById('aiChatMessages');
  if (!messages) return;

  // Render welcome
  messages.innerHTML =
    '<div class="ai-chat-welcome">' +
      '<div class="ai-chat-welcome-icon">' +
        '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">' +
          '<path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z"/>' +
        '</svg>' +
      '</div>' +
      '<div class="ai-chat-welcome-title">Assistant COCKPIT</div>' +
      '<div class="ai-chat-welcome-text">' +
        'Pose-moi des questions sur tes trades, demande-moi de créer ou modifier des entrées, ou de te donner des insights sur tes performances.' +
      '</div>' +
    '</div>';
}

function aiChatAddMessage(role, content, extra) {
  extra = extra || {};
  var messages = document.getElementById('aiChatMessages');
  if (!messages) return;

  // Remove welcome if user message
  var welcome = messages.querySelector('.ai-chat-welcome');
  if (welcome && role === 'user') {
    welcome.remove();
  }

  var now = new Date();
  var timeStr = String(now.getHours()).padStart(2, '0') + ':' + String(now.getMinutes()).padStart(2, '0');

  var div = document.createElement('div');
  div.className = 'ai-chat-msg ai-chat-msg-' + role;
  if (extra.error) div.classList.add('ai-chat-error');

  var displayContent = content;
  var actions = [];

  if (role === 'assistant') {
    actions = _aiParseActions(content);
    displayContent = _aiStripActions(content);
  }

  if (role === 'assistant' || role === 'system') {
    div.innerHTML =
      '<div class="ai-chat-msg-bubble">' + _aiRenderMarkdown(displayContent) + '</div>' +
      _aiRenderActions(actions) +
      '<div class="ai-chat-msg-time">' + timeStr + '</div>';
  } else {
    div.innerHTML =
      '<div class="ai-chat-msg-bubble">' + escapeHtml(displayContent) + '</div>' +
      '<div class="ai-chat-msg-time">' + timeStr + '</div>';
  }

  messages.appendChild(div);

  // Bind action buttons
  var actionBtns = div.querySelectorAll('.ai-chat-action-btn');
  for (var i = 0; i < actionBtns.length; i++) {
    actionBtns[i].addEventListener('click', _aiHandleActionClick);
  }

  aiChatScrollBottom();
}

function aiChatScrollBottom() {
  var messages = document.getElementById('aiChatMessages');
  if (!messages) return;
  // Use requestAnimationFrame to ensure DOM is flushed
  requestAnimationFrame(function() {
    messages.scrollTop = messages.scrollHeight;
  });
}

function aiChatShowLoading() {
  var messages = document.getElementById('aiChatMessages');
  if (!messages) return;
  var loading = document.createElement('div');
  loading.className = 'ai-chat-loading';
  loading.id = 'aiChatLoading';
  loading.innerHTML =
    '<div class="ai-chat-loading-dots">' +
      '<span></span><span></span><span></span>' +
    '</div>' +
    '<span class="ai-chat-loading-label">Réflexion...</span>';
  messages.appendChild(loading);
  aiChatScrollBottom();
}

function aiChatHideLoading() {
  var loading = document.getElementById('aiChatLoading');
  if (loading) loading.remove();
}

function aiChatSetBusy(busy) {
  var input = document.getElementById('aiChatInput');
  var send = document.getElementById('aiChatSend');
  if (input) input.disabled = busy;
  if (send) send.disabled = busy;
}

/* --- Pending image support --- */

var _aiChatPendingImageToken = null;

function _aiChatShowImagePreview(base64Data) {
  var preview = document.getElementById('aiChatImgPreview');
  if (!preview) return;
  preview.innerHTML =
    '<div class=\"ai-chat-img-chip\">' +
      '<img src=\"' + base64Data + '\" alt=\"Image uploadee\" class=\"ai-chat-img-thumb\">' +
      '<button type="button" class="ai-chat-img-remove" id="aiChatImgRemove" aria-label="Retirer image">' +
        '<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" width=\"12\" height=\"12\">' +
          '<line x1=\"18\" y1=\"6\" x2=\"6\" y2=\"18\"/><line x1=\"6\" y1=\"6\" x2=\"18\" y2=\"18\"/>' +
        '</svg>' +
      '</button>' +
    '</div>';
  preview.hidden = false;

  // Bind remove button
  var removeBtn = document.getElementById('aiChatImgRemove');
  if (removeBtn) {
    removeBtn.addEventListener('click', _aiChatClearImage);
  }
}

function _aiChatClearImage() {
  _aiChatPendingImageToken = null;
  var preview = document.getElementById('aiChatImgPreview');
  if (preview) {
    preview.hidden = true;
    preview.innerHTML = '';
  }
  var input = document.getElementById('aiChatImgInput');
  if (input) input.value = '';
}

function _aiChatUploadImage(file) {
  if (!file) return;
  // Validate type
  if (!file.type.match(/^image\/(png|jpeg|jpg|gif|webp)$/)) {
    toast("Format d'image non supporte. PNG, JPEG, GIF ou WebP.", 'error');
    return;
  }
  // Validate size (max 5MB)
  if (file.size > 5 * 1024 * 1024) {
    toast('Image trop volumineuse (max 5 Mo).', 'error');
    return;
  }

  var formData = new FormData();
  formData.append('file', file);

  // Show local preview immediately
  var reader = new FileReader();
  reader.onload = function(e) {
    _aiChatShowImagePreview(e.target.result);
  };
  reader.readAsDataURL(file);

  // Upload to server
  toast("Upload de l'image...", 'info');
  api('/api/ai/chat/upload-image', {
    method: 'POST',
    body: formData,
    // Ensure we don't set Content-Type manually — browser sets it with boundary
  }).then(function(result) {
    if (result && result.image_token) {
      _aiChatPendingImageToken = result.image_token;
      toast("Image prete. Dis a l'assistant de l'attacher a un trade.", 'success');
    } else {
      toast("Erreur lors de l'upload", 'error');
      _aiChatClearImage();
    }
  }).catch(function(err) {
    toast('Erreur upload: ' + (err.message || 'inconnue'), 'error');
    _aiChatClearImage();
  });
}

function _aiChatHandlePaste(e) {
  var clipboardData = e.clipboardData || e.originalEvent?.clipboardData || window.clipboardData;
  if (!clipboardData) return;
  var items = clipboardData.items;
  if (!items) return;
  for (var i = 0; i < items.length; i++) {
    if (items[i].type && items[i].type.indexOf('image') === 0) {
      var file = items[i].getAsFile();
      if (file) {
        e.preventDefault();
        _aiChatUploadImage(file);
        return;
      }
    }
  }
}

async function aiChatSend() {
  var input = document.getElementById('aiChatInput');
  var text = (input && input.value.trim()) || '';

  // Build message content: include image hint if pending
  var content = text;
  if (!content && !_aiChatPendingImageToken) return;

  // Push to history if needed
  if (!window.aiChatHistory) {
    window.aiChatHistory = [];
  }

  // Add user message
  var displayText = _aiChatPendingImageToken
    ? (text || 'Attache cette image a un trade')
    : text;
  aiChatAddMessage('user', displayText);
  window.aiChatHistory.push({ role: 'user', content: displayText });
  input.value = '';
  input.style.height = 'auto';

  aiChatSetBusy(true);
  aiChatShowLoading();

  try {
    // Build request with pending image token
    var body = { messages: window.aiChatHistory };
    if (_aiChatPendingImageToken) {
      body.pending_image_token = _aiChatPendingImageToken;
    }

    var result = await api('/api/ai/chat', {
      method: 'POST',
      body: JSON.stringify(body),
    });

    aiChatHideLoading();

    var responseText = result.response || result.error || 'Pas de réponse.';

    // Handle missing API key
    if (result.needs_api_key) {
      aiChatAddMessage('system', responseText);
      return;
    }

    // Handle circuit breaker
    if (result.circuit_open) {
      aiChatAddMessage('system', responseText);
      return;
    }

    aiChatAddMessage('assistant', responseText);
    window.aiChatHistory.push({ role: 'assistant', content: responseText });

  } catch (err) {
    aiChatHideLoading();
    aiChatAddMessage('assistant', '**Erreur :** ' + (err.message || "Impossible de contacter l'assistant."), { error: true });
    toast('Erreur API chat', 'error');
  } finally {
    aiChatSetBusy(false);
    input.focus();
  }
}

function aiChatClear() {
  window.aiChatHistory = [];
  var messages = document.getElementById('aiChatMessages');
  if (messages) messages.innerHTML = '';

  // Reset with welcome
  aiChatInit();

  // Also send a reset to the server to clear cache
  api('/api/ai/chat', {
    method: 'POST',
    body: JSON.stringify({ messages: [{ role: 'user', content: '' }], reset: true }),
  }).catch(function() { /* silent */ });

  toast('Nouvelle conversation', 'success');
}

function aiChatInputResize(el) {
  el.style.height = 'auto';
  el.style.height = Math.min(el.scrollHeight, 100) + 'px';
}

/* Handle Enter key (to send) vs Shift+Enter (newline) */

function _aiChatKeydown(e) {
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    aiChatSend();
  }
}

/* --- Bind --- */

function bindAIChat() {
  var input = document.getElementById('aiChatInput');
  var send = document.getElementById('aiChatSend');
  var clearBtn = document.getElementById('aiChatClear');

  if (!input || !send) return;

  aiChatInit();

  send.addEventListener('click', aiChatSend);
  input.addEventListener('keydown', _aiChatKeydown);
  input.addEventListener('input', function() { aiChatInputResize(this); });
  input.addEventListener('paste', _aiChatHandlePaste);

  // File input binding
  var imgInput = document.getElementById('aiChatImgInput');
  if (imgInput) {
    imgInput.addEventListener('change', function(e) {
      var files = e.target.files;
      if (files && files.length > 0) {
        _aiChatUploadImage(files[0]);
      }
    });
  }

  if (clearBtn) {
    clearBtn.addEventListener('click', aiChatClear);
  }

  // Focus input when panel opens
  var toggle = document.getElementById('aiPanelToggle');
  if (toggle) {
    toggle.addEventListener('click', function() {
      // Small delay to let panel open animation finish
      setTimeout(function() { input.focus(); }, 100);
    });
  }
}

// ---- 049_enhanced_select.js ----
// ---------- Enhanced select : remplace les <select> natifs par un dropdown custom ----------
//
// Le select natif est cache mais garde sa valeur (utilise pour la compatibilité formulaire).
// Un bouton + dropdown stylisé le remplace visuellement.
//
// Usage : enhanceSelects() apres tout render qui ajoute/modifie des selects.
// Les selects deja enhances (data-enhanced="1") sont ignores.

function enhanceSelects(container) {
  const root = container || document;
  const selects = root.querySelectorAll(".select-wrapper select:not([data-enhanced])");
  if (!selects.length) return;

  selects.forEach(function (select) {
    if (select.dataset.enhanced) return;
    select.dataset.enhanced = "1";

    // Cacher la fleche native
    var arrowSvg = select.parentNode.querySelector(".select-arrow");
    if (arrowSvg) arrowSvg.style.display = "none";

    // Cacher le select natif
    select.style.position = "absolute";
    select.style.opacity = "0";
    select.style.width = "0";
    select.style.height = "0";
    select.style.pointerEvents = "none";

    // Trigger button
    var trigger = document.createElement("button");
    trigger.type = "button";
    trigger.className = "custom-select-trigger";
    trigger.setAttribute("aria-haspopup", "listbox");
    trigger.setAttribute("aria-expanded", "false");

    var label = document.createElement("span");
    label.className = "trigger-label";
    label.textContent = _getSelectedText(select);

    var arrow = document.createElementNS("http://www.w3.org/2000/svg", "svg");
    arrow.setAttribute("viewBox", "0 0 16 16");
    arrow.setAttribute("width", "12");
    arrow.setAttribute("height", "12");
    arrow.setAttribute("fill", "none");
    arrow.setAttribute("stroke", "currentColor");
    arrow.setAttribute("stroke-width", "1.8");
    arrow.setAttribute("stroke-linecap", "round");
    arrow.setAttribute("stroke-linejoin", "round");
    arrow.className = "trigger-arrow";
    var polyline = document.createElementNS("http://www.w3.org/2000/svg", "polyline");
    polyline.setAttribute("points", "4 6 8 10 12 6");
    arrow.appendChild(polyline);

    trigger.appendChild(label);
    trigger.appendChild(arrow);

    // Dropdown
    var dropdown = document.createElement("div");
    dropdown.className = "custom-select-dropdown";
    dropdown.setAttribute("role", "listbox");
    dropdown.setAttribute("aria-label", select.id || "Options");

    Array.from(select.options).forEach(function (opt, i) {
      if (opt.disabled && !opt.value) return; // sauter le placeholder disabled

      var item = document.createElement("div");
      item.className = "custom-select-item";
      item.dataset.value = opt.value;
      item.textContent = opt.textContent;
      item.setAttribute("role", "option");
      item.setAttribute("aria-selected", opt.selected ? "true" : "false");
      if (opt.selected) item.classList.add("selected");

      item.addEventListener("click", function (e) {
        e.stopPropagation();
        _selectOption(select, opt.value, trigger, dropdown);
      });

      dropdown.appendChild(item);
    });

    // Insertion dans le DOM
    select.parentNode.appendChild(trigger);
    select.parentNode.appendChild(dropdown);

    // Toggle dropdown
    trigger.addEventListener("click", function (e) {
      e.stopPropagation();
      _toggleSelect(trigger, dropdown, select);
    });

    // Fermer si click ailleurs
    trigger._docHandler = function () { _closeSelect(trigger, dropdown); };
    document.addEventListener("click", trigger._docHandler);
  });
}

function _getSelectedText(select) {
  var idx = select.selectedIndex;
  if (idx >= 0 && select.options[idx]) return select.options[idx].textContent;
  return "\u2014";
}

function _selectOption(select, value, trigger, dropdown) {
  select.value = value;
  trigger.querySelector(".trigger-label").textContent = _getSelectedText(select);
  dropdown.querySelectorAll(".custom-select-item").forEach(function (el) {
    var sel = el.dataset.value === value;
    el.classList.toggle("selected", sel);
    el.setAttribute("aria-selected", sel ? "true" : "false");
  });
  _closeSelect(trigger, dropdown);
  select.dispatchEvent(new Event("change", { bubbles: true }));
}

function _toggleSelect(trigger, dropdown, select) {
  var isOpen = dropdown.classList.contains("open");
  document.querySelectorAll(".custom-select-dropdown.open").forEach(function (d) {
    if (d !== dropdown) {
      d.classList.remove("open");
      var t = d._trigger;
      if (t) { t.classList.remove("open"); t.setAttribute("aria-expanded", "false"); }
    }
  });
  if (isOpen) {
    _closeSelect(trigger, dropdown);
  } else {
    _openSelect(trigger, dropdown, select);
  }
}

function _openSelect(trigger, dropdown, select) {
  dropdown.classList.add("open");
  trigger.classList.add("open");
  trigger.setAttribute("aria-expanded", "true");
  dropdown._trigger = trigger;

  // Positionnement sous le trigger
  var rect = trigger.getBoundingClientRect();
  var ddH = Math.min(dropdown.scrollHeight || 200, 240);
  var spaceBelow = window.innerHeight - rect.bottom;
  var spaceAbove = rect.top;

  if (spaceBelow >= ddH || spaceBelow > spaceAbove) {
    dropdown.style.top = rect.bottom + "px";
    dropdown.style.left = rect.left + "px";
    dropdown.style.width = Math.max(rect.width, 160) + "px";
    dropdown.style.maxHeight = (spaceBelow - 4) + "px";
    dropdown.style.transformOrigin = "top";
  } else {
    dropdown.style.top = (rect.top - ddH) + "px";
    dropdown.style.left = rect.left + "px";
    dropdown.style.width = Math.max(rect.width, 160) + "px";
    dropdown.style.maxHeight = (spaceAbove - 4) + "px";
    dropdown.style.transformOrigin = "bottom";
  }

  // Scroll vers l'option selectionnée
  var sel = dropdown.querySelector(".custom-select-item.selected");
  if (sel) sel.scrollIntoView({ block: "nearest" });
}

function _closeSelect(trigger, dropdown) {
  dropdown.classList.remove("open");
  if (trigger) { trigger.classList.remove("open"); trigger.setAttribute("aria-expanded", "false"); }
}

// ---- 049_insights.js ----
// ---- 049_insights.js ---- Page Profil & Insights ML ----

(function () {
  "use strict";

  var _insightsInitialized = false;
  var _insightsToastTimeout = null;
  var _insightsRefreshing = false;
  var _savedCardCache = null; // cache pour _markSavedCards

  var INSIGHT_ICONS = {
    best_strategy: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><polyline points='5 8 7 10 11 6'/></svg>", cls: "success" },
    worst_strategy: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='5' x2='8' y2='8'/><line x1='8' y1='10' x2='8' y2='10.01'/></svg>", cls: "warning" },
    best_session: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><polyline points='5 8 7 10 11 6'/></svg>", cls: "success" },
    worst_session: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='5' x2='8' y2='8'/><line x1='8' y1='10' x2='8' y2='10.01'/></svg>", cls: "warning" },
    bias_correlation: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='7' x2='8' y2='11'/><circle cx='8' cy='5' r='0.5' fill='currentColor' stroke='none'/></svg>", cls: "info" },
    direction_strength: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><polyline points='5 8 7 10 11 6'/></svg>", cls: "success" },
    lesson_themes: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='7' x2='8' y2='11'/><circle cx='8' cy='5' r='0.5' fill='currentColor' stroke='none'/></svg>", cls: "info" },
    execution_quality: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><polyline points='5 8 7 10 11 6'/></svg>", cls: "success" },
    execution_warning: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='5' x2='8' y2='8'/><line x1='8' y1='10' x2='8' y2='10.01'/></svg>", cls: "warning" },
    rr_sweetspot: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='7' x2='8' y2='11'/><circle cx='8' cy='5' r='0.5' fill='currentColor' stroke='none'/></svg>", cls: "info" },
    recent_trend: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='7' x2='8' y2='11'/><circle cx='8' cy='5' r='0.5' fill='currentColor' stroke='none'/></svg>", cls: "info" },
    stdv_sweetspot: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><polyline points='5 8 7 10 11 6'/></svg>", cls: "success" },
    thesis_validated: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><polyline points='5 8 7 10 11 6'/></svg>", cls: "success" },
    thesis_invalid: { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='8' y1='5' x2='8' y2='8'/><line x1='8' y1='10' x2='8' y2='10.01'/></svg>", cls: "warning" },
  };

  function _dateKey(d) {
    return d.getFullYear() + "-" +
      String(d.getMonth() + 1).padStart(2, "0") + "-" +
      String(d.getDate()).padStart(2, "0");
  }

  function _getTodayStr() {
    return _dateKey(new Date());
  }

  function _get30dAgo() {
    var d = new Date();
    d.setDate(d.getDate() - 30);
    return _dateKey(d);
  }

  function _getFirstDayOfMonth() {
    var d = new Date();
    return d.getFullYear() + "-" + String(d.getMonth() + 1).padStart(2, "0") + "-01";
  }

  function _fetchApi(endpoint, params) {
    var qs = [];
    params = params || {};
    for (var k in params) {
      if (params[k] && params[k] !== "ALL" && params[k] !== "") {
        qs.push(encodeURIComponent(k) + "=" + encodeURIComponent(params[k]));
      }
    }
    var url = endpoint + (qs.length ? "?" + qs.join("&") : "");
    return fetch(url).then(function (r) {
      if (!r.ok) throw new Error("HTTP " + r.status);
      return r.json();
    });
  }

  function _renderEmpty() {
    return '<div class="insight-empty">' +
      '<div class="insight-empty__icon">#</div>' +
      '<div class="insight-empty__title">Pas assez de donnees</div>' +
      '<div class="insight-empty__text">Remplis au moins 3 trades avec resultat pour que le moteur commence a detecter des patterns.</div>' +
      "</div>";
  }

  function _renderProfileHeader(profile) {
    if (profile.empty) return "";
    var pnlCls = (profile.total_pnl || 0) >= 0 ? "up" : "down";
    var pnlSign = (profile.total_pnl || 0) >= 0 ? "+" : "";
    return '<div class="profile-banner">' +
      '<div class="profile-stat"><div class="profile-stat__value">' + (profile.total_trades || 0) + '</div><div class="profile-stat__label">Trades</div></div>' +
      '<div class="profile-stat"><div class="profile-stat__value">' + (profile.winrate || 0) + '%</div><div class="profile-stat__label">Winrate (' + (profile.wins || 0) + "W/" + (profile.losses || 0) + "L)</div></div>" +
      '<div class="profile-stat"><div class="profile-stat__value ' + pnlCls + '">' + pnlSign + (profile.total_pnl || 0) + '$</div><div class="profile-stat__label">PnL Total</div></div>' +
      '<div class="profile-stat"><div class="profile-stat__value">' + (profile.avg_rr || "-") + '</div><div class="profile-stat__label">R:R Moyen</div></div>' +
      "</div>";
  }

  function _stars(confidence) {
    var n = Math.round((confidence || 0) * 5);
    var s = "";
    for (var i = 0; i < n; i++) s += "*";
    var label = n + "/5 confiance";
    return '<span class="insight-stars" aria-label="' + label + '">' + s + "</span>";
  }

  function _confidenceClass(confidence) {
    if (!confidence) return "low";
    if (confidence >= 0.7) return "high";
    if (confidence >= 0.4) return "medium";
    return "low";
  }

  function _renderInsightCard(pattern) {
    var def = INSIGHT_ICONS[pattern.kind] || { icon: "<svg class='ii' viewBox='0 0 16 16' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round'><circle cx='8' cy='8' r='6'/><line x1='5' y1='8' x2='11' y2='8'/></svg>", cls: "info" };
    var cardCls = "insight-card";
    if (def.cls === "warning") cardCls += " insight-card--warning";
    else if (def.cls === "success") cardCls += " insight-card--success";
    else cardCls += " insight-card--info";

    var tags = (pattern.tags || []).map(function (t) {
      return '<span class="insight-tag">' + _escapeHtml(t) + "</span>";
    }).join("");

    var confPct = Math.round((pattern.confidence || 0) * 100);
    var confCls = _confidenceClass(pattern.confidence);

    return '<div class="' + cardCls + '" data-kind="' + _escapeHtml(pattern.kind || '') + '" data-title="' + _escapeHtml(pattern.title || '') + '">' +
      '<div class="insight-header">' +
      '<div class="insight-icon insight-icon--' + def.cls + '">' + def.icon + "</div>" +
      '<div class="insight-title">' + _escapeHtml(pattern.title || "") + "</div>" +
      '<span class="insight-badge">' + confPct + "%</span>" +
      "</div>" +
      '<div class="insight-body">' + _escapeHtml(pattern.body || "") + "</div>" +
      '<div class="insight-meta">' +
      '<span class="insight-confidence">' + _stars(pattern.confidence) + " " + confPct + "% confiance</span>" +
      (pattern.evidence_count ? "<span>" + pattern.evidence_count + " trades</span>" : "") +
      "</div>" +
      (tags ? '<div class="insight-meta" style="margin-top:8px">' + tags + "</div>" : "") +
      '<div class="confidence-track"><div class="confidence-fill confidence-fill--' + confCls + '" style="width:' + confPct + '%"></div></div>' +
      '<button type="button" class="insight-save-btn" onclick="InsightsCtrl.toggleSave(this)" title="Sauvegarder">&#9733;</button>' +
      "</div>";
  }

  function _renderStrategyTable(strategies) {
    if (!strategies || !strategies.length) return "";
    var best = strategies[0], worst = strategies[strategies.length - 1];
    var bestWr = 0, worstWr = 100;
    strategies.forEach(function (s) {
      if (s.winrate > bestWr) { bestWr = s.winrate; best = s; }
      if (s.winrate < worstWr && s.wins + s.losses >= 3) { worstWr = s.winrate; worst = s; }
    });

    var rows = strategies.map(function (s) {
      var pnlCls = (s.pnl || 0) >= 0 ? "up" : "down";
      var rowCls = "";
      if (s.name === (best && best.name) && s.winrate >= 60) rowCls = " best-row";
      else if (s.name === (worst && worst.name) && s.winrate < 45) rowCls = " worst-row";
      return '<tr class="' + rowCls + '"><td><strong>' + _escapeHtml(s.name || "-") + "</strong></td>" +
        '<td class="num">' + (s.total || 0) + "</td>" +
        "<td>" + (s.wins || 0) + "W/" + (s.losses || 0) + "L</td>" +
        '<td class="num">' + (s.winrate || 0) + "%</td>" +
        '<td class="num ' + pnlCls + '">' + ((s.pnl || 0) >= 0 ? "+" : "") + (s.pnl || 0) + "$</td></tr>";
    }).join("");

    return '<div class="insight-card insight-full" style="grid-column:1/-1">' +
      '<div class="insight-header"><div class="insight-icon insight-icon--info">#</div><div class="insight-title">Performance par strategie</div></div>' +
      '<table class="insight-table"><thead><tr>' +
      "<th>Strategie</th><th>Trades</th><th>Resultat</th><th>WR</th><th>PnL</th>" +
      "</tr></thead><tbody>" + rows + "</tbody></table></div>";
  }

  function _renderSuggestions(profile, patterns) {
    var warns = (patterns || []).filter(function (p) {
      return p.kind && (p.kind.indexOf("worst") >= 0 || p.kind.indexOf("warning") >= 0 || p.kind.indexOf("invalid") >= 0);
    });
    var goods = (patterns || []).filter(function (p) {
      return p.kind && (p.kind.indexOf("best") >= 0 || p.kind.indexOf("strength") >= 0 || p.kind.indexOf("sweetspot") >= 0);
    });

    var html = '<div class="insight-full" style="grid-column:1/-1">';
    html += '<div class="insight-header" style="margin-bottom:12px"><div class="insight-title">Recommandations</div></div>';

    warns.slice(0, 3).forEach(function (w) {
      html += '<div class="suggestion-card suggestion-card--warn"><div class="suggestion-icon">!</div><div class="suggestion-content"><strong>' +
        _escapeHtml(w.title || "") + "</strong><br/>" + _escapeHtml(w.body || "") + "</div></div>";
    });
    goods.slice(0, 3).forEach(function (g) {
      html += '<div class="suggestion-card suggestion-card--good"><div class="suggestion-icon">+</div><div class="suggestion-content"><strong>' +
        _escapeHtml(g.title || "") + "</strong><br/>" + _escapeHtml(g.body || "") + "</div></div>";
    });
    if (!warns.length && !goods.length) {
      html += '<div class="insight-empty">Ajoute des resultats a tes trades pour obtenir des recommandations.</div>';
    }
    html += "</div>";
    return html;
  }

  function loadInsights(opts) {
    opts = opts || {};
    var container = document.getElementById("insightsContent");
    var loading = document.getElementById("insightsLoading");
    if (!container) return;

    loading.style.display = "";
    container.style.display = "none";
    container.innerHTML = "";
    _insightsRefreshing = true;

    var params = {};
    if (opts.instrument && opts.instrument !== "ALL") params.instrument = opts.instrument;
    if (opts.from) params.from = opts.from;
    if (opts.to) params.to = opts.to;

    Promise.all([
      _fetchApi("/api/ml/profile", params),
      _fetchApi("/api/ml/insights", params),
    ]).then(function (results) {
      _insightsRefreshing = false;
      var profile = results[0];
      var insightsResp = results[1];
      var patterns = insightsResp.patterns || [];
      var html = "";

      loading.style.display = "none";
      container.style.display = "grid";
      html += _renderProfileHeader(profile);
      if (patterns.length) patterns.forEach(function (p) { html += _renderInsightCard(p); });
      else html += '<div style="grid-column:1/-1">' + _renderEmpty() + "</div>";
      if (profile.preferred_strategies && profile.preferred_strategies.length) html += _renderStrategyTable(profile.preferred_strategies);
      html += _renderSuggestions(profile, patterns);
      container.innerHTML = html;
      _markSavedCards();
    }).catch(function (err) {
      _insightsRefreshing = false;
      loading.style.display = "none";
      container.style.display = "grid";
      container.innerHTML = '<div class="insight-empty"><div class="insight-empty__icon">!</div><div class="insight-empty__title">Erreur</div><div class="insight-empty__text">' +
        _escapeHtml(err.message || "Impossible de charger les insights.") + "</div></div>";
    });
  }

  function _renderPretradeWidget() {
    _fetchApi("/api/ml/insights", { from: _get30dAgo() }).then(function (resp) {
      var patterns = resp.patterns || [];
      var container = document.getElementById("pretradeWidget");
      if (!container) return;
      var warnings = patterns.filter(function (p) {
        return p.kind && (p.kind.indexOf("worst") >= 0 || p.kind.indexOf("warning") >= 0);
      });
      var strengths = patterns.filter(function (p) {
        return p.kind && (p.kind.indexOf("best") >= 0 || p.kind.indexOf("strength") >= 0);
      });
      var items = [];
      strengths.slice(0, 2).forEach(function (s) {
        items.push('<span class="pretrade-item"><span class="pretrade-item__icon success"><svg class=\'ii\' viewBox=\'0 0 16 16\' fill=\'none\' stroke=\'currentColor\' stroke-width=\'2\' stroke-linecap=\'round\'><circle cx=\'8\' cy=\'8\' r=\'6\'/><polyline points=\'5 8 7 10 11 6\'/></svg></span> ' + _escapeHtml(s.title || "") + "</span>");
      });
      warnings.slice(0, 2).forEach(function (w) {
        items.push('<span class="pretrade-item"><span class="pretrade-item__icon warning"><svg class=\'ii\' viewBox=\'0 0 16 16\' fill=\'none\' stroke=\'currentColor\' stroke-width=\'2\' stroke-linecap=\'round\'><circle cx=\'8\' cy=\'8\' r=\'6\'/><line x1=\'8\' y1=\'5\' x2=\'8\' y2=\'8\'/><line x1=\'8\' y1=\'10\' x2=\'8\' y2=\'10.01\'/></svg></span> ' + _escapeHtml(w.title || "") + "</span>");
      });
      if (items.length) {
        container.innerHTML =
          '<div class="pretrade-widget">' +
          '<div class="pretrade-header">Pré-trade du jour</div>' +
          '<div class="pretrade-items">' + items.join("") + "</div></div>";
      }
    }).catch(function () {});
  }

  function showInsightToast(title, body, duration) {
    duration = duration || 6000;
    var toast = document.getElementById("toastInsight");
    var titleEl = document.getElementById("toastInsightTitle");
    var bodyEl = document.getElementById("toastInsightBody");
    if (!toast || !titleEl || !bodyEl) return;
    if (_insightsToastTimeout) clearTimeout(_insightsToastTimeout);
    titleEl.textContent = title;
    bodyEl.textContent = body;
    toast.classList.add("show");
    _insightsToastTimeout = setTimeout(function () {
      toast.classList.remove("show");
    }, duration);
  }

  function _initPostTradeToast() {
    var closeBtn = document.getElementById("toastInsightClose");
    if (closeBtn) {
      closeBtn.addEventListener("click", function () {
        var t = document.getElementById("toastInsight");
        if (t) t.classList.remove("show");
        if (_insightsToastTimeout) clearTimeout(_insightsToastTimeout);
      });
    }
  }

  function onTradeSaved(tradeData) {
    if (tradeData && tradeData.id) {
      _fetchApi("/api/ml/setups/similar", { trade_id: tradeData.id, limit: 3 }).then(function (data) {
        if (data.error || !data.similar_trades || !data.similar_trades.length) return;
        var similar = data.similar_trades;
        var wins = similar.filter(function (s) { return s.trade && s.trade.is_win === 1; }).length;
        var losses = similar.filter(function (s) { return s.trade && s.trade.is_win === 0; }).length;
        if (wins + losses >= 2) {
          var wr = Math.round(wins / (wins + losses) * 100);
          var body = wins + "W/" + losses + "L = " + wr + "% WR dans des trades similaires. ";
          body += wr >= 60 ? "Bon setup !" : "Sois prudent.";
          showInsightToast("Setups similaires", body);
        }
      }).catch(function () {});
    }
    _renderPretradeWidget();
  }

  function _initFilters() {
    var from = document.getElementById("filterFrom");
    var to = document.getElementById("filterTo");
    var instr = document.getElementById("filterInstrument");
    var strat = document.getElementById("filterStrategy");
    var refresh = document.getElementById("insightsRefreshBtn");
    if (!from || !to) return;

    // Restore saved filter state, or use journal's current month
    var saved = _loadInsightFilters();
    if (saved) {
      from.value = saved.from || _getFirstDayOfMonth();
      to.value = saved.to || _getTodayStr();
      if (saved.instrument && instr) instr.value = saved.instrument;
    } else {
      // Try to inherit from journal: use current month range
      if (typeof getJournalCustomWindow === "function" && typeof fmtDateKey === "function") {
        var cw = getJournalCustomWindow();
        if (cw && cw.from && cw.to) {
          from.value = fmtDateKey(cw.from);
          to.value = fmtDateKey(cw.to);
        } else {
          from.value = _getFirstDayOfMonth();
          to.value = _getTodayStr();
        }
      } else {
        from.value = _getFirstDayOfMonth();
        to.value = _getTodayStr();
      }
    }
    populateInstruments('filterInstrument');

    var quickBtns = [
      { label: "7j", days: 7 },
      { label: "30j", days: 30 },
      { label: "90j", days: 90 },
      { label: "Ce mois", fn: _getFirstDayOfMonth },
    ];

    function _saveFilterState() {
      try {
        localStorage.setItem("insightFilters", JSON.stringify({
          from: from ? from.value : "",
          to: to ? to.value : "",
          instrument: instr ? instr.value : "ALL",
          strategy: strat ? strat.value : "ALL",
        }));
      } catch(e) {}
    }

    function _loadInsightFilters() {
      try {
        var raw = JSON.parse(localStorage.getItem("insightFilters"));
        if (raw && raw.from && raw.to) return raw;
      } catch(e) {}
      return null;
    }

    function _applyFilter() {
      _saveFilterState();
      loadInsights({
        from: from.value || undefined,
        to: to.value || undefined,
        instrument: instr ? instr.value : undefined,
        strategy: strat ? strat.value : undefined,
      });
    }

    function _setQuickRange(days) {
      var d = new Date();
      d.setDate(d.getDate() - days);
      from.value = _dateKey(d);
      to.value = _getTodayStr();
      _applyFilter();
    }

    var btnContainer = document.getElementById("filterQuick");
    if (!btnContainer) return;
    btnContainer.innerHTML = "";
    quickBtns.forEach(function (q) {
      var btn = document.createElement("button");
      btn.type = "button";
      btn.className = "qbtn";
      btn.textContent = q.label;
      btn.addEventListener("click", function () {
        if (q.fn) {
          from.value = q.fn();
          to.value = _getTodayStr();
          _applyFilter();
        } else {
          _setQuickRange(q.days);
        }
      });
      btnContainer.appendChild(btn);
    });

    if (from) from.addEventListener("change", _applyFilter);
    if (to) to.addEventListener("change", _applyFilter);
    if (instr) instr.addEventListener("change", _applyFilter);
    if (strat) strat.addEventListener("change", _applyFilter);
    if (refresh) refresh.addEventListener("click", function () {
      if (_insightsRefreshing) return;
      _applyFilter();
    });
    _applyFilter();
  }

  function initInsights() {
    if (_insightsInitialized) return;
    _insightsInitialized = true;
    _renderPretradeWidget();
    _initPostTradeToast();
    _initFilters();
    if (typeof renderPerformance === "function") renderPerformance();

    document.addEventListener("trade:saved", function (e) {
      onTradeSaved(e.detail);
    });
  }

  function _markSavedCards() {
    if (_savedCardCache) {
      _applySavedCards(_savedCardCache);
      return;
    }
    fetch('/api/ml/knowledge').then(function (r) { return r.json(); }).then(function (cards) {
      _savedCardCache = cards || [];
      _applySavedCards(_savedCardCache);
    }).catch(function () {});
  }

  function _applySavedCards(cards) {
    if (!cards || !cards.length) return;
    var lookup = {};
    cards.forEach(function (c) { lookup[c.kind + '|' + c.title] = true; });
    document.querySelectorAll('.insight-card').forEach(function (card) {
      var key = (card.dataset.kind || '') + '|' + (card.dataset.title || '');
      if (lookup[key]) {
        card.classList.add('is-saved');
        var btn = card.querySelector('.insight-save-btn');
        if (btn) btn.title = 'Retirer des sauvegardes';
      }
    });
  }

  function _escapeHtml(str) {
    if (typeof str !== "string") return str || "";
    return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;").replace(/'/g, "&#039;");
  }

  window.InsightsCtrl = {
    toggleSave: function (btn) {
      var card = btn.closest('.insight-card');
      if (!card) return;
      var kind = card.dataset.kind;
      var title = card.dataset.title;
      if (!kind || !title) return;

      var isSaved = card.classList.contains('is-saved');

      if (isSaved) {
        fetch('/api/ml/knowledge?kind=' + encodeURIComponent(kind) + '&title=' + encodeURIComponent(title), { method: 'DELETE' })
          .then(function () {
            card.classList.remove('is-saved');
            btn.title = 'Sauvegarder';
            _savedCardCache = null; // invalider le cache
          }).catch(function () {});
      } else {
        var body = JSON.stringify({
          kind: kind, title: title,
          body: card.querySelector('.insight-body')?.textContent || '',
          confidence: parseFloat(card.querySelector('.insight-badge')?.textContent || '0') / 100,
        });
        fetch('/api/ml/knowledge', { method: 'POST', body: body, headers: { 'Content-Type': 'application/json' } })
          .then(function () {
            card.classList.add('is-saved');
            btn.title = 'Retirer des sauvegardes';
            _savedCardCache = null; // invalider le cache
          }).catch(function () {});
      }
    }
  };

  window.initInsights = initInsights;
  window.loadInsights = loadInsights;
  window.showInsightToast = showInsightToast;
  window.onTradeSaved = onTradeSaved;

  if (document.querySelector('.page[data-page="insights"].active')) {
    initInsights();
  } else {
    var _origGoPage = window.goPage;
    if (_origGoPage) {
      window.goPage = function (pageName) {
        _origGoPage(pageName);
        if (pageName === "insights") initInsights();
      };
    }
  }

  if (document.readyState === "complete" || document.readyState === "interactive") {
    if (document.querySelector('.page[data-page="insights"]')) {
      var checkPage = function () {
        if (document.querySelector('.page[data-page="insights"].active')) {
          initInsights();
        } else {
          setTimeout(checkPage, 300);
        }
      };
      setTimeout(checkPage, 500);
    }
  }
})();

// ---- 050_priority1_app_shell.js ----
// ---------- Priority 1 app shell ----------

const APP_SHELL_PAGES = {
  today: {
    title: "Dashboard",
    subtitle: "Vue du jour, performance et prochaine action.",
    documentTitle: "Dashboard - JOURNAL",
  },
  journal: {
    title: "Journal",
    subtitle: "Calendrier, table des trades, filtres et historique.",
    documentTitle: "Journal - JOURNAL",
  },
  stats: {
    title: "Stats",
    subtitle: "Performance, risque, patterns et breakdowns.",
    documentTitle: "Stats - JOURNAL",
  },
  settings: {
    title: "Settings",
    subtitle: "Profil, instruments, IA et preferences visuelles.",
    documentTitle: "Settings - JOURNAL",
  },
  insights: {
    title: "Insights",
    subtitle: "Profil comportemental et recommandations personnalisées.",
    documentTitle: "Insights - JOURNAL",
  },
};

function updateAppShell(pageName) {
  const page = APP_SHELL_PAGES[pageName] || APP_SHELL_PAGES.today;
  const title = document.getElementById("appTopbarTitle");
  const subtitle = document.getElementById("appTopbarSubtitle");
  if (title) title.textContent = page.title;
  if (subtitle) subtitle.textContent = page.subtitle;
  if (page.documentTitle) document.title = page.documentTitle;

  document.querySelectorAll(".nav-item[data-page]").forEach(function (btn) {
    const current = btn.dataset.page === pageName;
    btn.classList.toggle("active", current);
    if (current) btn.setAttribute("aria-current", "page");
    else btn.removeAttribute("aria-current");
  });
}

function bindAppShellActions() {
  document.getElementById("shellNewEntryBtn")?.addEventListener("click", function () {
    wizOpen({});
  });

  document.getElementById("shellCmdkBtn")?.addEventListener("click", function () {
    openCmdk();
  });

  document.getElementById("shellThemeBtn")?.addEventListener("click", function () {
    document.getElementById("themeToggle")?.click();
  });
}

(function installAppShellHooks() {
  const originalGoPage = window.goPage || goPage;
  window.goPage = function (pageName) {
    originalGoPage(pageName);
    updateAppShell(state.currentPage || pageName || "today");
  };
  goPage = window.goPage;

  document.addEventListener("DOMContentLoaded", function () {
    bindAppShellActions();
    updateAppShell(state.currentPage || "today");
  });
})();

// ---- 051_spotlight.js ----
// Legacy cursor spotlight disabled.
// The global empty-space background is handled by 055_interactive_empty_background.js.

// ---- 053_unified_date_picker.js ----
// ---------- Unified date/range picker ----------

var _unifiedDatePickerState = null;

function _udpDateKey(d) { return fmtDateKey(d); }
function _udpParse(key) { return parseDateKey(key) || new Date(); }
function _udpMonthStart(d) { return new Date(d.getFullYear(), d.getMonth(), 1); }
function _udpAddMonths(d, delta) { return new Date(d.getFullYear(), d.getMonth() + delta, 1); }
function _udpDaysInMonth(y, m) { return new Date(y, m + 1, 0).getDate(); }

function _udpRangeForShortcut(kind) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const start = new Date(today);
  if (kind === "today") return { from: _udpDateKey(today), to: _udpDateKey(today) };
  if (kind === "yesterday") {
    start.setDate(start.getDate() - 1);
    return { from: _udpDateKey(start), to: _udpDateKey(start) };
  }
  if (kind === "7d") start.setDate(start.getDate() - 6);
  else if (kind === "30d") start.setDate(start.getDate() - 29);
  else if (kind === "3m") start.setMonth(start.getMonth() - 3);
  else if (kind === "6m") start.setMonth(start.getMonth() - 6);
  else if (kind === "last_month") {
    const first = new Date(today.getFullYear(), today.getMonth() - 1, 1);
    const last = new Date(today.getFullYear(), today.getMonth(), 0);
    return { from: _udpDateKey(first), to: _udpDateKey(last) };
  } else if (kind === "month") {
    return {
      from: _udpDateKey(new Date(today.getFullYear(), today.getMonth(), 1)),
      to: _udpDateKey(new Date(today.getFullYear(), today.getMonth() + 1, 0)),
    };
  } else if (kind === "all") {
    // Calculer dynamiquement la date la plus ancienne depuis state.days
    var earliest = null;
    if (Array.isArray(state.days)) {
      for (var i = 0; i < state.days.length; i++) {
        if (state.days[i] && state.days[i].date && (!earliest || state.days[i].date < earliest)) {
          earliest = state.days[i].date;
        }
      }
    }
    return { from: earliest || "2020-01-01", to: _udpDateKey(today) };
  }
  return { from: _udpDateKey(start), to: _udpDateKey(today) };
}

function _udpMonthShortcut(monthOffset) {
  const now = new Date();
  const first = new Date(now.getFullYear(), now.getMonth() + monthOffset, 1);
  const last = new Date(now.getFullYear(), now.getMonth() + monthOffset + 1, 0);
  return { from: _udpDateKey(first), to: _udpDateKey(last) };
}

function _udpEnsure() {
  let root = $("#unifiedDatePicker");
  if (root) return root;
  root = document.createElement("div");
  root.id = "unifiedDatePicker";
  root.className = "udp hidden";
  root.innerHTML =
    '<div class="udp-backdrop" data-udp-close></div>' +
    '<div class="udp-panel" role="dialog" aria-modal="true" aria-label="Selection de date">' +
      '<aside class="udp-side">' +
        '<div class="udp-side-title">Raccourcis</div>' +
        '<button type="button" data-shortcut="today">Aujourd&#39;hui</button>' +
        '<button type="button" data-shortcut="yesterday">Hier</button>' +
        '<button type="button" data-shortcut="7d">7 derniers jours</button>' +
        '<button type="button" data-shortcut="30d">30 derniers jours</button>' +
        '<button type="button" data-shortcut="month">Ce mois</button>' +
        '<button type="button" data-shortcut="last_month">Mois dernier</button>' +
        '<button type="button" data-shortcut="3m">3 derniers mois</button>' +
        '<button type="button" data-shortcut="6m">6 derniers mois</button>' +
        '<button type="button" data-shortcut="all">Tout</button>' +
        '<div class="udp-side-title udp-month-title">Par mois</div>' +
        '<div class="udp-month-shortcuts" id="udpMonthShortcuts"></div>' +
      '</aside>' +
      '<main class="udp-main">' +
        '<div class="udp-inputs">' +
          '<label>Debut <span id="udpFromText">--</span></label>' +
          '<span class="udp-arrow">-></span>' +
          '<label>Fin <span id="udpToText">--</span></label>' +
        '</div>' +
        '<div class="udp-cal-head">' +
          '<button type="button" class="udp-nav" data-nav="-1" aria-label="Mois precedent">&lsaquo;</button>' +
          '<button type="button" class="udp-nav" data-nav="1" aria-label="Mois suivant">&rsaquo;</button>' +
        '</div>' +
        '<div class="udp-calendars" id="udpCalendars"></div>' +
        '<div class="udp-actions">' +
          '<button type="button" class="udp-cancel" data-udp-close>Annuler</button>' +
          '<button type="button" class="udp-apply" id="udpApply">Appliquer</button>' +
        '</div>' +
      '</main>' +
    '</div>';
  document.body.appendChild(root);
  _udpBind(root);
  return root;
}

function _udpBind(root) {
  root.addEventListener("click", function(e) {
    if (e.target.closest("[data-udp-close]")) { closeUnifiedDatePicker(); return; }
    const nav = e.target.closest("[data-nav]");
    if (nav && _unifiedDatePickerState) {
      _unifiedDatePickerState.anchor = _udpAddMonths(_unifiedDatePickerState.anchor, Number(nav.dataset.nav || 0));
      _udpRender();
      return;
    }
    const shortcut = e.target.closest("[data-shortcut]");
    if (shortcut && _unifiedDatePickerState) {
      const r = _udpRangeForShortcut(shortcut.dataset.shortcut);
      _unifiedDatePickerState.from = r.from;
      _unifiedDatePickerState.to = _unifiedDatePickerState.mode === "single" ? r.from : r.to;
      _unifiedDatePickerState.anchor = _udpMonthStart(_udpParse(_unifiedDatePickerState.from));
      _udpRender();
      _udpApply();
      return;
    }
    const monthShortcut = e.target.closest("[data-month-offset]");
    if (monthShortcut && _unifiedDatePickerState) {
      const r = _udpMonthShortcut(Number(monthShortcut.dataset.monthOffset || 0));
      _unifiedDatePickerState.from = r.from;
      _unifiedDatePickerState.to = _unifiedDatePickerState.mode === "single" ? r.from : r.to;
      _unifiedDatePickerState.anchor = _udpMonthStart(_udpParse(r.from));
      _udpRender();
      return;
    }
    const day = e.target.closest("[data-date]");
    if (day && _unifiedDatePickerState) { _udpPick(day.dataset.date); return; }
    if (e.target.closest("#udpApply")) _udpApply();
  });
  document.addEventListener("keydown", function(e) {
    if (e.key === "Escape") closeUnifiedDatePicker();
  });
}

function _udpPick(key) {
  const s = _unifiedDatePickerState;
  if (!s) return;
  if (s.mode === "single") {
    s.from = key;
    s.to = key;
    _udpRender();
    _udpApply();
    return;
  }
  if (!s.from || (s.from && s.to && s._complete)) {
    s.from = key;
    s.to = "";
    s._complete = false;
  } else if (key < s.from) {
    s.to = s.from;
    s.from = key;
    s._complete = true;
  } else {
    s.to = key;
    s._complete = true;
  }
  _udpRender();
}

function _udpApply() {
  const s = _unifiedDatePickerState;
  if (!s || !s.from) return;
  const from = s.from;
  const to = s.to || s.from;
  if (typeof s.onApply === "function") s.onApply(from, to);
  else if (s.input) {
    s.input.value = from;
    s.input.dispatchEvent(new Event("change", { bubbles: true }));
  }
  closeUnifiedDatePicker();
}

function _udpMonthHtml(anchor) {
  const y = anchor.getFullYear();
  const m = anchor.getMonth();
  const first = new Date(y, m, 1);
  const startOffset = (first.getDay() + 6) % 7;
  const days = _udpDaysInMonth(y, m);
  const prevDays = _udpDaysInMonth(y, m - 1);
  const cells = [];
  const s = _unifiedDatePickerState || {};
  for (let i = 0; i < 42; i++) {
    let d;
    let other = false;
    if (i < startOffset) {
      d = new Date(y, m - 1, prevDays - startOffset + i + 1);
      other = true;
    } else if (i >= startOffset + days) {
      d = new Date(y, m + 1, i - startOffset - days + 1);
      other = true;
    } else {
      d = new Date(y, m, i - startOffset + 1);
    }
    const key = _udpDateKey(d);
    const inRange = s.from && s.to && key >= s.from && key <= s.to;
    const edge = key === s.from || key === s.to;
    cells.push('<button type="button" class="udp-day' + (other ? " is-other" : "") + (inRange ? " is-range" : "") + (edge ? " is-edge" : "") + '" data-date="' + key + '">' + d.getDate() + '</button>');
  }
  return '<section class="udp-month"><h3>' + MONTHS_FR[m] + ' ' + y + '</h3><div class="udp-weekdays"><span>Lu</span><span>Ma</span><span>Me</span><span>Je</span><span>Ve</span><span>Sa</span><span>Di</span></div><div class="udp-days">' + cells.join("") + '</div></section>';
}

function _udpRender() {
  const s = _unifiedDatePickerState;
  if (!s) return;
  $("#udpFromText").textContent = s.from ? prettyDateKey(s.from) : "--";
  $("#udpToText").textContent = s.mode === "single" ? "Date simple" : (s.to ? prettyDateKey(s.to) : "--");
  $("#udpCalendars").innerHTML = _udpMonthHtml(s.anchor) + _udpMonthHtml(_udpAddMonths(s.anchor, 1));
  const monthBox = $("#udpMonthShortcuts");
  if (monthBox && !monthBox.children.length) {
    const now = new Date();
    for (let i = 0; i > -12; i--) {
      const d = new Date(now.getFullYear(), now.getMonth() + i, 1);
      const label = MONTHS_FR[d.getMonth()].slice(0, 3) + " " + String(d.getFullYear()).slice(2);
      monthBox.insertAdjacentHTML("beforeend", '<button type="button" data-month-offset="' + i + '">' + label + '</button>');
    }
  }
}

function closeUnifiedDatePicker() {
  $("#unifiedDatePicker")?.classList.add("hidden");
  _unifiedDatePickerState = null;
}

function openJournalRangePicker(opts = {}) {
  const root = _udpEnsure();
  const current = getJournalWindow();
  const from = opts.from || state.journalCustomFrom || current.from || _udpDateKey(new Date());
  const to = opts.to || state.journalCustomTo || current.to || from;
  _unifiedDatePickerState = {
    mode: "range",
    from,
    to,
    _complete: true,
    anchor: _udpMonthStart(_udpParse(from)),
    onApply: opts.onApply,
  };
  root.classList.remove("hidden");
  _udpRender();
}

function openUnifiedSingleDatePicker(input) {
  if (!input) return;
  const root = _udpEnsure();
  const value = input.value || _udpDateKey(new Date());
  _unifiedDatePickerState = {
    mode: "single",
    from: value,
    to: value,
    _complete: true,
    anchor: _udpMonthStart(_udpParse(value)),
    input,
  };
  root.classList.remove("hidden");
  _udpRender();
}

function bindUnifiedDatePickers(root = document) {
  if (root.__unifiedDatePickersBound) return;
  root.__unifiedDatePickersBound = true;
  root.querySelectorAll?.('input[type="date"]:not(.visually-hidden-date)').forEach(function(input) {
    input.readOnly = true;
    input.classList.add("udp-bound-input");
  });
  root.addEventListener("click", function(e) {
    const input = e.target.closest('input[type="date"]:not(.visually-hidden-date)');
    if (!input) return;
    e.preventDefault();
    input.readOnly = true;
    input.classList.add("udp-bound-input");
    input.blur();
    openUnifiedSingleDatePicker(input);
  });
  root.addEventListener("keydown", function(e) {
    const input = e.target.closest?.('input[type="date"]:not(.visually-hidden-date)');
    if (!input || (e.key !== "Enter" && e.key !== " ")) return;
    e.preventDefault();
    openUnifiedSingleDatePicker(input);
  });
}

document.addEventListener("DOMContentLoaded", function() {
  bindUnifiedDatePickers(document);
});

// ---- 054_chart_view_core.js ----
// ---------- Chart View Core — cadrage X+Y canonique ----------
// Module partagé entre 060 (widget BTC) et 062 (chart page).
// Garantit un comportement identique : même calcul de range prix,
// même verrouillage Y, même guards programmatic range.
//
// Configs :
//   WIDGET_VIEW — widget dashboard, follow agressif, compact
//   CHART_VIEW  — page chart classique, plus libre, plus large
//
// Usage :
//   window.ChartViewCore.computePriceRange(candles, visibleBars)
//   window.ChartViewCore.setPriceRange(ps, range, manualPriceRangeRef)
//   window.ChartViewCore.applyBestView(chart, series, candles, config, withProgRangeFn)

(function () {

  // ── CONFIGS ────────────────────────────────────────────
  var WIDGET_VIEW = {
    visibleBars: { '1m':1000,'3m':1000,'5m':1000,'15m':1000,'30m':1000,'1h':1000,'2h':1000,'4h':1000,'6h':1000,'8h':1000,'12h':1000,'1d':1000 },
    futureBars:  { '1m':24,'3m':15,'5m':10,'15m':5,'30m':3,'1h':2,'2h':2,'4h':1,'6h':1,'8h':1,'12h':1,'1d':3 },
    padding: { top: 0.08, bottom: 0.08, minRangeRatio: 0.002 },
  };

  var CHART_VIEW = {
    visibleBars: { '1m':1000,'3m':1000,'5m':1000,'15m':1000,'30m':1000,'1h':1000,'2h':1000,'4h':1000,'6h':1000,'8h':1000,'12h':1000,'1d':1000 },
    futureBars:  { '1m':22,'3m':20,'5m':12,'15m':6,'30m':4,'1h':3,'2h':2,'4h':2,'6h':2,'8h':1,'12h':1,'1d':3 },
    padding: { top: 0.10, bottom: 0.08, minRangeRatio: 0.0025 },
  };

  // ── COMPUTE PRICE RANGE ───────────────────────────────
  // Calcule un range Y sur les N dernières bougies visibles
  function computePriceRange(candles, visibleBars, padding) {
    if (!candles || !candles.length) return null;
    padding = padding || { top: 0.22, bottom: 0.18, minRangeRatio: 0.002 };

    var slice = candles.slice(-visibleBars);
    var high = -Infinity, low = Infinity;

    for (var i = 0; i < slice.length; i++) {
      var c = slice[i];
      if (Number.isFinite(c.high)) high = Math.max(high, c.high);
      if (Number.isFinite(c.low)) low = Math.min(low, c.low);
    }
    if (!Number.isFinite(high) || !Number.isFinite(low)) return null;

    var rawRange = Math.max(high - low, high * padding.minRangeRatio);
    return { from: low - rawRange * padding.bottom, to: high + rawRange * padding.top };
  }

  // ── SET PRICE RANGE ────────────────────────────────────
  // Verrouille l'axe Y via l'API LWC v5 ou fallback v4
  function setPriceRange(priceScale, range, manualPriceRangeRef) {
    if (!range || !Number.isFinite(range.from) || !Number.isFinite(range.to) || range.to <= range.from) return;

    if (manualPriceRangeRef && typeof manualPriceRangeRef === 'object') {
      manualPriceRangeRef.value = range;
    }

    if (typeof priceScale.setAutoScale === 'function' && typeof priceScale.setVisibleRange === 'function') {
      try { priceScale.setAutoScale(false); priceScale.setVisibleRange(range); } catch(e) {}
      return;
    }
    // Fallback v4 : refresh autoscaleInfoProvider
    // (le provider utilise manualPriceRangeRef, donc setVisibleLogicalRange le force à réévaluer)
  }

  // ── APPLY BEST VIEW (X + Y) ────────────────────────────
  // Applique le cadrage X (visibleLogicalRange) ET Y (priceRange)
  // en une seule opération protégée par withProgrammaticRange
  function applyBestView(chart, series, candles, config, withProgRangeFn, manualPriceRangeRef) {
    if (!chart || !series || !candles || !candles.length) return;

    var tf = config.timeframe || '3m';
    var visibleBars = (config.visibleBars || {})[tf] || 120;
    var futureBars = (config.futureBars || {})[tf] || 14;
    var padding = config.padding || { top: 0.22, bottom: 0.18, minRangeRatio: 0.002 };

    var lastIndex = candles.length - 1;

    withProgRangeFn(function () {
      try { chart.timeScale().setVisibleLogicalRange({ from: lastIndex + futureBars - visibleBars, to: lastIndex + futureBars }); } catch(e) {}

      var priceRange = computePriceRange(candles, visibleBars, padding);
      var ps;
      try { ps = series.priceScale(); } catch(e) {}
      if (ps) setPriceRange(ps, priceRange, manualPriceRangeRef);
    });
  }

  // ── AUTOSCALE INFO PROVIDER FACTORY ────────────────────
  // À passer à addCandlestickSeries / addLineSeries
  function makeAutoscaleInfoProvider(manualPriceRangeRef) {
    return function (baseImpl) {
      if (!manualPriceRangeRef || !manualPriceRangeRef.value) return baseImpl ? baseImpl() : null;
      var r = manualPriceRangeRef.value;
      return {
        priceRange: { minValue: r.from, maxValue: r.to },
        margins: { above: 0.06, below: 0.10 },
      };
    };
  }

  // ── EXPOSE ─────────────────────────────────────────────
  window.ChartViewCore = {
    WIDGET_VIEW: WIDGET_VIEW,
    CHART_VIEW: CHART_VIEW,
    computePriceRange: computePriceRange,
    setPriceRange: setPriceRange,
    applyBestView: applyBestView,
    makeAutoscaleInfoProvider: makeAutoscaleInfoProvider,
  };

})();

// ---- 054_journal_filter_picker_override.js ----
// ---------- Journal filters override: single range picker + lean controls ----------

function initJournalFilters() {
  var from = $("#jFilterFrom");
  var to = $("#jFilterTo");
  var instr = $("#jFilterInstrument");
  if (!from || !to || !instr) return;

  var now = new Date();
  populateInstruments('jFilterInstrument');
  var win = getJournalWindow();
  from.value = win.from || _fmtDate2(new Date(now.getFullYear(), now.getMonth(), 1));
  to.value = win.to || _fmtDate2(now);
  instr.value = state.statsInstrument || "ALL";
  updateJournalRangeTriggerLabel();

  from.onchange = _applyJournalFilter;
  to.onchange = _applyJournalFilter;
  instr.onchange = _applyJournalFilter;

  var rangeBtn = $("#journalRangePickerBtn");
  if (rangeBtn && !rangeBtn.dataset.bound) {
    rangeBtn.dataset.bound = "1";
    rangeBtn.addEventListener("click", function() {
      if (typeof openJournalRangePicker !== "function") return;
      openJournalRangePicker({
        from: from.value,
        to: to.value,
        onApply: function(start, end) {
          from.value = start;
          to.value = end;
          _applyJournalFilter();
        },
      });
    });
  }

  $$("#journalFilters .jfilter-layout-btn").forEach(function(btn) {
    if (btn.dataset.bound) return;
    btn.dataset.bound = "1";
    btn.addEventListener("click", function() {
      setJournalLayoutMode(btn.dataset.mode, { persist: true, rerender: true });
    });
  });

  // Metric toggle (PnL/Tr/Mix)
  $$("#calendarMetricToggle .calendar-metric-btn").forEach(function(btn) {
    if (btn.dataset.metricBound) return;
    btn.dataset.metricBound = "1";
    btn.addEventListener("click", function() {
      setCalendarMetricMode(btn.dataset.mode, { persist: true, rerender: true });
    });
  });

  bindJournalStatsArrows();
  updateJournalStatsDisplay();
}

function _applyJournalFilter() {
  var from = $("#jFilterFrom");
  var to = $("#jFilterTo");
  var instr = $("#jFilterInstrument");
  if (!from || !to || !instr) return;

  var fromDate = new Date(from.value + "T00:00:00");
  var toDate = new Date(to.value + "T00:00:00");
  if (!from.value || !to.value || isNaN(fromDate) || isNaN(toDate)) return;
  if (fromDate > toDate) {
    var oldFrom = from.value;
    from.value = to.value;
    to.value = oldFrom;
    fromDate = new Date(from.value + "T00:00:00");
    toDate = new Date(to.value + "T00:00:00");
  }

  state.currentMonth = new Date(toDate.getFullYear(), toDate.getMonth(), 1);
  state.statsInstrument = instr.value || "ALL";
  state.journalCustomFrom = from.value;
  state.journalCustomTo = to.value;
  state.journalRangeMode = "custom";
  localStorage.setItem(JOURNAL_RANGE_MODE_KEY, "custom");
  localStorage.setItem(JOURNAL_CUSTOM_RANGE_KEY, JSON.stringify({ from: from.value, to: to.value }));
  updateJournalRangeTriggerLabel();
  updateJournalRangeToggleUI();
  updateJournalControlsVisibility();
  loadMonth();
}

function updateJournalRangeTriggerLabel() {
  var label = $("#journalRangeLabel");
  var from = $("#jFilterFrom")?.value || state.journalCustomFrom || "";
  var to = $("#jFilterTo")?.value || state.journalCustomTo || "";
  if (!label) return;
  var txt = from && to ? (from === to ? prettyDateKey(from) : prettyDateKey(from) + " -> " + prettyDateKey(to)) : "Choisir une periode";
  label.textContent = txt;
  label.title = txt;
}

/* ---- Journal stats bar ---- */
var _journalStatsIndex = 0;

var _journalStatsConfig = [
  { key: "winrate",    label: "Winrate",     fmt: function(v) { return v != null ? v.toFixed(1) + "%" : "--"; } },
  { key: "tradesTotal",label: "Trades",      fmt: function(v) { return v != null ? v : "--"; } },
  { key: "pnlAvg",     label: "PnL Moy",     fmt: function(v) { return v != null ? fmtMoney(v) : "--"; } },
  { key: "rrAvg",      label: "RR Moy",      fmt: function(v) { return v != null ? Number(v).toFixed(2) + "R" : "--"; } },
  { key: "profitFactor",label: "Profit Fact", fmt: function(v) { return v != null ? Number(v).toFixed(2) : "--"; } },
  { key: "pnlTotal",   label: "PnL Total",   fmt: function(v) { return v != null ? fmtMoney(v) : "--"; } },
  { key: "streak",     label: "Streak",      fmt: function(v) { return v != null ? v : "--"; } },
  { key: "bestDay",    label: "Best Day",    fmt: function(v) { return v != null ? fmtMoney(v) : "--"; } },
  { key: "worstDay",   label: "Worst Day",   fmt: function(v) { return v != null ? fmtMoney(v) : "--"; } },
];

function computeJournalStats() {
  var days = state.days || [];
  var trades = [];
  days.forEach(function(day) {
    (day.trades || []).forEach(function(t) { trades.push(t); });
  });
  if (trades.length === 0) return { winrate: null, tradesTotal: 0, pnlAvg: null, rrAvg: null, profitFactor: null, pnlTotal: null, streak: null, bestDay: null, worstDay: null };

  var decided = 0, wins = 0, losses = 0, totalPnl = 0, totalRr = 0, rrCount = 0;
  var dayPnl = {}; // date -> sum
  var bestStreak = 0, curStreak = 0, lastResult = null;
  // Sort trades by date for streak computation
  var sorted = trades.slice().sort(function(a,b) { return (a.id||0) - (b.id||0); });

  sorted.forEach(function(t) {
    var m = deriveTradeMetrics(t);
    if (m.isWin === 1 || m.isWin === 0) {
      decided++;
      if (m.isWin === 1) wins++; else losses++;
      if (lastResult === null || m.isWin === lastResult) {
        curStreak++;
      } else {
        curStreak = 1;
      }
      lastResult = m.isWin;
      if (curStreak > bestStreak) bestStreak = curStreak;
    }
    var pnl = m.pnl;
    if (pnl != null) totalPnl += Number(pnl);
    if (m.rr != null) { totalRr += Number(m.rr); rrCount++; }
  });

  // Day-level aggregation for best/worst
  days.forEach(function(day) {
    var daySum = 0;
    (day.trades || []).forEach(function(t) {
      var m = deriveTradeMetrics(t);
      if (m.pnl != null) daySum += Number(m.pnl);
    });
    dayPnl[day.date] = daySum;
  });
  var bestDay = null, worstDay = null;
  Object.keys(dayPnl).forEach(function(d) {
    if (bestDay === null || dayPnl[d] > bestDay) bestDay = dayPnl[d];
    if (worstDay === null || dayPnl[d] < worstDay) worstDay = dayPnl[d];
  });

  // Profit Factor = sum(wins) / abs(sum(losses))
  var sumWins = 0, sumLosses = 0;
  sorted.forEach(function(t) {
    var m = deriveTradeMetrics(t);
    if (m.pnl != null && m.pnl > 0) sumWins += Number(m.pnl);
    if (m.pnl != null && m.pnl < 0) sumLosses += Number(m.pnl);
  });
  var profitFactor = sumLosses !== 0 ? sumWins / Math.abs(sumLosses) : (sumWins > 0 ? 999 : null);

  return {
    winrate: decided > 0 ? (wins / decided) * 100 : null,
    tradesTotal: trades.length,
    pnlAvg:  trades.length > 0 ? totalPnl / trades.length : null,
    rrAvg:   rrCount > 0 ? totalRr / rrCount : null,
    profitFactor: profitFactor,
    pnlTotal: totalPnl,
    streak: bestStreak > 1 ? (lastResult === 1 ? bestStreak + "W" : bestStreak + "L") : null,
    bestDay: bestDay,
    worstDay: worstDay,
  };
}

function updateJournalStatsDisplay() {
  var valueEl = $("#jfilterStatsValue");
  var labelEl = $("#jfilterStatsLabel");
  if (!valueEl || !labelEl) return;

  // Loading state: days pas encore charges
  if (!state.days || state.days.length === 0) {
    labelEl.textContent = _journalStatsConfig[_journalStatsIndex].label;
    valueEl.textContent = "...";
    valueEl.className = "jfilter-stats-loading";
    return;
  }

  var stats = computeJournalStats();
  var config = _journalStatsConfig[_journalStatsIndex];
  labelEl.textContent = config.label;
  valueEl.textContent = config.fmt(stats[config.key]);
  valueEl.className = "";
}

function bindJournalStatsArrows() {
  var row = $("#jfilterStatsRow");
  if (!row || row.dataset.statsBound) return;
  row.dataset.statsBound = "1";
  row.addEventListener("click", function(e) {
    var btn = e.target.closest(".jfilter-stats-arrow");
    if (!btn) return;
    var dir = Number(btn.dataset.dir) || 0;
    _journalStatsIndex = (_journalStatsIndex + dir + _journalStatsConfig.length) % _journalStatsConfig.length;
    updateJournalStatsDisplay();
  });
}

// ---- 055_indicator_vwap_core.js ----
// ---------- VWAP Core â€” Canonical source, stable by design ----------
// Module unique pour 060 (widget BTC) et 062 (chart page).
// RÃ¨gle absolue : VWAP ne dÃ©pend JAMAIS du timeframe affichÃ©.
// Le chart choisit juste comment AFFICHER, pas comment CALCULER.
//
// Architecture:
//   VWAP_SOURCE_CONFIG  â†’ source canonique fixe par pÃ©riode
//   getCanonicalVwap()  â†’ cache global + pending dedup
//   alignIndicatorToCandles() â†’ alignement vers les bougies du chart
//   drawVwapForChart()  â†’ helper haut niveau pour 060/062

window.BtcMarketClock = window.BtcMarketClock || (function () {
  var _offsetMs = 0;
  var _synced = false;
  var _source = 'local';

  return {
    sync: function (serverMs, src) {
      serverMs = Number(serverMs);
      if (!Number.isFinite(serverMs) || serverMs <= 0) return;
      _offsetMs = serverMs - Date.now();
      _synced = true;
      _source = src || 'unknown';
    },
    now: function () {
      return Date.now() + (_synced ? _offsetMs : 0);
    },
    isSynced: function () { return _synced; },
    offsetMs: function () { return _synced ? _offsetMs : 0; },
    source: function () { return _source; },
    reset: function () { _offsetMs = 0; _synced = false; _source = 'local'; }
  };
})();

(function () {

  // â”€â”€ CONFIG CANONIQUE â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  // IndÃ©pendante du timeframe actif du chart.
  // Chaque pÃ©riode a une source stable, prÃ©visible, rapide.
  // Modes :
  //   'rolling' → fenêtre glissante de durationMs depuis endTime
  //   'session' → session calendaire (UTC_DAY)
  var VWAP_SOURCE_CONFIG = {
    '1D':   { mode: 'session', session: 'UTC_DAY', interval: '15m', limit: 110, refreshMs: 60000 },
    '7D':   { mode: 'rolling', durationMs: 7 * 24 * 60 * 60 * 1000, interval: '15m', limit: 682, refreshMs: 60000 },
    '30D':  { mode: 'rolling', durationMs: 30 * 24 * 60 * 60 * 1000, interval: '1h',  limit: 730, refreshMs: 300000 },
    '90D':  { mode: 'rolling', durationMs: 90 * 24 * 60 * 60 * 1000, interval: '4h',  limit: 550, refreshMs: 900000 },
    '365D': { mode: 'rolling', durationMs: 365 * 24 * 60 * 60 * 1000, interval: '12h', limit: 750, refreshMs: 900000 },
  };

  var VWAP_COLORS = {
    '1D': '#f59e0b', '7D': '#06b6d4', '30D': '#a78bfa', '90D': '#f472b6', '365D': '#22c55e',
  };

  // â”€â”€ BORNES TEMPORELLES â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function _getUtcDayBounds(nowMs) {
    var d = new Date(nowMs);
    var start = Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate(), 0, 0, 0, 0);
    return { startTime: start, endTime: nowMs };
  }

  function _getSessionBounds(config, nowMs) {
    nowMs = nowMs || Date.now();
    var endTime = _getLastClosedCandleEndTime(config.interval, nowMs);
    if (config.mode === 'rolling') {
      var startTime = endTime - config.durationMs;
      return { startTime: startTime, endTime: endTime };
    }
    if (config.mode === 'session') {
      if (config.session === 'UTC_DAY') {
        var bounds = _getUtcDayBounds(nowMs);
        return { startTime: bounds.startTime, endTime: endTime };
      }
    }
    // Fallback: rolling 24h
    return { startTime: Date.now() - 86400000, endTime: Date.now() };
  }
  function _intervalToMs(interval) {
    var m = {
      '3m': 3*60000, '5m': 5*60000, '15m': 15*60000, '30m': 30*60000,
      '1h': 3600000, '2h': 7200000, '4h': 14400000, '6h': 21600000,
      '8h': 28800000, '12h': 43200000, '1d': 86400000,
    };
    return m[interval] || 3600000;
  }

  // endTime fixÃ© sur la derniÃ¨re bougie FERMÃ‰E de l'intervalle source
  // garanti identique entre deux appels Ã  quelques ms d'Ã©cart
  function _getLastClosedCandleEndTime(interval, now) {
    now = now || Date.now();
    var ms = _intervalToMs(interval);
    return Math.floor(now / ms) * ms - 1;
  }

  // â”€â”€ NORMALISATION â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function _numRequired(v) {
    if (v === null || v === undefined || v === '') return NaN;
    var n = Number(v);
    return Number.isFinite(n) ? n : NaN;
  }

  function _numOptional(v, fallback) {
    if (v === null || v === undefined || v === '') return fallback;
    var n = Number(v);
    return Number.isFinite(n) ? n : fallback;
  }

  function _normalizeTimeToSeconds(t) {
    if (t == null) return NaN;
    if (typeof t === 'number') return t > 1e12 ? Math.floor(t / 1000) : t;
    if (typeof t === 'string') {
      var n = parseInt(t, 10);
      return n > 1e12 ? Math.floor(n / 1000) : n;
    }
    return NaN;
  }

  function normalizeCandlesForLwc(raw) {
    var byTime = {};

    (raw || []).forEach(function (c) {
      if (!c) return;

      var rawTime = c.time != null ? c.time : (c.openTime != null ? c.openTime : c.t);
      var time = _normalizeTimeToSeconds(rawTime);

      var open = _numRequired(c.open);
      var high = _numRequired(c.high);
      var low = _numRequired(c.low);
      var close = _numRequired(c.close);
      var volume = _numOptional(c.volume, 0);

      if (!Number.isFinite(time) || time <= 0) return;
      if (!Number.isFinite(open) || !Number.isFinite(high) || !Number.isFinite(low) || !Number.isFinite(close)) return;

      if (high < low) return;
      if (high < Math.max(open, close)) return;
      if (low > Math.min(open, close)) return;

      byTime[time] = {
        time: time,
        open: open,
        high: high,
        low: low,
        close: close,
        volume: volume,
      };
    });

    return Object.keys(byTime)
      .map(function (t) { return byTime[t]; })
      .sort(function (a, b) { return a.time - b.time; });
  }

  function sanitizeLineData(points) {
    var byTime = {};

    (points || []).forEach(function (p) {
      if (!p) return;

      var time = Number(p.time);
      var value = Number(p.value);

      if (!Number.isFinite(time) || time <= 0) return;
      if (!Number.isFinite(value)) return;

      byTime[time] = { time: time, value: value };
    });

    return Object.keys(byTime)
      .map(function (t) { return byTime[t]; })
      .sort(function (a, b) { return a.time - b.time; });
  }

  // ── CALCUL VWAP ──
  // Cumul strict : typicalPrice * volume, running average
  function computeVwapSeries(candles) {
    var cumPV = 0, cumVol = 0, out = [];
    for (var i = 0; i < candles.length; i++) {
      var c = candles[i];
      var vol = Number(c.volume);
      if (!Number.isFinite(vol) || vol <= 0) continue;
      var tp = (c.high + c.low + c.close) / 3;
      cumPV += tp * vol;
      cumVol += vol;
      out.push({ time: c.time, value: cumPV / cumVol });
    }
    return out;
  }

  // Calcule VWAP + bandes d'écart-type 1σ, 2σ, 3σ (haut et bas)
  // Retourne { vwap: [...], u1, u2, u3, l1, l2, l3: [...] }
  function computeVwapBands(candles) {
    var cumPV = 0, cumVol = 0, cumSq = 0;
    var out = { vwap: [], u1: [], u2: [], u3: [], l1: [], l2: [], l3: [] };
    for (var i = 0; i < candles.length; i++) {
      var c = candles[i];
      var vol = Number(c.volume);
      if (!Number.isFinite(vol) || vol <= 0) continue;
      var tp = (c.high + c.low + c.close) / 3;
      cumPV += tp * vol;
      cumVol += vol;
      var v = cumPV / cumVol;
      var d = tp - v;
      cumSq += vol * d * d;
      var sig = Math.sqrt(cumSq / cumVol);
      var t = c.time;
      out.vwap.push({ time: t, value: v });
      out.u1.push({ time: t, value: v + sig });
      out.u2.push({ time: t, value: v + 2 * sig });
      out.u3.push({ time: t, value: v + 3 * sig });
      out.l1.push({ time: t, value: v - sig });
      out.l2.push({ time: t, value: v - 2 * sig });
      out.l3.push({ time: t, value: v - 3 * sig });
    }
    return out;
  }

  // Convertit #hex → rgba(r,g,b,alpha)
  function _hexToRgba(hex, alpha) {
    hex = hex.replace(/^#/, '');
    if (hex.length === 3) hex = hex[0] + hex[0] + hex[1] + hex[1] + hex[2] + hex[2];
    var r = parseInt(hex.slice(0, 2), 16);
    var g = parseInt(hex.slice(2, 4), 16);
    var b = parseInt(hex.slice(4, 6), 16);
    return 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')';
  }

  var BAND_KEYS = ['u1', 'u2', 'u3', 'l1', 'l2', 'l3'];
  // Opacité décroissante : +1/-1σ=75%, +2/-2σ=60%, +3/-3σ=45%
  var BAND_OPACITIES = { u1: 0.75, l1: 0.75, u2: 0.60, l2: 0.60, u3: 0.45, l3: 0.45 };

  // Durée d'une période en ms (pour le décalage du -1)
  function _getPeriodDurationMs(period) {
    var config = VWAP_SOURCE_CONFIG[period];
    if (!config) return 86400000;
    if (config.mode === 'rolling') return config.durationMs;
    return 24 * 60 * 60 * 1000; // session = 1 jour
  }

  // ── FETCH KLINES ──
  function _fetchKlines(symbol, interval, startTime, endTime, limit) {
    var params = 'symbol=' + symbol + '&interval=' + interval + '&limit=' + limit + '&soft=1';
    if (startTime) params += '&startTime=' + startTime;
    if (endTime) params += '&endTime=' + endTime;
    return fetch('/api/market/klines?' + params)
      .then(function (r) {
        if (!r.ok) throw new Error('HTTP ' + r.status);
        return r.json();
      })
      .then(function (data) { return data.candles || []; });
  }

  async function _fetchAndComputeCanonicalVwap(symbol, period, shiftMs) {
    var config = VWAP_SOURCE_CONFIG[period];
    if (!config) throw new Error('Unknown VWAP period: ' + period);

    var nowMs = Date.now();
    if (shiftMs) nowMs -= shiftMs;
    var bounds = _getSessionBounds(config, nowMs);
    var startTime = bounds.startTime;
    var endTime = bounds.endTime;

    console.log('[VWAP BOUNDS]', period, {
      mode: config.mode,
      interval: config.interval,
      start: new Date(startTime).toISOString(),
      end: new Date(endTime).toISOString(),
      limit: config.limit,
    });

    var raw = await _fetchKlines(symbol, config.interval, startTime, endTime, config.limit);

    console.log('[VWAP RAW]', period, {
      count: raw.length,
      first: raw[0] && new Date((raw[0].time || raw[0].openTime || raw[0].t) * 1000).toISOString(),
      last: raw[raw.length - 1] && new Date((raw[raw.length - 1].time || raw[raw.length - 1].openTime || raw[raw.length - 1].t) * 1000).toISOString(),
    });

    var candles = normalizeCandlesForLwc(raw)
      .filter(function (c) {
        var ms = c.time * 1000;
        return ms >= startTime && ms <= endTime && Number.isFinite(c.volume) && c.volume > 0;
      });

    return computeVwapBands(candles);
  }

  // â”€â”€ CACHE GLOBAL â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  var _cache = {};
  var _pending = {};

  function _cacheKey(symbol, period, previous) { return symbol + ':' + period + (previous ? ':prev' : ''); }

  async function getCanonicalVwap(symbol, period, previous) {
    var config = VWAP_SOURCE_CONFIG[period];
    if (!config) throw new Error('Unknown VWAP period: ' + period);

    var key = _cacheKey(symbol, period, !!previous);
    var cached = _cache[key];
    var now = Date.now();

    // Cache valide ? (v=2 = format bands, vwap+bands)
    if (cached && cached.v === 2 && now - cached.createdAt < config.refreshMs) {
      return cached.data;
    }

    // Ã‰vite les doubles fetchs simultanÃ©s (widget + chart page)
    if (_pending[key]) {
      return _pending[key];
    }

    var shiftMs = previous ? _getPeriodDurationMs(period) : 0;
    var promise = _fetchAndComputeCanonicalVwap(symbol, period, shiftMs)
      .then(function (data) {
        _cache[key] = { v: 2, createdAt: Date.now(), data: data };
        return data;
      })
      .catch(function (e) {
        console.warn("[VWAP] canonical fetch failed", period, e);
        if (cached && cached.data) return cached.data;
        return [];
      })
      .finally(function () {
        delete _pending[key];
      });

    _pending[key] = promise;
    return promise;
  }

  // â”€â”€ ALIGNEMENT â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  // Transforme les points VWAP canoniques pour qu'ils aient les
  // timestamps des bougies du chart actif.
  // Le temps du point canonique est prÃ©servÃ© (time: candle.time)
  function alignIndicatorToCandles(indicatorPoints, candles) {
    if (!indicatorPoints || !indicatorPoints.length || !candles || !candles.length) return [];

    // Filtrer et trier les points indicateurs
    var sorted = indicatorPoints.slice()
      .filter(function (p) { return p && Number.isFinite(p.time) && Number.isFinite(p.value); })
      .sort(function (a, b) { return a.time - b.time; });

    var out = [], j = 0;

    for (var ci = 0; ci < candles.length; ci++) {
      var t = candles[ci].time;
      // Avancer j jusqu'au dernier point â‰¤ candle.time
      while (j + 1 < sorted.length && sorted[j + 1].time <= t) j++;
      var p = sorted[j];
      if (p && p.time <= t) {
        out.push({ time: t, value: p.value });
      }
    }
    return out;
  }

  // ── DRAW HIGH-LEVEL ──
  // Helper pour 060 et 062 — fetch le VWAP canonique, aligne, setData
  // previous=true → période décalée (-1), série dans vwapSeriesMap[period + '-1']
  async function drawVwapForChart(state, period, previous, shouldAbort) {
    // state doit avoir: symbol, candles, vwapSeriesMap
    // previous peut être un booléen ; si function, c'est l'ancien shouldAbort
    if (typeof previous === 'function') { shouldAbort = previous; previous = false; }
    var isPrev = !!previous;

    var result = await getCanonicalVwap(state.symbol || 'BTCUSDT', period, isPrev);
    if (shouldAbort && shouldAbort()) return;
    if (!state.candles || !state.candles.length) return;

    // Extraire les données VWAP (support ancien format tableau)
    var vwapData = result;
    var bands = null;
    if (result && result.vwap) { vwapData = result.vwap; bands = result.bands || result; }

    var aligned = alignIndicatorToCandles(vwapData, state.candles);
    if (shouldAbort && shouldAbort()) return;
    if (aligned.length < 2) return;

    var seriesKey = period + (isPrev ? '-1' : '');
    var s = state.vwapSeriesMap[seriesKey];
    if (!s) return;
    if (shouldAbort && shouldAbort()) return;

    s.applyOptions({
      visible: true,
      color: VWAP_COLORS[period] || '#f59e0b',
      lineStyle: isPrev ? 2 : 0,  // 2 = Dashed
      lineWidth: isPrev ? 1 : 1.5,
      title: 'VWAP ' + period + (isPrev ? '-1' : ''),
      lastValueVisible: !isPrev,
      autoscaleInfoProvider: function () { return null; },
    });
    aligned = sanitizeLineData(aligned);
    if (aligned.length < 2) return;
    s.setData(aligned);

    // Bandes d'écart-type (uniquement pour la VWAP actuelle, pas la -1)
    if (!isPrev && bands) {
      for (var bi = 0; bi < BAND_KEYS.length; bi++) {
        var bk = BAND_KEYS[bi];
        if (shouldAbort && shouldAbort()) return;
        var bandData = bands[bk];
        if (!bandData || !bandData.length) continue;
        var alignedBand = alignIndicatorToCandles(bandData, state.candles);
        if (alignedBand.length < 2) continue;
        var bandSeries = state.vwapSeriesMap[period + '_' + bk];
        if (!bandSeries) continue;
        var alpha = BAND_OPACITIES[bk];
        bandSeries.applyOptions({
          visible: true,
          color: _hexToRgba(VWAP_COLORS[period] || '#f59e0b', alpha),
          lineWidth: 1,
          lineStyle: 0,
          title: period + ' ' + bk,
          lastValueVisible: false,
          autoscaleInfoProvider: function () { return null; },
        });
        bandSeries.setData(sanitizeLineData(alignedBand));
      }
    }
  }

  // â”€â”€ EVENT BUS VWAP â€” normalisation + synchro cross-component â”€â”€
  function normalizeVwapPeriods(periods) {
    var legacyMap = { 'D-NY': '1D', '24H': null };
    var seen = {};
    var out = [];
    (periods || []).forEach(function (p) {
      p = legacyMap[p] || p;
      if (!VWAP_SOURCE_CONFIG[p]) return;
      if (seen[p]) return;
      seen[p] = true;
      out.push(p);
    });
    return out;
  }

  function readActiveVwapPeriods() {
    try {
      var raw = JSON.parse(localStorage.getItem('chartVwapPeriods'));
      return normalizeVwapPeriods(Array.isArray(raw) ? raw : []);
    } catch(e) {
      return [];
    }
  }

  function saveActiveVwapPeriods(periods) {
    var normalized = normalizeVwapPeriods(periods);
    localStorage.setItem('chartVwapPeriods', JSON.stringify(normalized));
    window.dispatchEvent(new CustomEvent('chart:vwap-periods-changed', {
      detail: { periods: normalized }
    }));
    return normalized;
  }

  // â”€â”€ EXPOSE â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  window.BtcVwap = {
    VWAP_SOURCE_CONFIG: VWAP_SOURCE_CONFIG,
    VWAP_COLORS: VWAP_COLORS,
    normalizeVwapPeriods: normalizeVwapPeriods,
    readActiveVwapPeriods: readActiveVwapPeriods,
    saveActiveVwapPeriods: saveActiveVwapPeriods,
    normalizeCandlesForLwc: normalizeCandlesForLwc,
    computeVwapSeries: computeVwapSeries,
    getCanonicalVwap: getCanonicalVwap,
    alignIndicatorToCandles: alignIndicatorToCandles,
    drawVwapForChart: drawVwapForChart,
  };

})();

// ---- 056_indicator_midnight_core.js ----
// ---------- Midnight Core ----------
// Shared helper for 060 (BTC widget) and 062 (chart page).

(function () {
  var _cache = {};
  var _pending = {};

  var MIDNIGHT_COLOR = '#00f5ff';

  function _toMs(ts) {
    var n = Number(ts);
    if (!Number.isFinite(n) || n <= 0) return Date.now();
    return n > 1e12 ? n : n * 1000;
  }

  function getNyDateString(timestampMs) {
    var ms = _toMs(timestampMs);
    var parts = new Intl.DateTimeFormat('en-US', {
      timeZone: 'America/New_York',
      year: 'numeric',
      month: '2-digit',
      day: '2-digit',
    }).formatToParts(new Date(ms));

    var out = { year: '0000', month: '01', day: '01' };
    for (var i = 0; i < parts.length; i++) {
      var p = parts[i];
      if (p.type === 'year' || p.type === 'month' || p.type === 'day') {
        out[p.type] = p.value;
      }
    }
    return out.year + '-' + out.month + '-' + out.day;
  }

  function _cacheKey(symbol, dateNy) {
    return (symbol || 'BTCUSDT').toUpperCase() + ':' + dateNy;
  }

  function _fetchDay(symbol, dateNy, force) {
    var sym = (symbol || 'BTCUSDT').toUpperCase();
    var key = _cacheKey(sym, dateNy);

    if (force) delete _cache[key];
    if (!force && _cache[key]) return Promise.resolve(_cache[key]);
    if (_pending[key]) return _pending[key];

    var url = '/api/models/midnight/day?symbol=' + encodeURIComponent(sym) + '&date=' + encodeURIComponent(dateNy);
    if (force) url += '&_=' + Date.now();
    var req = fetch(url)
      .then(function (r) {
        if (!r.ok) throw new Error('HTTP ' + r.status);
        return r.json();
      })
      .then(function (data) {
        _cache[key] = data || null;
        return _cache[key];
      })
      .catch(function (e) {
        console.warn('[MIDNIGHT] fetch failed', sym, dateNy, e);
        return null;
      })
      .finally(function () {
        delete _pending[key];
      });

    _pending[key] = req;
    return req;
  }

  function _getNyMinuteOfDay(timestampMs) {
    var ms = _toMs(timestampMs);
    try {
      var parts = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/New_York',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false,
      }).formatToParts(new Date(ms));
      var out = { hour: '0', minute: '0' };
      for (var i = 0; i < parts.length; i++) {
        if (parts[i].type === 'hour' || parts[i].type === 'minute') out[parts[i].type] = parts[i].value;
      }
      var hour = parseInt(out.hour, 10);
      var minute = parseInt(out.minute, 10);
      if (!Number.isFinite(hour) || !Number.isFinite(minute)) return NaN;
      if (hour === 24) hour = 0;
      return hour * 60 + minute;
    } catch(e) {
      return NaN;
    }
  }

  function _shouldRefreshMutableMidnight(series, sym, dateNy, timestampMs) {
    var nowMs = _resolveNowMs(timestampMs);
    if (getNyDateString(nowMs) !== dateNy) return false;
    var nyMinute = _getNyMinuteOfDay(nowMs);
    if (!Number.isFinite(nyMinute) || nyMinute > 125) return false;
    if (series._midnightDrawnDate !== dateNy || series._midnightDrawnSymbol !== sym) return true;
    var now = Date.now();
    var last = Number(series._midnightLiveRefreshAt || 0);
    return !Number.isFinite(last) || now - last > 60000;
  }

  function _clearLines(series) {
    var lines = series && series._midnightPriceLines;
    if (!series || !Array.isArray(lines)) {
      if (series) series._midnightPriceLines = [];
      return;
    }
    for (var i = 0; i < lines.length; i++) {
      try { series.removePriceLine(lines[i]); } catch(e) {}
    }
    series._midnightPriceLines = [];
  }

  function _addLineSeries(chart, opts) {
    if (!chart) return null;
    try {
      if (typeof chart.addSeries === 'function' && window.LightweightCharts && window.LightweightCharts.LineSeries) {
        return chart.addSeries(window.LightweightCharts.LineSeries, opts);
      }
      if (typeof chart.addLineSeries === 'function') {
        return chart.addLineSeries(opts);
      }
    } catch(e) {}
    return null;
  }

  function _clearOpenSegment(series) {
    if (!series) return;
    var chart = series._midnightChart;
    var seg = series._midnightOpenSegmentSeries;
    if (chart && seg && typeof chart.removeSeries === 'function') {
      try { chart.removeSeries(seg); } catch(e) {}
    }
    series._midnightOpenSegmentSeries = null;
    series._midnightOpenPrice = NaN;
    series._midnightOpenStartSec = NaN;
    series._midnightOpenEndSec = NaN;
  }

  function _resolveNowMs(timestampMs) {
    var marketNow = window.BtcMarketClock && typeof window.BtcMarketClock.now === 'function'
      ? Number(window.BtcMarketClock.now())
      : NaN;
    if (Number.isFinite(marketNow) && marketNow > 0) return marketNow;
    return _toMs(timestampMs);
  }

  function _refreshOpenSegment(series, timestampMs) {
    if (!series || !series._midnightOpenSegmentSeries) return;
    var startSec = Number(series._midnightOpenStartSec);
    var price = Number(series._midnightOpenPrice);
    if (!Number.isFinite(startSec) || !Number.isFinite(price)) return;

    var nowSec = Math.floor(_resolveNowMs(timestampMs) / 1000);
    var endSec = Math.max(startSec + 1, nowSec);
    if (series._midnightOpenEndSec === endSec) return;

    series._midnightOpenEndSec = endSec;
    try {
      series._midnightOpenSegmentSeries.setData([
        { time: startSec, value: price },
        { time: endSec, value: price },
      ]);
    } catch(e) {}
  }

  async function drawMidnightLines(series, symbol, timestampMs, force, chartApi) {
    if (!series || typeof series.createPriceLine !== 'function' || typeof series.removePriceLine !== 'function') return;
    if (chartApi) series._midnightChart = chartApi;

    var sym = (symbol || 'BTCUSDT').toUpperCase();
    var dateNy = getNyDateString(timestampMs);
    var liveRefresh = !force && _shouldRefreshMutableMidnight(series, sym, dateNy, timestampMs);

    if (!force && !liveRefresh && series._midnightDrawnDate === dateNy && series._midnightDrawnSymbol === sym) {
      _refreshOpenSegment(series, timestampMs);
      return;
    }

    series._midnightDrawSeq = (series._midnightDrawSeq || 0) + 1;
    var drawSeq = series._midnightDrawSeq;
    if (liveRefresh) series._midnightLiveRefreshAt = Date.now();

    var payload = await _fetchDay(sym, dateNy, !!force || liveRefresh);
    if (drawSeq !== series._midnightDrawSeq) return;

    _clearLines(series);
    _clearOpenSegment(series);

    var levels = payload && payload.levels ? payload.levels : null;
    var midnightOpen = levels ? Number(levels.midnight_open) : NaN;
    if (!Number.isFinite(midnightOpen)) {
      series._midnightDrawnDate = dateNy;
      series._midnightDrawnSymbol = sym;
      return;
    }

    var midnightStartMs = payload && payload.windows && payload.windows.midnight
      ? Number(payload.windows.midnight.start_utc)
      : NaN;
    if (Number.isFinite(midnightStartMs)) {
      var startSec = Math.floor(midnightStartMs / 1000);
      var chart = series._midnightChart;
      var segSeries = _addLineSeries(chart, {
        color: MIDNIGHT_COLOR,
        lineWidth: 2,
        lineStyle: 0,
        priceLineVisible: false,
        lastValueVisible: true,
        crosshairMarkerVisible: false,
        title: 'Midnight Open',
        autoscaleInfoProvider: function () { return null; },
      });
      if (segSeries) {
        series._midnightOpenSegmentSeries = segSeries;
        series._midnightOpenPrice = midnightOpen;
        series._midnightOpenStartSec = startSec;
        series._midnightOpenEndSec = NaN;
        _refreshOpenSegment(series, timestampMs);
      }
    }

    series._midnightPriceLines = [];
    series._midnightDrawnDate = dateNy;
    series._midnightDrawnSymbol = sym;
  }

  window.BtcMidnight = {
    _cache: _cache,
    getNyDateString: getNyDateString,
    drawMidnightLines: drawMidnightLines,
    clearSeriesLines: function (series) {
      _clearLines(series);
      _clearOpenSegment(series);
    },
  };
})();

// ---- 056_journal_day_trade_cards.js ----
function journalTradeEditorHtml(day, trade) { return TradeEditorController.renderHtml(day, trade); }

// ---------- Journal inline day trades ----------

var _journalDayTradeCardsBound = false;
var _journalDayTradeCache = {};
var _journalDayTradeDays = {};
var _journalCardSaveTimers = {};
var _journalRefreshTimer = null;
var _jcardFieldFocused = false;

// ---- Intercepteur anti re-fired click (enregistre avant tout) ----
(function() {
  if (window._intRegistered) return;
  window._intRegistered = true;
  window.addEventListener('click', function interceptor(e) {
    var wrap = document.getElementById('journalDayTrades');
    if (!wrap || !wrap.classList.contains('is-editing')) return;
    var inPanel = e.target.closest('.jedit-panel');
    if (inPanel) return;
    if (!wrap.contains(e.target)) return;
    closeJournalTradeEditor();
    window._consumeClick = true;
    setTimeout(function() { window._consumeClick = false; }, 0);
    e.stopImmediatePropagation();
    e.preventDefault();
  }, true);
})();

// ---- collect / summarize helpers ----

function collectJournalDayTrades(days) {
  var out = [];
  (days || []).forEach(function (day) {
    (day.trades || []).forEach(function (trade) {
      out.push({ day: day, trade: trade });
    });
  });
  return out;
}

function summarizeJournalDayTrades(items) {
  return items.reduce(function (acc, item) {
    var m = deriveTradeMetrics(item.trade);
    var pnl = Number(m.pnl || 0);
    acc.pnl += pnl;
    if (m.isWin === 1) acc.wins += 1;
    if (m.isWin === 0) acc.losses += 1;
    acc.instruments[item.day.instrument || "-"] = true;
    return acc;
  }, { pnl: 0, wins: 0, losses: 0, instruments: {} });
}

// ---- inline edit: collect, save, refresh ----

function _journalCardCollectPayload(tid) {
  var tidStr = String(tid);
  var scroll = document.querySelector('.journal-flip-back-scroll[data-trade-id="' + tidStr + '"]');
  if (!scroll) return null;
  var trade = _journalDayTradeCache[tidStr];
  if (!trade) return null;

  var patch = {};

  // text / number inputs and textareas
  scroll.querySelectorAll('input.jcard-field, textarea.jcard-field').forEach(function (el) {
    patch[el.dataset.field] = el.value;
  });

  // pill groups — active pill value per group
  scroll.querySelectorAll('.jcard-pills').forEach(function (group) {
    var field = group.dataset.field;
    var active = group.querySelector('.jcard-pill.is-active');
    if (field) patch[field] = active ? active.dataset.value : '';
  });

  // star rating — stored on the wrapper's data-value
  scroll.querySelectorAll('.jcard-stars').forEach(function (group) {
    var field = group.dataset.field;
    if (field) {
      var starVal = group.dataset.value;
      if (starVal && starVal !== '0') patch[field] = starVal;
    }
  });

  return Object.assign({}, trade, patch);
}

function _journalCardSave(tid) {
  var tidStr = String(tid);
  var payload = _journalCardCollectPayload(tidStr);
  if (!payload) return;

  var scroll = document.querySelector('.journal-flip-back-scroll[data-trade-id="' + tidStr + '"]');
  var ind = scroll && scroll.querySelector('.jcard-save-ind');
  if (ind) { ind.textContent = '…'; ind.dataset.state = 'saving'; }

  api('/api/trades/' + tidStr, { method: 'PUT', body: JSON.stringify(payload) })
    .then(function (res) {
      var updated = (res && res.trade) ? res.trade : payload;
      _journalDayTradeCache[tidStr] = updated;
      _journalCardRefreshMetrics(tidStr, updated);
      _journalSyncStateAfterSave(tidStr, updated);
      _journalRefreshStateDebounced();
      if (ind) {
        ind.textContent = 'Sauvegardé ✓';
        ind.dataset.state = 'saved';
        setTimeout(function () {
          if (ind) { ind.textContent = ''; ind.dataset.state = ''; }
        }, 2200);
      }
    })
    .catch(function () {
      if (ind) { ind.textContent = 'Erreur'; ind.dataset.state = 'error'; }
    });
}

function _journalCardRefreshMetrics(tid, trade) {
  var tidStr = String(tid);
  var scroll = document.querySelector('.journal-flip-back-scroll[data-trade-id="' + tidStr + '"]');
  var card   = document.querySelector('.journal-flip-card[data-trade-id="' + tidStr + '"]');
  var editor = document.querySelector('.journal-trade-editor[data-trade-id="' + tidStr + '"]');
  var m      = deriveTradeMetrics(trade);
  var pnl    = Number(m.pnl || 0);
  var pnlClass    = pnl > 0 ? 'pos' : pnl < 0 ? 'neg' : 'flat';
  var resultClass = m.isWin === 1 ? 'win' : m.isWin === 0 ? 'loss' : 'neutral';
  var resultLabel = m.isWin === 1 ? 'WIN' : m.isWin === 0 ? 'LOSS' : '-';
  var rrTxt  = m.rr == null ? '-' : Number(m.rr).toFixed(2) + 'R';
  var pnlTxt = fmtMoney(pnl);

  // Back face
  if (scroll) {
    var pnlEl = scroll.querySelector('.jcard-pnl-display');
    if (pnlEl) { pnlEl.textContent = pnlTxt; pnlEl.className = 'jcard-pnl-display ' + pnlClass; }
    var rrEl  = scroll.querySelector('.jcard-rr-display');
    if (rrEl) rrEl.textContent = rrTxt;
    var resEl = scroll.querySelector('.jcard-result-display');
    if (resEl) { resEl.textContent = resultLabel; resEl.className = 'jcard-result-display ' + resultClass; }
  }

  // Front face
  if (card) {
    var topPnl = card.querySelector('.journal-flip-front .journal-trade-top-pnl');
    if (topPnl) { topPnl.textContent = pnlTxt; topPnl.className = 'journal-trade-top-pnl ' + pnlClass; }
    var topRes = card.querySelector('.journal-flip-front .journal-trade-result');
    if (topRes) { topRes.textContent = resultLabel; topRes.className = 'journal-trade-result ' + resultClass; }
    var frontPnl = card.querySelector('.journal-flip-front .journal-trade-pnl');
    if (frontPnl) { frontPnl.textContent = pnlTxt; frontPnl.className = 'journal-trade-pnl ' + pnlClass; }
  }

  if (editor) {
    var editorPnl = editor.querySelector('.jedit-metric-pnl strong');
    if (editorPnl) { editorPnl.textContent = pnlTxt; editorPnl.className = pnlClass; }
    var editorRr = editor.querySelector('.jedit-metric-rr strong');
    if (editorRr) editorRr.textContent = rrTxt;
    var editorResult = editor.querySelector('.jedit-metric-result strong');
    if (editorResult) { editorResult.textContent = resultLabel; editorResult.className = resultClass; }
  }
}

// ---- Full card DOM refresh + state sync after save ----

function _journalCardRefreshFull(tid, trade) {
  var tidStr = String(tid);
  var card = document.querySelector('.journal-flip-card[data-trade-id="' + tidStr + '"]');
  var day = _journalDayTradeDays[tidStr];
  if (!card || !day) return;

  // Preserve flip state
  var isFlipped = card.classList.contains('is-flipped');

  // Find card index within grid
  var grid = card.closest('.journal-day-trades-grid');
  var idx = 1;
  if (grid) {
    var allCards = grid.querySelectorAll('.journal-flip-card');
    for (var i = 0; i < allCards.length; i++) {
      if (allCards[i] === card) { idx = i + 1; break; }
    }
  }

  var newHtml = journalTradeFlipCardHtml(day, trade, idx, {});
  var temp = document.createElement('div');
  temp.innerHTML = newHtml;
  var newCard = temp.firstElementChild;
  if (isFlipped) newCard.classList.add('is-flipped');
  card.parentNode.replaceChild(newCard, card);
}

// Debounced state refresh for calendar, stats, filters
function _journalRefreshStateDebounced() {
  clearTimeout(_journalRefreshTimer);
  _journalRefreshTimer = setTimeout(function () {
    if (typeof loadMonth === 'function') loadMonth();
    if (typeof loadStats === 'function') loadStats({ refreshDays: true, skipRender: false });
  }, 400);
}

// Lightweight state sync after editor save - updates state.days in place
function _journalSyncStateAfterSave(tid, updated) {
  if (!state || !state.days) return;
  var targetId = Number(tid);
  state.days.forEach(function (day) {
    if (day.trades) {
      day.trades.forEach(function (trade, i) {
        if (Number(trade.id) === targetId) {
          day.trades[i] = updated;
        }
      });
    }
  });
}

function _journalCardScheduleSave(tid) {
  _journalCardSave(tid);
}

// ---- card-style editor drawer ----

// ---- Live recalc PnL/RR/is_win for editor before save ----

// ---- Live editor UI refresh after save ----

// ---- Inline warnings in editor sections ----

function openJournalTradeEditor(tid) {
  TradeEditorController.open(tid);
}

// Save a trade immediately via TradeEditorController
function _journalEditorSave(tid) {
  TradeEditorController.save(String(tid));
}

function _flushPendingJournalSaves() {
  // Execute pending editor saves immediately instead of dropping them
  Object.keys(TradeEditorController.saveTimers).forEach(function (tid) {
    clearTimeout(TradeEditorController.saveTimers[tid]);
    _journalEditorSave(tid);
  });
  TradeEditorController.saveTimers = {};

  // Execute pending card saves immediately
  Object.keys(_journalCardSaveTimers).forEach(function (tid) {
    clearTimeout(_journalCardSaveTimers[tid]);
    _journalCardSave(tid);
  });
  _journalCardSaveTimers = {};
}

function closeJournalTradeEditor(opts) {
  TradeEditorController.close(opts);
}


function _bindJournalClick(wrap) {
  wrap.addEventListener("click", function (e) {
    if (window._consumeClick) { window._consumeClick = false; e.stopImmediatePropagation(); e.preventDefault(); return; }
    var ec = e.target.closest("[data-journal-editor-close]"); if (ec) { e.stopPropagation(); closeJournalTradeEditor(); return; }
    var es = e.target.closest("[data-journal-editor-save]"); if (es) { e.stopPropagation(); var st = es.dataset.journalEditorSave || TradeEditorController.activeTradeId; if (st) TradeEditorController.save(st); return; }
    var cb = e.target.closest("[data-journal-day-close]"); if (cb) { closeJournalDayTrades(); return; }
    var eb = e.target.closest("[data-journal-trade-edit]");
    if (!eb && e.target.tagName === "BUTTON" && e.target.classList.contains("journal-back-edit")) eb = e.target;
    if (eb) { e.stopPropagation(); try { openJournalTradeEditor(eb.dataset.journalTradeEdit); } catch (_e) { console.error("[cockpit] Erreur ouverture editeur:", _e); } return; }
    var ep = e.target.closest(".jedit-pill"); if (ep) { e.stopPropagation(); var eg = ep.closest(".jedit-pills"); if (eg) { eg.querySelectorAll(".jedit-pill").forEach(function (p) { p.classList.remove("is-active"); }); ep.classList.add("is-active"); var ed = ep.closest(".journal-trade-editor"); var et = ed && ed.dataset.tradeId; if (et) { TradeEditorController.scheduleSave(et); TradeEditorController.recalcLive(ed); } } return; }
    var est = e.target.closest(".jedit-star"); if (est) { e.stopPropagation(); var esw = est.closest(".jedit-stars"); if (esw) { var ev = Number(est.dataset.val); if (String(esw.dataset.value) === String(ev)) ev = 0; esw.dataset.value = String(ev); esw.querySelectorAll(".jedit-star").forEach(function (s) { s.classList.toggle("is-lit", Number(s.dataset.val) <= ev); }); var ed2 = esw.closest(".journal-trade-editor"); var et2 = ed2 && ed2.dataset.tradeId; if (et2) TradeEditorController.scheduleSave(et2); } return; }
    var pill = e.target.closest(".jcard-pill"); if (pill) { e.stopPropagation(); var g = pill.closest(".jcard-pills"); if (g) { g.querySelectorAll(".jcard-pill").forEach(function (p) { p.classList.remove("is-active"); }); pill.classList.add("is-active"); var s = pill.closest(".journal-flip-back-scroll"); var t = s && s.dataset.tradeId; if (t) _journalCardScheduleSave(t); } return; }
    var star = e.target.closest(".jcard-star"); if (star) { e.stopPropagation(); var sw = star.closest(".jcard-stars"); if (sw) { var v = Number(star.dataset.val); if (String(sw.dataset.value) === String(v)) v = 0; sw.dataset.value = String(v); sw.querySelectorAll(".jcard-star").forEach(function (s) { s.classList.toggle("is-lit", Number(s.dataset.val) <= v); }); var s2 = sw.closest(".journal-flip-back-scroll"); var t3 = s2 && s2.dataset.tradeId; if (t3) _journalCardScheduleSave(t3); } return; }
    var fav = e.target.closest("[data-journal-fav]"); if (fav) { e.stopPropagation(); _toggleTradeFavorite(fav.dataset.journalFav, fav); return; }
    var dup = e.target.closest("[data-journal-dup]"); if (dup) { e.stopPropagation(); _duplicateTrade(dup.dataset.journalDup); return; }
    if (e.target.closest(".journal-back-icon")) { e.stopPropagation(); return; }
    if (e.target.closest(".journal-trade-editor")) { e.stopPropagation(); return; }
    if (_jcardFieldFocused) return;
    if (e.target.closest("input, textarea, select, .jcard-pills, .jcard-stars")) return;
    if (document.documentElement.classList.contains("html-editor-open")) { closeJournalTradeEditor(); return; }
    if (TradeEditorController.activeTradeId !== null) { closeJournalTradeEditor(); return; }
    if (TradeEditorController.justClosed) return;
    if (Date.now() - TradeEditorController.closeTime < 1200) return;
    if (document.querySelector("#journalDayTrades .journal-trade-editor")) return;
    var card = e.target.closest(".journal-flip-card"); if (!card || !wrap.contains(card)) return;
    card.classList.toggle("is-flipped");
  });
}

function _bindJournalFocusEvents(wrap) {
  wrap.addEventListener("focusin", function (e) { if (e.target.closest(".jcard-field")) _jcardFieldFocused = true; });
  wrap.addEventListener("focusout", function (e) { if (e.target.closest(".jcard-field")) { setTimeout(function () { _jcardFieldFocused = false; }, 300); } });
}

function _bindJournalFieldSaves(wrap) {
  wrap.addEventListener("focusout", function (e) {
    var field = e.target.closest(".jcard-field");
    if (field) { var s = field.closest(".journal-flip-back-scroll"); var t = s && s.dataset.tradeId; if (t) _journalCardScheduleSave(t); return; }
    var ef = e.target.closest(".jedit-field"); if (ef) { var ed = ef.closest(".journal-trade-editor"); var et = ed && ed.dataset.tradeId; if (et) TradeEditorController.scheduleSave(et); }
  });
}

function _bindJournalChangeSelect(wrap) {
  wrap.addEventListener("change", function (e) {
    var ef = e.target.closest(".jedit-field"); if (!ef) return;
    var ed = ef.closest(".journal-trade-editor");
    if (ef.tagName === "SELECT" && ef.dataset.field === "strategy") {
      var title = ed && ed.querySelector(".jedit-hero-copy h3");
      if (title) title.textContent = ef.options[ef.selectedIndex] ? ef.options[ef.selectedIndex].text : ef.value;
    }
    if (ed) {
      TradeEditorController.recalcLive(ed);
    }
  });
}

function _bindJournalKeydown(wrap) {
  wrap.addEventListener("keydown", function (e) {
    if (e.key === "Escape" && TradeEditorController.activeTradeId) { e.preventDefault(); closeJournalTradeEditor(); return; }
    if (e.key !== "Enter" && e.key !== " ") return;
    if (e.target.matches("input, textarea, select, button")) return;
    if (e.target.closest(".journal-trade-editor")) return;
    if (wrap.querySelector(".jcard-field:focus, .journal-flip-back-scroll:focus-within")) return;
    if (document.documentElement.classList.contains("html-editor-open")) return;
    if (TradeEditorController.activeTradeId !== null) return;
    if (Date.now() - TradeEditorController.closeTime < 1200) return;
    if (document.querySelector("#journalDayTrades .journal-trade-editor")) return;
    var card = e.target.closest(".journal-flip-card"); if (!card || !wrap.contains(card)) return;
    e.preventDefault(); card.classList.toggle("is-flipped");
  });
}

function _bindJournalMarginInput(wrap) {
  wrap.addEventListener("input", function (e) {
    // Sync TP -> Sortie for flip card
    if (e.target.matches(".jcard-field[data-field='take_profit']")) {
      var scroll = e.target.closest(".journal-flip-back-scroll");
      var exitInput = scroll && scroll.querySelector(".jcard-field[data-field='exit_price']");
      if (exitInput) exitInput.value = e.target.value;
    }
    // Sync TP -> Sortie for sidebar editor
    if (e.target.matches(".jedit-field[data-field='take_profit']")) {
      var editor = e.target.closest(".journal-trade-editor");
      var exitInput = editor && editor.querySelector(".jedit-field[data-field='exit_price']");
      if (exitInput) exitInput.value = e.target.value;
    }

    var field = e.target.closest(".journal-flip-back-scroll .jcard-margin-input, .journal-flip-back-scroll .jcard-field[data-field=\"leverage\"], .journal-flip-back-scroll .jcard-field[data-field=\"entry_price\"]");
    var scroll = e.target.closest(".journal-flip-back-scroll");
    if (field && scroll) {
      var tid = scroll.dataset.tradeId;
      if (tid) {
        var mi = scroll.querySelector(".jcard-margin-input"); var li = scroll.querySelector(".jcard-field[data-field=\"leverage\"]");
        var ei = scroll.querySelector(".jcard-field[data-field=\"entry_price\"]"); var pi = scroll.querySelector(".jcard-field[data-field=\"position_size\"]");
        if (mi && li && ei && pi) {
          if (field === mi || field.dataset.field === "leverage") {
            var m = Number(mi.value); var l = Number(li.value); var entryVal = Number(ei.value);
            if (m > 0 && l > 0 && entryVal > 0) { var c = computePositionSize(m, l, entryVal); if (c != null) { pi.value = String(c); _journalCardScheduleSave(tid); } }
          }
          if (field === pi) {
            var p = Number(pi.value); var l2 = Number(li.value); var entryVal2 = Number(ei.value);
            if (p > 0 && l2 > 0 && entryVal2 > 0) { var cm = computeMarginUsd(p, l2, entryVal2); if (cm != null) mi.value = String(cm); }
          }
        }
      }
    }

    if (scroll) {
      _recalcCardMetrics(scroll);
    }

    var editor = e.target.closest(".journal-trade-editor");
    if (editor) {
      TradeEditorController.recalcLive(editor);
    }
  });
}

function _recalcCardMetrics(scroll) {
  var tid = scroll.dataset.tradeId;
  var trade = _journalDayTradeCache[String(tid)];
  if (!trade) return;

  var entryEl = scroll.querySelector('.jcard-field[data-field="entry_price"]');
  var tpEl    = scroll.querySelector('.jcard-field[data-field="take_profit"]');
  var slEl    = scroll.querySelector('.jcard-field[data-field="stop_loss"]');
  var exitEl  = scroll.querySelector('.jcard-field[data-field="exit_price"]');
  var qtyEl   = scroll.querySelector('.jcard-field[data-field="position_size"]');

  var tempTrade = Object.assign({}, trade, {
    entry_price: entryEl ? entryEl.value : null,
    take_profit: tpEl ? tpEl.value : null,
    stop_loss: slEl ? slEl.value : null,
    exit_price: exitEl ? exitEl.value : null,
    position_size: qtyEl ? qtyEl.value : null
  });

  var m = deriveTradeMetrics(tempTrade);
  var pnl = Number(m.pnl || 0);
  var pnlClass = pnl > 0 ? "pos" : pnl < 0 ? "neg" : "flat";
  var resultClass = m.isWin === 1 ? "win" : m.isWin === 0 ? "loss" : "neutral";
  var resultLabel = m.isWin === 1 ? "WIN" : m.isWin === 0 ? "LOSS" : "-";
  var rrTxt = m.rr == null ? "-" : Number(m.rr).toFixed(2) + "R";
  var pnlTxt = fmtMoney(pnl);

  // Met a jour les elements de la carte
  var pnlEl = scroll.querySelector('.jcard-pnl-display');
  if (pnlEl) {
    pnlEl.textContent = pnlTxt;
    pnlEl.className = 'jcard-pnl-display ' + pnlClass;
  }
  var rrEl = scroll.querySelector('.jcard-rr-display');
  if (rrEl) {
    rrEl.textContent = rrTxt;
  }
  var resEl = scroll.querySelector('.jcard-result-display');
  if (resEl) {
    resEl.textContent = resultLabel;
    resEl.className = 'jcard-result-display ' + resultClass;
  }

  // Met a jour le badge R:R visuel
  var badgeEl = scroll.querySelector('.jcard-rr-visual-badge');
  if (badgeEl) {
    if (m.rr == null) {
      badgeEl.textContent = 'Niveaux incomplets';
      badgeEl.className = 'jcard-rr-visual-badge rr-neutral';
    } else {
      var rrVal = Number(m.rr);
      badgeEl.textContent = rrVal.toFixed(2) + ' R:R';
      if (rrVal < 1.0) {
        badgeEl.className = 'jcard-rr-visual-badge rr-low';
      } else if (rrVal < 2.0) {
        badgeEl.className = 'jcard-rr-visual-badge rr-medium';
      } else {
        badgeEl.className = 'jcard-rr-visual-badge rr-high';
      }
    }
  }
}


function _bindJournalScreenshotUpload(wrap) {
  wrap.addEventListener("click", function (e) { var se = e.target.closest(".journal-back-shot"); if (!se) return; var si = se.querySelector(".journal-shot-input"); if (!si) return; si.click(); });
  wrap.addEventListener("change", function (e) {
    var input = e.target.closest(".journal-shot-input"); if (!input || !input.files || !input.files[0]) return;
    var file = input.files[0]; var scroll = input.closest(".journal-flip-back-scroll"); if (!scroll) return;
    var tid = scroll.dataset.tradeId; if (!tid) return;
    var fd = new FormData(); fd.append("file", file);
    fetch("/api/trades/" + tid + "/screenshots", { method: "POST", body: fd })
      .then(function (r) { if (!r.ok) throw new Error("Upload echoue"); return r.json(); })
      .then(function () { return api("/api/trades/" + tid); })
      .then(function (u) { _journalDayTradeCache[String(tid)] = u; _journalCardRefreshFull(String(tid), u); _journalRefreshStateDebounced(); })
      .catch(function (err) { toast(err.message || "Erreur upload screenshot", "error"); });
    input.value = "";
  });
}

function bindJournalDayTrades() {
  var wrap = $("#journalDayTrades");
  if (!wrap || _journalDayTradeCardsBound) return;
  _bindJournalClick(wrap);
  _bindJournalFocusEvents(wrap);
  _bindJournalFieldSaves(wrap);
  _bindJournalChangeSelect(wrap);
  _bindJournalKeydown(wrap);
  _bindJournalMarginInput(wrap);
  _bindJournalScreenshotUpload(wrap);
  _journalDayTradeCardsBound = true;
  if (!window._journalCloseBound) {
    window._journalCloseBound = true;
    document.addEventListener("click", function _closeOnOutside(e) {
      var w = $("#journalDayTrades"); if (!w || w.classList.contains("hidden")) return;
      if (e.target.closest(".journal-flip-card, #journalDayTrades, .day, #journalTradesTbody, [data-journal-trade-edit]")) return;
      if (!w.contains(e.target)) closeJournalDayTrades();
    });
  }
}


// ---- render / close ----
function renderJournalDayTrades(dateKey, days) {
  var wrap = $("#journalDayTrades");
  if (!wrap) return;
  bindJournalDayTrades();

  var items = collectJournalDayTrades(days);
  if (!items.length) { closeJournalDayTrades(); return; }

  // Preserver l'etat des flips avant de detruire le DOM
  var flipped = {};
  wrap.querySelectorAll('.journal-flip-card.is-flipped').forEach(function (c) {
    var tid = c.dataset.tradeId;
    if (tid) flipped[tid] = true;
  });

  _journalDayTradeCache = {};
  _journalDayTradeDays  = {};
  items.forEach(function (item) {
    var id = String(item.trade.id);
    _journalDayTradeCache[id] = item.trade;
    _journalDayTradeDays[id]  = item.day;
  });

  var summary   = summarizeJournalDayTrades(items);
  var decided   = summary.wins + summary.losses;
  var wr        = decided ? Math.round(summary.wins / decided * 100) + "%" : "-";
  var instruments = Object.keys(summary.instruments).join(" / ");

  wrap.classList.remove("hidden");
  wrap.dataset.count = String(Math.min(items.length, 3));
  wrap.innerHTML = `
    <div class="journal-day-trades-grid">
      ${items.map(function (item, idx) {
        return journalTradeFlipCardHtml(item.day, item.trade, idx + 1, { dateKey: dateKey, wr: wr });
      }).join("")}
    </div>
  `;

  // Restaurer les flips preserves
  if (Object.keys(flipped).length) {
    Object.keys(flipped).forEach(function (tid) {
      var card = wrap.querySelector('.journal-flip-card[data-trade-id="' + tid + '"]');
      if (card) card.classList.add('is-flipped');
    });
  }

  var firstCard = wrap.querySelector(".journal-flip-card");
  if (firstCard) firstCard.focus({ preventScroll: true });
}

function closeJournalDayTrades() {
  var wrap = $("#journalDayTrades");
  if (!wrap) return;
  // Flush any pending saves before destroying
  _flushPendingJournalSaves();
  TradeEditorController.activeTradeId = null;
  document.documentElement.classList.remove('html-editor-open');
  wrap.classList.add("hidden");
  wrap.classList.remove("is-editing");
  delete wrap.dataset.count;
  wrap.innerHTML = "";
  _journalDayTradeCache = {};
  _journalDayTradeDays  = {};
}

// ---- helpers ----

function journalShortText() {
  for (var i = 0; i < arguments.length; i += 1) {
    var v = String(arguments[i] || "").trim();
    if (v) return v.length > 150 ? v.slice(0, 147) + "..." : v;
  }
  return "Aucun resume renseigne pour ce trade.";
}

function journalFmtPrice(v) {
  if (v == null || v === "") return "-";
  var n = Number(v);
  return Number.isFinite(n) ? n.toFixed(2) : "-";
}

function journalValueAttr(v) {
  return v == null ? "" : escapeHtml(String(v));
}

function journalTagsValue(tags) {
  return Array.isArray(tags) ? tags.join(", ") : "";
}

function journalSelectOption(value, label, current) {
  return '<option value="' + escapeHtml(value) + '"' + (String(current || '') === String(value) ? ' selected' : '') + '>' + escapeHtml(label) + '</option>';
}

function journalEditorField(label, field, value, type, opts) { return TradeEditorController.field(label, field, value, type, opts); }

function journalEditorTextarea(label, field, value, rows) { return TradeEditorController.textarea(label, field, value, rows); }

function journalEditorPills(field, current, choices) { return TradeEditorController.pills(field, current, choices); }

function journalEditorStrategyOptions(current) { return TradeEditorController.strategyOptions(current); }

// ---- flip card HTML ----

function _flipCardFrontInner(day, trade, m, pnl, pnlClass, resultClass, resultLabel, direction, strategy, rr, summary, shot, shotStyle, shotClass, tid, idx) {
  return `<div class="journal-flip-face journal-flip-front">
    <div class="journal-flip-top">
      <span class="metric-pill metric-pill--muted journal-trade-index">#${idx}</span>
      <span class="metric-pill metric-pill--cyan journal-trade-instrument">${escapeHtml(day.instrument || "-")}</span>
      <span class="metric-pill metric-pill--${pnlClass === 'pos' ? 'win' : pnlClass === 'neg' ? 'loss' : 'muted'} journal-trade-top-pnl ${pnlClass}">${fmtMoney(pnl)}</span>
      <span class="metric-pill metric-pill--${resultClass === 'win' ? 'win' : resultClass === 'loss' ? 'loss' : 'muted'} journal-trade-result ${resultClass}">${resultLabel}</span>
      <button type="button" class="journal-card-close" data-journal-day-close aria-label="Fermer">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" width="13" height="13"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
      </button>
    </div>
    <div class="journal-trade-shot ${shotClass}"${shotStyle}>
      ${shot ? "" : "<span>Aucune capture</span>"}
    </div>
    <div class="journal-trade-content">
      <div class="journal-trade-main">
        <div>
          <h4>${escapeHtml(strategy)}</h4>
          <p>${escapeHtml(summary)}</p>
        </div>
        <strong class="journal-trade-pnl ${pnlClass}">${fmtMoney(pnl)}</strong>
      </div>
      <div class="journal-trade-strip">
        <span class="metric-pill">${escapeHtml(direction)}</span>
        <span class="metric-pill">${escapeHtml(rr)}</span>
        <span class="metric-pill metric-pill--${resultClass === 'win' ? 'win' : resultClass === 'loss' ? 'loss' : 'muted'}">${escapeHtml(resultLabel)}</span>
      </div>
      <div class="journal-trade-card-actions">
        <span>${escapeHtml(resultLabel)}</span>
        <button type="button">Voir details</button>
      </div>
    </div>
  </div>`;
}

function _flipCardBackInner(day, trade, m, pnl, pnlClass, resultClass, resultLabel, direction, strategy, rr, summary, shot, shotStyle, shotClass, tid, idx, dateLabel, htf, starsHtml, qualityRaw, lessonsRaw) {
  var isFav = (trade.tags || []).includes("favoris");
  return `<div class="journal-flip-face journal-flip-back">
    <div class="journal-flip-back-scroll" data-trade-id="${tid}">
      <div class="journal-back-actions">
        <button type="button" class="journal-back-icon${isFav ? " is-active" : ""}" aria-label="Favoris" aria-pressed="${isFav}" data-journal-fav="${tid}">
          <svg viewBox="0 0 24 24" fill="${isFav ? "currentColor" : "none"}" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><path d="M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 0 0-7.8 7.8l1 1L12 21l7.8-7.6 1-1a5.5 5.5 0 0 0 0-7.8z"/></svg>
        </button>
        <button type="button" class="journal-back-icon" aria-label="Dupliquer" data-journal-dup="${tid}">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.9" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>
        </button>
        <span class="jcard-save-ind" data-state=""></span>
        <button type="button" class="journal-back-edit" data-journal-trade-edit="${tid}">Editer</button>
      </div>
      <h4>${escapeHtml(strategy)}</h4>
      <p class="journal-back-sub">${escapeHtml(dateLabel)} &middot; ${escapeHtml(day.instrument || "-")} &middot; ${escapeHtml(direction)}</p>
      <p class="journal-back-summary">${escapeHtml(summary)}</p>
      <div class="journal-back-stats">
        <div><strong>${escapeHtml(direction)}</strong><span>Direction</span></div>
        <div><strong>${escapeHtml(trade.session || '-')}</strong><span>Session</span></div>
        <div><strong class="jcard-rr-display">${escapeHtml(rr)}</strong><span>R multiple</span></div>
        <div><strong class="jcard-pnl-display ${pnlClass}">${fmtMoney(pnl)}</strong><span>PnL</span></div>
      </div>
      <h5>Niveaux</h5>
      <div class="journal-trade-detail-grid">
        <div>
          <span>Entree</span>
          <input class="jcard-field" type="number" step="0.01" data-field="entry_price" value="${trade.entry_price != null ? escapeHtml(String(trade.entry_price)) : ''}" placeholder="&mdash;"/>
        </div>
        <div>
          <span>TP</span>
          <input class="jcard-field" type="number" step="0.01" data-field="take_profit" value="${trade.take_profit != null ? escapeHtml(String(trade.take_profit)) : ''}" placeholder="&mdash;"/>
        </div>
        <div>
          <span>SL</span>
          <input class="jcard-field" type="number" step="0.01" data-field="stop_loss" value="${trade.stop_loss != null ? escapeHtml(String(trade.stop_loss)) : ''}" placeholder="&mdash;"/>
        </div>
        <div>
          <span>Sortie</span>
          <input class="jcard-field" type="number" step="0.01" data-field="exit_price" value="${trade.exit_price != null ? escapeHtml(String(trade.exit_price)) : ''}" placeholder="&mdash;"/>
        </div>
      </div>
      <div class="jcard-rr-visual-container">
        <div class="jcard-rr-visual-badge ${m.rr != null ? (m.rr < 1.0 ? 'rr-low' : m.rr < 2.0 ? 'rr-medium' : 'rr-high') : 'rr-neutral'}">
          ${m.rr != null ? Number(m.rr).toFixed(2) + ' R:R' : 'Niveaux incomplets'}
        </div>
      </div>
      <h5>Capture</h5>
      <div class="journal-back-shot" data-trade-shot="${tid}">
        ${shot ? `<img class="journal-back-shot-img" src="/screenshots/${escapeHtml(shot.filename)}" alt="Screenshot" />` : '<div class="journal-back-shot-empty"><svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><rect x="3" y="3" width="18" height="18" rx="3"/><circle cx="8.5" cy="8.5" r="1.5"/><path d="M21 15l-5-5L5 21"/></svg><span>Ajouter une photo</span></div>'}
        <input type="file" accept="image/*" class="journal-shot-input hidden" data-trade-shot-input="${tid}" />
      </div>
      <h5>Execution</h5>
      <div class="journal-trade-detail-grid jcard-exec-grid">
        <div><span>Resultat</span><strong class="jcard-result-display ${resultClass}">${escapeHtml(resultLabel)}</strong></div>
        <div><span>Marge $</span><input class="jcard-field jcard-margin-input" type="number" step="0.01" min="0" data-margin-input="1" value="${trade.position_size != null && trade.leverage != null && trade.entry_price != null ? escapeHtml(String(computeMarginUsd(trade.position_size, trade.leverage, trade.entry_price))) : ''}" placeholder="0.00"/></div>
        <div><span>Levier</span><input class="jcard-field" type="number" step="1" min="1" data-field="leverage" value="${trade.leverage != null ? escapeHtml(String(trade.leverage)) : ''}" placeholder="1x"/></div>
        <div><span>Position</span><input class="jcard-field" type="number" step="0.01" data-field="position_size" value="${trade.position_size != null ? escapeHtml(String(trade.position_size)) : ''}" placeholder="&mdash;"/></div>
        <div><span>Qualite</span><div class="jcard-stars" data-field="execution_quality" data-value="${qualityRaw}">${starsHtml}</div></div>
      </div>
      <h5>Contexte</h5>
      <div class="journal-trade-back-note"><span>HTF / plan</span><p>${escapeHtml(htf)}</p></div>
      <div class="journal-trade-back-note"><span>Review</span><textarea class="jcard-field jcard-textarea" data-field="lessons_learned" rows="3" placeholder="Lecons apprises&hellip;">${escapeHtml(lessonsRaw)}</textarea></div>
    </div>
  </div>`;
}

function journalTradeFlipCardHtml(day, trade, idx, deck) {
  var m           = deriveTradeMetrics(trade);
  var pnl         = Number(m.pnl || 0);
  var pnlClass    = pnl > 0 ? "pos" : pnl < 0 ? "neg" : "flat";
  var resultClass = m.isWin === 1 ? "win" : m.isWin === 0 ? "loss" : "neutral";
  var resultLabel = m.isWin === 1 ? "WIN" : m.isWin === 0 ? "LOSS" : "-";
  var direction   = (m.direction || trade.direction || "-").toUpperCase();
  var strategy    = trade.strategy ? prettify(trade.strategy) : "Strategie inconnue";
  var rr          = m.rr == null ? "-" : Number(m.rr).toFixed(2) + "R";
  var summary     = journalShortText(trade.why_trade, trade.scenario, trade.why_entry);
  var lessonsRaw  = String(trade.lessons_learned || "");
  var qualityRaw  = Number(trade.execution_quality) || 0;
  var dateLabel   = prettyDateKey((deck && deck.dateKey) || day.date);
  var htf         = journalShortText(day.htf_context, day.daily_notes, trade.scenario);
  var shot        = (trade.screenshots || [])[0];
  var shotStyle   = shot ? " style=\"background-image:url('/screenshots/" + escapeHtml(shot.filename) + "')\"" : "";
  var shotClass   = shot ? "has-shot" : "is-empty";
  var tid         = escapeHtml(String(trade.id));

  var starsHtml = [1, 2, 3, 4, 5].map(function (i) {
    return '<button type="button" class="jcard-star' + (qualityRaw >= i ? ' is-lit' : '') + '" data-val="' + i + '">★</button>';
  }).join('');

  return '<article class="journal-flip-card" tabindex="0" data-trade-id="' + tid + '">' +
    '<div class="journal-flip-card-inner">' +
    _flipCardFrontInner(day, trade, m, pnl, pnlClass, resultClass, resultLabel, direction, strategy, rr, summary, shot, shotStyle, shotClass, tid, idx) +
    _flipCardBackInner(day, trade, m, pnl, pnlClass, resultClass, resultLabel, direction, strategy, rr, summary, shot, shotStyle, shotClass, tid, idx, dateLabel, htf, starsHtml, qualityRaw, lessonsRaw) +
    '</div></article>';
}
// ---------- Favoris toggle ----------
function _toggleTradeFavorite(tid, btnEl) {
  var trade = _journalDayTradeCache[String(tid)];
  if (!trade) return;
  var tags = Array.isArray(trade.tags) ? trade.tags.slice() : [];
  var idx = tags.indexOf('favoris');
  var isFav = idx !== -1;
  if (isFav) { tags.splice(idx, 1); } else { tags.push('favoris'); }

  btnEl.classList.toggle('is-active', !isFav);
  btnEl.setAttribute('aria-pressed', String(!isFav));
  var svg = btnEl.querySelector('svg');
  if (svg) svg.setAttribute('fill', !isFav ? 'currentColor' : 'none');

  api('/api/trades/' + tid, {
    method: 'PUT',
    body: JSON.stringify({ tags: tags })
  }).then(function(updated) {
    _journalDayTradeCache[String(tid)] = updated;
    _journalSyncStateAfterSave(tid, updated);
    toast(isFav ? 'Retire des favoris' : 'Ajoute aux favoris', 'success');
    // Rafraichir le widget Favoris Carousel si la page Today est visible
    if (typeof window.refreshFavCarousel === 'function') {
      window.refreshFavCarousel();
    }
  }).catch(function() {
    // Rollback visuel
    btnEl.classList.toggle('is-active', isFav);
    btnEl.setAttribute('aria-pressed', String(isFav));
    if (svg) svg.setAttribute('fill', isFav ? 'currentColor' : 'none');
    toast('Erreur mise a jour favoris', 'error');
  });
}

// ---------- Duplicate trade ----------
function _duplicateTrade(tid) {
  var trade = _journalDayTradeCache[String(tid)];
  if (!trade) return;

  // Find the day for this trade
  var day = _journalDayTradeDays[String(tid)];
  if (!day) return;

  var tags = Array.isArray(trade.tags) ? trade.tags.slice() : [];
  if (!tags.includes('copie')) tags.push('copie');

  var payload = {
    strategy: trade.strategy,
    direction: trade.direction,
    entry_price: trade.entry_price,
    stop_loss: trade.stop_loss,
    take_profit: trade.take_profit,
    position_size: trade.position_size,
    leverage: trade.leverage,
    session: trade.session,
    tags: tags,
    why_trade: trade.why_trade,
    scenario: trade.scenario
  };

  api('/api/days/' + day.id + '/trades', {
    method: 'POST',
    body: JSON.stringify(payload)
  }).then(function() {
    _journalRefreshStateDebounced();
    toast('Trade duplique', 'success');
  }).catch(function(err) {
    toast(err && err.message ? err.message : 'Erreur duplication', 'error');
  });
}

// ---- 057_debug_labels.js ----
// ---- 057_debug_labels.js ----
// Affiche des labels sur chaque composant avec data-name.
// Activer: localStorage.DEBUG_LABELS = "1" puis reload.
// Desactiver: localStorage.removeItem("DEBUG_LABELS") puis reload.

if (localStorage.DEBUG_LABELS === "1") {
document.addEventListener("DOMContentLoaded", function () {
  var labels = document.querySelectorAll("[data-name]");
  labels.forEach(function (el) {
    var name = el.getAttribute("data-name");
    if (!name) return;
    var badge = document.createElement("span");
    badge.textContent = name;
    badge.style.cssText =
      "position:fixed;bottom:10px;right:10px;z-index:999999;" +
      "padding:3px 9px;border-radius:6px;" +
      "background:rgba(0,0,0,0.50);color:rgba(255,255,255,0.55);" +
      "font-family:'JetBrains Mono',monospace;font-size:9px;" +
      "letter-spacing:0.04em;pointer-events:none;" +
      "opacity:0;transition:opacity 0.2s ease;";
    badge.className = "hermes-debug-label";
    el.appendChild(badge);
    el.addEventListener("mouseenter", function () { badge.style.opacity = "1"; });
    el.addEventListener("mouseleave", function () { badge.style.opacity = "0"; });
  });
});
}

// ---- 058_trade_hero_card.js ----
// ---------- TradeHeroCard — reusable primitive ----------
// Two variants:
//   'flip-front' → journal card front face (light Apple, compact)
//   'card'       → modal trade list (dark theme, full details)
// Returns a DIV (not article) — caller wraps in appropriate container.

function tradeHeroCardHtml(trade, options) {
  options = options || {};
  var variant = options.variant || 'card';
  var day     = options.day || {};
  var idx     = options.index || 1;
  var extraHtml = options.extraHtml || '';
  var extraClasses = options.extraClasses || '';

  var m           = deriveTradeMetrics(trade);
  var pnl         = Number(m.pnl || 0);
  var pnlClass    = pnl > 0 ? 'pos' : pnl < 0 ? 'neg' : 'flat';
  var resultClass = m.isWin === 1 ? 'win' : m.isWin === 0 ? 'loss' : 'neutral';
  var resultLabel = m.isWin === 1 ? 'WIN' : m.isWin === 0 ? 'LOSS' : '\u2014';
  var direction   = (m.direction || trade.direction || '-').toUpperCase();
  var strategy    = trade.strategy ? prettify(trade.strategy) : 'Strategie inconnue';
  var rr          = m.rr == null ? '-' : Number(m.rr).toFixed(2) + 'R';
  var summary     = options.summary || journalShortText(trade.why_trade, trade.scenario, trade.why_entry);
  var tid         = escapeHtml(String(trade.id));
  var instr       = options.showInstrument !== false ? escapeHtml(day.instrument || '-') : '';
  var dateLabel   = options.dateLabel || (day.date ? prettyDateKey(day.date) : '');

  // Screenshot
  var shot     = (trade.screenshots || [])[0];
  var shotUrl  = shot ? '/screenshots/' + escapeHtml(shot.filename) : null;
  var shotStyle = shotUrl ? ' style="background-image:url(\'' + shotUrl + '\')"' : '';
  var hasShot   = !!shotUrl;

  // Helper: fmt price
  function _price(v) {
    return v != null && v !== '' ? Number(v).toFixed(2) : '\u2014';
  }

  // ── TOPBAR ──
  var topbarPill = function (text, cls) {
    return '<span class="metric-pill' + (cls ? ' ' + cls : '') + '">' + escapeHtml(text) + '</span>';
  };

  var topbar = '';
  if (variant === 'flip-front') {
    var pnlPillClass = pnlClass === 'pos' ? 'metric-pill--win' : pnlClass === 'neg' ? 'metric-pill--loss' : 'metric-pill--muted';
    var resPillClass = resultClass === 'win' ? 'metric-pill--win' : resultClass === 'loss' ? 'metric-pill--loss' : 'metric-pill--muted';
    topbar =
      '<div class="thc-topbar">' +
        topbarPill('#' + idx, 'metric-pill--muted journal-trade-index') +
        topbarPill(instr, 'metric-pill--cyan journal-trade-instrument') +
        topbarPill(fmtMoney(pnl), pnlPillClass + ' journal-trade-top-pnl ' + pnlClass) +
        topbarPill(resultLabel, resPillClass + ' journal-trade-result ' + resultClass) +
        '<button type="button" class="thc-close journal-card-close" data-journal-day-close aria-label="Fermer">' +
          '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" width="13" height="13"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>' +
        '</button>' +
      '</div>';
  } else if (variant === 'card') {
    topbar =
      '<div class="thc-topbar">' +
        '<div style="display:flex;align-items:center;gap:8px">' +
          topbarPill('#' + idx, 'trade-chip trade-chip-num') +
          topbarPill(instr, 'metric-pill--cyan') +
          '<span class="thc-strategy-name" style="font-size:13px;color:var(--text-soft,#c8ccdb);font-weight:700">' + escapeHtml(strategy) + '</span>' +
        '</div>' +
      '</div>';
  }

  // ── MEDIA ──
  var media = '';
  if (variant === 'flip-front' || variant === 'card') {
    if (hasShot) {
      media = '<div class="thc-media">' +
        '<div class="thc-shot"' + shotStyle + '></div>' +
        (variant === 'card' ? '<div class="trade-card-media-overlay"></div>' : '') +
      '</div>';
    } else {
      var emptyLabel = variant === 'flip-front'
        ? '<span>Aucune capture</span>'
        : '<span>Aucune capture</span><strong>' + escapeHtml(pnl > 0 ? 'Moteur propre' : pnl < 0 ? 'Point a corriger' : 'Setup neutre') + '</strong>';
      media = '<div class="thc-media is-empty">' +
        '<div class="thc-shot-empty">' + emptyLabel + '</div>' +
      '</div>';
    }
  }

  // ── BODY ──
  var dirPillClass = direction === 'LONG' ? 'long' : direction === 'SHORT' ? 'short' : '';
  var resPillClass = resultClass === 'win' ? 'win' : resultClass === 'loss' ? 'loss' : 'neutral';

  var stripHtml =
    '<div class="thc-strip">' +
      '<span class="metric-pill thc-direction' + (dirPillClass ? ' ' + dirPillClass : '') + '">' + escapeHtml(direction || '-') + '</span>' +
      '<span class="metric-pill">' + escapeHtml(rr) + '</span>' +
      '<span class="metric-pill metric-pill--' + resPillClass + '">' + escapeHtml(resultLabel) + '</span>' +
    '</div>';

  var body = '';
  if (variant === 'flip-front') {
    body =
      '<div class="thc-body">' +
        '<div style="display:flex;align-items:flex-start;justify-content:space-between;gap:16px;padding-bottom:14px">' +
          '<div style="flex:1">' +
            '<h4 class="thc-strategy-name">' + escapeHtml(strategy) + '</h4>' +
            '<p class="thc-summary">' + escapeHtml(summary) + '</p>' +
          '</div>' +
          '<div class="thc-pnl-large" style="flex-shrink:0">' +
            '<strong class="' + pnlClass + '">' + fmtMoney(pnl) + '</strong>' +
          '</div>' +
        '</div>' +
        stripHtml +
        '<div class="journal-trade-card-actions">' +
          '<span>' + escapeHtml(resultLabel) + '</span>' +
          '<button type="button">Voir details</button>' +
        '</div>' +
      '</div>';
  } else if (variant === 'card') {
    var thesisLabel = trade.thesis_validated === 'yes' ? 'These validee' : trade.thesis_validated === 'no' ? 'These rejetee' : 'These a qualifier';
    body =
      '<div class="thc-body">' +
        '<div style="display:flex;align-items:center;justify-content:space-between;gap:10px">' +
          '<div class="thc-strategy-name">' + escapeHtml(thesisLabel) + '</div>' +
          '<div class="thc-pnl ' + pnlClass + '">' + fmtMoney(pnl) + '</div>' +
        '</div>' +
        stripHtml +
        '<div class="thc-grid">' +
          _thcField('Entree', _price(trade.entry_price)) +
          _thcField('Sortie', _price(trade.exit_price)) +
          _thcField('Stop', _price(trade.stop_loss)) +
          _thcField('Target', _price(trade.take_profit)) +
        '</div>' +
        '<div class="thc-footer">' +
          '<span class="trade-meta-pill">Exec ' + (trade.execution_quality ? trade.execution_quality + '/5' : '-') + '</span>' +
          '<span class="trade-meta-pill">Pos ' + (trade.position_size != null ? Number(trade.position_size) + 'u' : '-') + '</span>' +
          '<span class="trade-edit-hint" style="margin-left:auto;font-size:10px;color:var(--cyan,#00E5FF);letter-spacing:0.45px;text-transform:uppercase;opacity:0.86">Cliquer pour editer</span>' +
        '</div>' +
        (summary ? '<div class="thc-footer-note">' + escapeHtml(summary) + '</div>' : '') +
      '</div>';
  }

  // ── ASSEMBLE — returns a DIV with variant class ──
  return '<div class="trade-hero-card thc--' + variant + ' ' + extraClasses + '"' +
    (variant === 'card' ? ' data-tid="' + tid + '"' : '') +
    '>' +
    topbar + media + body + extraHtml +
    '</div>';
}

// ── Internal helper ──

function _thcField(label, value) {
  return '<div class="thc-field">' +
    '<span class="thc-field-label">' + escapeHtml(label) + '</span>' +
    '<strong class="thc-field-value">' + value + '</strong>' +
  '</div>';
}

// ---- 059_trade_editor_controller.js ----
// ---------- TradeEditorController — inline trade editor ----------
// Responsabilités:
//   - Ouvrir/fermer l'éditeur (drawer latéral)
//   - Collecter le payload du formulaire
//   - Sauvegarder via API (direct ou debounced)
//   - Recalculer les métriques (PnL, RR, is_win) avant save
//   - Afficher les warnings de validation
//   - Gérer le statut save (sauvegarde/sauvé/erreur)
//   - Rafraîchir l'UI après save
//
// Dépend de: deriveTradeMetrics(), journalShortText(), api(), fmtMoney(), escapeHtml(), prettify(), prettyDateKey(), computeMarginUsd(), computePositionSize()

var TradeEditorController = {};

// ---- State ----
TradeEditorController.activeTradeId = null;
TradeEditorController.saveTimers = {};
TradeEditorController.closeTime = 0;
TradeEditorController.justClosed = false;

// ---- Status management ----
TradeEditorController.setStatus = function (editor, state, text) {
  var saveBtn = editor && editor.querySelector('.jedit-save');
  if (!saveBtn) return;
  if (state === 'saving') {
    saveBtn.textContent = text || 'Sauvegarde...';
  } else if (state === 'saved') {
    saveBtn.textContent = text || 'Sauvegarde';
    setTimeout(function () { if (document.body.contains(saveBtn)) saveBtn.textContent = 'Sauver'; }, 2200);
  } else {
    saveBtn.textContent = 'Sauver';
  }
};

// ---- Payload collection ----
TradeEditorController.collectPayload = function (tid) {
  var tidStr = String(tid);
  var editor = document.querySelector('.journal-trade-editor[data-trade-id="' + tidStr + '"]');
  var trade  = _journalDayTradeCache[tidStr];
  if (!editor || !trade) return null;

  var patch = {};

  editor.querySelectorAll('.jedit-field').forEach(function (el) {
    var field = el.dataset.field;
    if (!field) return;
    var val = el.value;
    if (el.dataset.type === 'number') {
      patch[field] = val === '' ? null : Number(val);
    } else if (el.dataset.type === 'int') {
      patch[field] = val === '' ? null : Number(val);
    } else if (el.dataset.type === 'bool') {
      patch[field] = val === '' ? null : val;
    } else if (el.dataset.type === 'tags') {
      patch[field] = String(val || '')
        .split(',')
        .map(function (tag) { return tag.trim(); })
        .filter(Boolean);
    } else {
      patch[field] = val === '' ? null : val;
    }
  });

  editor.querySelectorAll('.jedit-pills').forEach(function (group) {
    var field = group.dataset.field;
    var active = group.querySelector('.jedit-pill.is-active');
    if (field) patch[field] = active ? active.dataset.value : '';
  });

  editor.querySelectorAll('.jedit-stars').forEach(function (group) {
    var field = group.dataset.field;
    if (field) {
      var starVal = group.dataset.value;
      if (starVal && starVal !== '0') patch[field] = starVal;
    }
  });

  return Object.assign({}, trade, patch);
};

// ---- Metrics recalculation before save ----
TradeEditorController.recalcMetrics = function (collected, originalTrade) {
  var entry  = collected.entry_price != null ? Number(collected.entry_price) : null;
  var exit_  = collected.exit_price != null ? Number(collected.exit_price) : null;
  var stop   = collected.stop_loss != null ? Number(collected.stop_loss) : null;
  var target = collected.take_profit != null ? Number(collected.take_profit) : null;
  var qtyRaw = collected.position_size != null ? Number(collected.position_size) : null;
  var qty    = qtyRaw && qtyRaw > 0 ? qtyRaw : 1;
  var dir    = (collected.direction || '').toLowerCase();
  if (!dir && entry != null && stop != null && stop !== entry) {
    dir = stop < entry ? 'long' : 'short';
  }

  // Recalc RR if entry + stop + target available
  if (entry != null && stop != null && target != null && stop !== entry) {
    collected.rr = Number((Math.abs(target - entry) / Math.abs(entry - stop)).toFixed(4));
  }

  // Recalc PnL from exit if user didn't explicitly change pnl
  var pnlExplicit = collected.hasOwnProperty('pnl') && collected.pnl !== (originalTrade && originalTrade.pnl);
  if (!pnlExplicit && dir && entry != null && exit_ != null) {
    collected.pnl = dir === 'long' ? (exit_ - entry) * qty : (entry - exit_) * qty;
  }

  // Infer is_win from pnl
  if (collected.is_win == null || collected.is_win === '') {
    var pnlNum = collected.pnl != null ? Number(collected.pnl) : null;
    if (pnlNum != null) {
      collected.is_win = pnlNum > 0 ? '1' : pnlNum < 0 ? '0' : '';
    }
  }
};

TradeEditorController.recalcLive = function (editor) {
  var tid = editor.dataset.tradeId;
  var trade = _journalDayTradeCache[String(tid)];
  if (!trade) return;

  var entryEl = editor.querySelector('.jedit-field[data-field="entry_price"]');
  var tpEl    = editor.querySelector('.jedit-field[data-field="take_profit"]');
  var slEl    = editor.querySelector('.jedit-field[data-field="stop_loss"]');
  var exitEl  = editor.querySelector('.jedit-field[data-field="exit_price"]');
  var qtyEl   = editor.querySelector('.jedit-field[data-field="position_size"]');
  var levEl   = editor.querySelector('.jedit-field[data-field="leverage"]');

  var tempTrade = Object.assign({}, trade, {
    entry_price: entryEl ? entryEl.value : null,
    take_profit: tpEl ? tpEl.value : null,
    stop_loss: slEl ? slEl.value : null,
    exit_price: exitEl ? exitEl.value : null,
    position_size: qtyEl ? qtyEl.value : null,
    leverage: levEl ? levEl.value : null
  });

  var m = deriveTradeMetrics(tempTrade);
  var pnl = Number(m.pnl || 0);
  var pnlClass = pnl > 0 ? "pos" : pnl < 0 ? "neg" : "flat";
  var resultClass = m.isWin === 1 ? "win" : m.isWin === 0 ? "loss" : "neutral";
  var resultLabel = m.isWin === 1 ? "WIN" : m.isWin === 0 ? "LOSS" : "-";
  var rrTxt = m.rr == null ? "-" : Number(m.rr).toFixed(2) + "R";
  var pnlTxt = fmtMoney(pnl);

  // 1. Mettre a jour l'en-tete (jedit-metrics)
  var headPnl = editor.querySelector('.jedit-metric-pnl strong');
  if (headPnl) {
    headPnl.textContent = pnlTxt;
    headPnl.className = pnlClass;
  }
  var headRr = editor.querySelector('.jedit-metric-rr strong');
  if (headRr) {
    headRr.textContent = rrTxt;
  }
  var headRes = editor.querySelector('.jedit-metric-result strong');
  if (headRes) {
    headRes.textContent = resultLabel;
    headRes.className = resultClass;
  }

  // 2. Mettre a jour les champs d'inputs de la grille (PnL et RR)
  var inputPnl = editor.querySelector('.jedit-field[data-field="pnl"]');
  if (inputPnl) {
    inputPnl.value = m.pnl != null ? Number(m.pnl).toFixed(2) : "";
  }
  var inputRr = editor.querySelector('.jedit-field[data-field="rr"]');
  if (inputRr) {
    inputRr.value = m.rr != null ? Number(m.rr).toFixed(2) : "";
  }

  // 3. Mettre a jour le badge R:R visuel
  var badgeEl = editor.querySelector('.jcard-rr-visual-badge');
  if (badgeEl) {
    if (m.rr == null) {
      badgeEl.textContent = 'Niveaux incomplets';
      badgeEl.className = 'jcard-rr-visual-badge rr-neutral';
    } else {
      var rrVal = Number(m.rr);
      badgeEl.textContent = rrVal.toFixed(2) + ' R:R';
      if (rrVal < 1.0) {
        badgeEl.className = 'jcard-rr-visual-badge rr-low';
      } else if (rrVal < 2.0) {
        badgeEl.className = 'jcard-rr-visual-badge rr-medium';
      } else {
        badgeEl.className = 'jcard-rr-visual-badge rr-high';
      }
    }
  }
};


// ---- UI refresh after save ----
TradeEditorController.refreshUI = function (editor, trade) {
  if (!editor || !trade) return;

  // Update direction badge in topline
  var topline = editor.querySelector('.jedit-topline');
  if (topline) {
    var badges = topline.querySelectorAll('span');
    var dir = (trade.direction || '-').toUpperCase();
    if (badges.length >= 3) badges[2].textContent = dir;
  }

  // Le résumé (p) n'est plus refresh ici — le textarea contient déjà la donnée correcte.
  // L'ancienne version pouvait faire clignoter un texte d'un autre champ.
};

// ---- Inline warnings ----
TradeEditorController._warningSection = function (error) {
  var e = error.toLowerCase();
  if (e.indexOf('stop') >= 0 || e.indexOf('tp') >= 0 || e.indexOf("prix d'entree") >= 0) return 1; // Niveaux
  if (e.indexOf('pnl') >= 0) return 1;
  if (e.indexOf('these') >= 0 || e.indexOf('execution') >= 0 || e.indexOf('lecon') >= 0) return 3; // Review
  if (e.indexOf('plan') >= 0 || e.indexOf('override') >= 0) return 4; // Plan
  return 0;
};

TradeEditorController.showWarnings = function (editor, errorMsg) {
  TradeEditorController.clearWarnings(editor);
  if (!errorMsg) return;

  var errors = errorMsg.split('; ');
  errors.forEach(function (err) {
    err = err.trim();
    if (!err) return;
    var sectionIdx = TradeEditorController._warningSection(err);
    if (sectionIdx < 0) return;

    var sections = editor.querySelectorAll('.jedit-block');
    var target   = sections[sectionIdx];
    if (!target) return;

    var warn = document.createElement('div');
    warn.className = 'jedit-block-msg';
    warn.textContent = err;
    var title = target.querySelector('.jedit-block-title');
    if (title) title.parentNode.insertBefore(warn, title.nextSibling);
  });
};

TradeEditorController.clearWarnings = function (editor) {
  if (!editor) return;
  editor.querySelectorAll('.jedit-block-msg').forEach(function (el) { el.remove(); });
};

// ---- Field glow — feedback visuel par champ ---- //

// Mapping champ → section (utilisé par _changedFields pour filtrer les champs metier)
TradeEditorController._fieldToSection = {
  strategy: 0, direction: 0, stdv_level: 0, is_win: 0,
  entry_price: 1, stop_loss: 1, take_profit: 1, exit_price: 1,
  position_size: 1, leverage: 1, pnl: 1, rr: 1,
  why_trade: 2, why_entry: 2, scenario: 2, why_stop: 2, why_tp: 2,
  thesis_validated: 3, execution_quality: 3, tags: 3, lessons_learned: 3,
  plan_model: 4, plan_direction: 4, plan_alignment: 4, plan_score: 4,
  plan_errors: 4, plan_warnings: 4, plan_override_reason: 4, plan_snapshot: 4,
};

TradeEditorController._changedFields = function (payload, original) {
  var fields = {};
  if (!original) return fields;
  Object.keys(payload).forEach(function (key) {
    if (TradeEditorController._fieldToSection[key] === undefined) return;
    // Ignorer les champs qui seront recalculés par recalcMetrics
    // (leur diff est artifact du calcul, pas une modif volontaire)
    if (key === 'rr' || key === 'pnl' || key === 'is_win') return;
    if (String(payload[key] ?? '').trim() !== String(original[key] ?? '').trim()) {
      fields[key] = true;
    }
  });
  return fields;
};

TradeEditorController._findFieldEl = function (editor, fieldName) {
  if (!editor) return null;
  // Chercher l'élément du champ directement (input, textarea, select, pills, stars)
  return editor.querySelector(
    'input[data-field="' + fieldName + '"], ' +
    'textarea[data-field="' + fieldName + '"], ' +
    'select[data-field="' + fieldName + '"], ' +
    '.jedit-pills[data-field="' + fieldName + '"], ' +
    '.jedit-stars[data-field="' + fieldName + '"]'
  ) || null;
};

TradeEditorController._glowFields = function (editor, fields, type) {
  if (!editor) return;
  // Nettoyer les glows précédents du même type
  editor.querySelectorAll('.jedit-field-glow, .jedit-field-error').forEach(function (el) {
    el.classList.remove('jedit-field-glow', 'jedit-field-error');
  });
  if (type === '') return;
  Object.keys(fields).forEach(function (fieldName) {
    var wrap = TradeEditorController._findFieldEl(editor, fieldName);
    if (!wrap) return;
    if (type === 'success') {
      wrap.classList.add('jedit-field-glow');
    } else if (type === 'error') {
      wrap.classList.add('jedit-field-error');
    }
  });
};

// ---- Save ----
TradeEditorController.save = function (tid) {
  var tidStr  = String(tid);
  // Nettoyer tout timer en attente pour éviter une double sauvegarde
  clearTimeout(TradeEditorController.saveTimers[tidStr]);
  
  var original = _journalDayTradeCache[tidStr];
  var payload  = TradeEditorController.collectPayload(tidStr);
  var editor   = document.querySelector('.journal-trade-editor[data-trade-id="' + tidStr + '"]');
  if (!payload || !editor) return;

  // Détecter les champs modifiés
  var changedFields = TradeEditorController._changedFields(payload, original);

  TradeEditorController.recalcMetrics(payload, original);

  // Nettoyer les glows précédents
  TradeEditorController._glowFields(editor, {}, '');
  TradeEditorController.setStatus(editor, 'saving', 'Sauvegarde...');

  api('/api/trades/' + tidStr, { method: 'PUT', body: JSON.stringify(payload) })
    .then(function (res) {
      var updated = (res && res.trade) ? res.trade : res;
      updated = updated && updated.id ? updated : payload;
      _journalDayTradeCache[tidStr] = updated;
      _journalCardRefreshMetrics(tidStr, updated);
      TradeEditorController.refreshUI(editor, updated);
      _journalSyncStateAfterSave(tidStr, updated);
      TradeEditorController.clearWarnings(editor);
      TradeEditorController._glowFields(editor, changedFields, 'success');
      TradeEditorController.setStatus(editor, 'saved', 'Sauvegarde');
      // Retirer le glow après 1s
      setTimeout(function () {
        TradeEditorController._glowFields(editor, changedFields, '');
      }, 1000);
    })
    .catch(function (err) {
      TradeEditorController.showWarnings(editor, (err && err.message) ? err.message : null);
      TradeEditorController._glowFields(editor, changedFields, 'error');
    });
};

TradeEditorController.scheduleSave = function (tid) {
  // Sauvegarde immédiate à la sortie du champ, pas de debounce
  TradeEditorController.save(tid);
};

TradeEditorController.flushPending = function () {
  var timers = TradeEditorController.saveTimers;
  Object.keys(timers).forEach(function (tid) {
    clearTimeout(timers[tid]);
    TradeEditorController.save(tid);
  });
  TradeEditorController.saveTimers = {};
};

// ---- Open / Close ----
TradeEditorController.open = function (tid) {
  var tidStr = String(tid);
  var wrap   = $('#journalDayTrades');
  var trade  = _journalDayTradeCache[tidStr];
  var day    = _journalDayTradeDays[tidStr];
  if (!wrap || !trade || !day) return;

  // Repérer la card source
  var sourceCard = wrap.querySelector('.journal-flip-card[data-trade-id="' + tidStr + '"]');

  TradeEditorController.close({ immediate: true });
  TradeEditorController.activeTradeId = tidStr;
  wrap.classList.add('is-editing');
  wrap.classList.add('is-focusing');
  document.documentElement.classList.add('html-editor-open');
  document.documentElement.classList.add('journal-no-flip');

  // Card source monte, les autres s'atténuent (CSS transitions)
  if (sourceCard) sourceCard.classList.add('is-source');

  // Insérer l'éditeur immédiatement
  wrap.insertAdjacentHTML('beforeend', TradeEditorController.renderHtml(day, trade));

  var editor = wrap.querySelector('.journal-trade-editor[data-trade-id="' + tidStr + '"]');
  if (!editor) return;

  // Double RAF : laisser le navigateur peindre l'état initial (opacity:0)
  // avant de déclencher la transition vers l'état final (opacity:1)
  requestAnimationFrame(function () {
    requestAnimationFrame(function () {
      editor.classList.add('is-visible');
      var scroll = editor.querySelector('.jedit-scroll');
      if (scroll) {
        scroll.classList.add('is-revealing');
        scroll.addEventListener('scroll', function () {
          scroll.classList.toggle('is-stuck', scroll.scrollTop > 60);
        });
      }
    });
  });

  setTimeout(function () {
    var focusTarget = editor.querySelector('.jedit-field, .jedit-pill, .jedit-close');
    if (focusTarget && typeof focusTarget.focus === 'function') focusTarget.focus({ preventScroll: true });
  }, 220);
};

TradeEditorController.close = function (opts) {
  var wrap    = $('#journalDayTrades');
  var editor  = wrap && wrap.querySelector('.journal-trade-editor');
  if (!wrap || !editor) return;

  var closingTid = TradeEditorController.activeTradeId;
  TradeEditorController.flushPending();
  TradeEditorController.justClosed = true;
  TradeEditorController.closeTime = Date.now();

  // 🛡️ Mettre à jour les infos de la card SANS remplacer le DOM
  // pour éviter le glitch visuel
  if (closingTid && !(opts && opts.immediate)) {
    _journalCardRefreshMetrics(closingTid, _journalDayTradeCache[String(closingTid)]);
    // Mettre à jour le nom de la stratégie et le résumé sur la face avant
    var card = document.querySelector('.journal-flip-card[data-trade-id="' + String(closingTid) + '"]');
    var trade = _journalDayTradeCache[String(closingTid)];
    if (card && trade) {
      var h4 = card.querySelector('.journal-trade-main h4');
      if (h4) h4.textContent = escapeHtml(trade.strategy ? prettify(trade.strategy) : 'Strategie inconnue');
      var summary = card.querySelector('.journal-trade-main p');
      if (summary) summary.textContent = escapeHtml(TradeEditorController.shortText(trade.why_trade, trade.scenario, trade.why_entry));
    }
  }

  // 🔥 Unfocus : animation inverse
  wrap.classList.add('is-unfocusing');
  wrap.classList.remove('is-focusing');

  // Retirer is-source tout de suite pour que la card
  // suive la transition de retour normalement
  var sourceCard = wrap.querySelector('.journal-flip-card.is-source');
  if (sourceCard) sourceCard.classList.remove('is-source');

  if (opts && opts.immediate) {
    wrap.classList.remove('is-editing');
    wrap.classList.remove('is-unfocusing');
    document.documentElement.classList.remove('html-editor-open');
    document.documentElement.classList.remove('journal-no-flip');
    TradeEditorController.activeTradeId = null;
    editor.remove();
    setTimeout(function () { TradeEditorController.justClosed = false; }, 250);
    return;
  }

  editor.classList.remove('is-visible');
  wrap.classList.remove('is-editing');
  document.documentElement.classList.remove('journal-no-flip');

  // Attendre la fin de l'animation unfocus puis nettoyer
  setTimeout(function () {
    TradeEditorController.activeTradeId = null;
    document.documentElement.classList.remove('html-editor-open');
    wrap.classList.remove('is-unfocusing');
    if (editor.parentNode) editor.remove();
  }, 420);
  setTimeout(function () { TradeEditorController.justClosed = false; }, 500);
};

// ---- Editor HTML helpers ----
TradeEditorController.selectOption = function (value, label, current) {
  return '<option value="' + escapeHtml(value) + '"' + (String(current || '') === String(value) ? ' selected' : '') + '>' + escapeHtml(label) + '</option>';
};



TradeEditorController.sessionOptions = function (current) {
  var sessions = [
    { value: '', label: 'Choisir' },
    { value: 'asia', label: 'Asia' },
    { value: 'london', label: 'London' },
    { value: 'ny_am', label: 'NY AM' },
    { value: 'ny_pm', label: 'NY PM' },
  ];
  return sessions.map(function (s) {
    var sel = String(current) === s.value ? ' selected' : '';
    return '<option value="' + s.value + '"' + sel + '>' + s.label + '</option>';
  }).join('');
};
TradeEditorController.field = function (label, field, value, type, opts) {
  var o = opts || {};
  var inputType = type === 'number' || type === 'int' ? 'number' : 'text';
  var step      = o.step ? ' step="' + escapeHtml(o.step) + '"' : '';
  var placeholder = o.placeholder ? ' placeholder="' + escapeHtml(o.placeholder) + '"' : '';
  var dataType = type ? ' data-type="' + escapeHtml(type) + '"' : '';
  return '<label class="jedit-field-wrap"><span>' + escapeHtml(label) + '</span><input class="jedit-field" type="' + inputType + '"' + step + dataType + ' data-field="' + escapeHtml(field) + '" value="' + TradeEditorController.valueAttr(value) + '"' + placeholder + ' /></label>';
};

TradeEditorController.textarea = function (label, field, value, rows) {
  return '<label class="jedit-field-wrap jedit-text-wrap"><span>' + escapeHtml(label) + '</span><textarea class="jedit-field" data-field="' + escapeHtml(field) + '" rows="' + (rows || 3) + '">' + escapeHtml(String(value || '')) + '</textarea></label>';
};

TradeEditorController.pills = function (field, current, choices) {
  return '<div class="jedit-pills" data-field="' + escapeHtml(field) + '">' + choices.map(function (choice) {
    var active = String(current || '') === String(choice.value || '');
    return '<button type="button" class="jedit-pill' + (active ? ' is-active' : '') + '" data-value="' + escapeHtml(choice.value || '') + '">' + escapeHtml(choice.label) + '</button>';
  }).join('') + '</div>';
};

TradeEditorController.strategyOptions = function (current) {
  var values = [];
  (DEFAULT_STRATEGY_VALUES || []).forEach(function (value) { if (values.indexOf(value) === -1) values.push(value); });
  ((state && state.settings && state.settings.custom_strategies) || []).forEach(function (s) {
    if (s && s.value && values.indexOf(s.value) === -1) values.push(s.value);
  });
  if (current && values.indexOf(current) === -1) values.push(current);
  return values.map(function (value) { return TradeEditorController.selectOption(value, prettify(value), current); }).join('');
};

TradeEditorController.shortText = function () {
  for (var i = 0; i < arguments.length; i += 1) {
    var v = String(arguments[i] || '').trim();
    if (v) return v.length > 150 ? v.slice(0, 147) + '...' : v;
  }
  return 'Aucun resume renseigne pour ce trade.';
};

TradeEditorController.fmtPrice = function (v) {
  if (v == null || v === '') return '-';
  var n = Number(v);
  return Number.isFinite(n) ? n.toFixed(2) : '-';
};

TradeEditorController.valueAttr = function (v) {
  return v == null ? '' : escapeHtml(String(v));
};

TradeEditorController.tagsValue = function (tags) {
  return Array.isArray(tags) ? tags.join(', ') : '';
};

// ---- Editor HTML template ----
TradeEditorController.renderHtml = function (day, trade) {
  var m = deriveTradeMetrics(trade);
  var pnl = Number(m.pnl || 0);
  var pnlClass = pnl > 0 ? 'pos' : pnl < 0 ? 'neg' : 'flat';
  var resultClass = m.isWin === 1 ? 'win' : m.isWin === 0 ? 'loss' : 'neutral';
  var resultLabel = m.isWin === 1 ? 'WIN' : m.isWin === 0 ? 'LOSS' : '-';
  var direction   = (m.direction || trade.direction || '').toLowerCase();
  var rr    = m.rr == null ? '-' : Number(m.rr).toFixed(2) + 'R';
  var strategy = trade.strategy ? prettify(trade.strategy) : 'Strategie inconnue';
  var dateLabel = prettyDateKey(day.date);
  var shot = (trade.screenshots || [])[0];
  var shotStyle = shot ? ' style="background-image:url(\'/screenshots/' + escapeHtml(shot.filename) + '\')"' : '';
  var shotClass = shot ? 'has-shot' : 'is-empty';
  var qualityRaw = Number(trade.execution_quality) || 0;
  var tid = escapeHtml(String(trade.id));
  var winValue = trade.is_win == null ? '' : String(trade.is_win);
  var starsHtml = [1, 2, 3, 4, 5].map(function (i) {
    return '<button type="button" class="jedit-star' + (qualityRaw >= i ? ' is-lit' : '') + '" data-val="' + i + '">★</button>';
  }).join('');
  var screenshotsHtml = (trade.screenshots || []).length
    ? (trade.screenshots || []).map(function (s) {
        return '<a class="jedit-shot-thumb" href="/screenshots/' + escapeHtml(s.filename) + '" target="_blank" rel="noreferrer" style="background-image:url(&quot;/screenshots/' + escapeHtml(s.filename) + '&quot;)" aria-label="Ouvrir screenshot"></a>';
      }).join('')
    : '<div class="jedit-empty">Aucune capture pour ce trade.</div>';

  return '\n    <aside class="journal-trade-editor" data-trade-id="' + tid + '" role="dialog" aria-label="Edition du trade">\n      <div class="jedit-panel">\n        <div class="jedit-hero">\n          <div class="jedit-hero-shot ' + shotClass + '"' + shotStyle + '>' + (shot ? '' : '<span>Aucune capture</span>') + '</div>\n          <div class="jedit-hero-copy">\n            <div class="jedit-topline">\n              <span>' + escapeHtml(dateLabel) + '</span>\n              <span>' + escapeHtml(day.instrument || '-') + '</span>\n              <span>' + escapeHtml((direction || '-').toUpperCase()) + '</span>\n            </div>\n            <h3>' + escapeHtml(strategy) + '</h3>\n            <p>' + escapeHtml(TradeEditorController.shortText(trade.why_trade, trade.scenario, trade.why_entry)) + '</p>\n            <div class="jedit-metrics">\n              <div class="jedit-metric-pnl"><strong class="' + pnlClass + '">' + fmtMoney(pnl) + '</strong><span>PnL</span></div>\n              <div class="jedit-metric-rr"><strong>' + escapeHtml(rr) + '</strong><span>R multiple</span></div>\n              <div class="jedit-metric-result"><strong class="' + resultClass + '">' + escapeHtml(resultLabel) + '</strong><span>Resultat</span></div>\n            </div>\n          </div>\n          <div class="jedit-actions">\n            <span class="jedit-status" data-state=""></span>\n            <button type="button" class="jedit-save" data-journal-editor-save="' + tid + '">Sauver</button>\n            <button type="button" class="jedit-close" data-journal-editor-close aria-label="Fermer">\n              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" width="15" height="15"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>\n            </button>\n          </div>\n        </div>\n\n        <div class="jedit-scroll">\n          <div class="jedit-sticky">\n            <button type="button" class="jedit-save" data-journal-editor-save="' + tid + '">Sauver</button>\n            <button type="button" class="jedit-close" data-journal-editor-close aria-label="Fermer">\n              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round" width="15" height="15"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>\n            </button>\n          </div>\n          <section class="jedit-block jedit-identity">\n            <div class="jedit-block-title"><span>01</span><h4>Setup</h4></div>\n            <div class="jedit-grid">\n              <label class="jedit-field-wrap"><span>Strategie</span><select class="jedit-field" data-field="strategy">' + TradeEditorController.strategyOptions(trade.strategy || '') + '</select></label>\n              <label class="jedit-field-wrap"><span>Direction</span>' + TradeEditorController.pills('direction', direction, [{ value: 'long', label: 'Long' }, { value: 'short', label: 'Short' }, { value: '', label: '?' }]) + '</label>\n              <label class="jedit-field-wrap"><span>Session</span><select class="jedit-field" data-field="session">' + TradeEditorController.sessionOptions(trade.session || '') + '</select></label>\n              ' + TradeEditorController.field('Stdv', 'stdv_level', trade.stdv_level, 'number', { step: '0.5', placeholder: '1 - 5' }) + '\n              <label class="jedit-field-wrap"><span>Resultat</span><select class="jedit-field" data-field="is_win" data-type="bool">' + TradeEditorController.selectOption('', 'A qualifier', winValue) + TradeEditorController.selectOption('1', 'Win', winValue) + TradeEditorController.selectOption('0', 'Loss', winValue) + '</select></label>\n            </div>\n          </section>\n\n          <section class="jedit-block">\n            <div class="jedit-block-title"><span>02</span><h4>Niveaux</h4></div>\n            <div class="jedit-grid jedit-grid-5">\n              ' + TradeEditorController.field('Entree', 'entry_price', trade.entry_price, 'number', { step: '0.01' }) + '\n              ' + TradeEditorController.field('Stop', 'stop_loss', trade.stop_loss, 'number', { step: '0.01' }) + '\n              ' + TradeEditorController.field('TP', 'take_profit', trade.take_profit, 'number', { step: '0.01' }) + '\n              ' + TradeEditorController.field('Sortie', 'exit_price', trade.exit_price, 'number', { step: '0.01' }) + '\n              ' + TradeEditorController.field('Size', 'position_size', trade.position_size, 'number', { step: '0.01' }) + '\n              ' + TradeEditorController.field('Levier', 'leverage', trade.leverage, 'number', { step: '1', placeholder: '1x' }) + '\n              ' + TradeEditorController.field('PnL', 'pnl', trade.pnl, 'number', { step: '0.01' }) + '\n              ' + TradeEditorController.field('RR', 'rr', trade.rr, 'number', { step: '0.01' }) + '\n            </div>\n            <div class="jcard-rr-visual-container">\n              <div class="jcard-rr-visual-badge ' + (m.rr != null ? (m.rr < 1.0 ? 'rr-low' : m.rr < 2.0 ? 'rr-medium' : 'rr-high') : 'rr-neutral') + '">\n                ' + (m.rr != null ? Number(m.rr).toFixed(2) + ' R:R' : 'Niveaux incomplets') + '\n              </div>\n            </div>\n          </section>\n\n          <section class="jedit-block">\n            <div class="jedit-block-title"><span>03</span><h4>Scenario</h4></div>\n            <div class="jedit-notes">\n              ' + TradeEditorController.textarea('Pourquoi ce trade', 'why_trade', trade.why_trade, 3) + '\n              ' + TradeEditorController.textarea('Pourquoi cette entree', 'why_entry', trade.why_entry, 3) + '\n              ' + TradeEditorController.textarea('Scenario complet', 'scenario', trade.scenario, 4) + '\n              ' + TradeEditorController.textarea('Pourquoi ce stop', 'why_stop', trade.why_stop, 3) + '\n              ' + TradeEditorController.textarea('Pourquoi ce TP', 'why_tp', trade.why_tp, 3) + '\n            </div>\n          </section>\n\n          <section class="jedit-block">\n            <div class="jedit-block-title"><span>04</span><h4>Review</h4></div>\n            <div class="jedit-grid">\n              <label class="jedit-field-wrap"><span>These validee</span>' + TradeEditorController.pills('thesis_validated', trade.thesis_validated || '', [{ value: 'yes', label: 'Oui' }, { value: 'no', label: 'Non' }, { value: '', label: '?' }]) + '</label>\n              <label class="jedit-field-wrap"><span>Qualite execution</span><div class="jedit-stars" data-field="execution_quality" data-value="' + qualityRaw + '">' + starsHtml + '</div></label>\n              ' + TradeEditorController.field('Tags', 'tags', TradeEditorController.tagsValue(trade.tags), 'tags', { placeholder: 'tag1, tag2' }) + '\n              ' + TradeEditorController.textarea('Lecons apprises', 'lessons_learned', trade.lessons_learned, 4) + '\n            </div>\n          </section>\n\n          <section class="jedit-block">\n            <div class="jedit-block-title"><span>05</span><h4>Plan & captures</h4></div>\n            <div class="jedit-plan-grid">\n              <div><span>Plan model</span><strong>' + escapeHtml(trade.plan_model || '-') + '</strong></div>\n              <div><span>Direction plan</span><strong>' + escapeHtml(trade.plan_direction || '-') + '</strong></div>\n              <div><span>Alignement</span><strong>' + escapeHtml(trade.plan_alignment || 'unknown') + '</strong></div>\n              <div><span>Score</span><strong>' + (trade.plan_score == null ? '-' : escapeHtml(String(trade.plan_score))) + '</strong></div>\n            </div>\n            ' + TradeEditorController.textarea('Raison override plan', 'plan_override_reason', trade.plan_override_reason, 3) + '\n            <div class="jedit-shots">' + screenshotsHtml + '</div>\n          </section>\n        </div>\n      </div>\n    </aside>\n  ';
};

// ---- 060_btc_chart_widget.js ----
// ---------- BTC Chart widget — TradingView Lightweight Charts ----------
// v3.0 — Premium widget: custom viewport, free pan, follow mode, state isolation

(function () {
  // ──────────────────────────────────────────────
  //  CONFIG
  // ──────────────────────────────────────────────
  var BTC_WIDGET_VIEW = {
    visibleBars: { '1m':1000,'3m':1000,'5m':1000,'15m':1000,'30m':1000,'1h':1000,'2h':1000,'4h':1000,'6h':1000,'8h':1000,'12h':1000,'1d':1000 },
    futureBars:  { '1m':24,'3m':15,'5m':10,'15m':5,'30m':3,'1h':2,'2h':2,'4h':1,'6h':1,'8h':1,'12h':1,'1d':3 },
    barSpacing:  { '1m':6,'3m':8,'5m':8,'15m':9,'30m':10,'1h':11,'2h':12,'4h':13,'6h':14,'8h':14,'12h':15,'1d':10 },
  };

  var VWAP_COLORS = { '1D': '#f59e0b', '7D': '#06b6d4', '30D': '#a78bfa', '90D': '#f472b6', '365D': '#22c55e' };
  var INTERVAL_MS = {
    '1m': 60000, '3m': 180000, '5m': 300000, '15m': 900000,
    '30m': 1800000, '1h': 3600000, '2h': 7200000, '4h': 14400000,
    '6h': 21600000, '8h': 28800000, '12h': 43200000,
    '1d': 86400000, '3d': 259200000, '1w': 604800000, '1M': 2592000000,
  };

  // ──────────────────────────────────────────────
  //  STATE (isolé, ne partage rien avec 062)
  // ──────────────────────────────────────────────
  var S = {
    chart: null,
    container: null,
    candleSeries: null,
    countdownPriceLine: null,
    vwapSeriesMap: {},
    indicatorSeries: {},
    rsiSeries: null,
    candles: [],
    timeframe: '3m',
    follow: true,
    userDetached: false,
    hovered: false,
    userDragging: false,
    userGestureActive: false,
    programmaticRangeDepth: 0,
    suppressRangeEventsUntil: 0,
    listenersBound: false,
    _gestureTimer: null,
    renderToken: 0,
    manualPriceRange: null,
    // VWAP
    activeVwapPeriods: [],
    // Timers
    countdownTimer: null,
    countdownAnchor: null,
    refreshTimer: null,
    lastCandleTime: 0,
    lastCountdownFetchAt: 0,
    lastLiveYAdjustAt: 0,
    // WS
    ws: null,
    wsGeneration: 0,
    wsClosing: false,
    wsReconnectTimer: null,
    wsReconnectAttempts: 0,
    wsConnected: false,
    wsError: false,
    activeWsKey: null,
    // Flags
    chartReady: false,
    userIsInteracting: false,
    lastFetchTs: 0,
    FETCH_COOLDOWN_MS: 5000,
    firstFetchMs: 0,
    liveYSuppressUntil: 0,
    renderInFlight: false,
    fetchAbort: null,
    pendingRenderTimer: null,
    pendingWsTimer: null,
    pendingVwapTimer: null,
    candleCache: {},
    // Resize
    resizeObserver: null,
    didPrefetchTfs: false,
  };

  // VWAP periods from localStorage
  try { S.activeVwapPeriods = (window.BtcVwap && window.BtcVwap.readActiveVwapPeriods) ? window.BtcVwap.readActiveVwapPeriods() : []; } catch(e) {}

  // Indicator settings from localStorage
  var indSettings = {
    sma: { active: false, period: 20, color: '#f59e0b' },
    ema: { active: false, period: 20, color: '#06b6d4' },
    boll: { active: false, period: 20, color: '#a78bfa' },
    rsi: { active: false, period: 14, color: '#f472b6' },
  };
  try { var saved = JSON.parse(localStorage.getItem('chartIndSettings')); if (saved) { Object.keys(saved).forEach(function (k) { if (indSettings[k]) Object.assign(indSettings[k], saved[k]); }); } } catch(e) {}

  // ──────────────────────────────────────────────
  //  HELPERS
  // ──────────────────────────────────────────────
  function _getIntervalMs(interval) {
    var m = INTERVAL_MS[interval];
    if (m) return m;
    var match = interval.match(/^(\d+)(m|h|d|w|M)$/);
    if (!match) return 3600000;
    var num = parseInt(match[1], 10);
    var unit = match[2];
    var mult = { m: 60000, h: 3600000, d: 86400000, w: 604800000, M: 2592000000 };
    return num * (mult[unit] || 3600000);
  }

  function _numRequired(v) {
    if (v === null || v === undefined || v === '') return NaN;
    var n = Number(v);
    return Number.isFinite(n) ? n : NaN;
  }

  function _numOptional(v, fallback) {
    if (v === null || v === undefined || v === '') return fallback;
    var n = Number(v);
    return Number.isFinite(n) ? n : fallback;
  }

  function _normalizeCandles(rows) {
    var byTime = {};

    (rows || []).forEach(function (c) {
      if (!c) return;

      var rawTime = c.time != null ? c.time : (c.openTime != null ? c.openTime : c.t);
      var time = _numRequired(rawTime);
      if (time > 1e12) time = Math.floor(time / 1000);

      var open = _numRequired(c.open);
      var high = _numRequired(c.high);
      var low = _numRequired(c.low);
      var close = _numRequired(c.close);
      var volume = _numOptional(c.volume, 0);

      if (!Number.isFinite(time) || time <= 0) return;
      if (!Number.isFinite(open) || !Number.isFinite(high) || !Number.isFinite(low) || !Number.isFinite(close)) return;

      if (high < low) return;
      if (high < Math.max(open, close)) return;
      if (low > Math.min(open, close)) return;

      byTime[time] = {
        time: time,
        open: open,
        high: high,
        low: low,
        close: close,
        volume: volume,
      };
    });

    return Object.keys(byTime)
      .map(function (t) { return byTime[t]; })
      .sort(function (a, b) { return a.time - b.time; });
  }

  function _toValidServerTime(v) {
    if (v === null || v === undefined || v === '') return NaN;
    var n = Number(v);
    return Number.isFinite(n) && n > 1e12 ? n : NaN;
  }

  function _waitFrame() {
    return new Promise(function (resolve) { requestAnimationFrame(resolve); });
  }

  // ──────────────────────────────────────────────
  //  COMPAT LWC v4/v5
  // ──────────────────────────────────────────────
  function _addCandleSeries(api, opts) {
    if (typeof api.addSeries === 'function') return api.addSeries(window.LightweightCharts.CandlestickSeries, opts);
    return api.addCandlestickSeries(opts);
  }
  function _addLineSeries(api, opts) {
    if (typeof api.addSeries === 'function') return api.addSeries(window.LightweightCharts.LineSeries, opts);
    return api.addLineSeries(opts);
  }

  // ──────────────────────────────────────────────
  //  INDICATORS (idem 062)
  // ──────────────────────────────────────────────
  function _calcSMA(candles, period) {
    var result = [], sum = 0;
    for (var i = 0; i < candles.length; i++) {
      sum += candles[i].close;
      if (i >= period) sum -= candles[i - period].close;
      if (i >= period - 1) result.push({ time: candles[i].time, value: sum / period });
    }
    return result;
  }
  function _calcEMA(candles, period) {
    var result = [];
    var k = 2 / (period + 1);
    var ema = 0;
    for (var w = 0; w < period; w++) ema += candles[w].close;
    ema /= period;
    for (var i = 0; i < candles.length; i++) {
      ema = (candles[i].close - ema) * k + ema;
      if (i >= period - 1) result.push({ time: candles[i].time, value: ema });
    }
    return result;
  }
  function _calcBollinger(candles, period) {
    var smaData = _calcSMA(candles, period);
    var result = [];
    for (var i = 0; i < smaData.length; i++) {
      var idx = i + period - 1, sumSq = 0;
      for (var j = 0; j < period; j++) { var diff = candles[idx - j].close - smaData[i].value; sumSq += diff * diff; }
      var std = Math.sqrt(sumSq / period);
      result.push({ time: smaData[i].time, middle: smaData[i].value, upper: smaData[i].value + 2 * std, lower: smaData[i].value - 2 * std });
    }
    return result;
  }
  function _calcRSI(candles, period) {
    if (candles.length < period + 1) return [];
    var gains = [], losses = [];
    for (var i = 1; i < candles.length; i++) { var diff = candles[i].close - candles[i - 1].close; gains.push(diff > 0 ? diff : 0); losses.push(diff < 0 ? -diff : 0); }
    var avgGain = 0, avgLoss = 0;
    for (var j = 0; j < period; j++) { avgGain += gains[j]; avgLoss += losses[j]; }
    avgGain /= period; avgLoss /= period;
    var result = [];
    var rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    result.push({ time: candles[period].time, value: 100 - (100 / (1 + rs)) });
    for (var k = period; k < gains.length; k++) {
      avgGain = (avgGain * (period - 1) + gains[k]) / period;
      avgLoss = (avgLoss * (period - 1) + losses[k]) / period;
      rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
      result.push({ time: candles[k + 1].time, value: 100 - (100 / (1 + rs)) });
    }
    return result;
  }
  function _clearIndicators() {
    if (!S.chart) return;
    Object.keys(S.indicatorSeries).forEach(function (key) { try { S.chart.removeSeries(S.indicatorSeries[key]); } catch(e) {} });
    S.indicatorSeries = {};
    if (S.rsiSeries) { try { S.chart.removeSeries(S.rsiSeries); } catch(e) {} S.rsiSeries = null; }
  }
  function _renderIndicators(candles) {
    _clearIndicators();
    if (!S.chart || !candles || !candles.length) return;
    var s = indSettings;
    if (s.sma.active && candles.length >= s.sma.period) {
      var smaData = _calcSMA(candles, s.sma.period);
      S.indicatorSeries.sma = _addLineSeries(S.chart, { color: s.sma.color, lineWidth: 1.5, priceLineVisible: false, lastValueVisible: true, crosshairMarkerVisible: false, title: 'SMA ' + s.sma.period });
      S.indicatorSeries.sma.setData(smaData);
    }
    if (s.ema.active && candles.length >= s.ema.period) {
      var emaData = _calcEMA(candles, s.ema.period);
      S.indicatorSeries.ema = _addLineSeries(S.chart, { color: s.ema.color, lineWidth: 1.5, priceLineVisible: false, lastValueVisible: true, crosshairMarkerVisible: false, title: 'EMA ' + s.ema.period });
      S.indicatorSeries.ema.setData(emaData);
    }
    if (s.boll.active && candles.length >= s.boll.period) {
      var bollData = _calcBollinger(candles, s.boll.period);
      S.indicatorSeries.bollMid = _addLineSeries(S.chart, { color: s.boll.color, lineWidth: 1, priceLineVisible: false, lastValueVisible: true, crosshairMarkerVisible: false, title: 'BB ' + s.boll.period });
      S.indicatorSeries.bollUpper = _addLineSeries(S.chart, { color: s.boll.color, lineWidth: 1, priceLineVisible: false, lastValueVisible: false, crosshairMarkerVisible: false, lineStyle: 2 });
      S.indicatorSeries.bollLower = _addLineSeries(S.chart, { color: s.boll.color, lineWidth: 1, priceLineVisible: false, lastValueVisible: false, crosshairMarkerVisible: false, lineStyle: 2 });
      S.indicatorSeries.bollMid.setData(bollData.map(function (d) { return { time: d.time, value: d.middle }; }));
      S.indicatorSeries.bollUpper.setData(bollData.map(function (d) { return { time: d.time, value: d.upper }; }));
      S.indicatorSeries.bollLower.setData(bollData.map(function (d) { return { time: d.time, value: d.lower }; }));
    }
    if (s.rsi.active && candles.length >= s.rsi.period + 1) {
      try {
        S.rsiSeries = _addLineSeries(S.chart, { color: s.rsi.color, lineWidth: 1.5, priceLineVisible: false, lastValueVisible: true, crosshairMarkerVisible: false, priceScaleId: 'rsi_pane', title: 'RSI ' + s.rsi.period });
        S.chart.priceScale('rsi_pane').applyOptions({ scaleMargins: { top: 0.7, bottom: 0 }, visible: true });
        S.rsiSeries.setData(_calcRSI(candles, s.rsi.period));
      } catch(e) { console.error('[btc-widget] RSI:', e); }
    }
  }

  // ──────────────────────────────────────────────
  //  VWAP
  // ──────────────────────────────────────────────
  function _removeVwapSeries(key) {
    var s = S.vwapSeriesMap[key];
    if (s) {
      try { s.setData([]); } catch(e) {}
    }
  }

  // Délègue à BtcVwap (055) — cache global, source canonique, dedup
  async function _calcAndDrawVwap() {
    var token = S.renderToken;
    var tf = S.timeframe;

    try {
      S.activeVwapPeriods = (window.BtcVwap && window.BtcVwap.readActiveVwapPeriods)
        ? window.BtcVwap.readActiveVwapPeriods()
        : [];
    } catch(e) {}

    Object.keys(S.vwapSeriesMap).forEach(function (k) {
      var basePeriod = k.replace(/-1$/, '').replace(/_(u1|u2|u3|l1|l2|l3)$/, '');
      if (S.activeVwapPeriods.indexOf(basePeriod) < 0) _removeVwapSeries(k);
    });

    if (!S.activeVwapPeriods.length) return;
    if (!window.BtcVwap) return;
    if (!S.candles || !S.candles.length) return;

    // Re-sanitize defensif avant d'utiliser les candles comme base d'alignement VWAP.
    S.candles = _normalizeCandles(S.candles);
    if (S.candles.length < 2) return;

    var state = {
      symbol: 'BTCUSDT',
      candles: S.candles,
      vwapSeriesMap: S.vwapSeriesMap,
    };

    var vwapOrder = ['1D', '7D', '30D', '90D', '365D'];

    for (var vi = 0; vi < vwapOrder.length; vi++) {
      var p = vwapOrder[vi];

      if (S.activeVwapPeriods.indexOf(p) < 0) continue;
      if (token !== S.renderToken || tf !== S.timeframe) return;

      try {
        await window.BtcVwap.drawVwapForChart(state, p, false, function () {
          return token !== S.renderToken || tf !== S.timeframe;
        });
        await window.BtcVwap.drawVwapForChart(state, p, true, function () {
          return token !== S.renderToken || tf !== S.timeframe;
        });
      } catch (e) {
        console.warn('[BTC-WIDGET] VWAP draw failed', p, e);
      }

      if (token !== S.renderToken || tf !== S.timeframe) return;
      await _waitFrame();
    }
  }

  function _refreshWidgetVwapFromPrefs() {
    if (window.BtcVwap && window.BtcVwap.readActiveVwapPeriods) {
      S.activeVwapPeriods = window.BtcVwap.readActiveVwapPeriods();
    } else {
      try {
        var raw = JSON.parse(localStorage.getItem('chartVwapPeriods'));
        S.activeVwapPeriods = Array.isArray(raw) ? raw : [];
      } catch(e) {
        S.activeVwapPeriods = [];
      }
    }

    if (!S.chartReady || !S.candles || !S.candles.length) return;

    _calcAndDrawVwap().catch(function (e) {
      console.warn('[BTC-WIDGET] refresh VWAP failed', e);
    });
  }

  window.addEventListener('chart:vwap-periods-changed', function () {
    _refreshWidgetVwapFromPrefs();
  });

  window.addEventListener('storage', function (e) {
    if (e.key === 'chartVwapPeriods') {
      _refreshWidgetVwapFromPrefs();
    }
  });
  // ──────────────────────────────────────────────
  //  PRICE RANGE MANAGEMENT
  // ──────────────────────────────────────────────
  function computeBtcWidgetPriceRange(candles, tf) {
    if (!window.ChartViewCore) return null;
    var vb = BTC_WIDGET_VIEW.visibleBars[tf || S.timeframe] || 100;
    return window.ChartViewCore.computePriceRange(candles, vb, { top: 0.08, bottom: 0.08, minRangeRatio: 0.002 });
  }

  function getBtcWidgetCurrentPriceRange() {
    if (S.follow && S.manualPriceRange) return S.manualPriceRange;
    if (!S.candleSeries) return S.manualPriceRange;
    var ps = S.candleSeries.priceScale();
    if (typeof ps.getVisibleRange === 'function') {
      try { var r = ps.getVisibleRange(); if (r) return r; } catch(e) {}
    }
    return S.manualPriceRange;
  }

  function setBtcWidgetPriceRange(range) {
    if (!range || !Number.isFinite(range.from) || !Number.isFinite(range.to) || range.to <= range.from) return;
    S.manualPriceRange = range;
    var ps = S.candleSeries.priceScale();
    if (typeof ps.setVisibleRange === 'function' && typeof ps.setAutoScale === 'function') {
      try { ps.setAutoScale(false); ps.setVisibleRange(range); } catch(e) {}
      return;
    }
    // Fallback LWC 4.x: force via autoscaleInfoProvider + logical range reset
    var lr;
    try { lr = S.chart.timeScale().getVisibleLogicalRange(); } catch(e) {}
    if (lr) {
      try { S.chart.timeScale().setVisibleLogicalRange({ from: lr.from, to: lr.to }); } catch(e) {}
    }
  }

  function _applyLiveXRangeNoWrap() {
    var candles = S.candles;
    if (!candles || !candles.length) return;
    var tf = S.timeframe;
    var visibleBars = BTC_WIDGET_VIEW.visibleBars[tf] || 100;
    var futureBars = BTC_WIDGET_VIEW.futureBars[tf] || 14;
    var lastIndex = candles.length - 1;
    try { S.chart.timeScale().setVisibleLogicalRange({ from: lastIndex + futureBars - visibleBars, to: lastIndex + futureBars }); } catch(e) {}
  }

  function _withProgrammaticRange(fn) {
    S.programmaticRangeDepth++;
    S.suppressRangeEventsUntil = performance.now() + 250;
    try { fn(); } finally {
      requestAnimationFrame(function () {
        requestAnimationFrame(function () {
          S.programmaticRangeDepth = Math.max(0, S.programmaticRangeDepth - 1);
          S.suppressRangeEventsUntil = performance.now() + 100;
        });
      });
    }
  }

  function applyBtcWidgetBestView() {
    if (!S.candles || !S.candles.length || !S.chart) return;
    _withProgrammaticRange(function () {
      _applyLiveXRangeNoWrap();
      var priceRange = computeBtcWidgetPriceRange(S.candles, S.timeframe);
      setBtcWidgetPriceRange(priceRange);
    });
    S.liveYSuppressUntil = performance.now() + 2500;
    _updateBtcWidgetLiveButton();
  }

  // ──────────────────────────────────────────────
  //  LIVE STATE MANAGEMENT
  // ──────────────────────────────────────────────
  function _detachFromLive(reason) {
    if (!S.follow && S.userDetached) return;
    S.follow = false;
    S.userDetached = true;
    console.log('[BTC WIDGET] detached:', reason);
    _updateBtcWidgetLiveButton();
  }

  function _returnToLive(reason) {
    S.follow = true;
    S.userDetached = false;
    S.userDragging = false;
    S.userGestureActive = false;
    console.log('[BTC WIDGET] return to live:', reason);
    _withProgrammaticRange(function () { applyBtcWidgetBestView(); });
    _updateBtcWidgetLiveButton();
  }

  function _resetLiveState() {
    S.follow = true;
    S.userDetached = false;
    S.hovered = false;
    S.userDragging = false;
    S.userGestureActive = false;
    S.programmaticRangeDepth = 0;
    S.suppressRangeEventsUntil = performance.now() + 500;
    _updateBtcWidgetLiveButton();
  }

  function _updateBtcWidgetLiveButton() {
    var btn = document.getElementById('btc-widget-live-btn');
    if (!btn) return;
    var show = S.hovered && S.userDetached && !S.follow;
    btn.classList.toggle('hidden', !show);
  }

  // ──────────────────────────────────────────────
  //  EVENT BINDINGS (one-shot)
  // ──────────────────────────────────────────────
  function _bindHover() {
    var el = S.container;
    el.addEventListener('mouseenter', function () { S.hovered = true; _updateBtcWidgetLiveButton(); });
    el.addEventListener('mouseleave', function () { S.hovered = false; _updateBtcWidgetLiveButton(); });
  }

  function _bindUserIntent() {
    var el = S.container;
    el.addEventListener('wheel', function () {
      S.userGestureActive = true;
      _detachFromLive('wheel');
      if (S._gestureTimer) clearTimeout(S._gestureTimer);
      S._gestureTimer = setTimeout(function () { S.userGestureActive = false; }, 200);
    }, { passive: true });
  }

  function _bindRangeWatcher() {
    try {
      S.chart.timeScale().subscribeVisibleLogicalRangeChange(function () {
        if (S.programmaticRangeDepth > 0) return;
        if (performance.now() < S.suppressRangeEventsUntil) return;
        if (!S.userGestureActive && !S.userDragging) return;
        _detachFromLive('range-user-change');
      });
    } catch(e) {}
  }

  function bindBtcWidgetFreePan() {
    var el = S.container;
    if (!el) return;
    var gesture = null;
    var DRAG_THRESHOLD = 5;

    function resetGesture() {
      if (gesture && gesture.pointerId != null) {
        try { if (el.hasPointerCapture && el.hasPointerCapture(gesture.pointerId)) el.releasePointerCapture(gesture.pointerId); } catch(e) {}
      }
      gesture = null;
      S.userDragging = false;
      S.userGestureActive = false;
      el.classList.remove('btc-widget-dragging');
      _updateBtcWidgetLiveButton();
    }

    el.addEventListener('pointerdown', function (e) {
      if (e.button !== 0) return;
      if (e.target.closest('button, .tf-btn, .widget-btn, .btc-chart-interval, #btcChartCustom, #btc-widget-live-btn')) return;
      var logicalRange;
      try { logicalRange = S.chart.timeScale().getVisibleLogicalRange(); } catch(e) {}
      var priceRange = getBtcWidgetCurrentPriceRange();
      if (!logicalRange || !priceRange) return;
      gesture = {
        pointerId: e.pointerId, startX: e.clientX, startY: e.clientY,
        logicalRange: { from: logicalRange.from, to: logicalRange.to },
        priceRange: { from: priceRange.from, to: priceRange.to },
        dragging: false,
      };
    });

    window.addEventListener('pointermove', function (e) {
      if (!gesture || e.pointerId !== gesture.pointerId) return;
      var dx = e.clientX - gesture.startX;
      var dy = e.clientY - gesture.startY;
      var dist = Math.hypot(dx, dy);
      if (!gesture.dragging) {
        if (dist < DRAG_THRESHOLD) return;
        gesture.dragging = true;
        S.userDragging = true;
        S.userGestureActive = true;
        _detachFromLive('drag');
        try { el.setPointerCapture(gesture.pointerId); } catch(e) {}
        el.classList.add('btc-widget-dragging');
      }
      e.preventDefault();
      var rect = el.getBoundingClientRect();
      var plotW = Math.max(1, rect.width - 70);
      var plotH = Math.max(1, rect.height - 30);
      var logicalW = gesture.logicalRange.to - gesture.logicalRange.from;
      var priceH = gesture.priceRange.to - gesture.priceRange.from;
      var barsPerPx = logicalW / plotW;
      var pricePerPx = priceH / plotH;
      _withProgrammaticRange(function () {
        try { S.chart.timeScale().setVisibleLogicalRange({ from: gesture.logicalRange.from + (-dx * barsPerPx), to: gesture.logicalRange.to + (-dx * barsPerPx) }); } catch(e) {}
        setBtcWidgetPriceRange({ from: gesture.priceRange.from + (dy * pricePerPx), to: gesture.priceRange.to + (dy * pricePerPx) });
      });
    }, { passive: false });

    window.addEventListener('pointerup', resetGesture);
    window.addEventListener('pointercancel', resetGesture);
    window.addEventListener('blur', resetGesture);
    el.addEventListener('lostpointercapture', resetGesture);
    document.addEventListener('keydown', function (e) { if (e.key === 'Escape') resetGesture(); });

    el.addEventListener('dblclick', function () {
      resetGesture();
      _returnToLive('dblclick');
    });
  }

  function _bindListenersOnce() {
    if (S.listenersBound) return;
    S.listenersBound = true;
    _bindHover();
    _bindUserIntent();
    bindBtcWidgetFreePan();
    _bindRangeWatcher();
    var btn = document.getElementById('btc-widget-live-btn');
    if (btn) {
      btn.addEventListener('click', function (e) { e.stopPropagation(); _returnToLive('button'); });
    }
  }

  // ──────────────────────────────────────────────
  //  TIMER & COUNTDOWN
  // ──────────────────────────────────────────────
  function _getLiveYZone(tf) {
    if (tf === '1m') return { low: 0.18, high: 0.82 };
    if (tf === '3m') return { low: 0.18, high: 0.82 };
    if (tf === '5m') return { low: 0.20, high: 0.80 };
    return { low: 0.24, high: 0.76 };
  }

  function maybeFollowBtcWidgetPriceY(force) {
    if (S.userGestureActive) return;
    if (!force && !S.follow) return;
    if (!force && S.userDragging) return;
    if (!force && performance.now() < (S.liveYSuppressUntil || 0)) return;
    var candles = S.candles;
    if (!candles || !candles.length) return;
    var last = candles[candles.length - 1];
    if (!last) return;

    var now = performance.now();

    var currentRange = getBtcWidgetCurrentPriceRange();
    if (!currentRange) {
      S.lastLiveYAdjustAt = now;
      _withProgrammaticRange(function () { setBtcWidgetPriceRange(computeBtcWidgetPriceRange(candles, S.timeframe)); });
      return;
    }

    var height = currentRange.to - currentRange.from;
    if (!Number.isFinite(height) || height <= 0) return;

    var buffer = height * 0.035;

    // Ne bouge que si la bougie live sort du cadre (avec marge)
    var breaksTop = Number.isFinite(last.high) && last.high > currentRange.to - buffer;
    var breaksBottom = Number.isFinite(last.low) && last.low < currentRange.from + buffer;

    if (!force && !breaksTop && !breaksBottom) return;

    // Throttle lent : pas à chaque tick WS
    if (!force && now - (S.lastLiveYAdjustAt || 0) < 1000) return;

    var desiredRange = computeBtcWidgetPriceRange(candles, S.timeframe);
    if (!desiredRange) return;

    S.lastLiveYAdjustAt = now;
    _withProgrammaticRange(function () { setBtcWidgetPriceRange(desiredRange); });
  }

  // ── COUNTDOWN ANCHOR (basé sur candleCloseMs + performance.now()) ──

  function _toMs(t) {
    if (t == null) return NaN;
    var n = Number(t);
    if (!Number.isFinite(n)) return NaN;
    return n > 1e12 ? n : n * 1000;
  }

  function _getCandleCloseMs(candle, intervalMs) {
    if (candle.closeTime != null) return _toMs(candle.closeTime);
    if (candle.T != null) return _toMs(candle.T);
    if (candle.time != null) return _toMs(candle.time) + intervalMs;
    return NaN;
  }

  function _updateCountdownAnchor(candle, source, nowMsOverride) {
    if (!candle) return;
    var intervalMs = _getIntervalMs(S.timeframe);
    if (!intervalMs) return;
    var openMs = _toMs(candle.time != null ? (candle.openTime != null ? candle.openTime : candle.time) : (candle.t != null ? candle.t : 0));
    var closeMs = _getCandleCloseMs(candle, intervalMs);
    if (!Number.isFinite(openMs) || !Number.isFinite(closeMs)) return;

    var overrideNow = Number(nowMsOverride);
    var hasOverrideNow = Number.isFinite(overrideNow);

    var clockSynced = hasOverrideNow ||
      (window.BtcMarketClock && window.BtcMarketClock.isSynced && window.BtcMarketClock.isSynced());

    var marketNow = hasOverrideNow
      ? overrideNow
      : (window.BtcMarketClock ? window.BtcMarketClock.now() : Date.now());

    // Pas de reject si clock pas sync et source pas WS — on attend la sync
    if (!clockSynced && source !== 'ws') return;

    var remaining = closeMs - marketNow;
    if (remaining < -intervalMs) {
      console.warn('[COUNTDOWN] stale candle anchor, forcing latest fetch', { source, tf: S.timeframe, openMs, closeMs, marketNow, remaining });
      S.countdownAnchor = {
        candleOpenMs: openMs,
        candleCloseMs: closeMs,
        remainingAtAnchorMs: 0,
        perfAtAnchor: performance.now(),
        source: 'stale-' + (source || 'unknown'),
      };
      if (Date.now() - (S.lastCountdownFetchAt || 0) > 5000) {
        S.lastCountdownFetchAt = Date.now();
        _fetchLatestCandleOnly();
      }
      return;
    }
    if (remaining > intervalMs * 2) {
      console.warn('[COUNTDOWN] future candle anchor rejected', { source, tf: S.timeframe, openMs, closeMs, marketNow, remaining });
      return;
    }
    remaining = Math.max(0, Math.min(remaining, intervalMs));
    S.countdownAnchor = {
      candleOpenMs: openMs,
      candleCloseMs: closeMs,
      remainingAtAnchorMs: remaining,
      perfAtAnchor: performance.now(),
      source: source || 'unknown',
    };
  }

  function _formatCountdown(ms) {
    if (!Number.isFinite(ms) || ms <= 0) return '0:00';
    var totalSec = Math.ceil(ms / 1000);
    var h = Math.floor(totalSec / 3600);
    var m = Math.floor((totalSec % 3600) / 60);
    var s = totalSec % 60;
    var pad = function (n) { return n < 10 ? '0' + n : '' + n; };
    if (h > 0) return h + ':' + pad(m) + ':' + pad(s);
    return m + ':' + pad(s);
  }

  function _startCountdown() {
    if (S.countdownTimer) clearInterval(S.countdownTimer);
    S.countdownTimer = setInterval(function () {
      if (!S.countdownPriceLine) { _updateCountdownLabel('—'); return; }
      var anchor = S.countdownAnchor;
      if (!anchor) {
        var intervalMs = _getIntervalMs(S.timeframe);
        var nowMs = window.BtcMarketClock ? window.BtcMarketClock.now() : Date.now();
        var estimated = intervalMs ? intervalMs - (nowMs % intervalMs) : 0;
        _updateCountdownLabel(estimated > 0 ? _formatCountdown(estimated) : '—');

        if (S.renderInFlight) return;

        var clockReady = window.BtcMarketClock && window.BtcMarketClock.isSynced && window.BtcMarketClock.isSynced();
        if (S.chartReady && clockReady && !S.wsConnected && Date.now() - (S.lastCountdownFetchAt || 0) > 5000) {
          S.lastCountdownFetchAt = Date.now();
          _fetchLatestCandleOnly();
        }
        return;
      }
      var elapsed = performance.now() - anchor.perfAtAnchor;
      var remaining = anchor.remainingAtAnchorMs - elapsed;
      if (remaining <= 0) {
        _updateCountdownLabel('0:00');
        if (!S.wsConnected && Date.now() - (S.lastCountdownFetchAt || 0) > 10000) {
          S.lastCountdownFetchAt = Date.now();
          _fetchLatestCandleOnly();
        }
        return;
      }
      _updateCountdownLabel(_formatCountdown(remaining));
    }, 250);
  }

  function _updateCountdownLabel(txt) {
    if (!S.countdownPriceLine || !S.chart) return;
    try { S.countdownPriceLine.applyOptions({ title: txt === undefined ? '—' : txt }); } catch(e) {}
  }

  function _startAutoRefresh() {
    if (S.refreshTimer) clearInterval(S.refreshTimer);
    var ms = _getIntervalMs(S.timeframe);
    var interval = Math.min(60000, Math.max(15000, Math.floor(ms / 4)));
    S.refreshTimer = setInterval(function () {
      if (!S.chartReady) return;
      if (S.renderInFlight) return;
      if (!S.countdownAnchor) return;
      // Si WS fonctionne, pas besoin de REST refresh
      if (S.wsConnected && !S.wsError) return;
      // Fallback REST seulement proche de la cloture
      var elapsed = performance.now() - S.countdownAnchor.perfAtAnchor;
      if (elapsed < S.countdownAnchor.remainingAtAnchorMs + 1500) return;
      _fetchLatestCandleOnly();
    }, interval);
  }

  // REST fallback léger — update la dernière bougie, pas de full render
  function _fetchLatestCandleOnly() {
    if (S.renderInFlight) return Promise.resolve();
    var token = S.renderToken;
    var tf = S.timeframe;
    var url = '/api/market/klines?symbol=BTCUSDT&interval=' + tf + '&limit=3&soft=1';
    return fetch(url)
      .then(function (r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function (data) {
        if (token !== S.renderToken || tf !== S.timeframe) return;

        var raw = data.candles || [];
        if (!raw.length) return;
        var candles = _normalizeCandles(raw);
        var latest = candles[candles.length - 1];
        if (!latest || !latest.time) return;
        var last = S.candles && S.candles.length > 0 ? S.candles[S.candles.length - 1] : null;
        if (last && latest.time === last.time) {
          // Même bougie — update
          S.candles[S.candles.length - 1] = latest;
        } else if (latest.time > (last ? last.time : 0)) {
          // Nouvelle bougie — push
          S.candles.push(latest);
          if (S.candles.length > 1000) S.candles = S.candles.slice(-1000);
        }
        S.lastCandleTime = latest.time * 1000;
        _updateCountdownAnchor(latest, 'rest-fallback');
        S.candleSeries.update(latest);
        _drawMidnightForWidget(latest, false);
        if (S.follow && !S.userDragging) {
          _withProgrammaticRange(function () { maybeFollowBtcWidgetPriceY(); });
        }
      })
      .catch(function (e) {
        console.warn('[BTC-WIDGET] REST fallback failed', e);
      });
  }

  // ──────────────────────────────────────────────
  //  WS — Architecture générationnelle
  // ──────────────────────────────────────────────

  function _disconnectWs(reason) {
    S.wsGeneration++;
    if (S.wsReconnectTimer) { clearTimeout(S.wsReconnectTimer); S.wsReconnectTimer = null; }
    S.wsConnected = false;
    S.wsClosing = true;
    var ws = S.ws;
    S.ws = null;
    S.activeWsKey = null;
    if (ws) {
      try {
        ws.onopen = null;
        ws.onmessage = null;
        ws.onerror = null;
        ws.onclose = null;
        if (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING) {
          ws.close(1000, reason || 'intentional');
        }
      } catch(e) { console.warn('[BTC-WIDGET][WS] close error', e); }
    }
    setTimeout(function () { S.wsClosing = false; }, 500);
  }

  function _connectWs(reason, opts) {
    opts = opts || {};

    if (opts.token && opts.token !== S.renderToken) return;
    if (opts.tf && opts.tf !== S.timeframe) return;

    var tf = S.timeframe;
    var wsKey = 'BTCUSDT:' + tf;

    if (S.ws && S.activeWsKey === wsKey) {
      var alive = S.ws.readyState === WebSocket.OPEN || S.ws.readyState === WebSocket.CONNECTING;
      if (alive) return;
    }

    _disconnectWs('before-connect:' + reason);

    var generation = ++S.wsGeneration;
    S.activeWsKey = wsKey;

    var stream = 'btcusdt@kline_' + tf;
    var url = 'wss://stream.binance.com:9443/ws/' + stream;

    var newWs = new WebSocket(url);
    S.ws = newWs;

    newWs.onopen = function () {
      if (generation !== S.wsGeneration || newWs !== S.ws) return;
      if (opts.token && opts.token !== S.renderToken) {
        _disconnectWs('stale-open');
        return;
      }
      S.wsConnected = true;
    };

    newWs.onmessage = function (event) {
      if (generation !== S.wsGeneration || newWs !== S.ws) return;
      if (opts.token && opts.token !== S.renderToken) return;
      try { _handleWsMessage(event.data); } catch(e) { console.warn('[BTC-WIDGET][WS] msg', e); }
    };

    newWs.onclose = function () {
      if (generation !== S.wsGeneration || newWs !== S.ws) return;
      S.wsConnected = false;
    };

    newWs.onerror = function () {
      if (generation !== S.wsGeneration || newWs !== S.ws) return;
      S.wsError = true;
    };
  }

  function _scheduleWsReconnect(reason) {
    if (S.wsReconnectTimer) return;
    S.wsReconnectAttempts = Math.min((S.wsReconnectAttempts || 0) + 1, 6);
    var delay = Math.min(60000, 2000 * Math.pow(2, S.wsReconnectAttempts - 1));
    S.wsReconnectTimer = setTimeout(function () {
      S.wsReconnectTimer = null;
      _connectWs('reconnect:' + reason);
    }, delay);
  }

  function _upsertLiveCandle(rawCandle) {
    var normalized = _normalizeCandles([rawCandle]);
    if (!normalized.length) {
      console.warn('[BTC-WIDGET] invalid live candle ignored', { tf: S.timeframe, raw: rawCandle });
      return false;
    }
    var candle = normalized[0];
    if (!Array.isArray(S.candles)) S.candles = [];
    var idx = -1;
    for (var i = S.candles.length - 1; i >= 0; i--) {
      if (S.candles[i].time === candle.time) { idx = i; break; }
    }
    if (idx >= 0) { S.candles[idx] = candle; }
    else { S.candles.push(candle); }
    if (S.candles.length > 1000) S.candles = S.candles.slice(-1000);
    return true;
  }

  function _handleWsMessage(raw) {
    var d = JSON.parse(raw), k = d && d.k;
    if (!k) return;
    var candle = { time: Math.floor(k.t / 1000), openTime: k.t, closeTime: k.T, open: parseFloat(k.o), high: parseFloat(k.h), low: parseFloat(k.l), close: parseFloat(k.c), volume: parseFloat(k.v) };
    var ok = _upsertLiveCandle(candle);
    if (!ok) return;
    var safeCandle = S.candles[S.candles.length - 1];
    var priceEl = document.getElementById('btcChartPrice');
    if (priceEl) priceEl.textContent = '$' + safeCandle.close.toLocaleString('fr-FR', { minimumFractionDigits: 2 });
    S.lastCandleTime = k.t;

    var eventMs = Number(d.E);
    if (window.BtcMarketClock && Number.isFinite(eventMs)) {
      window.BtcMarketClock.sync(eventMs, 'ws-event');
    }
    _updateCountdownAnchor(safeCandle, 'ws', Number.isFinite(eventMs) ? eventMs : undefined);
    if (S.candleSeries) { try { S.candleSeries.update(safeCandle); } catch(e) {} }
    if (S.countdownPriceLine) { try { S.countdownPriceLine.applyOptions({ price: safeCandle.close }); } catch(e) {} }
    _drawMidnightForWidget(safeCandle, false);
    _withProgrammaticRange(function () { maybeFollowBtcWidgetPriceY(); });
  }

  // ──────────────────────────────────────────────
  //  CHART CREATION
  // ──────────────────────────────────────────────
  function createBtcWidgetChart(container) {
    if (S.chartReady) return;
    S.chartReady = true;
    S.container = container;
    if (!container || !container.parentElement) return;
    var isLight = document.body.classList.contains('light-mode');
    var tf = S.timeframe;
    S.chart = window.LightweightCharts.createChart(container, {
      autoSize: true,
      layout: { background: { type: 'solid', color: 'transparent' }, textColor: isLight ? '#1e293b' : '#d1d5db' },
      grid: { vertLines: { color: 'transparent' }, horzLines: { color: 'transparent' } },
      crosshair: { mode: 0 },
      rightPriceScale: { visible: true, autoScale: true, borderVisible: false, scaleMargins: { top: 0.04, bottom: 0.05 } },
      timeScale: {
        rightOffset: BTC_WIDGET_VIEW.futureBars[tf] || 14,
        barSpacing: BTC_WIDGET_VIEW.barSpacing[tf] || 9,
        minBarSpacing: 3,
        fixLeftEdge: false, fixRightEdge: false,
        lockVisibleTimeRangeOnResize: true,
        rightBarStaysOnScroll: false,
        timeVisible: true, secondsVisible: false, borderVisible: false,
      },
      handleScroll: { mouseWheel: true, pressedMouseMove: false, horzTouchDrag: true, vertTouchDrag: true },
      handleScale: { axisPressedMouseMove: true, mouseWheel: true, pinch: true },
      kineticScroll: { mouse: false, touch: false },
    });

    // Candle series
    S.candleSeries = _addCandleSeries(S.chart, {
      priceScaleId: 'right',
      upColor: '#22c55e', downColor: '#ef4444',
      borderVisible: false, wickUpColor: '#22c55e', wickDownColor: '#ef4444',
      lastValueVisible: false, priceLineVisible: false,
      autoscaleInfoProvider: window.ChartViewCore
        ? window.ChartViewCore.makeAutoscaleInfoProvider({ get value() { return S.manualPriceRange; }, set value(v) { S.manualPriceRange = v; } })
        : undefined,
    });

    // Countdown price line
    S.countdownPriceLine = S.candleSeries.createPriceLine({ price: 0, color: '#22c55e', lineWidth: 1, lineStyle: 2, axisLabelVisible: true, title: '—' });

    // VWAP series
    Object.keys(VWAP_COLORS).forEach(function (p) {
      S.vwapSeriesMap[p] = _addLineSeries(S.chart, {
        color: VWAP_COLORS[p], lineWidth: 1.5, priceLineVisible: false, lastValueVisible: false,
        crosshairMarkerVisible: false, title: 'VWAP ' + p, visible: true,
        autoscaleInfoProvider: function () { return null; },
      });
      S.vwapSeriesMap[p + '-1'] = _addLineSeries(S.chart, {
        color: VWAP_COLORS[p], lineWidth: 1, lineStyle: 2, priceLineVisible: false, lastValueVisible: false,
        crosshairMarkerVisible: false, title: 'VWAP ' + p + '-1', visible: true,
        autoscaleInfoProvider: function () { return null; },
      });
      S.vwapSeriesMap[p].setData([]);
      S.vwapSeriesMap[p + '-1'].setData([]);
      // Bandes d'écart-type (6 séries par période)
      var BAND_KEYS = ['u1', 'u2', 'u3', 'l1', 'l2', 'l3'];
      for (var bi = 0; bi < BAND_KEYS.length; bi++) {
        var bk = BAND_KEYS[bi];
        S.vwapSeriesMap[p + '_' + bk] = _addLineSeries(S.chart, {
          color: VWAP_COLORS[p], lineWidth: 1, lineStyle: 0, priceLineVisible: false, lastValueVisible: false,
          crosshairMarkerVisible: false, title: 'VWAP ' + p + ' ' + bk, visible: true,
          autoscaleInfoProvider: function () { return null; },
        });
        S.vwapSeriesMap[p + '_' + bk].setData([]);
      }
    });

    // Resize observer
    if (S.resizeObserver) S.resizeObserver.disconnect();
    S.resizeObserver = new ResizeObserver(function () {
      if (S.chart && container) {
        var cw = container.clientWidth, ch = Math.max(240, container.clientHeight || 360);
        if (cw > 0 && ch > 0) S.chart.applyOptions({ width: cw, height: ch });
      }
    });
    S.resizeObserver.observe(container);

    // Event bindings (one-shot)
    _bindListenersOnce();

    // Interval buttons
    document.querySelectorAll('.btc-chart-interval').forEach(function (btn) {
      btn.addEventListener('click', function () {
        document.querySelectorAll('.btc-chart-interval').forEach(function (b) { b.classList.remove('active'); });
        btn.classList.add('active');
        var ci = document.getElementById('btcChartCustom');
        if (ci) ci.value = '';
        _scheduleFetchAndRender(btn.dataset.interval, 'user');
      });
    });

    // Custom interval
    var customInput = document.getElementById('btcChartCustom');
    if (customInput) {
      customInput.addEventListener('change', function () {
        var val = this.value.trim().toLowerCase();
        if (!/^\d+(m|h|d|w|M)$/.test(val)) { this.classList.add('jedit-field-error'); this.title = 'Format: chiffre + m/h/d/w/M'; return; }
        this.classList.remove('jedit-field-error'); this.title = '';
        document.querySelectorAll('.btc-chart-interval').forEach(function (b) { b.classList.remove('active'); });
        _scheduleFetchAndRender(val, 'user');
      });
      customInput.addEventListener('keydown', function (e) { if (e.key === 'Enter') this.blur(); });
    }
  }

  // ──────────────────────────────────────────────
  //  FETCH & RENDER
  // ──────────────────────────────────────────────

  async function _fetchWidgetCandles(tf, signal) {
    var url = '/api/market/klines?symbol=BTCUSDT&interval=' + tf + '&limit=1000&soft=1';
    var r = await fetch(url, { signal: signal });
    if (!r.ok) throw new Error('HTTP ' + r.status);
    return await r.json();
  }

  function _scheduleFetchAndRender(tf, source) {
    if (tf) S.timeframe = tf;

    if (S.pendingRenderTimer) clearTimeout(S.pendingRenderTimer);
    if (S.pendingWsTimer) { clearTimeout(S.pendingWsTimer); S.pendingWsTimer = null; }
    if (S.pendingVwapTimer) { clearTimeout(S.pendingVwapTimer); S.pendingVwapTimer = null; }

    S.pendingRenderTimer = setTimeout(function () {
      S.pendingRenderTimer = null;
      _fetchAndRender(source || 'user');
    }, 80);
  }

  function _scheduleWsConnect(token, tf) {
    if (S.pendingWsTimer) clearTimeout(S.pendingWsTimer);

    S.pendingWsTimer = setTimeout(function () {
      S.pendingWsTimer = null;

      if (token !== S.renderToken || tf !== S.timeframe) return;
      _connectWs('idle-after-render', { token: token, tf: tf });
    }, 1800);
  }

  function _scheduleVwapDraw(token, tf) {
    if (S.pendingVwapTimer) clearTimeout(S.pendingVwapTimer);

    S.pendingVwapTimer = setTimeout(function () {
      S.pendingVwapTimer = null;

      if (token !== S.renderToken || tf !== S.timeframe) return;
      if (!S.activeVwapPeriods || !S.activeVwapPeriods.length) return;

      _calcAndDrawVwap().catch(function (e) {
        console.warn('[BTC-WIDGET] VWAP async render failed', e);
      });
    }, 350);
  }

  function _drawMidnightForWidget(candle, force) {
    if (!window.BtcMidnight || !S.candleSeries || !candle) return;
    var ts = Number(candle.time);
    if (!Number.isFinite(ts) || ts <= 0) return;
    window.BtcMidnight.drawMidnightLines(S.candleSeries, 'BTCUSDT', ts * 1000, !!force, S.chart)
      .catch(function (e) {
        console.warn('[BTC-WIDGET] midnight draw failed', e);
      });
  }

  function _cacheKey(tf) {
    return 'BTCUSDT:' + tf;
  }

  function _readWidgetCache(tf) {
    var key = _cacheKey(tf);

    if (S.candleCache[key] && S.candleCache[key].candles) {
      return S.candleCache[key].candles;
    }

    try {
      var raw = sessionStorage.getItem('btcWidgetCandles:' + tf);
      if (!raw) return null;

      var candles = _normalizeCandles(JSON.parse(raw));
      if (candles.length >= 2) {
        S.candleCache[key] = {
          candles: candles,
          ts: Date.now(),
        };
        return candles;
      }
    } catch(e) {}

    return null;
  }

  function _writeWidgetCache(tf, candles) {
    candles = _normalizeCandles(candles);
    if (candles.length < 2) return;

    var key = _cacheKey(tf);
    S.candleCache[key] = {
      candles: candles,
      ts: Date.now(),
    };

    try {
      sessionStorage.setItem('btcWidgetCandles:' + tf, JSON.stringify(candles));
    } catch(e) {}
  }

  function _prefetchWidgetTimeframesIdle() {
    var tfs = ['5m', '15m', '30m', '1h', '4h', '1d'];
    var current = S.timeframe;
    tfs = tfs.filter(function (tf) { return tf !== current; });

    var i = 0;
    function next() {
      if (i >= tfs.length) return;
      if (S.renderInFlight) { setTimeout(next, 1000); return; }
      var tf = tfs[i++];
      if (S.candleCache[_cacheKey(tf)]) { setTimeout(next, 250); return; }

      fetch('/api/market/klines?symbol=BTCUSDT&interval=' + tf + '&limit=1000&soft=1')
        .then(function (r) { return r.ok ? r.json() : null; })
        .then(function (data) {
          if (data && data.candles) _writeWidgetCache(tf, data.candles);
        })
        .catch(function () {})
        .then(function () { setTimeout(next, 250); });
    }

    if ('requestIdleCallback' in window) {
      requestIdleCallback(next, { timeout: 3000 });
    } else {
      setTimeout(next, 1500);
    }
  }

  async function _fetchAndRender(source) {
    var token = ++S.renderToken;
    var tf = S.timeframe;

    console.log('[BTC-WIDGET] render start token=', token, 'tf=', tf, 'source=', source);

    // Annule le fetch precedent
    if (S.fetchAbort) {
      try { S.fetchAbort.abort(); } catch(e) {}
    }
    S.fetchAbort = new AbortController();

    // Cache : affiche immediatement les donnees deja vues
    var cached = _readWidgetCache(tf);
    if (cached && cached.length >= 2) {
      S.candles = cached;
      S.manualPriceRange = null;

      try { _clearIndicators(); } catch(e) {}
      Object.keys(S.vwapSeriesMap || {}).forEach(function (k) {
        try { S.vwapSeriesMap[k].setData([]); } catch(e) {}
      });

      if (S.candleSeries) S.candleSeries.setData(cached);
      applyBtcWidgetBestView();

      var lastCached = cached[cached.length - 1];
      if (lastCached) {
        S.lastCandleTime = lastCached.time * 1000;
        var cacheNow = window.BtcMarketClock ? window.BtcMarketClock.now() : Date.now();
        if (!Number.isFinite(cacheNow) || cacheNow <= 0) cacheNow = Date.now();
        _updateCountdownAnchor(lastCached, 'cache', cacheNow);

        var priceEl = document.getElementById('btcChartPrice');
        if (priceEl) {
          priceEl.textContent = '$' + Number(lastCached.close).toLocaleString('fr-FR', {
            minimumFractionDigits: 2,
          });
        }
        if (S.countdownPriceLine) {
          try { S.countdownPriceLine.applyOptions({ price: lastCached.close }); } catch(e) {}
        }

        _startCountdown();
        _updateCountdownLabel();
        _drawMidnightForWidget(lastCached, false);
      }
    }

    // Annule le timer WS en attente
    if (S.pendingWsTimer) {
      clearTimeout(S.pendingWsTimer);
      S.pendingWsTimer = null;
    }

    // Annule la VWAP en attente
    if (S.pendingVwapTimer) {
      clearTimeout(S.pendingVwapTimer);
      S.pendingVwapTimer = null;
    }

    // Ne pas vider les series pendant un changement rapide :
    // LWC peut encore avoir un render rAF en cours.
    // On remplace les donnees seulement quand le nouveau fetch est pret.

    try {
      var data = await _fetchWidgetCandles(tf, S.fetchAbort.signal);

      if (token !== S.renderToken || tf !== S.timeframe) {
        console.warn('[BTC-WIDGET] stale render ignored after fetch', { token: token, tf: tf });
        return;
      }

      var candles = _normalizeCandles(data.candles || []);
      if (candles.length < 2) return;

      var serverNow = _toValidServerTime(data.serverTime);
      if (Number.isFinite(serverNow) && window.BtcMarketClock) {
        window.BtcMarketClock.sync(serverNow, 'klines-fetch-widget');
      }

      _writeWidgetCache(tf, candles);

      S.candles = candles;
      S.manualPriceRange = null;

      try { _clearIndicators(); } catch(e) {}
      Object.keys(S.vwapSeriesMap || {}).forEach(function (k) {
        try { S.vwapSeriesMap[k].setData([]); } catch(e) {}
      });

      if (S.candleSeries) S.candleSeries.setData(candles);

      if (token !== S.renderToken || tf !== S.timeframe) return;

      applyBtcWidgetBestView();

      var last = candles[candles.length - 1];
      S.lastCandleTime = last.time * 1000;
      var fetchNow = Number.isFinite(serverNow) ? serverNow : (window.BtcMarketClock ? window.BtcMarketClock.now() : Date.now());
      if (!Number.isFinite(fetchNow) || fetchNow <= 0) fetchNow = Date.now();
      _updateCountdownAnchor(last, 'fetch', fetchNow);

      var priceEl = document.getElementById('btcChartPrice');
      if (priceEl) {
        priceEl.textContent = '$' + Number(last.close).toLocaleString('fr-FR', {
          minimumFractionDigits: 2,
        });
      }

      if (S.countdownPriceLine) {
        try { S.countdownPriceLine.applyOptions({ price: last.close }); } catch(e) {}
      }

      _startCountdown();
      _startAutoRefresh();
      _updateCountdownLabel();
      _drawMidnightForWidget(last, false);

      if (token !== S.renderToken || tf !== S.timeframe) return;

      if (S.activeVwapPeriods.length > 0) {
        _scheduleVwapDraw(token, tf);
      }

      if (token !== S.renderToken || tf !== S.timeframe) return;

      _scheduleWsConnect(token, tf);

      if (!S.didPrefetchTfs) {
        S.didPrefetchTfs = true;
        setTimeout(_prefetchWidgetTimeframesIdle, 3000);
      }

    } catch (e) {
      if (e && e.name === 'AbortError') return;
      if (token !== S.renderToken || tf !== S.timeframe) return;
      console.warn('[BTC-WIDGET] render failed:', e);
    }
  }

  // ──────────────────────────────────────────────
  //  INIT
  // ──────────────────────────────────────────────
  document.addEventListener('mousedown', function() { S.userIsInteracting = true; }, { passive: true });
  document.addEventListener('mouseup', function() { S.userIsInteracting = false; }, { passive: true });
  document.addEventListener('touchstart', function() { S.userIsInteracting = true; }, { passive: true });
  document.addEventListener('touchend', function() { S.userIsInteracting = false; }, { passive: true });

  function loadLibrary() {
    var container = document.getElementById('btcChartContainer');
    if (!container) { setTimeout(loadLibrary, 100); return; }
    if (S.chartReady) return;
    if (container.clientHeight < 50) container.style.minHeight = '320px';

    if (typeof window.LightweightCharts !== 'undefined') {
      createBtcWidgetChart(container);
      _fetchAndRender('user');
      return;
    }
    var urls = [
      '/static/vendor/lightweight-charts.standalone.production.js',
      'https://unpkg.com/lightweight-charts@5.0.7/dist/lightweight-charts.standalone.production.js',
      'https://cdn.jsdelivr.net/npm/lightweight-charts@5.0.7/dist/lightweight-charts.standalone.production.js',
      'https://cdnjs.cloudflare.com/ajax/libs/lightweight-charts/5.0.7/lightweight-charts.standalone.production.js',
    ];
    function tryCdn(idx) {
      if (idx >= urls.length) { container.innerHTML = '<div style="padding:20px;text-align:center;color:var(--text-muted);font-size:13px">Impossible de charger le graphique (CDN bloque)</div>'; return; }
      var script = document.createElement('script');
      script.src = urls[idx];
      script.onload = function () { createBtcWidgetChart(container); _fetchAndRender('user'); };
      script.onerror = function () { tryCdn(idx + 1); };
      document.head.appendChild(script);
    }
    tryCdn(0);
  }

  document.addEventListener('DOMContentLoaded', function () { setTimeout(loadLibrary, 50); });

  var _origGoPage = window.goPage;
  if (_origGoPage) {
    window.goPage = function (pageName) {
      _origGoPage(pageName);
      if (pageName === 'today') setTimeout(loadLibrary, 50);
    };
  }

  window.initBtcChart = loadLibrary;
})();

// ---- 061_hyperliquid_market_widget.js ----
// ---------- Hyperliquid markets dashboard widget ----------

(function () {
  var POLL_MS = 12000;
  var selectedMarket = localStorage.getItem("hlMarketWidget:selected") || "BTC";
  var timer = null;
  var loading = false;
  var snapshot = null;

  function $(id) { return document.getElementById(id); }

  function esc(v) {
    if (typeof escapeHtml === "function") return escapeHtml(v == null ? "" : String(v));
    return String(v == null ? "" : v).replace(/[&<>"']/g, function (ch) {
      return ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;" })[ch];
    });
  }

  function fmtNum(v, digits) {
    var n = Number(v);
    if (!Number.isFinite(n)) return "--";
    return n.toLocaleString("en-US", { maximumFractionDigits: digits == null ? 4 : digits });
  }

  function fmtPct(v) {
    var n = Number(v);
    if (!Number.isFinite(n)) return "--";
    return (n * 100).toFixed(4) + "%";
  }

  function setStatus(text, mode) {
    var el = $("hlMarketStatus");
    if (!el) return;
    el.textContent = text;
    el.dataset.mode = mode || "";
  }

  async function getJson(url) {
    var r = await fetch(url);
    var data = await r.json().catch(function () { return null; });
    if (!r.ok || !data) throw new Error((data && data.error) || ("HTTP " + r.status));
    return data;
  }

  async function load(force) {
    if (loading) return;
    loading = true;
    setStatus("sync...", "loading");
    var q = force ? "&force=1" : "";
    try {
      var base = "?market=" + encodeURIComponent(selectedMarket) + q;
      var results = await Promise.allSettled([
        getJson("/api/hyperliquid/catalog" + (force ? "?force=1" : "")),
        getJson("/api/hyperliquid/resolve" + base),
        getJson("/api/hyperliquid/contexts" + base),
        getJson("/api/hyperliquid/orderbook" + base),
        getJson("/api/hyperliquid/trades" + base),
        getJson("/api/hyperliquid/funding" + base),
        getJson("/api/hyperliquid/predicted-funding" + base),
        getJson("/api/hyperliquid/mids" + (force ? "?force=1" : "")),
        getJson("/api/hyperliquid/open-interest-caps" + (force ? "?force=1" : "")),
        getJson("/api/hyperliquid/dexs" + (force ? "?force=1" : "")),
        getJson("/api/hyperliquid/annotations" + (force ? "?force=1" : "")),
      ]);
      snapshot = {
        catalog: value(results[0]),
        resolve: value(results[1]),
        contexts: value(results[2]),
        book: value(results[3]),
        trades: value(results[4]),
        funding: value(results[5]),
        predicted: value(results[6]),
        mids: value(results[7]),
        caps: value(results[8]),
        dexs: value(results[9]),
        annotations: value(results[10]),
        errors: results.filter(function (x) { return x.status === "rejected"; }).map(function (x) { return x.reason && x.reason.message; }),
        updatedAt: Date.now(),
      };
      render();
      setStatus("live " + new Date(snapshot.updatedAt).toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit", second: "2-digit" }), "ok");
    } catch (e) {
      snapshot = { error: e.message || String(e) };
      render();
      setStatus("error", "error");
    } finally {
      loading = false;
    }
  }

  function value(result) {
    return result && result.status === "fulfilled" ? result.value : null;
  }

  function activeContext() {
    var rows = snapshot && snapshot.contexts && Array.isArray(snapshot.contexts.contexts)
      ? snapshot.contexts.contexts
      : [];
    return rows[0] || null;
  }

  function activeCoin() {
    return (snapshot && snapshot.resolve && snapshot.resolve.coin)
      || (activeContext() && activeContext().coin)
      || selectedMarket;
  }

  function activeGlobalMid() {
    var mids = snapshot && snapshot.mids && snapshot.mids.mids ? snapshot.mids.mids : null;
    return mids ? mids[activeCoin()] : null;
  }

  function renderSummary() {
    var coin = $("hlMarketCoin");
    var mark = $("hlMarketMark");
    var funding = $("hlMarketFunding");
    var ctx = activeContext();
    if (coin) coin.textContent = activeCoin();
    if (mark) mark.textContent = fmtNum((ctx && (ctx.markPx || ctx.midPx || ctx.oraclePx)) || activeGlobalMid(), 2);
    if (funding) funding.textContent = fmtPct(ctx && ctx.funding);
  }

  function kv(label, value) {
    return '<div class="hl-market-kv"><span>' + esc(label) + '</span><strong>' + esc(value) + '</strong></div>';
  }

  function renderContext() {
    var ctx = activeContext();
    if (!ctx) return '<div class="hl-market-empty">No context for ' + esc(selectedMarket) + '.</div>';
    return '<div class="hl-market-section"><h4>Context</h4>' +
      '<div class="hl-market-kvgrid">' +
        kv("Mark", fmtNum(ctx.markPx, 2)) +
        kv("Mid", fmtNum(ctx.midPx, 2)) +
        kv("All mids", fmtNum(activeGlobalMid(), 2)) +
        kv("Oracle", fmtNum(ctx.oraclePx, 2)) +
        kv("Funding", fmtPct(ctx.funding)) +
        kv("Open interest", fmtNum(ctx.openInterest, 2)) +
        kv("24h notional", fmtNum(ctx.dayNtlVlm, 0)) +
      '</div></div>';
  }

  function renderBook() {
    var book = snapshot && snapshot.book;
    var bids = book && Array.isArray(book.bids) ? book.bids.slice(0, 5) : [];
    var asks = book && Array.isArray(book.asks) ? book.asks.slice(0, 5) : [];
    function sideRows(rows, side) {
      return rows.map(function (r) {
        return '<div class="hl-market-book-row ' + side + '"><span>' + fmtNum(r.price, 2) + '</span><span>' + fmtNum(r.size, 4) + '</span><span>' + fmtNum(r.n, 0) + '</span></div>';
      }).join("");
    }
    return '<div class="hl-market-section"><h4>L2 Book</h4>' +
      '<div class="hl-market-book-head"><span>Price</span><span>Size</span><span>N</span></div>' +
      sideRows(asks.reverse(), "ask") +
      sideRows(bids, "bid") +
    '</div>';
  }

  function renderTrades() {
    var data = snapshot && snapshot.trades;
    var trades = data && Array.isArray(data.trades) ? data.trades.slice(-8).reverse() : [];
    if (!trades.length) return '<div class="hl-market-section"><h4>Tape</h4><div class="hl-market-empty">No recent trade.</div></div>';
    return '<div class="hl-market-section"><h4>Tape</h4>' + trades.map(function (t) {
      var side = t.side === "buy" ? "buy" : "sell";
      return '<div class="hl-market-trade ' + side + '"><span>' + esc(side.toUpperCase()) + '</span><span>' + fmtNum(t.price, 2) + '</span><span>' + fmtNum(t.size, 4) + '</span></div>';
    }).join("") + '</div>';
  }

  function renderFunding() {
    var funding = snapshot && snapshot.funding && Array.isArray(snapshot.funding.funding) ? snapshot.funding.funding.slice(-5).reverse() : [];
    var predicted = snapshot && snapshot.predicted && Array.isArray(snapshot.predicted.predictedFunding) ? snapshot.predicted.predictedFunding : [];
    var caps = snapshot && snapshot.caps && Array.isArray(snapshot.caps.markets) ? snapshot.caps.markets : [];
    var rows = funding.map(function (f) {
      return '<div class="hl-market-mini-row"><span>' + esc(f.time ? new Date(Number(f.time)).toLocaleString("fr-FR", { day: "2-digit", hour: "2-digit", minute: "2-digit" }) : f.coin || "") + '</span><strong>' + fmtPct(f.fundingRate) + '</strong></div>';
    }).join("");
    var predText = predicted.length ? predicted.map(function (p) { return Array.isArray(p) ? p[0] : ""; }).filter(Boolean).join(", ") : "--";
    var capHit = caps.indexOf(activeCoin()) >= 0 ? "yes" : "no";
    return '<div class="hl-market-section"><h4>Funding / Risk</h4>' +
      '<div class="hl-market-kvgrid">' + kv("Predicted venues", predText) + kv("OI cap", capHit) + '</div>' +
      (rows || '<div class="hl-market-empty">No funding history.</div>') +
    '</div>';
  }

  function renderCatalog() {
    var catalog = snapshot && snapshot.catalog;
    var priority = catalog && catalog.priority ? catalog.priority : {};
    var dexs = snapshot && snapshot.dexs && Array.isArray(snapshot.dexs.dexs) ? snapshot.dexs.dexs : [];
    var annotations = snapshot && snapshot.annotations;
    var annCount = annotations && annotations.annotations
      ? (Array.isArray(annotations.annotations) ? annotations.annotations.length : Object.keys(annotations.annotations).length)
      : 0;
    return '<div class="hl-market-section"><h4>Catalog</h4>' +
      '<div class="hl-market-kvgrid">' +
        kv("Assets", catalog ? catalog.count : "--") +
        kv("DEXs", dexs.length) +
        kv("Annotations", annCount) +
        kv("BTC", priority.BTC && priority.BTC.coin || "--") +
        kv("ES", priority.ES && priority.ES.coin || "--") +
        kv("NASDAQ", priority.NASDAQ && priority.NASDAQ.coin || "--") +
      '</div></div>';
  }

  function render() {
    var main = $("hlMarketMain");
    var side = $("hlMarketSide");
    if (!main || !side) return;
    renderSummary();
    if (!snapshot) {
      main.innerHTML = '<div class="hl-market-empty">Loading Hyperliquid data.</div>';
      side.innerHTML = "";
      return;
    }
    if (snapshot.error) {
      main.innerHTML = '<div class="hl-market-empty is-error">' + esc(snapshot.error) + '</div>';
      side.innerHTML = "";
      return;
    }
    main.innerHTML = renderContext() + renderBook();
    side.innerHTML = renderTrades() + renderFunding() + renderCatalog();
  }

  function bind() {
    document.querySelectorAll("[data-hl-market]").forEach(function (btn) {
      if (btn._hlMarketBound) return;
      btn._hlMarketBound = true;
      btn.addEventListener("click", function () {
        selectedMarket = btn.getAttribute("data-hl-market") || "BTC";
        localStorage.setItem("hlMarketWidget:selected", selectedMarket);
        document.querySelectorAll("[data-hl-market]").forEach(function (b) { b.classList.toggle("active", b === btn); });
        load(true);
      });
      btn.classList.toggle("active", btn.getAttribute("data-hl-market") === selectedMarket);
    });
    var refresh = $("hlMarketRefreshBtn");
    if (refresh && !refresh._hlMarketBound) {
      refresh._hlMarketBound = true;
      refresh.addEventListener("click", function () { load(true); });
    }
  }

  function init() {
    if (!document.querySelector(".hl-market-widget")) return;
    bind();
    render();
    load(false);
    if (!timer) {
      timer = setInterval(function () {
        if (document.body.getAttribute("data-current-page") === "today") load(false);
      }, POLL_MS);
    }
  }

  window.initHyperliquidMarketWidget = init;
  if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", init);
  else setTimeout(init, 0);
})();

// ---- 061_hyperliquid_wallet_widget.js ----
// ---------- Hyperliquid wallets dashboard widget ----------

(function () {
  var POLL_MS = 7000;
  var state = {
    initialized: false,
    loading: false,
    timer: null,
    wallets: [],
    rows: [],
    eventsByWallet: {},
    selectedWalletId: localStorage.getItem("hlWalletWidget:selectedId") || "",
    editingWalletId: "",
    lastError: "",
    liveError: "",
    lastUpdated: 0,
  };

  function $(id) { return document.getElementById(id); }

  function fmtUsd(value) {
    var n = Number(value);
    if (!Number.isFinite(n)) return "--";
    var sign = n > 0 ? "+" : "";
    return sign + "$" + Math.abs(n).toLocaleString("en-US", {
      minimumFractionDigits: Math.abs(n) >= 100 ? 0 : 2,
      maximumFractionDigits: Math.abs(n) >= 100 ? 0 : 2,
    });
  }

  function fmtNum(value, digits) {
    var n = Number(value);
    if (!Number.isFinite(n)) return "--";
    return n.toLocaleString("en-US", { maximumFractionDigits: digits == null ? 4 : digits });
  }

  function shortAddr(address) {
    address = String(address || "");
    if (address.length <= 12) return address;
    return address.slice(0, 6) + "..." + address.slice(-4);
  }

  function normalizeAddressInput(value) {
    var compact = String(value || "").replace(/[\s\u200B-\u200D\uFEFF]/g, "");
    var match = compact.match(/0[xX][a-fA-F0-9]{40}/);
    return match ? match[0].toLowerCase() : "";
  }

  function escape(v) {
    if (typeof escapeHtml === "function") return escapeHtml(v == null ? "" : String(v));
    return String(v == null ? "" : v).replace(/[&<>"']/g, function (ch) {
      return ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#039;" })[ch];
    });
  }

  function setStatus(text, mode) {
    var el = $("hlWalletStatus");
    if (!el) return;
    el.textContent = text;
    el.dataset.mode = mode || "";
  }

  async function readJson(url, opts) {
    var res = await fetch(url, opts || {});
    var data = await res.json().catch(function () { return null; });
    if (!res.ok || !data) {
      var detail = data && data.detail ? " - " + data.detail : "";
      throw new Error(((data && (data.error || data.message)) || ("HTTP " + res.status)) + detail);
    }
    return data;
  }

  async function loadWallets(force) {
    if (state.loading) return;
    state.loading = true;
    setStatus("sync...", "loading");
    try {
      var suffix = force ? "?force=1" : "";
      var data = await readJson("/api/hyperliquid/wallets/state" + suffix);
      state.rows = Array.isArray(data.wallets) ? data.wallets : [];
      state.wallets = state.rows.map(function (r) { return r.wallet; }).filter(Boolean);
      ensureSelectedWallet();
      state.lastError = "";
      state.liveError = Array.isArray(data.errors) && data.errors.length ? data.errors.length + " wallet live state unavailable" : "";
      state.lastUpdated = Date.now();
      await loadEvents(force);
      render();
      setStatus((state.liveError ? "partial " : "live ") + new Date(state.lastUpdated).toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit", second: "2-digit" }), state.liveError ? "loading" : "ok");
    } catch (e) {
      await loadWalletListFallback(e);
    } finally {
      state.loading = false;
    }
  }

  async function loadWalletListFallback(error) {
    try {
      var data = await readJson("/api/hyperliquid/wallets");
      var wallets = Array.isArray(data.wallets) ? data.wallets : [];
      state.rows = wallets.map(function (wallet) {
        return { wallet: wallet, state: null, positions: [], openOrders: [] };
      });
      state.wallets = wallets;
      ensureSelectedWallet();
      state.eventsByWallet = {};
      state.lastError = "";
      state.liveError = "Live state unavailable: " + ((error && error.message) || String(error || "unknown error"));
      state.lastUpdated = Date.now();
      render();
      setStatus("partial", "loading");
    } catch (fallbackError) {
      state.lastError = (fallbackError && fallbackError.message) || (error && error.message) || String(error || fallbackError);
      state.liveError = "";
      render();
      setStatus("error", "error");
    }
  }

  async function loadEvents(force) {
    var active = state.wallets.filter(function (w) { return w && w.is_active; }).slice(0, 24);
    var pairs = await Promise.all(active.map(function (wallet) {
      var url = "/api/hyperliquid/wallets/" + wallet.id + "/events?limit=8" + (force ? "&force=1" : "");
      return readJson(url).then(function (data) {
        return [wallet.id, Array.isArray(data.events) ? data.events : []];
      }).catch(function () { return [wallet.id, []]; });
    }));
    state.eventsByWallet = {};
    pairs.forEach(function (pair) { state.eventsByWallet[pair[0]] = pair[1]; });
  }

  async function addWallet(address, label) {
    await readJson("/api/hyperliquid/wallets", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ address: address, label: label }),
    });
    await loadWallets(true);
  }

  async function updateWallet(id, address, label) {
    await readJson("/api/hyperliquid/wallets/" + id, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ address: address, label: label }),
    });
    state.editingWalletId = "";
    await loadWallets(true);
  }

  async function deleteWallet(id) {
    await readJson("/api/hyperliquid/wallets/" + id, { method: "DELETE" });
    if (String(state.selectedWalletId) === String(id)) {
      state.selectedWalletId = "";
      localStorage.removeItem("hlWalletWidget:selectedId");
    }
    await loadWallets(true);
  }

  function ensureSelectedWallet() {
    var rows = state.rows || [];
    if (!rows.length) {
      state.selectedWalletId = "";
      localStorage.removeItem("hlWalletWidget:selectedId");
      return;
    }
    var found = rows.some(function (row) {
      return row.wallet && String(row.wallet.id) === String(state.selectedWalletId);
    });
    if (!found) {
      state.selectedWalletId = String(rows[0].wallet && rows[0].wallet.id || "");
      if (state.selectedWalletId) localStorage.setItem("hlWalletWidget:selectedId", state.selectedWalletId);
    }
  }

  function selectedRow() {
    ensureSelectedWallet();
    return (state.rows || []).find(function (row) {
      return row.wallet && String(row.wallet.id) === String(state.selectedWalletId);
    }) || null;
  }

  function positionHtml(pos) {
    var side = pos.side || "flat";
    var cls = side === "long" ? "is-long" : side === "short" ? "is-short" : "";
    var pnl = Number(pos.unrealizedPnl);
    var pnlCls = pnl > 0 ? "is-profit" : pnl < 0 ? "is-loss" : "";
    return '<div class="hl-position ' + cls + '">' +
      '<div class="hl-position-main">' +
        '<span class="hl-coin">' + escape(pos.coin || "--") + '</span>' +
        '<span class="hl-side">' + escape(side.toUpperCase()) + '</span>' +
        '<span class="hl-size">' + fmtNum(pos.absSize, 5) + '</span>' +
      '</div>' +
      '<div class="hl-position-meta">' +
        '<span>Entry ' + fmtNum(pos.entryPx, 2) + '</span>' +
        '<span>Value ' + fmtUsd(pos.positionValue) + '</span>' +
        '<span class="' + pnlCls + '">' + fmtUsd(pos.unrealizedPnl) + '</span>' +
      '</div>' +
    '</div>';
  }

  function orderHtml(order) {
    return '<div class="hl-order">' +
      '<span>' + escape(order.coin || "--") + '</span>' +
      '<span>' + escape((order.side || "").toUpperCase()) + '</span>' +
      '<span>' + fmtNum(order.size, 5) + " @ " + fmtNum(order.limitPx, 2) + '</span>' +
    '</div>';
  }

  function walletTabHtml(row) {
    var wallet = row.wallet || {};
    var positions = Array.isArray(row.positions) ? row.positions : [];
    var orders = Array.isArray(row.openOrders) ? row.openOrders : [];
    var label = wallet.label || shortAddr(wallet.address);
    var upnl = positions.reduce(function (sum, pos) {
      var n = Number(pos.unrealizedPnl);
      return sum + (Number.isFinite(n) ? n : 0);
    }, 0);
    var pnlCls = upnl > 0 ? "is-profit" : upnl < 0 ? "is-loss" : "";
    var selected = String(wallet.id) === String(state.selectedWalletId);
    var editing = String(wallet.id) === String(state.editingWalletId);

    return '<div class="hl-wallet-tab-wrap ' + (selected ? "active" : "") + (editing ? " is-editing" : "") + '">' +
      '<button type="button" class="hl-wallet-tab" data-hl-select="' + wallet.id + '">' +
        '<strong>' + escape(label) + '</strong>' +
        '<span>' + positions.length + ' pos</span>' +
        '<em class="' + pnlCls + '">' + (positions.length ? fmtUsd(upnl) : "--") + '</em>' +
        (orders.length ? '<small>' + orders.length + ' orders</small>' : "") +
      '</button>' +
      '<button type="button" class="hl-wallet-edit-btn" data-hl-edit="' + wallet.id + '" title="Edit wallet">' +
        '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.1" stroke-linecap="round" stroke-linejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.1 2.1 0 0 1 3 3L7 19l-4 1 1-4 12.5-12.5z"/></svg>' +
      '</button>' +
    '</div>';
  }

  function renderWalletEditor() {
    if (!state.editingWalletId) return "";
    var row = (state.rows || []).find(function (r) {
      return r.wallet && String(r.wallet.id) === String(state.editingWalletId);
    });
    if (!row || !row.wallet) return "";
    var wallet = row.wallet;
    return '<form class="hl-wallet-edit-panel" id="hlWalletEditForm" data-wallet-id="' + wallet.id + '">' +
      '<input type="text" id="hlWalletEditLabel" value="' + escape(wallet.label || "") + '" placeholder="Label">' +
      '<input type="text" id="hlWalletEditAddress" value="' + escape(wallet.address || "") + '" spellcheck="false" placeholder="0x wallet address">' +
      '<button type="submit" class="btn-primary">Save</button>' +
      '<button type="button" class="hl-wallet-delete-action" data-hl-delete="' + wallet.id + '">Delete</button>' +
      '<button type="button" class="hl-wallet-cancel-action" data-hl-cancel-edit="1">Cancel</button>' +
    '</form>';
  }

  function renderWalletDetail() {
    var row = selectedRow();
    if (!row) return '<div class="hl-empty-panel">Select a wallet.</div>';
    var wallet = row.wallet || {};
    var positions = Array.isArray(row.positions) ? row.positions : [];
    var orders = Array.isArray(row.openOrders) ? row.openOrders : [];
    var label = wallet.label || shortAddr(wallet.address);
    var posHtml = positions.length
      ? positions.map(positionHtml).join("")
      : '<div class="hl-empty-line">No open position</div>';
    var orderBlock = orders.length
      ? '<div class="hl-orders"><h4>Open orders</h4>' + orders.map(orderHtml).join("") + '</div>'
      : "";

    return '<section class="hl-wallet-detail-card">' +
      '<div class="hl-wallet-detail-head">' +
        '<div class="hl-wallet-id">' +
          '<strong>' + escape(label) + '</strong>' +
          '<span>' + escape(wallet.address || "") + '</span>' +
        '</div>' +
        '<div class="hl-wallet-detail-actions">' +
          '<strong>' + positions.length + ' positions</strong>' +
          '<button type="button" class="hl-wallet-delete" data-hl-delete="' + wallet.id + '" title="Remove">&times;</button>' +
        '</div>' +
      '</div>' +
      '<div class="hl-positions">' + posHtml + '</div>' +
      orderBlock +
    '</section>';
  }

  function eventHtml(event, wallet) {
    var type = event.type || "event";
    var cls = type.indexOf("close") >= 0 || type.indexOf("partial") >= 0 ? "is-close" : type.indexOf("open") >= 0 ? "is-open" : "";
    var label = event.label || type;
    var who = wallet ? (wallet.label || shortAddr(wallet.address)) : "";
    return '<div class="hl-event ' + cls + '">' +
      '<div><strong>' + escape(event.coin || "--") + '</strong><span>' + escape(label.replace(/_/g, " ")) + '</span></div>' +
      '<div><span>' + escape(who) + '</span><span>' + fmtNum(event.size, 5) + (event.price ? " @ " + fmtNum(event.price, 2) : "") + '</span></div>' +
    '</div>';
  }

  function renderEvents() {
    var events = [];
    var byId = {};
    state.wallets.forEach(function (w) { byId[w.id] = w; });
    var ids = state.selectedWalletId ? [String(state.selectedWalletId)] : Object.keys(state.eventsByWallet);
    ids.forEach(function (id) {
      (state.eventsByWallet[id] || []).forEach(function (event) {
        events.push({ wallet: byId[id], event: event });
      });
    });
    events.sort(function (a, b) { return Number(b.event.time || 0) - Number(a.event.time || 0); });
    if (!events.length) return '<div class="hl-empty-panel">No recent wallet event.</div>';
    return events.slice(0, 10).map(function (x) { return eventHtml(x.event, x.wallet); }).join("");
  }

  function render() {
    var tabs = $("hlWalletTabs");
    var detail = $("hlWalletDetail");
    var events = $("hlWalletEvents");
    var countEl = $("hlWalletCount");
    var posCountEl = $("hlPositionCount");
    var upnlEl = $("hlWalletUpnl");
    if (!tabs || !detail || !events) return;

    var rows = state.rows || [];
    var allPositions = [];
    rows.forEach(function (r) { allPositions = allPositions.concat(Array.isArray(r.positions) ? r.positions : []); });
    var upnl = allPositions.reduce(function (sum, pos) {
      var n = Number(pos.unrealizedPnl);
      return sum + (Number.isFinite(n) ? n : 0);
    }, 0);

    if (countEl) countEl.textContent = String(rows.length);
    if (posCountEl) posCountEl.textContent = String(allPositions.length);
    if (upnlEl) {
      upnlEl.textContent = allPositions.length ? fmtUsd(upnl) : "--";
      upnlEl.className = upnl > 0 ? "is-profit" : upnl < 0 ? "is-loss" : "";
    }

    if (state.lastError) {
      tabs.innerHTML = '<div class="hl-empty-panel is-error">' + escape(state.lastError) + '</div>';
      detail.innerHTML = "";
      events.innerHTML = "";
      return;
    }

    var liveBanner = state.liveError ? '<div class="hl-empty-panel is-warning">' + escape(state.liveError) + '</div>' : "";
    var editorSlot = $("hlWalletEditorSlot");
    tabs.innerHTML = liveBanner + (rows.length ? rows.map(walletTabHtml).join("") : '<div class="hl-empty-panel">Add a wallet to start tracking positions.</div>');
    if (editorSlot) editorSlot.innerHTML = rows.length ? renderWalletEditor() : "";
    detail.innerHTML = rows.length ? renderWalletDetail() : "";
    events.innerHTML = renderEvents();
  }

  function bind() {
    var form = $("hlWalletForm");
    var refresh = $("hlWalletRefreshBtn");
    var tabs = $("hlWalletTabs");
    var editorSlot = $("hlWalletEditorSlot");
    var detail = $("hlWalletDetail");
    if (form && !form._hlBound) {
      form._hlBound = true;
      form.addEventListener("submit", async function (e) {
        e.preventDefault();
        var address = $("hlWalletAddressInput");
        var label = $("hlWalletLabelInput");
        var normalized = normalizeAddressInput(address && address.value);
        if (!address || !normalized) {
          state.lastError = "Adresse Hyperliquid invalide";
          state.liveError = "";
          render();
          setStatus("error", "error");
          return;
        }
        try {
          await addWallet(normalized, label ? label.value.trim() : "");
          address.value = "";
          if (label) label.value = "";
        } catch (err) {
          state.lastError = err.message || String(err);
          state.liveError = "";
          render();
          setStatus("error", "error");
        }
      });
    }
    if (refresh && !refresh._hlBound) {
      refresh._hlBound = true;
      refresh.addEventListener("click", function () { loadWallets(true); });
    }
    if (tabs && !tabs._hlBound) {
      tabs._hlBound = true;
      tabs.addEventListener("click", function (e) {
        var edit = e.target.closest("[data-hl-edit]");
        if (edit) {
          e.preventDefault();
          state.editingWalletId = String(edit.getAttribute("data-hl-edit") || "");
          state.selectedWalletId = state.editingWalletId;
          if (state.selectedWalletId) localStorage.setItem("hlWalletWidget:selectedId", state.selectedWalletId);
          render();
          return;
        }
        var select = e.target.closest("[data-hl-select]");
        if (!select) return;
        e.preventDefault();
        state.selectedWalletId = String(select.getAttribute("data-hl-select") || "");
        if (state.selectedWalletId) localStorage.setItem("hlWalletWidget:selectedId", state.selectedWalletId);
        render();
      });
    }
    if (editorSlot && !editorSlot._hlBound) {
      editorSlot._hlBound = true;
      editorSlot.addEventListener("click", function (e) {
        var cancel = e.target.closest("[data-hl-cancel-edit]");
        if (!cancel) return;
        e.preventDefault();
        state.editingWalletId = "";
        render();
      });
      editorSlot.addEventListener("submit", async function (e) {
        var editForm = e.target.closest("#hlWalletEditForm");
        if (!editForm) return;
        e.preventDefault();
        var address = $("hlWalletEditAddress");
        var label = $("hlWalletEditLabel");
        var normalized = normalizeAddressInput(address && address.value);
        if (!normalized) {
          state.lastError = "Adresse Hyperliquid invalide";
          render();
          setStatus("error", "error");
          return;
        }
        try {
          await updateWallet(editForm.getAttribute("data-wallet-id"), normalized, label ? label.value.trim() : "");
        } catch (err) {
          state.lastError = err.message || String(err);
          render();
          setStatus("error", "error");
        }
      });
      editorSlot.addEventListener("click", async function (e) {
        var btn = e.target.closest(".hl-wallet-delete-action[data-hl-delete]");
        if (!btn) return;
        e.preventDefault();
        if (!confirm("Supprimer ce wallet Hyperliquid ?")) return;
        await deleteWallet(btn.getAttribute("data-hl-delete"));
      });
    }
    if (detail && !detail._hlBound) {
      detail._hlBound = true;
      detail.addEventListener("click", async function (e) {
        var btn = e.target.closest("[data-hl-delete]");
        if (!btn) return;
        e.preventDefault();
        await deleteWallet(btn.getAttribute("data-hl-delete"));
      });
    }
  }

  function init() {
    var root = document.querySelector(".hl-wallet-widget");
    if (!root) return;
    bind();
    if (!state.initialized) {
      state.initialized = true;
      loadWallets(false);
      state.timer = setInterval(function () {
        if (document.body.getAttribute("data-current-page") === "today") loadWallets(false);
      }, POLL_MS);
    } else {
      render();
    }
  }

  window.initHyperliquidWalletWidget = init;
  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    setTimeout(init, 0);
  }
})();

// ---- 062_chart_page.js ----
// ---------- Chart page — TradingView Lightweight Charts XXL ----------
// v2.0 — Indicators: SMA, EMA, Bollinger, RSI + Settings panel

(function () {
  var chart = null;
  var candlestickSeries = null;
  var volumeSeries = null;

  // Indicator series
  var indicatorSeries = {};
  var rsiSeries = null;
  var rsiPaneId = 'rsi_pane';

  // VWAP (multi-periode)
  var vwapSeriesMap = {};
  var activeVwapPeriods = [];
  try {
    var savedVwap = JSON.parse(localStorage.getItem('chartVwapPeriods'));
    if (Array.isArray(savedVwap)) activeVwapPeriods = savedVwap.filter(function(p) { return window.BtcVwap && window.BtcVwap.VWAP_SOURCE_CONFIG && window.BtcVwap.VWAP_SOURCE_CONFIG[p]; });
  } catch(e) {}
  var VWAP_COLORS = { '1D': '#f59e0b', '7D': '#06b6d4', '30D': '#a78bfa', '90D': '#f472b6', '365D': '#22c55e' };

  // State
  var countdownPriceLine = null;
  var currentInterval = localStorage.getItem('chartDefInterval') || '3m';
  var currentSymbol = localStorage.getItem('chartDefSymbol') || 'BTCUSDT';
  var chartStyle = localStorage.getItem('chartDefStyle') || 'candlestick';
  var countdownTimer = null;
  var countdownAnchor = null;
  var lastCandleTime = 0;
  var lastCountdownFetchAt = 0;
  var lastPrice = 0;
  var manualPriceRange = null;
  var resizeObserver = null;
  var refreshTimer = null;
  var ws = null;
  var wsGeneration = 0;
  var wsClosing = false;
  var wsReconnectTimer = null;
  var wsReconnectAttempts = 0;
  var wsConnected = false;
  var wsError = false;
  var lastWsConnectAt = 0;
  var activeWsKey = null;

  // Guards anti-boucle
  var chartReady = false;
  var _isFetching = false;

  function _numRequired(v) {
    if (v === null || v === undefined || v === '') return NaN;
    var n = Number(v);
    return Number.isFinite(n) ? n : NaN;
  }

  function _numOptional(v, fallback) {
    if (v === null || v === undefined || v === '') return fallback;
    var n = Number(v);
    return Number.isFinite(n) ? n : fallback;
  }

  function _normalizeChartCandles(rows) {
    var byTime = {};

    (rows || []).forEach(function (c) {
      if (!c) return;

      var rawTime = c.time != null ? c.time : (c.openTime != null ? c.openTime : c.t);
      var time = _numRequired(rawTime);
      if (time > 1e12) time = Math.floor(time / 1000);

      var open = _numRequired(c.open);
      var high = _numRequired(c.high);
      var low = _numRequired(c.low);
      var close = _numRequired(c.close);
      var volume = _numOptional(c.volume, 0);

      if (!Number.isFinite(time) || time <= 0) return;
      if (!Number.isFinite(open) || !Number.isFinite(high) || !Number.isFinite(low) || !Number.isFinite(close)) return;

      if (high < low) return;
      if (high < Math.max(open, close)) return;
      if (low > Math.min(open, close)) return;

      byTime[time] = {
        time: time,
        open: open,
        high: high,
        low: low,
        close: close,
        volume: volume,
      };
    });

    return Object.keys(byTime)
      .map(function (t) { return byTime[t]; })
      .sort(function (a, b) { return a.time - b.time; });
  }
  var _lastFetchTs = 0;
  var _FETCH_COOLDOWN_MS = 5000;

  // Flag interaction utilisateur (evite override WS pendant scroll)
  var _userIsInteracting = false;
  // Timestamp du premier fetch (evite de sauvegarder un zoom pas encore stabilise)
  var _firstFetchMs = 0;

  // ── Helper rAF ──
  function _waitFrame() {
    return new Promise(function (resolve) { requestAnimationFrame(resolve); });
  }

  // ── Programmatic range guard (emprunté à 060) ──
  var _programmaticRangeDepth = 0;
  var _suppressRangeEventsUntil = 0;
  function _withProgrammaticRange(fn) {
    _programmaticRangeDepth++;
    _suppressRangeEventsUntil = performance.now() + 250;
    try { fn(); } finally {
      requestAnimationFrame(function () {
        requestAnimationFrame(function () {
          _programmaticRangeDepth = Math.max(0, _programmaticRangeDepth - 1);
          _suppressRangeEventsUntil = performance.now() + 100;
        });
      });
    }
  }

  // ── Compat LWC v4/v5 ──
  function _addCandleSeries(api, opts) {
    if (typeof api.addSeries === 'function') return api.addSeries(window.LightweightCharts.CandlestickSeries, opts);
    return api.addCandlestickSeries(opts);
  }
  function _addLineSeries(api, opts) {
    if (typeof api.addSeries === 'function') return api.addSeries(window.LightweightCharts.LineSeries, opts);
    return api.addLineSeries(opts);
  }
  function _addHistogramSeries(api, opts) {
    if (typeof api.addSeries === 'function') return api.addSeries(window.LightweightCharts.HistogramSeries, opts);
    return api.addHistogramSeries(opts);
  }
  function _addAreaSeries(api, opts) {
    if (typeof api.addSeries === 'function') return api.addSeries(window.LightweightCharts.AreaSeries, opts);
    return api.addAreaSeries(opts);
  }

  // ── INDICATOR CALCULATIONS ──
  function _applyChartBestView(savedTarget, keepZoom, candles) {
    if (!chart || !chart.timeScale()) return;
    if (!candles || !candles.length) return;

    _withProgrammaticRange(function () {
      // Calculer le range logique
      var logicalAfter;
      try { logicalAfter = chart.timeScale().getVisibleLogicalRange(); } catch(e) {}
      if (!logicalAfter) return;
      var totalLogical = Math.round(logicalAfter.to);

      if (savedTarget && totalLogical > 100) {
        // Zoom préservé du rendu précédent
        var nb = Math.min(100, totalLogical);
        chart.timeScale().setVisibleLogicalRange({ from: totalLogical - nb, to: totalLogical });
      } else if (!keepZoom && candles && candles.length) {
        // Premier chargement ou changement de timeframe — basé sur les nouvelles données, pas le range courant
        var tf = currentInterval || '3m';
        var focusBars = (window.ChartViewCore.CHART_VIEW.visibleBars || {})[tf] || 120;
        var nb = Math.min(focusBars, candles.length);
        var lastIdx = candles.length - 1;
        var vpState = window.VolumeProfile && window.VolumeProfile.getSettings ? window.VolumeProfile.getSettings() : { active: true };
        var rightPad = vpState.active ? Math.max(42, Math.round(nb * 0.30)) : Math.max(6, Math.min(18, Math.round(nb * 0.08)));
        chart.timeScale().setVisibleLogicalRange({ from: Math.max(0, lastIdx - nb + 1), to: lastIdx + rightPad });
      }

      // Y — price range via ChartViewCore (si disponible)
      if (window.ChartViewCore && candles && candles.length) {
        var tf = currentInterval || '3m';
        var vb = (window.ChartViewCore.CHART_VIEW.visibleBars || {})[tf] || 120;
        var padding = window.ChartViewCore.CHART_VIEW.padding || { top: 0.22, bottom: 0.18, minRangeRatio: 0.0025 };
        var priceRange = window.ChartViewCore.computePriceRange(candles, vb, padding);
        if (candlestickSeries) {
          var ps;
          try { ps = candlestickSeries.priceScale(); } catch(e) {}
          if (ps) window.ChartViewCore.setPriceRange(ps, priceRange, {
            get value() { return manualPriceRange; },
            set value(v) { manualPriceRange = v; },
          });
        }
      }
    });
  }

  // Settings state
  var indSettings = {
    sma: { active: false, period: 20, color: '#f59e0b' },
    ema: { active: false, period: 20, color: '#06b6d4' },
    boll: { active: false, period: 20, color: '#a78bfa' },
    rsi: { active: false, period: 14, color: '#f472b6' },
  };

  // Load saved settings
  try {
    var savedInd = JSON.parse(localStorage.getItem('chartIndSettings'));
    if (savedInd) {
      Object.keys(savedInd).forEach(function (k) {
        if (indSettings[k]) Object.assign(indSettings[k], savedInd[k]);
      });
    }
  } catch(e) {}

  var INTERVAL_MS = {
    '1m': 60000, '3m': 180000, '5m': 300000, '15m': 900000,
    '30m': 1800000, '1h': 3600000, '2h': 7200000, '4h': 14400000,
    '6h': 21600000, '8h': 28800000, '12h': 43200000,
    '1d': 86400000, '3d': 259200000, '1w': 604800000, '1M': 2592000000,
  };

  var PAIR_NAMES = { 'BTCUSDT': 'BTC/USDT', 'ETHUSDT': 'ETH/USDT' };
  function getPairName(s) { return PAIR_NAMES[s] || s; }
  function _hyperliquidCoin() {
    return String(currentSymbol || 'BTCUSDT').replace(/USDT$/i, '').toUpperCase();
  }

  // ── INDICATOR CALCULATIONS ──

  function calcSMA(candles, period) {
    var result = [], sum = 0;
    for (var i = 0; i < candles.length; i++) {
      sum += candles[i].close;
      if (i >= period) sum -= candles[i - period].close;
      if (i >= period - 1) result.push({ time: candles[i].time, value: sum / period });
    }
    return result;
  }

  function calcEMA(candles, period) {
    var result = [];
    var k = 2 / (period + 1);
    // Warmup : SMA des period premieres bougies
    var ema = 0;
    for (var w = 0; w < period; w++) ema += candles[w].close;
    ema /= period;
    for (var i = 0; i < candles.length; i++) {
      ema = (candles[i].close - ema) * k + ema;
      if (i >= period - 1) result.push({ time: candles[i].time, value: ema });
    }
    return result;
  }

  function calcBollinger(candles, period) {
    var smaData = calcSMA(candles, period);
    var result = [];
    for (var i = 0; i < smaData.length; i++) {
      var idx = i + period - 1;
      var sumSq = 0;
      for (var j = 0; j < period; j++) {
        var diff = candles[idx - j].close - smaData[i].value;
        sumSq += diff * diff;
      }
      var std = Math.sqrt(sumSq / period);
      result.push({
        time: smaData[i].time,
        middle: smaData[i].value,
        upper: smaData[i].value + 2 * std,
        lower: smaData[i].value - 2 * std,
      });
    }
    return result;
  }

  function calcRSI(candles, period) {
    if (candles.length < period + 1) return [];
    var gains = [], losses = [];
    for (var i = 1; i < candles.length; i++) {
      var diff = candles[i].close - candles[i - 1].close;
      gains.push(diff > 0 ? diff : 0);
      losses.push(diff < 0 ? -diff : 0);
    }
    var avgGain = 0, avgLoss = 0;
    for (var j = 0; j < period; j++) {
      avgGain += gains[j];
      avgLoss += losses[j];
    }
    avgGain /= period;
    avgLoss /= period;

    var result = [];
    // First RSI starts at index 'period' in gains/losses (candle index = period)
    var rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
    result.push({ time: candles[period].time, value: 100 - (100 / (1 + rs)) });

    for (var k = period; k < gains.length; k++) {
      avgGain = (avgGain * (period - 1) + gains[k]) / period;
      avgLoss = (avgLoss * (period - 1) + losses[k]) / period;
      rs = avgLoss === 0 ? 100 : avgGain / avgLoss;
      result.push({ time: candles[k + 1].time, value: 100 - (100 / (1 + rs)) });
    }
    return result;
  }

  function _clearIndicators() {
    if (!chart) return;
    Object.keys(indicatorSeries).forEach(function (key) {
      try { chart.removeSeries(indicatorSeries[key]); } catch(e) {}
    });
    indicatorSeries = {};
    if (rsiSeries) {
      try { chart.removeSeries(rsiSeries); } catch(e) {}
      rsiSeries = null;
    }
  }

  function _renderIndicators(candles) {
    _clearIndicators();
    if (!chart || !candles || !candles.length) return;

    var s = indSettings;

    // SMA
    if (s.sma.active && candles.length >= s.sma.period) {
      var smaData = calcSMA(candles, s.sma.period);
      indicatorSeries.sma = _addLineSeries(chart, {
        color: s.sma.color, lineWidth: 1.5, priceLineVisible: false,
        lastValueVisible: true, crosshairMarkerVisible: false,
        title: 'SMA ' + s.sma.period,
      });
      indicatorSeries.sma.setData(smaData);
    }

    // EMA
    if (s.ema.active && candles.length >= s.ema.period) {
      var emaData = calcEMA(candles, s.ema.period);
      indicatorSeries.ema = _addLineSeries(chart, {
        color: s.ema.color, lineWidth: 1.5, priceLineVisible: false,
        lastValueVisible: true, crosshairMarkerVisible: false,
        title: 'EMA ' + s.ema.period,
      });
      indicatorSeries.ema.setData(emaData);
    }

    // Bollinger
    if (s.boll.active && candles.length >= s.boll.period) {
      var bollData = calcBollinger(candles, s.boll.period);
      indicatorSeries.bollMid = _addLineSeries(chart, {
        color: s.boll.color, lineWidth: 1, priceLineVisible: false,
        lastValueVisible: true, crosshairMarkerVisible: false,
        title: 'BB ' + s.boll.period,
      });
      indicatorSeries.bollUpper = _addLineSeries(chart, {
        color: s.boll.color, lineWidth: 1, priceLineVisible: false,
        lastValueVisible: false, crosshairMarkerVisible: false, lineStyle: 2,
      });
      indicatorSeries.bollLower = _addLineSeries(chart, {
        color: s.boll.color, lineWidth: 1, priceLineVisible: false,
        lastValueVisible: false, crosshairMarkerVisible: false, lineStyle: 2,
      });
      indicatorSeries.bollMid.setData(bollData.map(function (d) { return { time: d.time, value: d.middle }; }));
      indicatorSeries.bollUpper.setData(bollData.map(function (d) { return { time: d.time, value: d.upper }; }));
      indicatorSeries.bollLower.setData(bollData.map(function (d) { return { time: d.time, value: d.lower }; }));
    }

    // RSI (separate pane)
    if (s.rsi.active && candles.length >= s.rsi.period + 1) {
      try {
        rsiSeries = _addLineSeries(chart, {
          color: s.rsi.color, lineWidth: 1.5, priceLineVisible: false,
          lastValueVisible: true, crosshairMarkerVisible: false,
          priceScaleId: rsiPaneId,
          title: 'RSI ' + s.rsi.period,
        });
        chart.priceScale(rsiPaneId).applyOptions({
          scaleMargins: { top: 0.7, bottom: 0 },
          visible: true,
        });
        var rsiData = calcRSI(candles, s.rsi.period);
        rsiSeries.setData(rsiData);
      } catch(e) {
        console.error('[chart] RSI pane error:', e);
      }
    }
  }

  // ── WEBSOCKET — Architecture générationnelle ──

  function _getWsKey() {
    return (currentSymbol || 'BTCUSDT') + ':' + (currentInterval || '3m');
  }

  function _disconnectWs(reason) {
    wsGeneration++;
    if (wsReconnectTimer) { clearTimeout(wsReconnectTimer); wsReconnectTimer = null; }
    wsConnected = false;
    wsClosing = true;
    var old = ws;
    ws = null;
    activeWsKey = null;
    if (old) {
      try {
        old.onopen = null;
        old.onmessage = null;
        old.onerror = null;
        old.onclose = null;
        if (old.readyState === WebSocket.OPEN || old.readyState === WebSocket.CONNECTING) {
          old.close(1000, reason || 'intentional');
        }
      } catch(e) { console.warn('[chart][WS] close error', e); }
    }
    setTimeout(function () { wsClosing = false; }, 500);
  }

  function _connectWs(reason, opts) {
    opts = opts || {};
    var force = !!opts.force;
    var wsKey = _getWsKey();
    var now = Date.now();

    if (ws && activeWsKey === wsKey) {
      var alive = ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING;
      if (alive) return;
    }

    if (!force && now - lastWsConnectAt < 10000) return;
    lastWsConnectAt = now;

    wsGeneration++;
    var generation = wsGeneration;

    if (wsReconnectTimer) { clearTimeout(wsReconnectTimer); wsReconnectTimer = null; }

    var stream = currentSymbol.toLowerCase() + '@kline_' + currentInterval;
    var url = 'wss://stream.binance.com:9443/ws/' + stream;

    wsClosing = false;
    wsError = false;
    wsConnected = false;
    activeWsKey = wsKey;

    var newWs = new WebSocket(url);
    ws = newWs;

    newWs.onopen = function () {
      if (generation !== wsGeneration || newWs !== ws) return;
      wsConnected = true;
      wsError = false;
      wsReconnectAttempts = 0;
    };

    newWs.onmessage = function (event) {
      if (generation !== wsGeneration || newWs !== ws) return;
      try { _handleWsMessage(event.data); } catch(e) { console.warn('[chart][WS] msg', e); }
    };

    newWs.onclose = function (event) {
      if (generation !== wsGeneration || newWs !== ws) return;
      wsConnected = false;
      if (wsClosing || event.code === 1000 || event.code === 1001) return;
      wsError = true;
      _scheduleWsReconnect('unexpected-close');
    };

    newWs.onerror = function () {
      if (generation !== wsGeneration || newWs !== ws) return;
      wsError = true;
    };
  }

  function _scheduleWsReconnect(reason) {
    if (wsReconnectTimer) return;
    wsReconnectAttempts = Math.min((wsReconnectAttempts || 0) + 1, 6);
    var delay = Math.min(60000, 2000 * Math.pow(2, wsReconnectAttempts - 1));
    wsReconnectTimer = setTimeout(function () {
      wsReconnectTimer = null;
      _connectWs('reconnect:' + reason);
    }, delay);
  }

  function _handleWsMessage(raw) {
    var d = JSON.parse(raw);
    var k = d && d.k;
    if (!k) return;

    var rawCandle = {
      time: Math.floor(k.t / 1000),
      openTime: k.t,
      closeTime: k.T,
      open: k.o,
      high: k.h,
      low: k.l,
      close: k.c,
      volume: k.v,
    };

    var candle = _normalizeLiveChartCandle(rawCandle);
    if (!candle) {
      console.warn('[chart][WS] invalid candle ignored', {
        interval: currentInterval,
        raw: rawCandle,
      });
      return;
    }

    lastPrice = candle.close;
    var priceEl = document.getElementById('chartPrice');
    if (priceEl) priceEl.textContent = '$' + candle.close.toLocaleString('fr-FR', { minimumFractionDigits: 2 });
    lastCandleTime = k.t;

    var eventMs = Number(d.E);
    if (window.BtcMarketClock && Number.isFinite(eventMs)) {
      window.BtcMarketClock.sync(eventMs, 'ws-event');
    }
    _updateCountdownAnchor(candle, 'ws', Number.isFinite(eventMs) ? eventMs : undefined);
    if (candlestickSeries) {
      try {
        if (chartStyle === 'candlestick') {
          candlestickSeries.update(candle);
        } else {
          candlestickSeries.update({ time: candle.time, value: candle.close });
        }
      } catch(e) {}
      if (volumeSeries) {
        try { volumeSeries.update({ time: candle.time, value: candle.volume, color: candle.close >= candle.open ? 'rgba(34,197,94,0.3)' : 'rgba(239,68,68,0.3)' }); } catch(e) {}
      }
    }
    if (countdownPriceLine) {
      try { countdownPriceLine.applyOptions({ price: candle.close }); } catch(e) {}
    }
  }

  function _getIntervalMs(interval) {
    var m = INTERVAL_MS[interval];
    if (m) return m;
    var match = interval.match(/^(\d+)(m|h|d|w|M)$/);
    if (!match) return 3600000;
    var num = parseInt(match[1], 10);
    var unit = match[2];
    var mult = { m: 60000, h: 3600000, d: 86400000, w: 604800000, M: 2592000000 };
    return num * (mult[unit] || 3600000);
  }

  function _loadLibrary(cb) {
    if (typeof window.LightweightCharts !== 'undefined') { cb(); return; }
    var urls = [
      '/static/vendor/lightweight-charts.standalone.production.js',
      'https://unpkg.com/lightweight-charts@5.0.7/dist/lightweight-charts.standalone.production.js',
      'https://cdn.jsdelivr.net/npm/lightweight-charts@5.0.7/dist/lightweight-charts.standalone.production.js',
    ];
    function tryCdn(idx) {
      if (idx >= urls.length) { console.error('[chart] CDN indisponible'); return; }
      var s = document.createElement('script');
      s.src = urls[idx];
      s.onload = cb;
      s.onerror = function () { tryCdn(idx + 1); };
      document.head.appendChild(s);
    }
    tryCdn(0);
  }

  function initChartPage() {
    var container = document.getElementById('chartCanvas');
    if (!container) return;
    if (chart) {
      _fetchAndRender(true, 'user');
      return;
    }

    // Interaction listeners pour _userIsInteracting
    function _onInteractStart() { _userIsInteracting = true; }
    function _onInteractEnd() { _userIsInteracting = false; }
    document.addEventListener('mousedown', _onInteractStart, { passive: true });
    document.addEventListener('mouseup', _onInteractEnd, { passive: true });
    document.addEventListener('touchstart', _onInteractStart, { passive: true });
    document.addEventListener('touchend', _onInteractEnd, { passive: true });

    _loadLibrary(function () {
      _createChart(container);
      _fetchAndRender(false, 'user');
    });
  }

  function _createChart(container) {
    if (chart) return;
    var wrap = document.getElementById('chartCanvasWrap');
    if (!wrap) return;

    // The analytics workspace is deliberately dark regardless of journal theme.
    var isLight = false;
    var w = container.clientWidth || wrap.clientWidth || 900;
    var h = container.clientHeight || wrap.clientHeight || 500;

    try {
      chart = window.LightweightCharts.createChart(container, {
        width: w,
        height: h,
        layout: {
          background: { type: 'solid', color: 'transparent' },
          textColor: isLight ? '#1e293b' : '#9ca3af',
          fontSize: 11,
        },
        grid: {
          vertLines: { color: 'transparent' },
          horzLines: { color: 'transparent' },
        },
        crosshair: { mode: 0 },
        rightPriceScale: {
          borderColor: isLight ? 'rgba(0,0,0,0.08)' : 'rgba(255,255,255,0.06)',
          borderVisible: false,
          scaleMargins: { top: 0.05, bottom: 0.25 },
          autoScale: true,
        },
        timeScale: {
          borderColor: isLight ? 'rgba(0,0,0,0.08)' : 'rgba(255,255,255,0.06)',
          timeVisible: true,
          secondsVisible: false,
          borderVisible: false,
          rightOffset: 20,
          shiftVisibleRangeOnNewBar: false,
          rightBarStaysOnScroll: false,
          lockVisibleTimeRangeOnResize: true,
        },
        handleScroll: { vertTouchDrag: true, horzTouchDrag: true, pressedMouseMove: true, mouseWheel: true },
        handleScale: { axisPressedMouseMove: true, mouseWheel: true, pinch: true },
        kineticScroll: { mouse: false, touch: false },
      });

      window.__lwcChart = chart;

      // Candlestick series
      var seriesOpts = {
        upColor: '#22d3ee',
        downColor: '#fb7185',
        borderDownColor: '#fb7185',
        borderUpColor: '#22d3ee',
        wickDownColor: '#fb7185',
        wickUpColor: '#22d3ee',
        lastValueVisible: false,
        priceLineVisible: false,
        autoscaleInfoProvider: window.ChartViewCore
          ? window.ChartViewCore.makeAutoscaleInfoProvider({ get value() { return manualPriceRange; }, set value(v) { manualPriceRange = v; } })
          : undefined,
      };

      // Handle chart style
      if (chartStyle === 'line') {
        candlestickSeries = _addLineSeries(chart, {
          color: '#22c55e',
          lineWidth: 2,
          lastValueVisible: false,
          priceLineVisible: false,
        });
      } else if (chartStyle === 'area') {
        candlestickSeries = _addAreaSeries(chart, {
          lineColor: '#22c55e',
          topColor: 'rgba(34,197,94,0.3)',
          bottomColor: 'rgba(34,197,94,0.02)',
          lineWidth: 2,
          lastValueVisible: false,
          priceLineVisible: false,
        });
      } else {
        candlestickSeries = _addCandleSeries(chart, seriesOpts);
      }

      // Price line + countdown
      countdownPriceLine = candlestickSeries.createPriceLine({
        price: 0,
        color: '#22c55e',
        lineWidth: 1,
        lineStyle: 2,
        axisLabelVisible: true,
        title: '—',
      });

      // Volume
      volumeSeries = _addHistogramSeries(chart, {
        priceFormat: { type: 'volume' },
        priceScaleId: 'volume',
      });
      chart.priceScale('volume').applyOptions({
        scaleMargins: { top: 0.85, bottom: 0 },
      });

      // Pré-créer les séries VWAP — visibles dès le départ avec données vides
      Object.keys(VWAP_COLORS).forEach(function (p) {
        vwapSeriesMap[p] = _addLineSeries(chart, {
          color: VWAP_COLORS[p], lineWidth: 1.5,
          priceLineVisible: false, lastValueVisible: false,
          crosshairMarkerVisible: false,
          title: 'VWAP ' + p,
          visible: true,
          autoscaleInfoProvider: function () { return null; },
        });
        vwapSeriesMap[p].setData([]);
        vwapSeriesMap[p + '-1'] = _addLineSeries(chart, {
          color: VWAP_COLORS[p], lineWidth: 1, lineStyle: 2,
          priceLineVisible: false, lastValueVisible: false,
          crosshairMarkerVisible: false,
          title: 'VWAP ' + p + '-1',
          visible: true,
          autoscaleInfoProvider: function () { return null; },
        });
        vwapSeriesMap[p + '-1'].setData([]);
        // Bandes d'écart-type (6 séries par période)
        var _bandKeys = ['u1', 'u2', 'u3', 'l1', 'l2', 'l3'];
        for (var _bi = 0; _bi < _bandKeys.length; _bi++) {
          var _bk = _bandKeys[_bi];
          vwapSeriesMap[p + '_' + _bk] = _addLineSeries(chart, {
            color: VWAP_COLORS[p], lineWidth: 1, lineStyle: 0,
            priceLineVisible: false, lastValueVisible: false,
            crosshairMarkerVisible: false,
            title: 'VWAP ' + p + ' ' + _bk,
            visible: true,
            autoscaleInfoProvider: function () { return null; },
          });
          vwapSeriesMap[p + '_' + _bk].setData([]);
        }
      });

      // Resize
      if (resizeObserver) resizeObserver.disconnect();
      resizeObserver = new ResizeObserver(function () {
        if (chart && wrap) {
          var cw = container.clientWidth || wrap.clientWidth;
          var ch = container.clientHeight || wrap.clientHeight;
          if (cw > 0 && ch > 0) chart.applyOptions({ width: cw, height: ch });
          if (window.ChartDrawings && window.ChartDrawings.onResize) {
            window.ChartDrawings.onResize();
          }
        }
      });
      resizeObserver.observe(wrap);

      // ── BIND UI EVENTS ──

      _bindVpDropdown();
      _bindVwap();
      _bindTimeframes();
      _bindPairs();
      _bindWorkspaceModes();
      _bindSettingsPanel();

      // ── DRAWING TOOLS ──
      _initDrawingTools();

      // ── VOLUME PROFILE ──
      _initVolumeProfile();
      if (window.HyperliquidWorkspace) {
        window.HyperliquidWorkspace.init(chart, candlestickSeries, document.getElementById('chartCanvasWrap'));
      }

      chartReady = true;
      _startCountdown();
      _startAutoRefresh();

    } catch (e) {
      console.error('[chart] createChart error:', e);
    }
  }

  // ── DRAWING TOOLS ──

  function _initDrawingTools() {
    var wrap = document.getElementById('chartCanvasWrap');
    if (!wrap || !window.ChartDrawings) return;

    // Create toolbar buttons
    var toolbar = document.getElementById('drawToolbar');
    if (!toolbar) return;

    var tools = window.ChartDrawings.tools;
    toolbar.innerHTML = '';
    tools.forEach(function (t) {
      var btn = document.createElement('button');
      btn.type = 'button';
      if (t.id === 'cursor') {
        // Cursor = toggle snap: 🧲 = snap actif (OHLC), ⊹ = curseur libre
        btn.className = 'draw-toolbar-btn is-active' + (!window.ChartDrawings.getSnapEnabled() ? ' draw-snap-on' : '');
        btn.dataset.tool = 'cursor';
        btn.dataset.label = !window.ChartDrawings.getSnapEnabled() ? 'Snap ON' : 'Curseur';
        btn.textContent = !window.ChartDrawings.getSnapEnabled() ? '🧲' : '⊹';
        btn.addEventListener('click', function () {
          var snapOn = !window.ChartDrawings.getSnapEnabled();
          window.ChartDrawings.setSnapEnabled(snapOn);
          btn.textContent = !snapOn ? '🧲' : '⊹';
          btn.dataset.label = !snapOn ? 'Snap ON' : 'Curseur';
          btn.classList.toggle('draw-snap-on', !snapOn);
          // Sync LWC crosshair mode avec snap
          try { chart.applyOptions({ crosshair: { mode: snapOn ? 0 : 1 } }); } catch(e) {}
          // Toujours passer en mode curseur
          toolbar.querySelectorAll('.draw-toolbar-btn').forEach(function (b) { b.classList.remove('is-active'); });
          btn.classList.add('is-active');
          window.ChartDrawings.setTool('cursor');
        });
      } else {
        btn.className = 'draw-toolbar-btn';
        btn.dataset.tool = t.id;
        btn.dataset.label = t.label;
        btn.textContent = t.icon;
        btn.addEventListener('click', function () {
          toolbar.querySelectorAll('.draw-toolbar-btn').forEach(function (b) { b.classList.remove('is-active'); });
          btn.classList.add('is-active');
          window.ChartDrawings.setTool(t.id);
        });
      }
      toolbar.appendChild(btn);
    });

    // Clear button
    var clearBtn = document.createElement('button');
    clearBtn.type = 'button';
    clearBtn.className = 'draw-toolbar-btn draw-clear';
    clearBtn.dataset.label = 'Tout effacer';
    clearBtn.textContent = '✕';
    clearBtn.addEventListener('click', function () {
      if (confirm('Effacer tous les dessins ?')) {
        window.ChartDrawings.clearAll();
      }
    });
    toolbar.appendChild(clearBtn);

    // Init drawing engine
    window.ChartDrawings.init(chart, candlestickSeries, wrap, false);
  }

  // ── VOLUME PROFILE ──

  function _initVolumeProfile() {
    var wrap = document.getElementById('chartCanvasWrap');
    if (!wrap || !window.VolumeProfile) return;
    window.VolumeProfile.init(chart, candlestickSeries, wrap);
  }

  function _bindWorkspaceModes() {
    var buttons = document.querySelectorAll('.workspace-mode');
    if (!buttons.length) return;
    buttons.forEach(function (button) {
      button.addEventListener('click', function () {
        if (window.HyperliquidWorkspace) {
          window.HyperliquidWorkspace.setMode(button.dataset.workspaceMode || 'profile');
        }
      });
    });
  }

  // ── VWAP ──

  function _bindVpDropdown() {
    var toggle = document.getElementById('vpToggle');
    var dropdown = document.getElementById('vpDropdown');
    if (!toggle || !dropdown) return;
    toggle.addEventListener('click', function (e) {
      e.stopPropagation();
      dropdown.classList.toggle('hidden');
      var panel = document.getElementById('chartSettingsPanel');
      if (panel) panel.classList.add('hidden');
      var vwap = document.getElementById('vwapDropdown');
      if (vwap) vwap.classList.add('hidden');
      // Sync UI from VP state
      if (!dropdown.classList.contains('hidden')) {
        var s = window.VolumeProfile ? window.VolumeProfile.getSettings() : null;
        if (s) {
          document.getElementById('vpActive').checked = !!s.active;
          toggle.classList.toggle('active', !!s.active);
          document.getElementById('vpBucketSize').value = s.bucketSize;
          document.getElementById('vpPeriod').value = s.period;
          if (document.getElementById('vpMetric')) document.getElementById('vpMetric').value = s.metric || 'notional';
          document.getElementById('vpVaPercent').value = s.vaPercent;
          document.getElementById('vpShowPOC').checked = !!s.showPOC;
          document.getElementById('vpShowVAH').checked = !!s.showVAH;
          document.getElementById('vpShowVAL').checked = !!s.showVAL;
          if (document.getElementById('vpColorPOC')) document.getElementById('vpColorPOC').value = s.colorPOC;
          if (document.getElementById('vpColorVAH')) document.getElementById('vpColorVAH').value = s.colorVAH;
          if (document.getElementById('vpColorVAL')) document.getElementById('vpColorVAL').value = s.colorVAL;
          if (document.getElementById('vpColorHvn')) document.getElementById('vpColorHvn').value = s.colorHvn;
          if (document.getElementById('vpShowNodes')) document.getElementById('vpShowNodes').checked = !!s.showNodes;
          if (document.getElementById('vpPeakN')) document.getElementById('vpPeakN').value = s.vpPeakN || 9;
          if (document.getElementById('vpTroughN')) document.getElementById('vpTroughN').value = s.vpTroughN || 7;
          if (document.getElementById('vpThreshold')) document.getElementById('vpThreshold').value = s.vpThreshold || 10;
        }
      }
    });
    document.addEventListener('click', function (e) {
      if (!dropdown.contains(e.target) && e.target !== toggle) dropdown.classList.add('hidden');
    }, false);
    // Apply on change
    dropdown.addEventListener('change', function () {
      _readVpSettingsFromUI();
      // Sync toggle active state
      var active = document.getElementById('vpActive');
      toggle.classList.toggle('active', active && active.checked);
    });
    // Init toggle state from saved settings
    setTimeout(function () {
      var s = window.VolumeProfile ? window.VolumeProfile.getSettings() : null;
      if (s) toggle.classList.toggle('active', !!s.active);
    }, 100);
  }

  function _bindVwap() {
    var vwapToggle = document.getElementById('vwapToggle');
    var vwapDropdown = document.getElementById('vwapDropdown');
    if (!vwapToggle || !vwapDropdown) return;

    vwapToggle.addEventListener('click', function (e) {
      e.stopPropagation();
      vwapDropdown.classList.toggle('hidden');
      // Close settings if open
      var panel = document.getElementById('chartSettingsPanel');
      if (panel) panel.classList.add('hidden');
    });
    document.addEventListener('click', function () { vwapDropdown.classList.add('hidden'); }, false);
    vwapDropdown.querySelectorAll('.chart-ind-opt').forEach(function (btn) {
      btn.addEventListener('click', function (e) {
        e.stopPropagation();
        var period = btn.dataset.vwap;
        btn.classList.toggle('active');
        var idx = activeVwapPeriods.indexOf(period);
        if (idx >= 0) { activeVwapPeriods.splice(idx, 1); }
        else { activeVwapPeriods.push(period); }
        vwapToggle.classList.toggle('active', activeVwapPeriods.length > 0);
        if (window.BtcVwap && window.BtcVwap.saveActiveVwapPeriods) {
          activeVwapPeriods = window.BtcVwap.saveActiveVwapPeriods(activeVwapPeriods);
        } else {
          try { localStorage.setItem('chartVwapPeriods', JSON.stringify(activeVwapPeriods)); } catch(e) {}
          window.dispatchEvent(new CustomEvent('chart:vwap-periods-changed', {
            detail: { periods: activeVwapPeriods }
          }));
        }
        vwapDropdown.classList.add('hidden');
        _fetchAndRender(true, 'user');
      });
    });
    // Restaurer l'etat des boutons depuis activeVwapPeriods
    vwapDropdown.querySelectorAll('.chart-ind-opt').forEach(function (btn) {
      if (activeVwapPeriods.indexOf(btn.dataset.vwap) >= 0) btn.classList.add('active');
    });
    if (activeVwapPeriods.length > 0) vwapToggle.classList.add('active');
  }

  // ── VWAP (multi-periode) — délègue à BtcVwap (055) ──
  var _mainCandles = [];  // Bougies principales (stockees pour alignment VWAP)

  function _drawMidnightForChart(candle, force) {
    if (!window.BtcMidnight || !candlestickSeries || !candle) return;
    var ts = Number(candle.time);
    if (!Number.isFinite(ts) || ts <= 0) return;
    window.BtcMidnight.drawMidnightLines(candlestickSeries, currentSymbol, ts * 1000, !!force, chart)
      .catch(function (e) {
        console.warn('[chart] midnight draw failed', e);
      });
  }

  function _removeVwapSeries(key) {
    var s = vwapSeriesMap[key];
    if (s) {
      try {
        var ts = chart.timeScale();
        var saved;
        try { saved = ts.getVisibleRange(); } catch(e2) {}
        s.applyOptions({ visible: false, lastValueVisible: false });
        s.setData([]);
        if (saved) { try { ts.setVisibleRange({ from: saved.from, to: saved.to }); } catch(e2) {} }
      } catch(e) {}
    }
  }

  async function _calcAndDrawVwap() {
    var interval = currentInterval;
    var sym = currentSymbol;
    Object.keys(vwapSeriesMap).forEach(function (k) {
      var basePeriod = k.replace(/-1$/, '').replace(/_(u1|u2|u3|l1|l2|l3)$/, '');
      if (activeVwapPeriods.indexOf(basePeriod) < 0) _removeVwapSeries(k);
    });
    if (!activeVwapPeriods.length) return;
    if (!window.BtcVwap) return;

    try {
      try { chart.applyOptions({ handleScroll: false, handleScale: false }); } catch(e) {}
      try { chart.timeScale().applyOptions({ shiftVisibleRangeOnNewBar: false }); } catch(e) {}

      var state = {
        symbol: currentSymbol,
        candles: _mainCandles,
        vwapSeriesMap: vwapSeriesMap,
      };

      var vwapOrder = ['1D', '7D', '30D', '90D', '365D'];
      for (var vi = 0; vi < vwapOrder.length; vi++) {
        var p = vwapOrder[vi];
        if (activeVwapPeriods.indexOf(p) < 0) continue;
        if (interval !== currentInterval || sym !== currentSymbol) return;
        await window.BtcVwap.drawVwapForChart(state, p, false, function () {
          return interval !== currentInterval || sym !== currentSymbol;
        });
        if (interval !== currentInterval || sym !== currentSymbol) return;
        await window.BtcVwap.drawVwapForChart(state, p, true, function () {
          return interval !== currentInterval || sym !== currentSymbol;
        });
        if (interval !== currentInterval || sym !== currentSymbol) return;
        await _waitFrame();
      }
    } finally {
      try { chart.applyOptions({ handleScroll: true, handleScale: true }); } catch(e) {}
      try { chart.timeScale().applyOptions({ shiftVisibleRangeOnNewBar: true, rightBarStaysOnScroll: true }); } catch(e) {}
    }
  }

  // ── TIMEFRAMES ──

  function _bindTimeframes() {
    var btns = document.querySelectorAll('.chart-tf-btn');
    btns.forEach(function (btn) {
      btn.addEventListener('click', function () {
        btns.forEach(function (b) { b.classList.remove('active'); });
        btn.classList.add('active');
        currentInterval = btn.dataset.interval;
        countdownAnchor = null;
        _updateCountdownLabel('—');
        if (countdownTimer) _startCountdown();
        _disconnectWs('timeframe');
        _fetchAndRender(false, 'user');
      });
    });
    // Activer le bon bouton
    btns.forEach(function (b) {
      if (b.dataset.interval === currentInterval) b.classList.add('active');
    });
  }

  // ── PAIRS ──

  function _bindPairs() {
    document.querySelectorAll('.chart-pair-btn').forEach(function (btn) {
      btn.addEventListener('click', function () {
        document.querySelectorAll('.chart-pair-btn').forEach(function (b) { b.classList.remove('active'); });
        btn.classList.add('active');
        currentSymbol = btn.dataset.symbol;
        _disconnectWs('pair');
        _fetchAndRender(false, 'user');
      });
    });
  }

  // ── SETTINGS PANEL ──

  function _bindSettingsPanel() {
    var btn = document.getElementById('chartSettingsBtn');
    var panel = document.getElementById('chartSettingsPanel');
    var close = document.getElementById('chartSettingsClose');
    var save = document.getElementById('chartSettingsSave');
    var reset = document.getElementById('chartSettingsReset');
    if (!btn || !panel) return;

    // Open / close
    btn.addEventListener('click', function (e) {
      e.stopPropagation();
      panel.classList.toggle('hidden');
      // Close VWAP if open
      var vwap = document.getElementById('vwapDropdown');
      if (vwap) vwap.classList.add('hidden');
      if (!panel.classList.contains('hidden')) {
        _syncSettingsUI();
      }
    });

    if (close) {
      close.addEventListener('click', function () { panel.classList.add('hidden'); });
    }

    document.addEventListener('click', function (e) {
      if (!panel.contains(e.target) && e.target !== btn && !btn.contains(e.target)) {
        panel.classList.add('hidden');
      }
    });

    // Sync UI from state
    function _syncSettingsUI() {
      var s = indSettings;
      _setChecked('indSmaActive', s.sma.active);
      _setVal('indSmaPeriod', s.sma.period);
      _setColor('indSmaColor', s.sma.color);
      _setChecked('indEmaActive', s.ema.active);
      _setVal('indEmaPeriod', s.ema.period);
      _setColor('indEmaColor', s.ema.color);
      _setChecked('indBollActive', s.boll.active);
      _setVal('indBollPeriod', s.boll.period);
      _setColor('indBollColor', s.boll.color);
      _setChecked('indRsiActive', s.rsi.active);
      _setVal('indRsiPeriod', s.rsi.period);
      _setColor('indRsiColor', s.rsi.color);
      _setVal('chartDefInterval', currentInterval);
      _setVal('chartDefSymbol', currentSymbol);
      _setVal('chartDefStyle', chartStyle);
      _renderSessionControls();
    }

    // Render session zone controls dynamically
    function _renderSessionControls() {
      var container = document.getElementById('chartSessionControls');
      if (!container || !window.ChartDrawings) return;
      var sessions = window.ChartDrawings.getSessionSettings();
      if (!sessions || !sessions.length) return;

      container.innerHTML = '';
      sessions.forEach(function (sess) {
        var row = document.createElement('div');
        row.className = 'chart-settings-row';
        row.innerHTML =
          '<div class="chart-settings-label">' +
            '<span class="chart-session-dot" style="background:' + sess.color + '"></span> ' +
            '<span>' + sess.name + '</span>' +
            '<span class="chart-session-hours">' + sess.timezone + ' ' + sess.start + '–' + sess.end + '</span>' +
          '</div>' +
          '<div class="chart-settings-controls">' +
            '<input type="color" class="chart-settings-color chart-session-color" data-sess-id="' + sess.id + '" value="' + sess.color + '">' +
            '<label class="chart-toggle">' +
              '<input type="checkbox" class="chart-session-active" data-sess-id="' + sess.id + '"' + (sess.active ? ' checked' : '') + '>' +
              '<span class="chart-toggle-track"><span class="chart-toggle-thumb"></span></span>' +
            '</label>' +
          '</div>';
        container.appendChild(row);
      });
    }

    // Read session settings from UI and push to drawing engine
    function _readSessionSettingsFromUI() {
      if (!window.ChartDrawings) return;
      var sessions = window.ChartDrawings.getSessionSettings();
      if (!sessions || !sessions.length) return;

      sessions.forEach(function (sess) {
        var cb = document.querySelector('.chart-session-active[data-sess-id="' + sess.id + '"]');
        if (cb) sess.active = cb.checked;
        var colorInput = document.querySelector('.chart-session-color[data-sess-id="' + sess.id + '"]');
        if (colorInput) sess.color = colorInput.value;
      });

      window.ChartDrawings.updateSessions(sessions);
    }

    function _setChecked(id, val) {
      var el = document.getElementById(id);
      if (el) el.checked = !!val;
    }
    function _setVal(id, val) {
      var el = document.getElementById(id);
      if (el) el.value = val;
    }
    function _setColor(id, val) {
      var el = document.getElementById(id);
      if (el) el.value = val;
    }

    // Save
    if (save) {
      save.addEventListener('click', function () {
        _readSettingsFromUI();
        _readSessionSettingsFromUI();
        _saveSettings();
        _applySettings();
        panel.classList.add('hidden');
        toast('Paramètres du chart sauvegardés', 'success');
      });
    }

    // Reset
    if (reset) {
      reset.addEventListener('click', function () {
        localStorage.removeItem('chartIndSettings');
        localStorage.removeItem('chartDefInterval');
        localStorage.removeItem('chartDefSymbol');
        localStorage.removeItem('chartDefStyle');
        localStorage.removeItem('chartSessionSettings');
        indSettings = {
          sma: { active: false, period: 20, color: '#f59e0b' },
          ema: { active: false, period: 20, color: '#06b6d4' },
          boll: { active: false, period: 20, color: '#a78bfa' },
          rsi: { active: false, period: 14, color: '#f472b6' },
        };
        currentInterval = '3m';
        currentSymbol = 'BTCUSDT';
        chartStyle = 'candlestick';
        _syncSettingsUI();
        _applySettings();
        // Reset sessions to defaults
        if (window.ChartDrawings) {
          var defaultSess = [
            { id: 'asian', name: 'Asie',      timezone: 'Asia/Tokyo',        start: '09:00', end: '15:00', color: '#ffdd00', active: true, opacity: 0.12 },
            { id: 'london', name: 'Londres',   timezone: 'Europe/London',     start: '08:00', end: '16:30', color: '#0066ff', active: true, opacity: 0.12 },
            { id: 'ny_rth', name: 'NY RTH',    timezone: 'America/New_York', start: '09:30', end: '16:00', color: '#ff0066', active: true, opacity: 0.12 },
            { id: 'ny_ext', name: 'NY Ext',    timezone: 'America/New_York', start: '08:00', end: '17:00', color: '#ff7733', active: false, opacity: 0.08 },
          ];
          window.ChartDrawings.updateSessions(defaultSess);
        }
        // Reset VP
        localStorage.removeItem('chartVolumeProfileSettings');
        if (window.VolumeProfile) {
          window.VolumeProfile.init(chart, candlestickSeries, document.getElementById('chartCanvasWrap'));
        }
        panel.classList.add('hidden');
        toast('Paramètres réinitialisés', 'info');
      });
    }
  }

  function _readSettingsFromUI() {
    function _gv(id) {
      var el = document.getElementById(id);
      return el ? el.value : null;
    }
    function _gc(id) {
      var el = document.getElementById(id);
      return el ? el.checked : false;
    }

    indSettings.sma.active = _gc('indSmaActive');
    indSettings.sma.period = parseInt(_gv('indSmaPeriod')) || 20;
    indSettings.sma.color = _gv('indSmaColor') || '#f59e0b';
    indSettings.ema.active = _gc('indEmaActive');
    indSettings.ema.period = parseInt(_gv('indEmaPeriod')) || 20;
    indSettings.ema.color = _gv('indEmaColor') || '#06b6d4';
    indSettings.boll.active = _gc('indBollActive');
    indSettings.boll.period = parseInt(_gv('indBollPeriod')) || 20;
    indSettings.boll.color = _gv('indBollColor') || '#a78bfa';
    indSettings.rsi.active = _gc('indRsiActive');
    indSettings.rsi.period = parseInt(_gv('indRsiPeriod')) || 14;
    indSettings.rsi.color = _gv('indRsiColor') || '#f472b6';
    currentInterval = _gv('chartDefInterval') || currentInterval;
    currentSymbol = _gv('chartDefSymbol') || currentSymbol;
    chartStyle = _gv('chartDefStyle') || chartStyle;
  }

  function _readVpSettingsFromUI() {
    if (!window.VolumeProfile) return;
    var s = {};
    function gc(id) { var el = document.getElementById(id); return el ? el.checked : false; }
    function gv(id) { var el = document.getElementById(id); return el ? el.value : null; }
    s.active = gc('vpActive');
    s.rowSize = gv('vpBucketSize') || 'auto';
    s.profileType = gv('vpPeriod') || 'session';
    s.metric = gv('vpMetric') || 'notional';
    s.vaPercent = parseInt(gv('vpVaPercent')) || 70;
    s.showPOC = gc('vpShowPOC');
    s.showVAH = gc('vpShowVAH');
    s.showVAL = gc('vpShowVAL');
    s.colorPOC = gv('vpColorPOC') || '#f59e0b';
    s.colorVAH = gv('vpColorVAH') || '#22c55e';
    s.colorVAL = gv('vpColorVAL') || '#ef4444';
    s.colorHvn = gv('vpColorHvn') || '#06b6d4';
    s.showNodes = gc('vpShowNodes');
    s.vpPeakN = parseInt(gv('vpPeakN')) || 9;
    s.vpTroughN = parseInt(gv('vpTroughN')) || 7;
    s.vpThreshold = parseInt(gv('vpThreshold')) || 10;
    window.VolumeProfile.updateSettings(s);
    if (window.HyperliquidWorkspace) {
      window.HyperliquidWorkspace.updateSettings({
        metric: s.metric, profileType: s.profileType, rowSize: s.rowSize, vaPercent: s.vaPercent,
      });
    }
  }

  function _syncVpSettingsUI() {
    if (!window.VolumeProfile) return;
    var s = window.VolumeProfile.getSettings();
    function sc(id, val) { var el = document.getElementById(id); if (el) el.checked = !!val; }
    function sv(id, val) { var el = document.getElementById(id); if (el) el.value = val; }
    sc('vpActive', s.active);
    sv('vpBucketSize', s.bucketSize);
    sv('vpPeriod', s.period);
    sv('vpMetric', s.metric || 'notional');
    sv('vpVaPercent', s.vaPercent);
    sc('vpShowPOC', s.showPOC);
    sc('vpShowVAH', s.showVAH);
    sc('vpShowVAL', s.showVAL);
    sv('vpColorPOC', s.colorPOC);
    sv('vpColorVAH', s.colorVAH);
    sv('vpColorVAL', s.colorVAL);
    sv('vpColorHvn', s.colorHvn);
    sc('vpShowNodes', s.showNodes);
    sv('vpPeakN', s.vpPeakN || 9);
    sv('vpTroughN', s.vpTroughN || 7);
    sv('vpThreshold', s.vpThreshold || 10);
  }

  function _saveSettings() {
    try {
      localStorage.setItem('chartIndSettings', JSON.stringify({
        sma: { active: indSettings.sma.active, period: indSettings.sma.period, color: indSettings.sma.color },
        ema: { active: indSettings.ema.active, period: indSettings.ema.period, color: indSettings.ema.color },
        boll: { active: indSettings.boll.active, period: indSettings.boll.period, color: indSettings.boll.color },
        rsi: { active: indSettings.rsi.active, period: indSettings.rsi.period, color: indSettings.rsi.color },
      }));
      localStorage.setItem('chartDefInterval', currentInterval);
      localStorage.setItem('chartDefSymbol', currentSymbol);
      localStorage.setItem('chartDefStyle', chartStyle);
      if (window.BtcVwap && window.BtcVwap.saveActiveVwapPeriods) {
        window.BtcVwap.saveActiveVwapPeriods(activeVwapPeriods);
      } else {
        localStorage.setItem('chartVwapPeriods', JSON.stringify(activeVwapPeriods));
        window.dispatchEvent(new CustomEvent('chart:vwap-periods-changed', {
          detail: { periods: activeVwapPeriods }
        }));
      }
    } catch(e) {}
  }

  function _applySettings() {
    // Rebuild chart with new style if needed
    // For indicators, just re-render with current data
    if (chart) _fetchAndRender(true, 'user');
  }

  // ── FETCH & RENDER ──

  function _fetchAndRender(keepZoom, _source) {
    if (!candlestickSeries) return;
    if (_isFetching) return;
    if (_source !== 'user') {
      var now = Date.now();
      if (_lastFetchTs && (now - _lastFetchTs) < _FETCH_COOLDOWN_MS) return;
      _lastFetchTs = now;
    }
    _isFetching = true;
    if (!_firstFetchMs) _firstFetchMs = Date.now();

    // WS reset : UNIQUEMENT sur init/user/timeframe/pair
    var shouldResetWs = _source === 'init' || _source === 'user' || _source === 'timeframe' || _source === 'pair' || _source === 'settings';
    if (shouldResetWs) _disconnectWs('render:' + _source);

    // Sauvegarder le zoom si on doit le restaurer apres setData
    var savedTarget = null;
    if (keepZoom && !_userIsInteracting && chart && chart.timeScale()) {
      if (_source === 'user' || Date.now() - _firstFetchMs > 2000) {
        try {
          var logicalRange = chart.timeScale().getVisibleLogicalRange();
          if (logicalRange) {
            var rangeWidth = logicalRange.to - logicalRange.from;
            if (rangeWidth >= 80) {
              savedTarget = { from: logicalRange.from, to: logicalRange.to };
            }
          }
        } catch(e) {}
      }
      try { chart.priceScale('right').applyOptions({ autoScale: false }); } catch(e) {}
    }

    var _chartLimitMap = { '1m': 1000, '3m': 1000, '5m': 1000, '15m': 1000, '30m': 1000, '1h': 1000, '2h': 1000, '4h': 1000, '6h': 1000, '8h': 1000, '12h': 1000, '1d': 1000 };
    var url = '/api/hyperliquid/klines?market=' + encodeURIComponent(_hyperliquidCoin()) + '&interval=' + currentInterval + '&limit=' + (_chartLimitMap[currentInterval] || 1000);
    fetch(url)
      .then(function (r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function (data) {
        if (data.error) { console.error('[chart]', data.error); toast(data.error, 'error'); return; }

        if (data.serverTime != null && window.BtcMarketClock && Number.isFinite(Number(data.serverTime))) {
          window.BtcMarketClock.sync(Number(data.serverTime), 'klines-fetch-chart');
        }

        var candles = _normalizeChartCandles(data.candles || []);
        if (!candles.length) return;

        candlestickSeries.setData(chartStyle === 'candlestick' ? candles : candles.map(function (c) { return { time: c.time, value: c.close }; }));

        var last = candles[candles.length - 1];
        lastCandleTime = last.time * 1000;
        _updateCountdownAnchor(last, 'fetch');
        lastPrice = last.close;
        _startCountdown();
        _startAutoRefresh();
        _updateStats(candles);
        _mainCandles = candles;
        _drawMidnightForChart(last, false);

        // Point fantôme pour étendre le range autorisé par LWC
        var intervalSec = Math.floor(_getIntervalMs(currentInterval) / 1000);
        var phantomTime = last.time + intervalSec * 5;
        try { candlestickSeries.update({ time: phantomTime, open: last.close, high: last.close, low: last.close, close: last.close }); } catch(e) {}

        // WS 062 desactive - le dashboard BTC widget gere son propre WS
        //
        // if (shouldResetWs) {
        //   setTimeout(function () {
        //     _connectWs('after-render:' + _source, { force: true });
        //   }, 250);
        // }

        // VWAP — seulement sur init/user/timeframe (pas sur auto)
        if (activeVwapPeriods.length > 0 && shouldResetWs) {
          _calcAndDrawVwap().finally(function () {
            _isFetching = false;
            _applyChartBestView(savedTarget, keepZoom, candles);
          });
        } else {
          _isFetching = false;
          _applyChartBestView(savedTarget, keepZoom, candles);
        }

        // Volume Profile
        if (window.VolumeProfile) {
          window.VolumeProfile.setContext({ coin: _hyperliquidCoin(), interval: currentInterval, candles: candles });
        }
        if (window.HyperliquidWorkspace) {
          window.HyperliquidWorkspace.setContext({ coin: _hyperliquidCoin(), interval: currentInterval, candles: candles });
        }

        // Indicators
        _renderIndicators(candles);

        // Price line
        if (countdownPriceLine) {
          try { countdownPriceLine.applyOptions({ price: last.close }); } catch(e) {}
        }
        _updateCountdownLabel();

        volumeSeries.setData(candles.map(function (c) {
          return { time: c.time, value: c.volume, color: c.close >= c.open ? 'rgba(34,211,238,0.24)' : 'rgba(251,113,133,0.24)' };
        }));
      })
      .catch(function (err) {
        console.error('[chart] fetch error:', err);
        _isFetching = false;
      });
  }

  function _updateStats(candles) {
    if (!candles.length) return;
    var last = candles[candles.length - 1];
    var first = candles[0];
    var change = last.close - first.close;
    var changePct = (change / first.close) * 100;

    var priceEl = document.getElementById('chartPrice');
    if (priceEl) priceEl.textContent = '$' + Number(last.close).toLocaleString('fr-FR', { minimumFractionDigits: 2 });

    var changeEl = document.getElementById('chartChange');
    if (changeEl) {
      var sign = change >= 0 ? '+' : '';
      changeEl.textContent = sign + change.toFixed(2) + ' (' + sign + changePct.toFixed(2) + '%)';
      changeEl.style.color = change >= 0 ? 'var(--win)' : 'var(--loss)';
    }

    var setStat = function (id, val) {
      var el = document.getElementById(id);
      if (el) el.textContent = val != null ? Number(val).toLocaleString('fr-FR', { minimumFractionDigits: 2 }) : '—';
    };
    setStat('chartOpen', last.open);
    setStat('chartHigh', last.high);
    setStat('chartLow', last.low);
    setStat('chartClose', last.close);
    setStat('chartVol', last.volume);
  }

  // ── COUNTDOWN ANCHOR (basé sur candleCloseMs + performance.now()) ──

  function _toMs(t) {
    if (t == null) return NaN;
    var n = Number(t);
    if (!Number.isFinite(n)) return NaN;
    return n > 1e12 ? n : n * 1000;
  }

  function _getCandleCloseMs(candle, intervalMs) {
    if (candle.closeTime != null) return _toMs(candle.closeTime);
    if (candle.T != null) return _toMs(candle.T);
    if (candle.time != null) return _toMs(candle.time) + intervalMs;
    return NaN;
  }

  function _updateCountdownAnchor(candle, source, nowMsOverride) {
    if (!candle) return;
    var intervalMs = _getIntervalMs(currentInterval);
    if (!intervalMs) return;
    var openMs = _toMs(candle.time != null ? (candle.openTime != null ? candle.openTime : candle.time) : (candle.t != null ? candle.t : 0));
    var closeMs = _getCandleCloseMs(candle, intervalMs);
    if (!Number.isFinite(openMs) || !Number.isFinite(closeMs)) return;

    var overrideNow = Number(nowMsOverride);
    var hasOverrideNow = Number.isFinite(overrideNow);

    var clockSynced = hasOverrideNow ||
      (window.BtcMarketClock && window.BtcMarketClock.isSynced && window.BtcMarketClock.isSynced());

    var marketNow = hasOverrideNow
      ? overrideNow
      : (window.BtcMarketClock ? window.BtcMarketClock.now() : Date.now());

    // Pas de reject si clock pas sync et source pas WS — on attend la sync
    if (!clockSynced && source !== 'ws') return;

    var remaining = closeMs - marketNow;
    if (remaining < -intervalMs) {
      console.warn('[COUNTDOWN] stale candle anchor, forcing latest fetch', { source, tf: currentInterval, openMs, closeMs, marketNow, remaining });
      countdownAnchor = {
        candleOpenMs: openMs,
        candleCloseMs: closeMs,
        remainingAtAnchorMs: 0,
        perfAtAnchor: performance.now(),
        source: 'stale-' + (source || 'unknown'),
      };
      if (Date.now() - (lastCountdownFetchAt || 0) > 5000) {
        lastCountdownFetchAt = Date.now();
        _fetchLatestCandleOnly();
      }
      return;
    }
    if (remaining > intervalMs * 2) {
      console.warn('[COUNTDOWN] future candle anchor rejected', { source, tf: currentInterval, openMs, closeMs, marketNow, remaining });
      return;
    }
    remaining = Math.max(0, Math.min(remaining, intervalMs));
    countdownAnchor = {
      candleOpenMs: openMs,
      candleCloseMs: closeMs,
      remainingAtAnchorMs: remaining,
      perfAtAnchor: performance.now(),
      source: source || 'unknown',
    };
  }

  function _formatCountdown(ms) {
    if (!Number.isFinite(ms) || ms <= 0) return '0:00';
    var totalSec = Math.ceil(ms / 1000);
    var h = Math.floor(totalSec / 3600);
    var m = Math.floor((totalSec % 3600) / 60);
    var s = totalSec % 60;
    var pad = function (n) { return n < 10 ? '0' + n : '' + n; };
    if (h > 0) return h + ':' + pad(m) + ':' + pad(s);
    return m + ':' + pad(s);
  }

  function _startCountdown() {
    if (countdownTimer) clearInterval(countdownTimer);
    countdownTimer = setInterval(function () {
      if (!countdownPriceLine) { _updateCountdownLabel('—'); return; }
      if (!countdownAnchor) {
        var intervalMs = _getIntervalMs(currentInterval);
        var clockSynced = window.BtcMarketClock && window.BtcMarketClock.isSynced && window.BtcMarketClock.isSynced();
        var nowMs = window.BtcMarketClock ? window.BtcMarketClock.now() : Date.now();
        var estimated = intervalMs ? intervalMs - (nowMs % intervalMs) : 0;
        _updateCountdownLabel(estimated > 0 ? _formatCountdown(estimated) : '—');
        if (chartReady && clockSynced && !_isFetching && !wsConnected && Date.now() - (lastCountdownFetchAt || 0) > 5000) {
          lastCountdownFetchAt = Date.now();
          _fetchLatestCandleOnly();
        }
        return;
      }
      var elapsed = performance.now() - countdownAnchor.perfAtAnchor;
      var remaining = countdownAnchor.remainingAtAnchorMs - elapsed;
      if (remaining <= 0) {
        _updateCountdownLabel('0:00');
        if (!wsConnected && Date.now() - (lastCountdownFetchAt || 0) > 10000) {
          lastCountdownFetchAt = Date.now();
          _fetchLatestCandleOnly();
        }
        return;
      }
      _updateCountdownLabel(_formatCountdown(remaining));
    }, 250);
  }

  function _updateCountdownLabel(timerTxt) {
    if (!countdownPriceLine || !chart) return;
    if (timerTxt === undefined) timerTxt = '—';
    try { countdownPriceLine.applyOptions({ title: timerTxt }); } catch(e) {}
  }

  // ── AUTO REFRESH ──
  function _startAutoRefresh() {
    if (refreshTimer) clearInterval(refreshTimer);
    var ms = _getIntervalMs(currentInterval);
    var interval = Math.min(60000, Math.max(15000, Math.floor(ms / 4)));
    refreshTimer = setInterval(function () {
      if (!chart || !candlestickSeries) return;
      if (_isFetching) return;
      if (!countdownAnchor) return;
      if (wsConnected && !wsError) return;
      var elapsed = performance.now() - countdownAnchor.perfAtAnchor;
      if (elapsed < countdownAnchor.remainingAtAnchorMs + 1500) return;
      _fetchLatestCandleOnly();
    }, interval);
  }

  // ── REST FALLBACK LÉGER ──
  function _fetchLatestCandleOnly() {
    if (_isFetching) return Promise.resolve();
    var interval = currentInterval;
    var sym = currentSymbol;
    var url = '/api/hyperliquid/klines?market=' + encodeURIComponent(_hyperliquidCoin()) + '&interval=' + interval + '&limit=3';
    return fetch(url)
      .then(function (r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function (data) {
        if (interval !== currentInterval || sym !== currentSymbol) return;

        if (data.serverTime != null && window.BtcMarketClock && Number.isFinite(Number(data.serverTime))) {
          window.BtcMarketClock.sync(Number(data.serverTime), 'klines-latest-chart');
        }

        var raw = data.candles || [];
        if (!raw.length) return;
        var candles = _normalizeChartCandles(raw);
        if (!candles.length) return;
        var latest = candles[candles.length - 1];
        if (!latest || !latest.time) return;
        if (_mainCandles && _mainCandles.length > 0) {
          var last = _mainCandles[_mainCandles.length - 1];
          if (last && latest.time === last.time) {
            _mainCandles[_mainCandles.length - 1] = latest;
          } else if (latest.time > (last ? last.time : 0)) {
            _mainCandles.push(latest);
            if (_mainCandles.length > 1000) _mainCandles = _mainCandles.slice(-1000);
          }
        }
        lastCandleTime = latest.time * 1000;
        _updateCountdownAnchor(latest, 'rest-fallback');
        candlestickSeries.update(chartStyle === 'candlestick' ? latest : { time: latest.time, value: latest.close });
        if (volumeSeries) {
          volumeSeries.update({ time: latest.time, value: latest.volume, color: latest.close >= latest.open ? 'rgba(34,197,94,0.3)' : 'rgba(239,68,68,0.3)' });
        }
        if (countdownPriceLine) {
          try { countdownPriceLine.applyOptions({ price: latest.close }); } catch(e) {}
        }
        var priceEl = document.getElementById('chartPrice');
        if (priceEl) priceEl.textContent = '$' + Number(latest.close).toLocaleString('fr-FR', { minimumFractionDigits: 2 });
        _drawMidnightForChart(latest, false);
      })
      .catch(function (e) { console.warn('[chart] REST fallback failed', e); });
  }

  // ── INIT ──

  // Polling robuste : attend que #chartCanvas soit dans le DOM avant de lancer le callback
  // maxRetries × interval ms (par défaut 20 × 50ms = 1s max)
  function _waitForContainer(callback, maxRetries, interval) {
    maxRetries = maxRetries || 20;
    interval = interval || 50;
    var retries = 0;
    function poll() {
      if (document.getElementById('chartCanvas')) {
        callback();
        return;
      }
      retries++;
      if (retries >= maxRetries) {
        console.warn('[chart] #chartCanvas introuvable apres ' + (maxRetries * interval) + 'ms');
        return;
      }
      setTimeout(poll, interval);
    }
    poll();
  }

  function _tryInit() {
    if (document.querySelector('.page[data-page="chart"].active')) {
      _waitForContainer(initChartPage);
    }
  }

  document.addEventListener('DOMContentLoaded', function () { setTimeout(_tryInit, 50); });

  // Hook dans goPage existante
  var _origGoPage = window.goPage;
  if (_origGoPage) {
    window.goPage = function (pageName) {
      var hasV6Orderflow = pageName === 'orderflow' && document.getElementById('v6-orderflow-root');
      var requestedMode = pageName === 'orderflow' && !hasV6Orderflow ? 'footprint' : null;
      if (requestedMode) pageName = 'chart';
      _origGoPage(pageName);
      if (pageName === 'chart') {
        _waitForContainer(function () {
          initChartPage();
          if (requestedMode && window.HyperliquidWorkspace) {
            window.HyperliquidWorkspace.setMode(requestedMode);
          }
          _waitForContainer(function () {
            if (chart) {
              var wrap = document.getElementById('chartCanvasWrap');
              if (wrap) chart.applyOptions({ width: wrap.clientWidth, height: wrap.clientHeight });
            }
          }, 10, 100);
        });
      }
    };
  }

  window.initChartPage = initChartPage;
})();

// ---- 063_favorites_carousel.js ----
// ---------- Favorites Carousel Widget (reuses journal flip card) ----------
// Uses journalTradeFlipCardHtml() so recto/verso is identical to journal.

(function () {
  'use strict';

  var _trades       = [];
  var _currentIndex = 0;
  var _observer     = null;

  // ── Render / init ──────────────────────────────────────────
  function initFavCarousel() {
    var track   = document.getElementById('favCarouselTrack');
    var empty   = document.getElementById('favCarouselEmpty');
    var countEl = document.getElementById('favCarouselCount');
    if (!track) return;

    // Show skeleton
    track.innerHTML = '<div class="fav-skeleton"></div>';
    if (empty) empty.style.display = 'none';

    fetch('/api/trades/favorites')
      .then(function (r) { if (!r.ok) throw new Error('HTTP ' + r.status); return r.json(); })
      .then(function (data) {
        _trades = Array.isArray(data) ? data : [];
        _currentIndex = 0;
        track.innerHTML = '';

        if (_observer) { _observer.disconnect(); _observer = null; }

        if (_trades.length === 0) {
          if (empty)   { empty.style.display = ''; }
          if (countEl) { countEl.textContent = ''; }
          _updateDots(0);
          _updateArrows();
          return;
        }

        if (empty) empty.style.display = 'none';
        _updateCount();

        _trades.forEach(function (trade, i) {
          var day = {
            id: trade.day_id,
            instrument: trade.day_instrument || '-',
            date: trade.day_date || (trade.created_at ? trade.created_at.slice(0, 10) : ''),
          };

          var slide = document.createElement('div');
          slide.className = 'fav-carousel-slide';
          slide.dataset.index = i;

          if (typeof journalTradeFlipCardHtml === 'function') {
            slide.innerHTML = journalTradeFlipCardHtml(day, trade, i + 1, [trade]);
          }

          track.appendChild(slide);
        });

        _updateDots(_trades.length);
        _updateArrows();
        _setupObserver();
      })
      .catch(function (err) {
        console.error('[fav-carousel]', err);
        track.innerHTML = '';
        if (empty) empty.style.display = '';
        if (countEl) countEl.textContent = '';
        _updateDots(0);
        _updateArrows();
      });
  }

  // ── Navigation ───────────────────────────────────────────────
  function _goTo(idx, smooth) {
    if (idx < 0 || idx >= _trades.length) return;
    var track = document.getElementById('favCarouselTrack');
    if (!track) return;
    var slide = track.children[idx];
    if (!slide) return;
    slide.scrollIntoView({ behavior: smooth === false ? 'instant' : 'smooth', block: 'nearest', inline: 'start' });
    _currentIndex = idx;
    _updateDots(_trades.length);
    _updateArrows();
    _updateCount();
  }

  function _updateDots(count) {
    var el = document.getElementById('favCarouselDots');
    if (!el) return;
    if (count <= 1) { el.innerHTML = ''; return; }
    var html = '';
    for (var i = 0; i < count; i++) {
      html += '<button type="button" class="fav-carousel-dot' + (i === _currentIndex ? ' is-active' : '') +
              '" data-dot="' + i + '" aria-label="Trade ' + (i + 1) + '"></button>';
    }
    el.innerHTML = html;
  }

  function _updateArrows() {
    var left  = document.getElementById('favCarouselLeft');
    var right = document.getElementById('favCarouselRight');
    if (!left || !right) return;
    var n = _trades.length;
    left.style.display  = n > 1 ? '' : 'none';
    right.style.display = n > 1 ? '' : 'none';
    left.disabled  = _currentIndex <= 0;
    right.disabled = _currentIndex >= n - 1;
  }

  function _updateCount() {
    var el = document.getElementById('favCarouselCount');
    if (!el) return;
    if (_trades.length > 1) {
      el.textContent = (_currentIndex + 1) + ' / ' + _trades.length;
    } else if (_trades.length === 1) {
      el.textContent = '1 trade';
    } else {
      el.textContent = '';
    }
  }

  // ── Flip helpers (uses journal-flip-card class) ─────────────
  function _flipCard(card, toBack) {
    document.querySelectorAll('.journal-flip-card.is-flipped').forEach(function (c) {
      if (c !== card) c.classList.remove('is-flipped');
    });
    if (toBack === undefined) {
      card.classList.toggle('is-flipped');
    } else {
      card.classList.toggle('is-flipped', toBack);
    }
  }

  // ── Intersection observer ────────────────────────────────────
  function _setupObserver() {
    var track = document.getElementById('favCarouselTrack');
    if (!track) return;

    _observer = new IntersectionObserver(function (entries) {
      entries.forEach(function (e) {
        if (e.isIntersecting) {
          var idx = parseInt(e.target.dataset.index, 10);
          if (!isNaN(idx) && idx !== _currentIndex) {
            _currentIndex = idx;
            _updateDots(_trades.length);
            _updateArrows();
            _updateCount();
          }
        }
      });
    }, { root: track, threshold: 0.55 });

    Array.from(track.children).forEach(function (s) { _observer.observe(s); });
  }

  // ── Global delegated click handler ──────────────────────────
  document.addEventListener('click', function (e) {

    // Arrow left / right
    var left = e.target.closest('#favCarouselLeft');
    if (left) { e.preventDefault(); e.stopPropagation(); _goTo(_currentIndex - 1); return; }

    var right = e.target.closest('#favCarouselRight');
    if (right) { e.preventDefault(); e.stopPropagation(); _goTo(_currentIndex + 1); return; }

    // Dot
    var dot = e.target.closest('.fav-carousel-dot');
    if (dot) { _goTo(parseInt(dot.dataset.dot, 10)); return; }

    // Flip back (journal card uses data-journal-day-close or similar)
    var backBtn = e.target.closest('[data-journal-day-close]');
    if (backBtn) {
      e.stopPropagation();
      var card = backBtn.closest('.journal-flip-card');
      if (card) _flipCard(card, false);
      return;
    }

    // Flip card (click anywhere on journal-flip-card that isn't a button)
    var card = e.target.closest('.journal-flip-card');
    if (card) {
      if (e.target.closest('button, input, textarea, a, select, [data-journal-day-close]')) return;
      e.stopPropagation();
      _flipCard(card);
      return;
    }
  }, true); // useCapture = true to intercept before journal handler

  // ── Keyboard support ─────────────────────────────────────────
  document.addEventListener('keydown', function (e) {
    var focused = document.activeElement;
    if (!focused) return;

    var card = focused.closest('.journal-flip-card');
    if (card) {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); _flipCard(card); return; }
      if (e.key === 'Escape' && card.classList.contains('is-flipped')) { _flipCard(card, false); return; }
    }

    var wrap = document.getElementById('favCarouselWrap');
    if (wrap && (wrap.contains(focused) || wrap.matches(':hover'))) {
      if (e.key === 'ArrowLeft')  { _goTo(_currentIndex - 1); return; }
      if (e.key === 'ArrowRight') { _goTo(_currentIndex + 1); return; }
    }
  });

  // ── Swipe touch support ──────────────────────────────────────
  (function () {
    var startX = 0, startY = 0, isDragging = false;
    document.addEventListener('touchstart', function (e) {
      var wrap = e.target.closest('#favCarouselWrap');
      if (!wrap) return;
      startX = e.touches[0].clientX;
      startY = e.touches[0].clientY;
      isDragging = true;
    }, { passive: true });
    document.addEventListener('touchend', function (e) {
      if (!isDragging) return;
      isDragging = false;
      var dx = e.changedTouches[0].clientX - startX;
      var dy = e.changedTouches[0].clientY - startY;
      if (Math.abs(dx) > Math.abs(dy) && Math.abs(dx) > 40) {
        _goTo(dx < 0 ? _currentIndex + 1 : _currentIndex - 1);
      }
    }, { passive: true });
  })();

  // ── Boot hooks ───────────────────────────────────────────────
  function _waitForFavContainer(callback, maxRetries, interval) {
    maxRetries = maxRetries || 20;
    interval = interval || 50;
    var retries = 0;
    function poll() {
      if (document.getElementById('favCarouselTrack')) {
        callback();
        return;
      }
      retries++;
      if (retries >= maxRetries) { console.warn('[fav-carousel] container introuvable'); return; }
      setTimeout(poll, interval);
    }
    poll();
  }

  var _origGoPage = window.goPage;
  if (_origGoPage) {
    window.goPage = function (pageName) {
      _origGoPage(pageName);
      if (pageName === 'today') {
        _waitForFavContainer(initFavCarousel);
      }
    };
  }

  window.refreshFavCarousel = initFavCarousel;

  document.addEventListener('DOMContentLoaded', function () {
    if (document.querySelector('.page[data-page="today"].active')) {
      _waitForFavContainer(initFavCarousel);
    }
  });

})();

// ---- 063a_hyperliquid_workspace.js ----
// ---------- Hyperliquid workspace: integrated FOOTPRINT / HEATMAP layers ----------
(function () {
  'use strict';

  var STORAGE_KEY = 'chartWorkspaceSettings';
  var WS_URL = 'wss://api.hyperliquid.xyz/ws';
  var settings = {
    mode: 'profile',
    metric: 'notional',
    profileType: 'session',
    rowSize: 'auto',
    vaPercent: 70,
  };
  try { Object.assign(settings, JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}')); } catch (e) {}

  var state = {
    chart: null,
    series: null,
    container: null,
    canvas: null,
    ctx: null,
    coin: 'BTC',
    interval: '3m',
    candles: [],
    profile: null,
    footprint: null,
    heatmap: null,
    requestId: 0,
    resizeObserver: null,
    refreshTimer: null,
    tradeRefreshTimer: null,
    bookPollTimer: null,
    liveWs: null,
    liveGeneration: 0,
    liveCoin: null,
    liveConnected: false,
    liveBooks: [],
    liveTrades: [],
    liveTradesSeen: 0,
    reconnectTimer: null,
  };

  function _save() {
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(settings)); } catch (e) {}
  }

  function _status(text, type) {
    var el = document.getElementById('chartDataStatus');
    if (!el) return;
    el.className = 'workspace-data-status' + (type ? ' ' + type : '');
    el.textContent = text;
  }

  function _syncStatus() {
    if (settings.mode === 'profile') return;
    var live = state.liveConnected ? 'LIVE' : 'CONNECTING';
    if (settings.mode === 'heatmap') {
      _status('HEATMAP | ' + live + ' L2 snapshots | archive gap', 'partial');
      return;
    }
    _status('FOOTPRINT | ' + live + ' trades | history partial', 'partial');
  }

  function _ensureCanvas() {
    if (!state.container) return;
    if (!state.canvas) {
      state.canvas = document.createElement('canvas');
      state.canvas.className = 'hl-workspace-overlay';
      state.container.appendChild(state.canvas);
      state.ctx = state.canvas.getContext('2d');
    }
    _resize();
  }

  function _resize() {
    if (!state.canvas || !state.container) return;
    var rect = state.container.getBoundingClientRect();
    var dpr = window.devicePixelRatio || 1;
    state.canvas.width = Math.round(rect.width * dpr);
    state.canvas.height = Math.round(rect.height * dpr);
    state.canvas.style.width = rect.width + 'px';
    state.canvas.style.height = rect.height + 'px';
    state.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    render();
  }

  function init(chart, series, container) {
    state.chart = chart;
    state.series = series;
    state.container = container;
    _ensureCanvas();
    if (state.resizeObserver) state.resizeObserver.disconnect();
    state.resizeObserver = new ResizeObserver(_resize);
    state.resizeObserver.observe(container);
    setMode(settings.mode);
  }

  function setContext(context) {
    context = context || {};
    var priorCoin = state.coin;
    state.coin = context.coin || state.coin;
    state.interval = context.interval || state.interval;
    state.candles = context.candles || state.candles;
    if (priorCoin !== state.coin && settings.mode !== 'profile') {
      _disconnectLive();
      state.liveBooks = [];
      state.liveTrades = [];
      state.liveTradesSeen = 0;
      _startLive();
    }
    if (settings.mode !== 'profile') refresh();
  }

  function _range() {
    var end = state.candles.length
      ? Math.max(state.candles[state.candles.length - 1].time * 1000 + 1, Date.now())
      : Date.now();
    var start = state.candles.length
      ? state.candles[Math.max(0, state.candles.length - 150)].time * 1000
      : end - 6 * 60 * 60 * 1000;
    return { start: start, end: end };
  }

  function _baseParams(range) {
    return 'coin=' + encodeURIComponent(state.coin)
      + '&startTime=' + Math.floor(range.start) + '&endTime=' + Math.floor(range.end)
      + '&metric=' + encodeURIComponent(settings.metric)
      + '&rowSize=' + encodeURIComponent(settings.rowSize);
  }

  function refresh() {
    if (settings.mode === 'profile') return;
    var range = _range();
    var token = ++state.requestId;
    var base = _baseParams(range);
    var profileUrl = '/api/hyperliquid/analytics/volume-profile?' + base
      + '&vaPercent=' + settings.vaPercent + '&profileType=' + settings.profileType;
    var dataUrl = settings.mode === 'footprint'
      ? '/api/hyperliquid/analytics/footprint?' + base + '&interval=' + encodeURIComponent(state.interval) + '&imbalanceRatio=3&stack=3'
      : '/api/hyperliquid/analytics/heatmap?' + base + '&resolution=5s';
    Promise.all([
      fetch(profileUrl).then(function (r) { return r.json(); }),
      fetch(dataUrl).then(function (r) { return r.json(); }),
    ]).then(function (responses) {
      if (token !== state.requestId) return;
      state.profile = responses[0];
      if (settings.mode === 'footprint') state.footprint = responses[1];
      else state.heatmap = responses[1];
      _syncStatus();
      render();
    }).catch(function () {
      if (token !== state.requestId) return;
      _status('Hyperliquid analytics unavailable', 'gap');
      render();
    });
  }

  function _disconnectLive() {
    state.liveGeneration++;
    state.liveConnected = false;
    state.liveCoin = null;
    if (state.reconnectTimer) {
      clearTimeout(state.reconnectTimer);
      state.reconnectTimer = null;
    }
    var socket = state.liveWs;
    state.liveWs = null;
    if (!socket) return;
    try {
      socket.onopen = null;
      socket.onmessage = null;
      socket.onclose = null;
      socket.onerror = null;
      if (socket.readyState === WebSocket.CONNECTING || socket.readyState === WebSocket.OPEN) {
        socket.close(1000, 'workspace-mode-change');
      }
    } catch (e) {}
  }

  function _scheduleTradeRefresh() {
    if (state.tradeRefreshTimer) return;
    state.tradeRefreshTimer = setTimeout(function () {
      state.tradeRefreshTimer = null;
      if (settings.mode === 'footprint') refresh();
    }, 350);
  }

  function _pushBookSnapshot(rows, timeMs) {
    if (!rows.length) return;
    state.liveBooks.push({ timeMs: timeMs || Date.now(), rows: rows });
    if (state.liveBooks.length > 120) state.liveBooks.splice(0, state.liveBooks.length - 120);
    render();
  }

  function _normalizeWsTrade(row) {
    if (!row) return null;
    var timeMs = Number(row.timeMs || row.time || Date.now());
    var price = Number(row.price || row.px);
    var size = Number(row.sizeBase || row.sz || row.size);
    if (!Number.isFinite(timeMs) || !Number.isFinite(price) || !Number.isFinite(size) || price <= 0 || size <= 0) {
      return null;
    }
    var rawSide = String(row.aggressorSide || row.side || '').toUpperCase();
    var side = rawSide === 'B' || rawSide === 'BUY' ? 'buy'
      : rawSide === 'A' || rawSide === 'S' || rawSide === 'SELL' ? 'sell'
      : null;
    return {
      timeMs: timeMs,
      price: price,
      sizeBase: size,
      notionalUsd: price * size,
      aggressorSide: side,
    };
  }

  function _pushTrades(rows) {
    var added = 0;
    (rows || []).forEach(function (row) {
      var normalized = _normalizeWsTrade(row);
      if (!normalized) return;
      state.liveTrades.push(normalized);
      added++;
    });
    if (!added) return;
    state.liveTradesSeen += added;
    if (state.liveTrades.length > 1200) state.liveTrades.splice(0, state.liveTrades.length - 1200);
    render();
  }

  function _ingestWsBook(book) {
    var levels = book && book.levels || [[], []];
    var rows = {};
    [[0, 'bidSize'], [1, 'askSize']].forEach(function (side) {
      (levels[side[0]] || []).forEach(function (level) {
        var px = Number(level.px);
        var sz = Number(level.sz);
        if (!Number.isFinite(px) || !Number.isFinite(sz)) return;
        if (!rows[px]) rows[px] = { price: px, bidSize: 0, askSize: 0 };
        rows[px][side[1]] = sz;
      });
    });
    _pushBookSnapshot(Object.keys(rows).map(function (key) { return rows[key]; }), Number(book.time) || Date.now());
  }

  function _primeBook() {
    if (settings.mode !== 'heatmap') return;
    fetch('/api/hyperliquid/orderbook?market=' + encodeURIComponent(state.coin) + '&force=1')
      .then(function (response) { return response.json(); })
      .then(function (book) {
        var rows = {};
        [['bids', 'bidSize'], ['asks', 'askSize']].forEach(function (side) {
          (book[side[0]] || []).forEach(function (level) {
            var px = Number(level.price);
            var sz = Number(level.size);
            if (!Number.isFinite(px) || !Number.isFinite(sz)) return;
            if (!rows[px]) rows[px] = { price: px, bidSize: 0, askSize: 0 };
            rows[px][side[1]] = sz;
          });
        });
        _pushBookSnapshot(Object.keys(rows).map(function (key) { return rows[key]; }), Number(book.time) || Date.now());
      }).catch(function () {});
  }

  function _startLive() {
    if (settings.mode === 'profile') return;
    if (state.liveWs && state.liveCoin === state.coin
        && (state.liveWs.readyState === WebSocket.CONNECTING || state.liveWs.readyState === WebSocket.OPEN)) {
      return;
    }
    _disconnectLive();
    state.liveCoin = state.coin;
    var generation = ++state.liveGeneration;
    var socket;
    try {
      socket = new WebSocket(WS_URL);
    } catch (e) {
      _syncStatus();
      return;
    }
    state.liveWs = socket;
    socket.onopen = function () {
      if (generation !== state.liveGeneration || state.liveWs !== socket) return;
      state.liveConnected = true;
      socket.send(JSON.stringify({ method: 'subscribe', subscription: { type: 'trades', coin: state.coin } }));
      socket.send(JSON.stringify({ method: 'subscribe', subscription: { type: 'l2Book', coin: state.coin } }));
      _syncStatus();
    };
    socket.onmessage = function (event) {
      if (generation !== state.liveGeneration || state.liveWs !== socket) return;
      var payload;
      try { payload = JSON.parse(event.data); } catch (e) { return; }
      if (payload.channel === 'trades' && Array.isArray(payload.data)) {
        _pushTrades(payload.data);
        _scheduleTradeRefresh();
      } else if (payload.channel === 'l2Book' && payload.data) {
        _ingestWsBook(payload.data);
      }
    };
    socket.onerror = function () {
      if (generation !== state.liveGeneration || state.liveWs !== socket) return;
      state.liveConnected = false;
      _syncStatus();
    };
    socket.onclose = function () {
      if (generation !== state.liveGeneration || state.liveWs !== socket) return;
      state.liveConnected = false;
      state.liveWs = null;
      _syncStatus();
      state.reconnectTimer = setTimeout(function () {
        if (generation === state.liveGeneration && settings.mode !== 'profile') _startLive();
      }, 2000);
    };
  }

  function _startModeRuntime() {
    if (state.refreshTimer) clearInterval(state.refreshTimer);
    if (state.bookPollTimer) clearInterval(state.bookPollTimer);
    state.refreshTimer = null;
    state.bookPollTimer = null;
    if (settings.mode === 'profile') {
      _disconnectLive();
      return;
    }
    _startLive();
    state.refreshTimer = setInterval(function () {
      if (settings.mode !== 'profile') refresh();
    }, settings.mode === 'footprint' ? 1800 : 8000);
    if (settings.mode === 'heatmap') {
      _primeBook();
      state.bookPollTimer = setInterval(_primeBook, 2000);
    }
  }

  function setMode(mode) {
    mode = String(mode || 'profile').toLowerCase();
    if (['profile', 'footprint', 'heatmap'].indexOf(mode) < 0) mode = 'profile';
    settings.mode = mode;
    _save();
    document.querySelectorAll('.workspace-mode').forEach(function (button) {
      button.classList.toggle('active', button.dataset.workspaceMode === mode);
    });
    _ensureCanvas();
    state.canvas.style.display = mode === 'profile' ? 'none' : 'block';
    if (window.VolumeProfile && window.VolumeProfile.setMode) window.VolumeProfile.setMode(mode);
    _startModeRuntime();
    if (mode !== 'profile') {
      _syncStatus();
      refresh();
    } else {
      render();
    }
  }

  function updateSettings(patch) {
    Object.assign(settings, patch || {});
    _save();
    if (settings.mode !== 'profile') refresh();
  }

  function _fmt(value) {
    if (!Number.isFinite(Number(value))) return '-';
    var abs = Math.abs(Number(value));
    if (abs >= 1000000) return (Number(value) / 1000000).toFixed(1) + 'M';
    if (abs >= 1000) return (Number(value) / 1000).toFixed(1) + 'k';
    if (abs >= 10) return Number(value).toFixed(0);
    return Number(value).toFixed(1);
  }

  function _priceY(value) {
    try { return state.series && state.series.priceToCoordinate(Number(value)); } catch (e) { return null; }
  }

  function _timeX(timeMs) {
    try { return state.chart && state.chart.timeScale().timeToCoordinate(Number(timeMs) / 1000); } catch (e) { return null; }
  }

  function _intervalMs(interval) {
    var match = String(interval || '3m').match(/^(\d+)([mhdw])$/);
    if (!match) return 180000;
    var value = Number(match[1]) || 3;
    var unit = match[2];
    if (unit === 'm') return value * 60000;
    if (unit === 'h') return value * 3600000;
    if (unit === 'd') return value * 86400000;
    return value * 7 * 86400000;
  }

  function _timeXInterpolated(timeMs) {
    var direct = _timeX(timeMs);
    if (direct != null) return direct;
    var candles = state.candles || [];
    var tSec = Number(timeMs) / 1000;
    if (!candles.length || !Number.isFinite(tSec)) return null;
    for (var i = 1; i < candles.length; i++) {
      var prev = candles[i - 1];
      var next = candles[i];
      if (tSec >= prev.time && tSec <= next.time) {
        var x0 = _timeX(prev.time * 1000);
        var x1 = _timeX(next.time * 1000);
        if (x0 != null && x1 != null && next.time !== prev.time) {
          return x0 + (x1 - x0) * ((tSec - prev.time) / (next.time - prev.time));
        }
      }
    }
    var spacing = _barSpacing();
    var intervalSec = Math.max(1, _intervalMs(state.interval) / 1000);
    var first = candles[0];
    var last = candles[candles.length - 1];
    if (tSec < first.time) {
      var firstX = _timeX(first.time * 1000);
      return firstX == null ? null : firstX - ((first.time - tSec) / intervalSec) * spacing;
    }
    var lastX = _timeX(last.time * 1000);
    return lastX == null ? null : lastX + ((tSec - last.time) / intervalSec) * spacing;
  }

  function _barSpacing() {
    if (state.candles.length < 2) return 44;
    var current = _timeX(state.candles[state.candles.length - 1].time * 1000);
    var prior = _timeX(state.candles[state.candles.length - 2].time * 1000);
    return current != null && prior != null ? Math.abs(current - prior) : 44;
  }

  function _label(ctx, x, y, text, color) {
    ctx.font = '700 10px "JetBrains Mono", monospace';
    var width = ctx.measureText(text).width + 16;
    ctx.fillStyle = 'rgba(8, 15, 21, 0.92)';
    ctx.fillRect(x, y, width, 21);
    ctx.strokeStyle = 'rgba(113, 137, 154, 0.16)';
    ctx.strokeRect(x + 0.5, y + 0.5, width - 1, 20);
    ctx.fillStyle = color;
    ctx.fillText(text, x + 8, y + 14);
    return width;
  }

  function render() {
    if (!state.ctx || !state.canvas || settings.mode === 'profile') return;
    var dpr = window.devicePixelRatio || 1;
    var width = state.canvas.width / dpr;
    var height = state.canvas.height / dpr;
    var ctx = state.ctx;
    ctx.clearRect(0, 0, width, height);

    var top = 40;
    var bottom = height - 42;
    var profileWidth = Math.min(270, Math.max(180, width * 0.20));
    var right = width - 56;
    var profileLeft = right - profileWidth;
    var plotRight = profileLeft - 22;

    ctx.fillStyle = 'rgba(6, 13, 19, 0.64)';
    ctx.fillRect(profileLeft - 12, 0, profileWidth + 20, bottom);
    ctx.strokeStyle = 'rgba(56, 211, 238, 0.08)';
    ctx.beginPath();
    ctx.moveTo(profileLeft - 12, top);
    ctx.lineTo(profileLeft - 12, bottom);
    ctx.stroke();

    var title = settings.mode === 'footprint'
      ? 'FOOTPRINT  /  SELL x BUY (AGGRESSIVE)'
      : 'HEATMAP  /  OBSERVED L2 LIQUIDITY';
    _label(ctx, 18, 14, title, '#b4cbd8');
    if (state.liveConnected) _label(ctx, 18, 42, 'LIVE  ' + state.coin + '-PERP', '#22d3ee');
    else _label(ctx, 18, 42, 'CONNECTING LIVE  ' + state.coin + '-PERP', '#f6c366');

    if (settings.mode === 'heatmap') _drawHeatmap(ctx, plotRight, top, bottom);
    else _drawFootprint(ctx, plotRight, top, bottom);
    _drawProfile(ctx, profileLeft, right, top, bottom);
  }

  function _drawHeatmapModern(ctx, plotRight, top, bottom) {
    var tiles = state.heatmap && state.heatmap.tiles || [];
    var snapshots = state.liveBooks || [];
    var allBooks = [];
    var tileGroup = {};

    tiles.forEach(function (tile) {
      if (!tileGroup[tile.timeMs]) tileGroup[tile.timeMs] = [];
      tileGroup[tile.timeMs].push(tile);
    });
    Object.keys(tileGroup).forEach(function (key) {
      allBooks.push({
        timeMs: Number(key),
        rows: tileGroup[key].map(function (tile) {
          return {
            price: Number(tile.price),
            bidSize: Number(tile.bidSize) || 0,
            askSize: Number(tile.askSize) || 0,
          };
        }),
      });
    });
    snapshots.forEach(function (book) {
      allBooks.push({
        timeMs: Number(book.timeMs) || Date.now(),
        rows: (book.rows || []).map(function (row) {
          return {
            price: Number(row.price),
            bidSize: Number(row.bidSize) || 0,
            askSize: Number(row.askSize) || 0,
          };
        }),
      });
    });
    allBooks.sort(function (a, b) { return a.timeMs - b.timeMs; });

    if (!allBooks.length) {
      _label(ctx, 18, 72, 'WAITING FOR L2 BOOK DATA  /  HISTORICAL ARCHIVE NOT LOADED', '#f6c366');
      return true;
    }

    var timeline = allBooks.map(function (book) {
      return { book: book, x: _timeXInterpolated(book.timeMs), synthetic: false };
    }).filter(function (item) {
      return item.x != null && item.x >= -80 && item.x <= plotRight + 80;
    });

    var syntheticMode = false;
    var timelineWidth = timeline.length ? timeline[timeline.length - 1].x - timeline[0].x : 0;
    if (((!tiles.length && snapshots.length) || (snapshots.length > 4 && timelineWidth < 160))) {
      var live = snapshots.slice(-96);
      var left = Math.max(76, plotRight - Math.min(560, Math.max(180, plotRight - 110)));
      var rightEdge = plotRight - 96;
      var span = Math.max(80, rightEdge - left);
      timeline = live.map(function (book, index) {
        var ratio = live.length <= 1 ? 1 : index / (live.length - 1);
        return { book: book, x: left + span * ratio, synthetic: true };
      });
      syntheticMode = true;
    }

    if (!timeline.length) {
      _label(ctx, 18, 72, 'L2 DATA OUTSIDE CURRENT VIEW  /  PAN TO LIVE BOOK', '#f6c366');
      return true;
    }

    var maxL2Size = 1;
    timeline.forEach(function (item) {
      (item.book.rows || []).forEach(function (row) {
        maxL2Size = Math.max(maxL2Size, Number(row.bidSize) || 0, Number(row.askSize) || 0);
      });
    });

    ctx.save();
    ctx.beginPath();
    ctx.rect(0, top, plotRight, bottom - top);
    ctx.clip();

    for (var idx = 0; idx < timeline.length; idx++) {
      var item = timeline[idx];
      var next = timeline[idx + 1];
      var x = item.x;
      var w = next ? Math.max(2, Math.min(18, next.x - x + 0.75))
        : (item.synthetic ? 5 : Math.max(4, Math.min(16, _barSpacing() * 0.18)));
      var rows = (item.book.rows || []).slice().sort(function (a, b) { return b.price - a.price; });

      for (var rIdx = 0; rIdx < rows.length; rIdx++) {
        var row = rows[rIdx];
        var y = _priceY(row.price);
        if (y == null || y < top - 20 || y > bottom + 20) continue;
        var nextRow = rows[rIdx + 1];
        var nextY = nextRow ? _priceY(nextRow.price) : null;
        var h = nextY != null && nextY > y ? nextY - y : 6;
        h = Math.max(1.5, Math.min(14, h + 0.5));

        var bid = Number(row.bidSize) || 0;
        var ask = Number(row.askSize) || 0;
        if (bid > 0) {
          var bidAlpha = 0.035 + Math.min(0.76, Math.log1p(bid) / Math.log1p(maxL2Size) * 0.70);
          ctx.fillStyle = 'rgba(34, 211, 238, ' + bidAlpha + ')';
          ctx.fillRect(x, y - h / 2, w, h);
        }
        if (ask > 0) {
          var askAlpha = 0.035 + Math.min(0.76, Math.log1p(ask) / Math.log1p(maxL2Size) * 0.70);
          ctx.fillStyle = 'rgba(251, 113, 133, ' + askAlpha + ')';
          ctx.fillRect(x, y - h / 2, w, h);
        }
      }
    }

    var oldestLive = snapshots.length ? snapshots[0].timeMs : null;
    var newestLive = snapshots.length ? snapshots[snapshots.length - 1].timeMs : null;
    var liveLeft = Math.max(76, plotRight - 560);
    var liveRight = plotRight - 98;
    var maxTradeSize = Math.max.apply(null, [1].concat((state.liveTrades || []).map(function (trade) {
      return Number(trade.sizeBase) || 0;
    })));
    (state.liveTrades || []).slice(-260).forEach(function (trade) {
      var x = _timeXInterpolated(trade.timeMs);
      if ((x == null || x < -50 || x > plotRight + 50) && oldestLive && newestLive && newestLive > oldestLive) {
        var ratio = Math.max(0, Math.min(1, (trade.timeMs - oldestLive) / (newestLive - oldestLive)));
        x = liveLeft + (liveRight - liveLeft) * ratio;
      }
      var y = _priceY(trade.price);
      if (x == null || y == null || x < -30 || x > plotRight + 30 || y < top || y > bottom) return;
      var radius = Math.max(2, Math.min(11, 2 + Math.log1p(trade.sizeBase) / Math.log1p(maxTradeSize) * 8));
      ctx.fillStyle = trade.aggressorSide === 'buy' ? 'rgba(34, 211, 238, 0.88)' : 'rgba(251, 113, 133, 0.86)';
      ctx.strokeStyle = 'rgba(4, 10, 15, 0.72)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.arc(x, y, radius, 0, Math.PI * 2);
      ctx.fill();
      ctx.stroke();
    });

    if (state.heatmap && state.heatmap.partial) {
      ctx.strokeStyle = 'rgba(246, 195, 102, 0.10)';
      ctx.lineWidth = 1;
      for (var hatch = -bottom; hatch < plotRight; hatch += 22) {
        ctx.beginPath();
        ctx.moveTo(hatch, bottom);
        ctx.lineTo(hatch + 80, bottom - 80);
        ctx.stroke();
      }
    }
    ctx.restore();

    var currentBook = snapshots.length ? snapshots[snapshots.length - 1] : allBooks[allBooks.length - 1];
    if (currentBook) {
      ctx.save();
      var domWidth = 92;
      var domLeft = plotRight - domWidth;
      ctx.fillStyle = 'rgba(7, 14, 20, 0.48)';
      ctx.fillRect(domLeft, top, domWidth, bottom - top);
      ctx.fillStyle = '#647887';
      ctx.font = '700 8px "JetBrains Mono", monospace';
      ctx.textAlign = 'left';
      ctx.fillText('LIVE DOM', domLeft + 6, top + 12);

      var currentRows = (currentBook.rows || []).slice().sort(function (a, b) { return b.price - a.price; });
      var maxDomSize = Math.max.apply(null, [1].concat(currentRows.map(function (row) {
        return Math.max(Number(row.bidSize) || 0, Number(row.askSize) || 0);
      })));
      currentRows.forEach(function (row) {
        var y = _priceY(row.price);
        if (y == null || y < top || y > bottom) return;
        var bid = Number(row.bidSize) || 0;
        var ask = Number(row.askSize) || 0;
        var size = Math.max(bid, ask);
        if (size <= 0) return;
        var barW = Math.min(domWidth - 6, (size / maxDomSize) * (domWidth - 6));
        var xStart = plotRight - barW;
        ctx.fillStyle = bid >= ask ? 'rgba(34, 211, 238, 0.30)' : 'rgba(251, 113, 133, 0.28)';
        ctx.fillRect(xStart, y - 2, barW, 4);
        ctx.fillStyle = bid >= ask ? '#22d3ee' : '#fb7185';
        ctx.fillRect(xStart, y - 2, 2, 4);
        if (size >= maxDomSize * 0.08 && barW > 30) {
          ctx.font = 'bold 8px "JetBrains Mono", monospace';
          ctx.fillStyle = '#ffffff';
          ctx.textAlign = 'right';
          ctx.fillText(Math.round(size), plotRight - 4, y + 3);
        }
      });
      ctx.restore();
    }

    var totalBidSize = 0;
    var totalAskSize = 0;
    var maxBidWall = { price: 0, size: 0 };
    var maxAskWall = { price: 0, size: 0 };
    if (currentBook) {
      (currentBook.rows || []).forEach(function (row) {
        var bid = Number(row.bidSize) || 0;
        var ask = Number(row.askSize) || 0;
        totalBidSize += bid;
        totalAskSize += ask;
        if (bid > maxBidWall.size) maxBidWall = { price: Number(row.price) || 0, size: bid };
        if (ask > maxAskWall.size) maxAskWall = { price: Number(row.price) || 0, size: ask };
      });
    }

    var totalBook = totalBidSize + totalAskSize || 1;
    var bidPct = Math.round(totalBidSize / totalBook * 100);
    var askPct = 100 - bidPct;
    ctx.save();
    ctx.fillStyle = 'rgba(7, 13, 20, 0.82)';
    ctx.strokeStyle = 'rgba(255,255,255,0.06)';
    ctx.lineWidth = 1;
    ctx.fillRect(18, 72, 398, 52);
    ctx.strokeRect(18, 72, 398, 52);
    ctx.fillStyle = 'rgba(255,255,255,0.34)';
    ctx.font = 'bold 8px "JetBrains Mono", monospace';
    ctx.textAlign = 'left';
    ctx.fillText('BOOK IMBALANCE', 30, 84);
    ctx.fillStyle = 'rgba(251,113,133,0.28)';
    ctx.fillRect(30, 90, 124, 5);
    ctx.fillStyle = '#22d3ee';
    ctx.fillRect(30, 90, 124 * (bidPct / 100), 5);
    ctx.fillStyle = '#ffffff';
    ctx.fillText(bidPct + '% Bids / ' + askPct + '% Asks', 30, 108);
    ctx.fillStyle = 'rgba(255,255,255,0.34)';
    ctx.fillText('LIQUIDITY WALLS (DOM)', 184, 84);
    ctx.fillStyle = '#22d3ee';
    ctx.fillText('BUY WALL  $' + maxBidWall.price.toFixed(1) + '  ' + Math.round(maxBidWall.size), 184, 98);
    ctx.fillStyle = '#fb7185';
    ctx.fillText('SELL WALL $' + maxAskWall.price.toFixed(1) + '  ' + Math.round(maxAskWall.size), 184, 112);
    ctx.restore();

    var modeText = syntheticMode ? 'LIVE L2 BOOK STRIP' : 'TIME-ALIGNED L2 BOOK';
    _label(ctx, 18, bottom - 28, modeText + '  /  TRADES AS BUBBLES  /  NO LIQUIDITY INTERPOLATION', '#f6c366');
    return true;
  }

  function _drawHeatmap(ctx, plotRight, top, bottom) {
    if (_drawHeatmapModern(ctx, plotRight, top, bottom)) return;
    var tiles = state.heatmap && state.heatmap.tiles || [];
    var snapshots = state.liveBooks || [];

    // Unifier les tuiles historiques et les snapshots live dans une seule chronologie
    var allBooks = [];

    // 1. Ajouter les tuiles historiques (groupées par timeMs)
    var tileGroup = {};
    tiles.forEach(function(tile) {
      if (!tileGroup[tile.timeMs]) tileGroup[tile.timeMs] = [];
      tileGroup[tile.timeMs].push(tile);
    });
    Object.keys(tileGroup).forEach(function(tStr) {
      var tMs = Number(tStr);
      allBooks.push({
        timeMs: tMs,
        rows: tileGroup[tStr].map(function(tile) {
          return {
            price: Number(tile.price),
            bidSize: Number(tile.bidSize) || 0,
            askSize: Number(tile.askSize) || 0
          };
        })
      });
    });

    // 2. Ajouter les snapshots live L2
    snapshots.forEach(function(book) {
      allBooks.push({
        timeMs: book.timeMs,
        rows: book.rows.map(function(row) {
          return {
            price: Number(row.price),
            bidSize: Number(row.bidSize) || 0,
            askSize: Number(row.askSize) || 0
          };
        })
      });
    });

    // Trier chronologiquement par timeMs croissant
    allBooks.sort(function(a, b) { return a.timeMs - b.timeMs; });

    if (allBooks.length === 0) {
      _label(ctx, 18, 72, 'WAITING FOR L2 BOOK DATA  /  HISTORICAL ARCHIVE NOT LOADED', '#f6c366');
      return;
    }

    // Trouver la taille maximale de l'orderbook dans le range visible pour calibrer la brillance (opacité)
    var maxL2Size = 1;
    var visibleBooks = allBooks.filter(function(b) {
      var x = _timeX(b.timeMs);
      return x != null && x >= -50 && x <= plotRight + 50;
    });

    visibleBooks.forEach(function(b) {
      b.rows.forEach(function(r) {
        var size = Math.max(r.bidSize, r.askSize);
        if (size > maxL2Size) maxL2Size = size;
      });
    });

    // 3. RESSORT DE LA HEATMAP EN ARRIÈRE-PLAN CONTINU (INTEGRATED BACKGROUND)
    for (var idx = 0; idx < allBooks.length; idx++) {
      var book = allBooks[idx];
      var x = _timeX(book.timeMs);
      if (x == null || x < -50 || x > plotRight + 50) continue;

      var nextBook = allBooks[idx + 1];
      var nextX = nextBook ? _timeX(nextBook.timeMs) : null;
      var w = (nextX != null && nextX > x) ? (nextX - x) : 10; // par défaut 10px
      w = Math.max(1, w + 0.5); // léger overlap pour éviter les lignes de découpe blanches

      var sortedRows = book.rows.slice().sort(function(a, b) { return b.price - a.price; });

      for (var rIdx = 0; rIdx < sortedRows.length; rIdx++) {
        var row = sortedRows[rIdx];
        var y = _priceY(row.price);
        if (y == null || y < top - 20 || y > bottom + 20) continue;

        var nextRow = sortedRows[rIdx + 1];
        var nextY = nextRow ? _priceY(nextRow.price) : null;
        var h = (nextY != null && nextY > y) ? (nextY - y) : 6; // par défaut 6px
        h = Math.max(1, h + 0.5); // overlap

        var bid = row.bidSize;
        var ask = row.askSize;
        var size = Math.max(bid, ask);
        if (size < 0.01) continue;

        // Échelle logarithmique pour faire ressortir les "murs" de liquidité de manière néon intense
        var ratio = size / maxL2Size;
        var alpha = 0.03 + Math.min(0.85, Math.log1p(ratio * 9) / Math.log1p(9) * 0.70);

        if (bid >= ask) {
          ctx.fillStyle = 'rgba(6, 182, 212, ' + alpha + ')'; // Bleu / Cyan néon pour les Bids
        } else {
          ctx.fillStyle = 'rgba(236, 72, 153, ' + alpha + ')'; // Rose / Magenta néon pour les Asks
        }
        ctx.fillRect(x, y - h / 2, w, h);
      }
    }

    // 4. DRAW DYNAMIC DOM SIDEBAR (DEPTH OF MARKET) DIRECTLY AT THE RIGHT EDGE
    var currentBook = snapshots.length ? snapshots[snapshots.length - 1] : (allBooks.length ? allBooks[allBooks.length - 1] : null);
    if (currentBook) {
      ctx.save();
      // Fond transparent de la zone DOM
      var domWidth = 85; 
      var domLeft = plotRight - domWidth;
      ctx.fillStyle = 'rgba(7, 14, 20, 0.40)';
      ctx.fillRect(domLeft, top, domWidth, bottom - top);

      var sortedCurrent = currentBook.rows.slice().sort(function(a, b) { return b.price - a.price; });
      var maxDomSize = Math.max.apply(null, sortedCurrent.map(function(r) { return Math.max(r.bidSize, r.askSize); })) || 1;

      sortedCurrent.forEach(function (row, rowIndex) {
        var y = _priceY(row.price);
        if (y == null || y < top || y > bottom) return;

        var bid = Number(row.bidSize) || 0;
        var ask = Number(row.askSize) || 0;
        var size = Math.max(bid, ask);
        if (size < 0.01) return;

        var barW = Math.min(domWidth - 4, (size / maxDomSize) * (domWidth - 4));
        var xStart = plotRight - barW;

        // Remplissage horizontal néon aligné sur le prix
        ctx.fillStyle = bid >= ask ? 'rgba(6, 182, 212, 0.28)' : 'rgba(236, 72, 153, 0.25)';
        ctx.fillRect(xStart, y - 2, barW, 4);

        // Bord néon lumineux à l'extrémité
        ctx.fillStyle = bid >= ask ? '#06b6d4' : '#ec4899';
        ctx.fillRect(xStart, y - 2, 2, 4);

        // Afficher les valeurs numériques des gros blocs sur le DOM
        if (size >= maxDomSize * 0.08 && barW > 30) {
          ctx.font = 'bold 8px "JetBrains Mono", monospace';
          ctx.fillStyle = '#ffffff';
          ctx.textAlign = 'right';
          ctx.fillText(Math.round(size), plotRight - 4, y + 3);
        }
      });
      ctx.restore();
    }

    // 5. HUD METRICS OVERLAY AT TOP-LEFT
    ctx.save();
    var totalBidSize = 0;
    var totalAskSize = 0;
    var maxBidWall = { price: 0, size: 0 };
    var maxAskWall = { price: 0, size: 0 };

    if (currentBook) {
      currentBook.rows.forEach(function (row) {
        var bid = Number(row.bidSize) || 0;
        var ask = Number(row.askSize) || 0;
        totalBidSize += bid;
        totalAskSize += ask;
        if (bid > maxBidWall.size) maxBidWall = { price: row.price, size: bid };
        if (ask > maxAskWall.size) maxAskWall = { price: row.price, size: ask };
      });
    }

    var totalBook = totalBidSize + totalAskSize || 1;
    var bidPct = Math.round(totalBidSize / totalBook * 100);
    var askPct = 100 - bidPct;

    ctx.fillStyle = 'rgba(7, 13, 20, 0.82)';
    ctx.strokeStyle = 'rgba(255,255,255,0.06)';
    ctx.lineWidth = 1;
    ctx.fillRect(18, 72, 380, 48);
    ctx.strokeRect(18, 72, 380, 48);

    ctx.fillStyle = 'rgba(255,255,255,0.3)';
    ctx.font = 'bold 8px "JetBrains Mono", monospace';
    ctx.fillText('BOOK IMBALANCE', 30, 84);
    
    ctx.fillStyle = 'rgba(236,72,153,0.3)'; // magenta asks
    ctx.fillRect(30, 89, 120, 5);
    ctx.fillStyle = '#06b6d4'; // cyan bids
    ctx.fillRect(30, 89, 120 * (bidPct / 100), 5);

    ctx.fillStyle = '#ffffff';
    ctx.fillText(bidPct + '% Bids / ' + askPct + '% Asks', 30, 105);

    if (maxBidWall.size > 0 || maxAskWall.size > 0) {
      ctx.fillStyle = 'rgba(255,255,255,0.3)';
      ctx.fillText('LIQUIDITY WALLS (DOM)', 180, 84);

      ctx.fillStyle = '#06b6d4';
      ctx.fillText('BUY WALL: $' + maxBidWall.price.toFixed(1) + ' (' + Math.round(maxBidWall.size) + ')', 180, 94);
      ctx.fillStyle = '#ec4899';
      ctx.fillText('SELL WALL: $' + maxAskWall.price.toFixed(1) + ' (' + Math.round(maxAskWall.size) + ')', 180, 104);
    }
    ctx.restore();

    _label(ctx, 18, bottom - 28, 'HEATMAP INTEGRATED  /  ACTIVE REAL-TIME L2 ORDERBOOK', '#f6c366');
  }

  function _liveRowSize(trades) {
    var prices = trades.map(function (trade) { return trade.price; });
    if (!prices.length) return 1;
    var high = Math.max.apply(null, prices);
    var low = Math.min.apply(null, prices);
    var tick = high >= 10000 ? 1 : high >= 1000 ? 0.1 : high >= 10 ? 0.01 : 0.0001;
    var desired = Math.max(tick, (high - low) / 36);
    return Math.max(tick, Math.ceil(desired / tick) * tick);
  }

  function _liveFootprintCandles() {
    var trades = (state.liveTrades || []).slice(-900);
    if (!trades.length) return { candles: [], cvd: 0 };
    var intervalMs = _intervalMs(state.interval);
    var rowSize = _liveRowSize(trades);
    var buckets = {};

    trades.forEach(function (trade) {
      var bucketMs = Math.floor(trade.timeMs / intervalMs) * intervalMs;
      var candle = buckets[bucketMs];
      if (!candle) {
        candle = buckets[bucketMs] = {
          time: Math.floor(bucketMs / 1000),
          openTime: bucketMs,
          open: trade.price,
          high: trade.price,
          low: trade.price,
          close: trade.price,
          levels: {},
          buyVolume: 0,
          sellVolume: 0,
          delta: 0,
        };
      }
      candle.high = Math.max(candle.high, trade.price);
      candle.low = Math.min(candle.low, trade.price);
      candle.close = trade.price;
      var price = Math.floor((trade.price + rowSize * 1e-9) / rowSize) * rowSize;
      price = Math.round(price * 100000000) / 100000000;
      var level = candle.levels[price];
      if (!level) {
        level = candle.levels[price] = { price: price, buyVolume: 0, sellVolume: 0, totalVolume: 0, delta: 0 };
      }
      var volume = settings.metric === 'base' ? trade.sizeBase : trade.notionalUsd;
      if (trade.aggressorSide === 'buy') {
        level.buyVolume += volume;
        candle.buyVolume += volume;
      } else if (trade.aggressorSide === 'sell') {
        level.sellVolume += volume;
        candle.sellVolume += volume;
      }
      level.totalVolume += volume;
      level.delta = level.buyVolume - level.sellVolume;
      candle.delta += trade.aggressorSide === 'buy' ? volume : trade.aggressorSide === 'sell' ? -volume : 0;
    });

    var cvd = 0;
    var candles = Object.keys(buckets).sort().map(function (key) {
      var candle = buckets[key];
      cvd += candle.delta;
      candle.cvd = cvd;
      candle.levels = Object.keys(candle.levels).map(function (price) { return candle.levels[price]; })
        .sort(function (a, b) { return a.price - b.price; });
      return candle;
    });
    return { candles: candles, cvd: cvd };
  }

  function _mergeFootprintCandles(serverCandles, liveCandles) {
    var merged = {};
    (serverCandles || []).forEach(function (candle) {
      merged[candle.openTime || candle.time * 1000] = candle;
    });
    (liveCandles || []).forEach(function (candle) {
      merged[candle.openTime || candle.time * 1000] = candle;
    });
    return Object.keys(merged).sort(function (a, b) { return Number(a) - Number(b); }).map(function (key) { return merged[key]; });
  }

  function _drawFootprintDomContext(ctx, plotRight, top, bottom) {
    var book = state.liveBooks.length ? state.liveBooks[state.liveBooks.length - 1] : null;
    if (!book || !book.rows || !book.rows.length) return;
    var width = 72;
    var left = plotRight - width;
    var rows = book.rows.slice().sort(function (a, b) { return b.price - a.price; });
    var maxSize = Math.max.apply(null, [1].concat(rows.map(function (row) {
      return Math.max(Number(row.bidSize) || 0, Number(row.askSize) || 0);
    })));
    ctx.save();
    ctx.fillStyle = 'rgba(7, 14, 20, 0.38)';
    ctx.fillRect(left, top, width, bottom - top);
    ctx.font = '700 8px "JetBrains Mono", monospace';
    ctx.fillStyle = '#647887';
    ctx.textAlign = 'left';
    ctx.fillText('DOM CTX', left + 6, top + 12);
    rows.forEach(function (row) {
      var y = _priceY(row.price);
      if (y == null || y < top || y > bottom) return;
      var bid = Number(row.bidSize) || 0;
      var ask = Number(row.askSize) || 0;
      var size = Math.max(bid, ask);
      if (size <= 0) return;
      var bar = Math.max(2, (size / maxSize) * (width - 8));
      ctx.fillStyle = bid >= ask ? 'rgba(34, 211, 238, 0.24)' : 'rgba(251, 113, 133, 0.22)';
      ctx.fillRect(plotRight - bar, y - 1.5, bar, 3);
    });
    ctx.restore();
  }

  function _drawFootprint(ctx, plotRight, top, bottom) {
    var livePack = _liveFootprintCandles();
    var serverCandles = state.footprint && state.footprint.candles || [];
    var candles = _mergeFootprintCandles(serverCandles, livePack.candles);
    if (!candles.length) {
      _label(ctx, 18, 72, 'WAITING FOR EXECUTED TRADES  /  HISTORY NOT IMPORTED', '#f6c366');
      _drawFootprintDomContext(ctx, plotRight, top, bottom);
      return;
    }
    var spacing = _barSpacing();
    var shown = candles.slice(-Math.max(1, Math.floor(plotRight / 62)));
    var cellWidth = shown.length <= 3 ? Math.max(132, Math.min(168, spacing * 3.4)) : Math.max(46, Math.min(82, spacing * 1.35));

    shown.forEach(function (candle, index) {
      var centerX = _timeX(candle.openTime || candle.time * 1000);
      if (centerX == null) centerX = plotRight - (shown.length - index) * (cellWidth + 4);
      if (centerX < 0 || centerX > plotRight + cellWidth) return;
      var x = Math.min(plotRight - cellWidth - 8, Math.max(56, centerX - cellWidth / 2));
      var levels = candle.levels || [];
      var naturalStep = levels.length > 1 ? Math.abs((_priceY(levels[1].price) || 0) - (_priceY(levels[0].price) || 0)) : 0;
      var magnified = shown.length <= 3 && naturalStep < 13;
      var rowHeight = magnified ? 22 : Math.max(12, Math.min(20, naturalStep || 14));
      var centerY = _priceY(candle.close);
      if (centerY == null) centerY = (top + bottom) / 2;

      ctx.strokeStyle = candle.close >= candle.open ? 'rgba(34,211,238,0.40)' : 'rgba(251,113,133,0.40)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(centerX, _priceY(candle.high) || centerY);
      ctx.lineTo(centerX, _priceY(candle.low) || centerY);
      ctx.stroke();

      if (levels.length === 0) return;

      var sortedLevels = levels.slice().sort(function(a, b) { return b.price - a.price; });

      var maxVol = 0;
      var maxLvlVol = 0;
      var pocLevel = null;
      for (var li = 0; li < sortedLevels.length; li++) {
        var lv = sortedLevels[li];
        var totalVol = (lv.buyVolume || 0) + (lv.sellVolume || 0);
        if (totalVol > maxLvlVol) {
          maxLvlVol = totalVol;
          pocLevel = lv;
        }
        if (lv.buyVolume > maxVol) maxVol = lv.buyVolume;
        if (lv.sellVolume > maxVol) maxVol = lv.sellVolume;
      }
      if (maxVol < 1) maxVol = 1;

      var imbalanceRatio = 3.0;
      for (var li = 0; li < sortedLevels.length; li++) {
        var lv = sortedLevels[li];
        lv.buyImbalance = false;
        lv.sellImbalance = false;

        if (li < sortedLevels.length - 1) {
          var belowBid = sortedLevels[li + 1].sellVolume;
          if (lv.buyVolume >= (belowBid || 0.01) * imbalanceRatio) {
            lv.buyImbalance = true;
          }
        }
        if (li > 0) {
          var aboveAsk = sortedLevels[li - 1].buyVolume;
          if (lv.sellVolume >= (aboveAsk || 0.01) * imbalanceRatio) {
            lv.sellImbalance = true;
          }
        }
      }

      var stackedBuyZones = [];
      var stackedSellZones = [];
      var consecutiveBuys = [];
      var consecutiveSells = [];
      var stackCount = 3;

      for (var li = 0; li < sortedLevels.length; li++) {
        var lv = sortedLevels[li];
        
        if (lv.buyImbalance) consecutiveBuys.push(lv);
        else {
          if (consecutiveBuys.length >= stackCount) stackedBuyZones.push(consecutiveBuys.slice());
          consecutiveBuys = [];
        }

        if (lv.sellImbalance) consecutiveSells.push(lv);
        else {
          if (consecutiveSells.length >= stackCount) stackedSellZones.push(consecutiveSells.slice());
          consecutiveSells = [];
        }
      }
      if (consecutiveBuys.length >= stackCount) stackedBuyZones.push(consecutiveBuys);
      if (consecutiveSells.length >= stackCount) stackedSellZones.push(consecutiveSells);

      var halfW = cellWidth / 2;
      var splitX = x + halfW;

      if (shown.length <= 3) {
        var matrixTop = centerY - sortedLevels.length * rowHeight / 2 - 18;
        var matrixHeight = sortedLevels.length * rowHeight + 38;
        ctx.fillStyle = 'rgba(5, 12, 18, 0.72)';
        ctx.fillRect(x - 7, matrixTop, cellWidth + 14, matrixHeight);
        ctx.strokeStyle = 'rgba(56, 211, 238, 0.18)';
        ctx.strokeRect(x - 7.5, matrixTop + 0.5, cellWidth + 15, matrixHeight - 1);
        ctx.font = '800 8px "JetBrains Mono", monospace';
        ctx.textAlign = 'center';
        ctx.fillStyle = '#fb7185';
        ctx.fillText('SELL', x + halfW / 2, matrixTop + 12);
        ctx.fillStyle = '#22d3ee';
        ctx.fillText('BUY', splitX + halfW / 2, matrixTop + 12);
      }

      sortedLevels.forEach(function (level, levelIndex) {
        var levelY = magnified
          ? centerY + (sortedLevels.length / 2 - levelIndex - 0.5) * rowHeight
          : _priceY(level.price);
        if (levelY == null || levelY < top || levelY > bottom) return;

        var cellX = x;
        var cellY = levelY - rowHeight / 2;

        var bidAlpha = Math.min(0.85, 0.05 + (level.sellVolume / maxVol) * 0.5);
        ctx.fillStyle = 'rgba(251,113,133,' + bidAlpha + ')';
        ctx.fillRect(cellX, cellY, halfW, rowHeight - 1);

        var askAlpha = Math.min(0.85, 0.05 + (level.buyVolume / maxVol) * 0.5);
        ctx.fillStyle = 'rgba(34,211,238,' + askAlpha + ')';
        ctx.fillRect(splitX, cellY, halfW, rowHeight - 1);

        if (level.buyImbalance) {
          ctx.fillStyle = 'rgba(34,211,238,0.42)';
          ctx.fillRect(splitX, cellY, halfW, rowHeight - 1);
        }
        if (level.sellImbalance) {
          ctx.fillStyle = 'rgba(251,113,133,0.42)';
          ctx.fillRect(cellX, cellY, halfW, rowHeight - 1);
        }

        if (pocLevel && level.price === pocLevel.price) {
          ctx.strokeStyle = '#f59e0b';
          ctx.lineWidth = 1.2;
          ctx.strokeRect(cellX + 0.5, cellY + 0.5, cellWidth - 1, rowHeight - 2);
        } else {
          ctx.strokeStyle = 'rgba(255,255,255,0.06)';
          ctx.lineWidth = 0.5;
          ctx.strokeRect(cellX, cellY, cellWidth, rowHeight - 1);
        }

        ctx.strokeStyle = 'rgba(255,255,255,0.15)';
        ctx.beginPath();
        ctx.moveTo(splitX, cellY);
        ctx.lineTo(splitX, cellY + rowHeight - 1);
        ctx.stroke();

        if (rowHeight >= 11 && cellWidth >= 75) {
          ctx.save();
          ctx.font = shown.length <= 3 ? 'bold 10px "JetBrains Mono", monospace' : 'bold 9px "JetBrains Mono", monospace';
          ctx.textBaseline = 'middle';

          ctx.textAlign = 'right';
          ctx.fillStyle = level.sellImbalance ? '#fda4af' : '#ffffff';
          ctx.fillText(_fmt(level.sellVolume), splitX - 4, levelY);

          ctx.textAlign = 'left';
          ctx.fillStyle = level.buyImbalance ? '#67e8f9' : '#ffffff';
          ctx.fillText(_fmt(level.buyVolume), splitX + 4, levelY);

          ctx.restore();
        }
      });

      stackedBuyZones.forEach(function (zone) {
        var topLvl = zone[0];
        var botLvl = zone[zone.length - 1];
        var yTop = (magnified ? centerY + (sortedLevels.length / 2 - sortedLevels.indexOf(topLvl) - 0.5) * rowHeight : _priceY(topLvl.price)) - rowHeight / 2;
        var yBot = (magnified ? centerY + (sortedLevels.length / 2 - sortedLevels.indexOf(botLvl) - 0.5) * rowHeight : _priceY(botLvl.price)) + rowHeight / 2;

        ctx.strokeStyle = '#22d3ee';
        ctx.lineWidth = 2;
        ctx.fillStyle = 'rgba(34,211,238,0.13)';
        ctx.fillRect(x, yTop, cellWidth, yBot - yTop);
        ctx.strokeRect(x, yTop, cellWidth, yBot - yTop);
      });

      stackedSellZones.forEach(function (zone) {
        var topLvl = zone[0];
        var botLvl = zone[zone.length - 1];
        var yTop = (magnified ? centerY + (sortedLevels.length / 2 - sortedLevels.indexOf(topLvl) - 0.5) * rowHeight : _priceY(topLvl.price)) - rowHeight / 2;
        var yBot = (magnified ? centerY + (sortedLevels.length / 2 - sortedLevels.indexOf(botLvl) - 0.5) * rowHeight : _priceY(botLvl.price)) + rowHeight / 2;

        ctx.strokeStyle = '#fb7185';
        ctx.lineWidth = 2;
        ctx.fillStyle = 'rgba(251,113,133,0.13)';
        ctx.fillRect(x, yTop, cellWidth, yBot - yTop);
        ctx.strokeRect(x, yTop, cellWidth, yBot - yTop);
      });

      ctx.save();
      ctx.font = 'bold 8px "JetBrains Mono", monospace';
      ctx.textAlign = 'center';
      ctx.fillStyle = candle.delta >= 0 ? '#22d3ee' : '#fb7185';
      var labelY = Math.min(bottom - 8, centerY + sortedLevels.length * rowHeight / 2 + 18);
      ctx.fillText((candle.delta >= 0 ? '+' : '') + _fmt(candle.delta), x + cellWidth / 2, labelY);
      ctx.restore();
    });

    ctx.textAlign = 'left';
    _drawFootprintDomContext(ctx, plotRight, top, bottom);
    var cvdValue = (state.footprint && Number.isFinite(Number(state.footprint.cvd))) ? Number(state.footprint.cvd) : 0;
    cvdValue += livePack.cvd || 0;
    _label(ctx, 18, bottom - 28, 'CVD  ' + _fmt(cvdValue) + '  /  EXECUTED TRADES + LIVE DOM CONTEXT', '#f6c366');
  }

  function _drawProfile(ctx, left, right, top, bottom) {
    var profile = state.profile;
    var levels = profile && profile.levels || [];
    ctx.font = '700 9px "JetBrains Mono", monospace';
    ctx.textAlign = 'left';
    ctx.fillStyle = '#647887';
    ctx.fillText('INTEGRATED VOLUME PROFILE', left, 26);
    if (!levels.length) {
      ctx.fillStyle = '#f6c366';
      ctx.fillText('NO TRADE COVERAGE', left, 44);
      return;
    }
    var maximum = Math.max.apply(null, levels.map(function (level) { return level.totalVolume; })) || 1;
    var width = right - left;
    levels.forEach(function (level) {
      var yy = _priceY(level.price);
      if (yy == null || yy < top || yy > bottom) return;
      var bar = level.totalVolume / maximum * width;
      var sell = level.totalVolume ? bar * level.sellVolume / level.totalVolume : 0;
      ctx.globalAlpha = level.price >= profile.val && level.price <= profile.vah ? 0.88 : 0.35;
      ctx.fillStyle = '#fb7185';
      ctx.fillRect(right - bar, yy - 3, sell, 6);
      ctx.fillStyle = '#22d3ee';
      ctx.fillRect(right - bar + sell, yy - 3, bar - sell, 6);
    });
    ctx.globalAlpha = 1;
    [[profile.poc, '#f59e0b', 'POC'], [profile.vah, '#38d3ee', 'VAH'], [profile.val, '#fb7185', 'VAL']].forEach(function (item) {
      if (item[0] == null) return;
      var yy = _priceY(item[0]);
      if (yy == null || yy < top || yy > bottom) return;
      ctx.strokeStyle = item[1];
      ctx.globalAlpha = item[2] === 'POC' ? 0.90 : 0.48;
      ctx.beginPath();
      ctx.moveTo(left - 8, yy);
      ctx.lineTo(right, yy);
      ctx.stroke();
      ctx.globalAlpha = 1;
      ctx.fillStyle = item[1];
      ctx.fillText(item[2] + ' ' + Number(item[0]).toFixed(2), left, yy - 6);
    });
  }

  window.HyperliquidWorkspace = {
    init: init,
    setContext: setContext,
    setMode: setMode,
    updateSettings: updateSettings,
    getSettings: function () { return Object.assign({}, settings); },
    refresh: refresh,
  };
})();

// ---- 064_chart_drawings.js ----
// ---------- Chart Drawing Engine v3 — Canvas Overlay ----------
// Tools: Box, Trend, Horizontal, Horizontal Ray, Vertical, Fibonacci, Text
// Features: opacity, fib level toggles, templates, colors, extends, text labels
// v3.2 — Session zones: Asian, London, New York time-based overlays

(function () {
  'use strict';

  var DRAW_TOOLS = [
    { id: 'cursor',        label: 'Curseur',      icon: '⊹' },
    { id: 'box',           label: 'Rectangle',     icon: '▭' },
    { id: 'trendline',     label: 'Trend line',    icon: '↗' },
    { id: 'horizontal',    label: 'Horizontale',   icon: '—' },
    { id: 'horizontalray', label: 'Rayon horiz.',  icon: '→' },
    { id: 'vertical',      label: 'Verticale',     icon: '│' },
    { id: 'fibonacci',     label: 'Fibonacci',     icon: 'ϕ' },
    { id: 'text',          label: 'Texte',          icon: 'T' },
  ];

  var LINE_WIDTHS = [1, 1.5, 2, 2.5, 3];
  var LINE_STYLES = [
    { id: 'solid',  label: '─', dash: [] },
    { id: 'dashed', label: '╌', dash: [6, 4] },
    { id: 'dotted', label: '┈', dash: [2, 4] },
  ];
  var TOOL_COLORS = ['#06b6d4', '#22c55e', '#f59e0b', '#ef4444', '#a78bfa', '#f472b6', '#fb923c', '#ffffff', '#9ca3af'];

  var FIB_LEVELS = [
    { key: 0,     label: '0',     color: '#9ca3af' },
    { key: 0.236, label: '23.6',  color: '#06b6d4' },
    { key: 0.382, label: '38.2',  color: '#22c55e' },
    { key: 0.5,   label: '50',    color: '#f59e0b' },
    { key: 0.618, label: '61.8',  color: '#ef4444' },
    { key: 1,     label: '100',   color: '#9ca3af' },
    { key: 2,     label: '200',   color: '#a78bfa' },
    { key: 2.5,   label: '250',   color: '#f472b6' },
    { key: 3,     label: '300',   color: '#fb923c' },
    { key: 4,     label: '400',   color: '#34d399' },
    { key: 4.5,   label: '450',   color: '#818cf8' },
    { key: 5,     label: '500',   color: '#e879f9' },
  ];
  // Default: all levels visible
  var DEFAULT_FIB_VISIBLE = {};
  FIB_LEVELS.forEach(function (l) { DEFAULT_FIB_VISIBLE[l.key] = true; });

  function _formatFibLabel(key) {
    var pct = key * 100;
    var rounded = Math.round(pct * 1000) / 1000;
    return String(rounded).replace(/\.?0+$/, '');
  }

  function _normalizeFibLevels(levels) {
    var normalized;
    if (Array.isArray(levels)) {
      normalized = levels.map(function (l, idx) {
        var key = Number(l.key);
        if (!Number.isFinite(key)) return null;
        return {
          key: key,
          label: String(l.label || _formatFibLabel(key)),
          color: l.color || TOOL_COLORS[idx % TOOL_COLORS.length],
          visible: l.visible !== false,
        };
      }).filter(Boolean);
    } else {
      var visible = levels && typeof levels === 'object' ? levels : DEFAULT_FIB_VISIBLE;
      normalized = FIB_LEVELS.map(function (l) {
        return {
          key: Number(l.key),
          label: l.label,
          color: l.color,
          visible: visible[l.key] !== false,
        };
      });
    }
    normalized.sort(function (a, b) { return a.key - b.key; });
    return normalized;
  }

  function _cloneFibLevels(levels) {
    return _normalizeFibLevels(levels).map(function (l) {
      return { key: l.key, label: l.label, color: l.color, visible: l.visible !== false };
    });
  }

  function _defaultFibLevels() { return _cloneFibLevels(FIB_LEVELS); }

  function _fibLevelPrice(points, key) {
    var price1 = points[0].price;
    var price2 = points[1].price;
    return price2 + (price1 - price2) * key;
  }

  var STORAGE_KEY = 'chartDrawings';
  var TEMPLATE_KEY = 'chartDrawTemplates';
  var MAX_UNDO = 30;

  // ── SESSION PRESETS ──
  // Chaque session définit ses horaires en heure locale du marché.
  // timezone = fuseau horaire IANA (ex: 'America/New_York')
  // start/end = heures locales au format 'HH:MM'
  // Le rendu convertit automatiquement en UTC selon la date affichée,
  // ce qui gère correctement les passages à l'heure d'été (DST).
  var SESSION_PRESETS = [
    { id: 'asian',     name: 'Asie',      timezone: 'Asia/Tokyo',          start: '09:00', end: '15:00', color: '#ffdd00', active: true,  opacity: 0.12 },
    { id: 'london',    name: 'Londres',   timezone: 'Europe/London',       start: '08:00', end: '16:30', color: '#0066ff', active: true,  opacity: 0.12 },
    { id: 'ny_rth',    name: 'NY RTH',    timezone: 'America/New_York',   start: '09:30', end: '16:00', color: '#ff0066', active: true,  opacity: 0.12 },
    { id: 'ny_ext',    name: 'NY Ext',    timezone: 'America/New_York',   start: '08:00', end: '17:00', color: '#ff7733', active: false, opacity: 0.08 },
  ];

  var SESSION_STORAGE_KEY = 'chartSessionSettings';
  // ── / SESSION PRESETS

  // ── TIMEZONE HELPERS ──
  // Calcule le décalage UTC (en minutes) d'une timezone pour une date donnée.
  // Utilise Intl.DateTimeFormat.formatToParts — fiable sur tous les navigateurs modernes.
  function _getTzOffsetMinutes(dateMs, timezone) {
    try {
      var parts = new Intl.DateTimeFormat('en-CA', {
        timeZone: timezone,
        year: 'numeric', month: '2-digit', day: '2-digit',
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: false,
      }).formatToParts(new Date(dateMs));
      var v = {};
      for (var pi = 0; pi < parts.length; pi++) { v[parts[pi].type] = parts[pi].value; }
      var tzDate = Date.UTC(
        parseInt(v.year), parseInt(v.month) - 1,
        parseInt(v.day), parseInt(v.hour),
        parseInt(v.minute), parseInt(v.second)
      );
      return Math.round((tzDate - dateMs) / 60000);
    } catch (e) { return 0; }
  }

  // Convertit les horaires locaux d'une session en secondes UTC pour un jour donné.
  // dayUtcSeconds = minuit UTC du jour (timestamp en secondes)
  // Retourne { startUtcSeconds, endUtcSeconds }
  function _getSessionUtcRangeForChartDay(dayUtcSeconds, session) {
    var dateMs = dayUtcSeconds * 1000;
    var offsetMinutes = _getTzOffsetMinutes(dateMs, session.timezone);

    var startP = session.start.split(':');
    var endP = session.end.split(':');
    var startLocalMin = parseInt(startP[0]) * 60 + parseInt(startP[1]);
    var endLocalMin = parseInt(endP[0]) * 60 + parseInt(endP[1]);

    var startUtc = dayUtcSeconds + (startLocalMin - offsetMinutes) * 60;
    var endUtc = dayUtcSeconds + (endLocalMin - offsetMinutes) * 60;

    // Gérer les sessions qui traversent minuit (start > end)
    if (endUtc <= startUtc) {
      endUtc += 86400;
    }

    return { startUtcSeconds: startUtc, endUtcSeconds: endUtc };
  }
  // ── / TIMEZONE HELPERS

  // ── STATE ──

  var state = {
    ctx: null, chart: null, series: null, container: null, canvas: null,
    drawings: [],
    undoStack: [],
    sessions: [], // session zone configs
    activeTool: 'cursor',
    isDrawing: false, dragStart: null, previewPoint: null,
    selectedIndex: -1, // -1 = none, >=0 = editing an existing drawing
    snapEnabled: false, // false = snap actif (OHLC) — cf. _snapPoint inverse
    _crosshairPos: null, // position souris pour crosshair canvas
    _drag: null, // drag state: { idx, startTime, startPrice, pointIdx }
    toolOptions: {
      color: '#06b6d4', fillColor: '#06b6d4', opacity: 0.3,
      lineWidth: 1.5, lineStyle: 'solid',
      extendLeft: false, extendRight: true,
      text: '', fibLevels: _defaultFibLevels(),
    },
  };

  // ── INIT ──

  function initDrawings(chart, series, container) {
    state.chart = chart; state.series = series; state.container = container;
    _loadDrawings();
    _loadSessionSettings();
    _createCanvas();
    _bindEvents();
    _renderAll();
    _syncOptionsUI();
  }

  function destroyDrawings() {
    _stopRenderLoop();
    clearTimeout(_interactionTimeout);
    if (state.canvas) {
      state.canvas.removeEventListener('click', _onCanvasClick);
      state.canvas.removeEventListener('mousemove', _onMouseMove);
      state.canvas.removeEventListener('mouseleave', _onMouseLeave);
      state.canvas.removeEventListener('dblclick', _onDblClick);
      if (state.canvas.parentNode) state.canvas.parentNode.removeChild(state.canvas);
    }
    window.removeEventListener('resize', _onWindowResize);
    state.chart = null; state.series = null; state.container = null;
    state.ctx = null; state.canvas = null; state.drawings = []; state.undoStack = [];
  }

  // ── CANVAS ──

  function _createCanvas() {
    if (!state.container) return;
    state.canvas = document.createElement('canvas');
    state.canvas.className = 'draw-overlay';
    state.canvas.style.cssText = 'position:absolute;inset:0;z-index:10;pointer-events:none;width:100%;height:100%;';
    state.container.appendChild(state.canvas);
    state.ctx = state.canvas.getContext('2d');
    _resizeCanvas();
  }

  function _resizeCanvas() {
    var c = state.canvas; if (!c || !state.container) return;
    var pane = _getLwcPaneRect();
    var rect = pane || { left: 0, top: 0, width: state.container.clientWidth, height: state.container.clientHeight };
    var dpr = window.devicePixelRatio || 1;
    c.style.left = rect.left + 'px';
    c.style.top = rect.top + 'px';
    c.style.width = rect.width + 'px';
    c.style.height = rect.height + 'px';
    c.width = Math.round(rect.width * dpr);
    c.height = Math.round(rect.height * dpr);
    if (state.ctx) state.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }

  // Cache du pane rect pour eviter querySelectorAll + getBoundingClientRect a 60fps
  var _cachedPaneRect = null;

  function _invalidatePaneRect() { _cachedPaneRect = null; }

  // Trouve le rectangle du pane LWC interne (pas tout le container)
  function _getLwcPaneRect() {
    if (_cachedPaneRect) return _cachedPaneRect;
    if (!state.container) return null;
    var containerRect = state.container.getBoundingClientRect();
    var canvases = Array.prototype.slice.call(
      state.container.querySelectorAll('canvas')
    ).filter(function (c) {
      return c !== state.canvas && !c.classList.contains('draw-overlay');
    });
    if (!canvases.length) return null;
    var best = null, bestArea = 0;
    for (var i = 0; i < canvases.length; i++) {
      var r = canvases[i].getBoundingClientRect();
      var area = r.width * r.height;
      if (r.width > 100 && r.height > 100 && area > bestArea) {
        best = r; bestArea = area;
      }
    }
    if (!best) return null;
    var result = {
      left: best.left - containerRect.left,
      top: best.top - containerRect.top,
      width: best.width,
      height: best.height,
      absLeft: best.left,
      absTop: best.top,
    };
    _cachedPaneRect = result;
    return result;
  }

  // ── COORDINATES ──

  function _clientToPanePoint(clientX, clientY) {
    if (!state.container) return null;
    var pane = _getLwcPaneRect();
    var rect = pane
      ? { left: pane.absLeft, top: pane.absTop }
      : state.container.getBoundingClientRect();
    return {
      x: clientX - rect.left,
      y: clientY - rect.top,
    };
  }

  function _toPixel(time, price) {
    var x = state.chart.timeScale().timeToCoordinate(time);
    var y = state.series.priceToCoordinate(price);
    // Si timeToCoordinate echoue (temps au-dela des donnees), calculer via le ratio temps/pixel
    if (x == null && state.chart && state.chart.timeScale()) {
      try {
        var vr = state.chart.timeScale().getVisibleRange();
        if (vr && vr.from != null && vr.to != null) {
          var lx = state.chart.timeScale().timeToCoordinate(vr.from);
          var rx = state.chart.timeScale().timeToCoordinate(vr.to);
          if (lx != null && rx != null && rx !== lx) {
            // Inverser le calcul: (time - vr.from) * (pixels / time) + offset gauche
            var pxPerTime = (rx - lx) / (vr.to - vr.from);
            x = lx + (time - vr.from) * pxPerTime;
          }
        }
      } catch(e) {}
    }
    if (x == null || y == null) return null;
    return { x: x, y: y };
  }

  function _toTimePrice(clientX, clientY) {
    var point = _clientToPanePoint(clientX, clientY);
    if (!point) return null;
    var x = point.x;
    var y = point.y;
    var tp = state.chart.timeScale().coordinateToTime(x);
    var pp = state.series.coordinateToPrice(y);
    if (pp == null) return null;
    // Si clic au-dela du temps visible (dans le futur/droite), prendre le bord droit de la time scale
    if (tp == null) {
      try {
        var vr = state.chart.timeScale().getVisibleRange();
        if (vr && vr.from != null && vr.to != null) {
          var lx = state.chart.timeScale().timeToCoordinate(vr.from);
          var rx = state.chart.timeScale().timeToCoordinate(vr.to);
          if (lx != null && rx != null && rx !== lx) {
            var timePerPx = (vr.to - vr.from) / (rx - lx);
            tp = vr.from + (x - lx) * timePerPx;
          }
        }
      } catch(e) {}
    }
    if (tp == null) return null;
    return { time: tp, price: pp };
  }

  // Snap un point {time, price} a la bougie la plus proche (OHLC)
  function _snapPoint(tp, clientX, tool) {
    if (!tp) return tp;
    if (tool === 'cursor' || tool === 'fibonacci') return tp;
    if (state.snapEnabled || !state.chart || !state.series || !state.container) return tp;
    try {
      var point = _clientToPanePoint(clientX, 0);
      if (!point) return tp;
      var x = point.x;
      var logical = state.chart.timeScale().coordinateToLogical(x);
      if (logical == null) return tp;
      var index = Math.round(logical);
      var candle = state.series.dataByIndex(index);
      if (!candle || typeof candle.high !== 'number' || typeof candle.time !== 'number') return tp;
      tp.time = candle.time;
      var candidates = [
        { val: candle.high,  dist: Math.abs(candle.high - tp.price) },
        { val: candle.low,   dist: Math.abs(candle.low - tp.price) },
        { val: candle.open,  dist: Math.abs(candle.open - tp.price) },
        { val: candle.close, dist: Math.abs(candle.close - tp.price) },
      ];
      candidates.sort(function (a, b) { return a.dist - b.dist; });
      tp.price = candidates[0].val;
    } catch(e) {
      console.warn('[drawings] snap error:', e);
    }
    return tp;
  }

  function _createDrawing(type, points) {
    var o = state.toolOptions;
    var d = {
      id: _uid(), type: type, points: points,
      color: o.color, fillColor: o.fillColor,
      lineWidth: o.lineWidth, lineStyle: o.lineStyle,
      opacity: o.opacity,
      extendLeft: o.extendLeft, extendRight: o.extendRight,
      text: o.text || '',
      fibLevels: type === 'fibonacci' ? _cloneFibLevels(o.fibLevels) : null,
      locked: false,
      createdAt: Date.now(),
    };
    return d;
  }

  function _uid() { return 'draw_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 6); }

  // ── STORAGE ──

  function _saveDrawings() { try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state.drawings)); } catch(e) {} }
  function _loadDrawings() {
    try { var r = localStorage.getItem(STORAGE_KEY); state.drawings = r ? JSON.parse(r) : []; } catch(e) { state.drawings = []; }
  }

  // ── SESSION ZONE STORAGE ──

  function _loadSessionSettings() {
    try {
      var r = localStorage.getItem(SESSION_STORAGE_KEY);
      if (r) {
        var saved = JSON.parse(r);

        // Migration : détecter l'ancien format (startHour/endHour) et le convertir
        var needsMigration = saved.length > 0 && saved[0].startHour !== undefined;
        if (needsMigration) {
          var OLD_TO_NEW = {
            'asian':   { timezone: 'Asia/Tokyo',        start: '09:00', end: '15:00' },
            'london':  { timezone: 'Europe/London',     start: '08:00', end: '16:30' },
            'newyork': { timezone: 'America/New_York',  start: '09:30', end: '16:00' },
          };
          var OLD_ID_MAP = { 'newyork': 'ny_rth' };
          saved = saved.map(function (old) {
            var preset = OLD_TO_NEW[old.id];
            if (!preset) return old; // unknown, keep as-is
            return {
              id: OLD_ID_MAP[old.id] || old.id,
              name: old.name,
              timezone: preset.timezone,
              start: preset.start,
              end: preset.end,
              color: old.color || '#ff0066',
              active: old.active !== false,
              opacity: old.opacity != null ? old.opacity : 0.12,
            };
          });
          // Sauvegarder au nouveau format immédiatement
          try { localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(saved)); } catch(e) {}
        }

        // Merge with presets: keep saved if exists, fallback to preset defaults
        state.sessions = SESSION_PRESETS.map(function (preset) {
          var existing = null;
          for (var i = 0; i < saved.length; i++) {
            if (saved[i].id === preset.id) { existing = saved[i]; break; }
          }
          return existing ? Object.assign({}, preset, existing) : Object.assign({}, preset);
        });
      } else {
        state.sessions = SESSION_PRESETS.map(function (p) { return Object.assign({}, p); });
      }
    } catch(e) {
      state.sessions = SESSION_PRESETS.map(function (p) { return Object.assign({}, p); });
    }
  }

  function _saveSessionSettings() {
    try { localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify(state.sessions)); } catch(e) {}
  }

  function updateSessions(sessions) {
    state.sessions = sessions;
    _saveSessionSettings();
    _renderAll();
  }

  function getSessionSettings() { return state.sessions.slice(); }

  // ── / SESSION ZONE STORAGE

  // ── UNDO ──

  function _pushUndoState() {
    try {
      state.undoStack.push(JSON.stringify(state.drawings));
      if (state.undoStack.length > MAX_UNDO) state.undoStack.shift();
    } catch(e) {}
  }

  function undo() {
    if (!state.undoStack.length) return;
    try {
      state.drawings = JSON.parse(state.undoStack.pop());
      _saveDrawings();
      _renderAll();
    } catch(e) {}
  }

  // ── TEMPLATES ──

  function saveTemplate(name) {
    if (!name || !state.drawings.length) return;
    try {
      var templates = JSON.parse(localStorage.getItem(TEMPLATE_KEY)) || {};
      templates[name] = { name: name, drawings: JSON.parse(JSON.stringify(state.drawings)), savedAt: Date.now() };
      localStorage.setItem(TEMPLATE_KEY, JSON.stringify(templates));
      return true;
    } catch(e) { return false; }
  }

  function loadTemplate(name) {
    try {
      var templates = JSON.parse(localStorage.getItem(TEMPLATE_KEY)) || {};
      var t = templates[name];
      if (!t) return false;
      _pushUndoState();
      state.drawings = JSON.parse(JSON.stringify(t.drawings));
      _saveDrawings();
      _renderAll();
      return true;
    } catch(e) { return false; }
  }

  function listTemplates() {
    try {
      var templates = JSON.parse(localStorage.getItem(TEMPLATE_KEY)) || {};
      var names = Object.keys(templates);
      names.sort(function (a, b) { return templates[b].savedAt - templates[a].savedAt; });
      return names.map(function (n) { return templates[n]; });
    } catch(e) { return []; }
  }

  function deleteTemplate(name) {
    try {
      var templates = JSON.parse(localStorage.getItem(TEMPLATE_KEY)) || {};
      delete templates[name];
      localStorage.setItem(TEMPLATE_KEY, JSON.stringify(templates));
    } catch(e) {}
  }

  // ── TOOL MANAGEMENT ──

  function setActiveTool(toolId) {
    state.selectedIndex = -1; // clear selection on tool change
    state.activeTool = toolId || 'cursor';
    state.isDrawing = false; state.dragStart = null; state.previewPoint = null; state._crosshairPos = null;
    if (toolId === 'horizontal' || toolId === 'horizontalray' || toolId === 'vertical') {
      state.toolOptions.extendLeft = false; state.toolOptions.extendRight = true;
    } else if (toolId === 'text') {
      state.toolOptions.text = '';
    }
    _updateCanvasPointer();
    _syncOptionsUI();
    _renderAll();
  }

  function getActiveTool() { return state.activeTool; }

  function _updateCanvasPointer() {
    if (!state.canvas) return;
    state.canvas.style.pointerEvents = state.activeTool === 'cursor' ? 'none' : 'all';
    state.canvas.style.cursor = state.activeTool === 'cursor' ? '' : 'crosshair';
  }

  // ── LOCK TOGGLE ──

  function _syncLockButton(d) {
    var btn = document.getElementById('drawLockToggle');
    if (!btn) return;
    var locked = d && d.locked;
    btn.textContent = locked ? '🔒' : '🔓';
    btn.title = locked ? 'Déverrouiller le dessin' : 'Verrouiller le dessin (clic traverse vers le chart)';
    btn.dataset.locked = locked ? 'true' : 'false';
  }

  function _toggleLock() {
    if (state.selectedIndex < 0 || state.selectedIndex >= state.drawings.length) return;
    var d = state.drawings[state.selectedIndex];
    d.locked = !d.locked;
    _saveDrawings();
    _syncLockButton(d);
    _renderAll();
    toast('Dessin ' + (d.locked ? 'verrouillé' : 'déverrouillé'), 'info');
  }

  // ── / LOCK TOGGLE

  function _deleteSelectedDrawing() {
    if (state.selectedIndex < 0 || state.selectedIndex >= state.drawings.length) {
      if (typeof toast === 'function') toast('Aucun dessin selectionne', 'info');
      return;
    }
    _pushUndoState();
    state.drawings.splice(state.selectedIndex, 1);
    state.selectedIndex = -1;
    _saveDrawings();
    _syncOptionsUI();
    _renderAll();
    if (typeof toast === 'function') toast('Dessin supprime', 'success');
  }

  function _syncOptionsUI() {
    ['drawOptionsPanel', 'drawOptionsPanelWidget'].forEach(function (id) {
      var panel = document.getElementById(id);
      if (panel) {
        if (state.activeTool === 'cursor' && state.selectedIndex < 0) { panel.classList.add('hidden'); }
        else { panel.classList.remove('hidden'); }
      }
    });

    _setVal('drawColorPick', state.toolOptions.color);
    _setVal('drawFillColor', state.toolOptions.fillColor);
    _setVal('drawLineWidth', state.toolOptions.lineWidth);
    _setVal('drawLineStyle', state.toolOptions.lineStyle);
    _setVal('drawOpacity', state.toolOptions.opacity);
    var ov = document.getElementById('drawOpacityVal');
    if (ov) ov.textContent = parseFloat(state.toolOptions.opacity).toFixed(2);
    _setChecked('drawExtLeft', state.toolOptions.extendLeft);
    _setChecked('drawExtRight', state.toolOptions.extendRight);
    _setVal('drawText', state.toolOptions.text);

    // Row visibility : selon le tool actif OU le dessin selectionne
    var tool = state.activeTool;
    if (tool === 'cursor' && state.selectedIndex >= 0) {
      // Utiliser le type du dessin selectionne
      var sel = state.drawings[state.selectedIndex];
      if (sel) tool = sel.type;
    }
    _showEl('drawExtRow', tool === 'trendline');
    _showEl('drawTextRow', tool === 'text' || tool === 'trendline' || tool === 'horizontal' || tool === 'horizontalray' || tool === 'vertical' || tool === 'box');
    _showEl('drawFillRow', tool === 'box');
    _showEl('drawOpacityRow', tool === 'box');
    _showEl('drawFibSection', tool === 'fibonacci');

    // Swatches
    var swatches = document.getElementById('drawColorSwatches');
    if (swatches && swatches.innerHTML === '') {
      TOOL_COLORS.forEach(function (c) {
        var sw = document.createElement('button');
        sw.type = 'button';
        sw.className = 'draw-swatch' + (c === state.toolOptions.color ? ' is-active' : '');
        sw.style.background = c;
        sw.dataset.color = c;
        sw.addEventListener('click', function () {
          swatches.querySelectorAll('.draw-swatch').forEach(function (s) { s.classList.remove('is-active'); });
          this.classList.add('is-active');
          state.toolOptions.color = c;
          _setVal('drawColorPick', c);
          _readOptionsFromUI();
        });
        swatches.appendChild(sw);
      });
    }
    // Update active swatch
    if (swatches) {
      swatches.querySelectorAll('.draw-swatch').forEach(function (s) {
        s.classList.toggle('is-active', s.dataset.color === state.toolOptions.color);
      });
    }

    // Fib level toggles
    var fibList = document.getElementById('drawFibLevels');
    if (fibList) {
      fibList.innerHTML = '';
      state.toolOptions.fibLevels = _cloneFibLevels(state.toolOptions.fibLevels);
      state.toolOptions.fibLevels.forEach(function (l, idx) {
        var vis = l.visible !== false;
        var levelColor = state.toolOptions.color || l.color;
        var row = document.createElement('div');
        row.className = 'draw-fib-row';
        row.innerHTML =
          '<input type="checkbox" ' + (vis ? 'checked' : '') + ' data-fib-index="' + idx + '">' +
          '<span class="draw-fib-dot" style="background:' + levelColor + '"></span>' +
          '<span class="draw-fib-label">' + l.label + '%</span>' +
          '<button type="button" class="draw-fib-delete" data-fib-index="' + idx + '" title="Supprimer ce niveau">×</button>';
        row.querySelector('input').addEventListener('change', function () {
          var level = state.toolOptions.fibLevels[parseInt(this.dataset.fibIndex, 10)];
          if (level) level.visible = this.checked;
          _readOptionsFromUI();
        });
        row.querySelector('.draw-fib-delete').addEventListener('click', function (ev) {
          ev.preventDefault();
          ev.stopPropagation();
          state.toolOptions.fibLevels.splice(parseInt(this.dataset.fibIndex, 10), 1);
          _readOptionsFromUI();
          _syncOptionsUI();
        });
        fibList.appendChild(row);
      });

      var addRow = document.createElement('div');
      addRow.className = 'draw-fib-add';
      addRow.innerHTML =
        '<input type="number" step="0.1" inputmode="decimal" placeholder="78.6" title="Niveau en pourcentage">' +
        '<button type="button" title="Ajouter un niveau">Ajouter</button>';
      var addInput = addRow.querySelector('input');
      var addBtn = addRow.querySelector('button');
      var addLevel = function () {
        var pct = parseFloat(addInput.value);
        if (!Number.isFinite(pct)) {
          if (typeof toast === 'function') toast('Niveau fibo invalide', 'warning');
          return;
        }
        var key = Math.round((pct / 100) * 1000000) / 1000000;
        var exists = state.toolOptions.fibLevels.some(function (l) { return Math.abs(l.key - key) < 0.000001; });
        if (exists) {
          if (typeof toast === 'function') toast('Ce niveau fibo existe deja', 'info');
          return;
        }
        state.toolOptions.fibLevels.push({
          key: key,
          label: _formatFibLabel(key),
          color: TOOL_COLORS[state.toolOptions.fibLevels.length % TOOL_COLORS.length],
          visible: true,
        });
        state.toolOptions.fibLevels.sort(function (a, b) { return a.key - b.key; });
        addInput.value = '';
        _readOptionsFromUI();
        _syncOptionsUI();
      };
      addBtn.addEventListener('click', addLevel);
      addInput.addEventListener('keydown', function (ev) {
        if (ev.key === 'Enter') {
          ev.preventDefault();
          addLevel();
        }
      });
      fibList.appendChild(addRow);
    }
  }

  function _setVal(id, val) { var e = document.getElementById(id); if (e) e.value = val; }
  function _setChecked(id, val) { var e = document.getElementById(id); if (e) e.checked = !!val; }
  function _showEl(id, show) {
    var e = document.getElementById(id);
    if (!e) return;
    e.style.display = show ? '' : 'none';
    e.classList.toggle('draw-opt-row--hidden', !show);
    e.classList.toggle('draw-opt-section--hidden', !show);
  }

  function _readOptionsFromUI() {
    function gv(id) { var e = document.getElementById(id); return e ? e.value : null; }
    function gc(id) { var e = document.getElementById(id); return e ? e.checked : false; }
    state.toolOptions.color = gv('drawColorPick') || '#06b6d4';
    state.toolOptions.fillColor = gv('drawFillColor') || '#06b6d4';
    state.toolOptions.lineWidth = parseFloat(gv('drawLineWidth')) || 1.5;
    state.toolOptions.lineStyle = gv('drawLineStyle') || 'solid';
    var opacity = parseFloat(gv('drawOpacity'));
    state.toolOptions.opacity = Number.isFinite(opacity) ? opacity : 0.3;
    state.toolOptions.extendLeft = gc('drawExtLeft');
    state.toolOptions.extendRight = gc('drawExtRight');
    state.toolOptions.text = gv('drawText') || '';

    // Apply to selected drawing (live edit)
    if (state.selectedIndex >= 0 && state.selectedIndex < state.drawings.length) {
      var d = state.drawings[state.selectedIndex];
      d.color = state.toolOptions.color;
      d.fillColor = state.toolOptions.fillColor;
      d.lineWidth = state.toolOptions.lineWidth;
      d.lineStyle = state.toolOptions.lineStyle;
      d.opacity = state.toolOptions.opacity;
      d.extendLeft = state.toolOptions.extendLeft;
      d.extendRight = state.toolOptions.extendRight;
      d.text = state.toolOptions.text;
      if (d.type === 'fibonacci') d.fibLevels = _cloneFibLevels(state.toolOptions.fibLevels);
      _saveDrawings();
      _renderAll();
    }
  }

  // ── EVENTS ──

  // rAF render loop — double rAF pour laisser LWC finir son rendu avant nous
  var _renderLoopRunning = false;
  var _rafA = null;
  var _rafB = null;
  var _interactionTimeout = null;
  var IDLE_DELAY_MS = 200;

  function _startRenderLoop() {
    if (_renderLoopRunning) return;
    _renderLoopRunning = true;

    function tick() {
      if (!_renderLoopRunning) return;

      _rafA = requestAnimationFrame(function () {
        _rafA = null;
        // Deuxieme rAF : LWC a fini ses transforms internes
        _rafB = requestAnimationFrame(function () {
          _rafB = null;
          if (!_renderLoopRunning) return;
          _resizeCanvas();
          _renderAll();
          tick();
        });
      });
    }

    tick();
  }

  function _stopRenderLoop() {
    _renderLoopRunning = false;
    if (_rafA) { cancelAnimationFrame(_rafA); _rafA = null; }
    if (_rafB) { cancelAnimationFrame(_rafB); _rafB = null; }
    // Dernier rendu stabilise
    requestAnimationFrame(function () {
      requestAnimationFrame(function () {
        _resizeCanvas();
        _renderAll();
      });
    });
  }

  function _scheduleStop() {
    clearTimeout(_interactionTimeout);
    _interactionTimeout = setTimeout(_stopRenderLoop, IDLE_DELAY_MS);
  }

  function _bindEvents() {
    if (!state.canvas) return;
    state.canvas.addEventListener('click', _onCanvasClick);
    state.canvas.addEventListener('mousemove', _onMouseMove);
    state.canvas.addEventListener('mouseleave', _onMouseLeave);
    state.canvas.addEventListener('dblclick', _onDblClick);

      // Click handler sur le conteneur pour hit-test en mode curseur
      if (state.container) {
        // Mousedown en phase CAPTURE pour intercepter avant LWC
        state.container.addEventListener('mousedown', function (e) {
          if (state.activeTool !== 'cursor' || e.button !== 0) return;
          if (e.target.closest('#drawOptionsPanel, #drawOptionsPanelWidget')) return;
          var tp = _toTimePrice(e.clientX, e.clientY);
          if (!tp) return;
          var hitIdx = _hitTestIndex(tp.time, tp.price);
          if (hitIdx >= 0 && !state.drawings[hitIdx].locked) {
            e.stopPropagation();
            e.preventDefault();
            // Detecter si le clic est sur une extremite (resize) ou le corps (deplacer)
            var dragPointIdx = -1; // -1 = deplacement complet
            var d = state.drawings[hitIdx];
            if (d.points && tp) {
              var cpx = _toPixel(tp.time, tp.price);
              if (cpx) {
                for (var p = 0; p < Math.min(d.points.length, 2); p++) {
                  var ppx = _toPixel(d.points[p].time, d.points[p].price);
                  if (ppx) {
                    var dist = Math.sqrt((cpx.x - ppx.x) * (cpx.x - ppx.x) + (cpx.y - ppx.y) * (cpx.y - ppx.y));
                    if (dist < 15) { dragPointIdx = p; break; }
                  }
                }
              }
            }
            state._drag = {
              idx: hitIdx,
              startX: e.clientX,
              startY: e.clientY,
              startTime: tp.time,
              startPrice: tp.price,
              pointIdx: dragPointIdx,
              // Snapshot immuable des points originaux au mousedown
              origPoints: JSON.parse(JSON.stringify(d.points)),
            };
            if (state.selectedIndex !== hitIdx) _selectDrawing(hitIdx);
            if (state.canvas) state.canvas.style.cursor = 'grabbing';
          }
        }, { capture: true });

        state.container.addEventListener('mouseup', function (e) {
          if (state._drag) {
            // Drag termine : sauvegarder
            _saveDrawings();
            state._drag = null;
            state.canvas.style.cursor = state.activeTool === 'cursor' ? '' : 'crosshair';
            _scheduleStop();
          }
        });

        state.container.addEventListener('click', function (e) {
          if (state.activeTool !== 'cursor') return;
          // Ne pas interferer avec les clics dans le panneau d'options
          if (e.target.closest('#drawOptionsPanel, #drawOptionsPanelWidget')) return;
          // Ignorer si on vient de draguer
          if (state._drag) return;
          var tp = _toTimePrice(e.clientX, e.clientY);
          if (tp) {
            var hitIdx = _hitTestIndex(tp.time, tp.price);
            if (hitIdx >= 0) {
              e.stopPropagation();
              _selectDrawing(hitIdx);
            } else {
              _deselectDrawing();
            }
          } else {
            _deselectDrawing();
          }
        });
        // Fallback: document-level click si le container ne capte pas
        document.addEventListener('click', function (e) {
          if (state.activeTool !== 'cursor') return;
          if (!state.container || !state.container.contains(e.target)) return;
          // Ne pas interferer avec les clics dans le panneau d'options
          if (e.target.closest('#drawOptionsPanel, #drawOptionsPanelWidget')) return;
          var tp = _toTimePrice(e.clientX, e.clientY);
          if (tp) {
            var hitIdx = _hitTestIndex(tp.time, tp.price);
            if (hitIdx >= 0) {
              e.stopPropagation();
              _selectDrawing(hitIdx);
            } else {
              _deselectDrawing();
            }
          } else {
            _deselectDrawing();
          }
        });
      }

    // Render loop synchro parfaite pendant interaction souris
    if (state.container) {
      state.container.addEventListener('mousemove', function (e) {
        // Drag: deplacer le dessin selectionne
        if (state._drag) {
          var d = state.drawings[state._drag.idx];
          if (d && d.points) {
            var current = _toTimePrice(e.clientX, e.clientY);
            if (!current) return;
            var dt = current.time - state._drag.startTime;
            var dp = current.price - state._drag.startPrice;
            // Appliquer sur le snapshot original (pas d'accumulation)
            if (state._drag.pointIdx >= 0) {
              var pi = state._drag.pointIdx;
              d.points[pi] = {
                time: state._drag.origPoints[pi].time + dt,
                price: state._drag.origPoints[pi].price + dp,
              };
            } else {
              for (var pi = 0; pi < d.points.length; pi++) {
                d.points[pi] = {
                  time: state._drag.origPoints[pi].time + dt,
                  price: state._drag.origPoints[pi].price + dp,
                };
              }
            }
            _renderAll();
          }
        }
        if (state._drag || state.activeTool !== 'cursor' || (e.buttons & 1)) {
          _startRenderLoop();
          _scheduleStop();
        }
      }, { passive: true });
      state.container.addEventListener('wheel', function () {
        _startRenderLoop();
        _scheduleStop();
      }, { passive: true });
      state.container.addEventListener('mouseleave', function () {
        clearTimeout(_interactionTimeout);
        _stopRenderLoop();
      });
    }

    document.addEventListener('change', function (e) {
      if (e.target.id === 'drawTemplateLoad') {
        _onTemplateLoad();
        return;
      }
      if (e.target.closest('#drawOptionsPanel, #drawOptionsPanelWidget')) _readOptionsFromUI();
    });

    // Live preview for drawing option controls.
    document.addEventListener('input', function (e) {
      if (e.target.closest('#drawOptionsPanel, #drawOptionsPanelWidget')) {
        if (e.target.id === 'drawOpacity') {
          var valEl = document.getElementById('drawOpacityVal');
          if (valEl) valEl.textContent = parseFloat(e.target.value).toFixed(2);
        }
        _readOptionsFromUI();
        return;
      }
      if (e.target.id === 'drawOpacity') {
        var valEl = document.getElementById('drawOpacityVal');
        if (valEl) valEl.textContent = parseFloat(e.target.value).toFixed(2);
        _readOptionsFromUI();
      }
    });

    document.addEventListener('click', function (e) {
      var action = e.target.closest('#drawTemplateSave, #drawTemplateDelete, #drawLockToggle, #drawDeleteSelected');
      if (!action) return;
      e.preventDefault();
      e.stopPropagation();
      if (action.id === 'drawTemplateSave') _onTemplateSave();
      else if (action.id === 'drawTemplateDelete') _onTemplateDelete();
      else if (action.id === 'drawLockToggle') _toggleLock();
      else if (action.id === 'drawDeleteSelected') _deleteSelectedDrawing();
    });

    // Mouseup global pour finaliser le drag meme hors container
    document.addEventListener('mouseup', function () {
      if (state._drag) {
        _saveDrawings();
        state._drag = null;
        if (state.canvas) state.canvas.style.cursor = state.activeTool === 'cursor' ? '' : 'crosshair';
      }
    });
    // Keyboard: Ctrl+Z for undo + Escape to deselect
    document.addEventListener('keydown', function (e) {
      if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
        e.preventDefault();
        undo();
      }
      if (e.key === 'Escape' && state.selectedIndex >= 0) {
        _deselectDrawing();
      }
    });

    if (state.chart && state.chart.timeScale()) {
      var _debounceTimer = null;
      function _scheduleRender() {
        _invalidatePaneRect();
        _startRenderLoop();
        _scheduleStop();
        if (_debounceTimer) return;
        _debounceTimer = setTimeout(function () { _debounceTimer = null; _renderAll(); }, 16);
      }
      state.chart.timeScale().subscribeVisibleTimeRangeChange(_scheduleRender);
      state.chart.timeScale().subscribeVisibleLogicalRangeChange(_scheduleRender);
    }

    // Redraw on window resize — DEPRECATED, utilise le ResizeObserver du chart page
    // window.addEventListener('resize', _onWindowResize);
  }

  function _onWindowResize() {
    _resizeCanvas();
    _renderAll();
  }

  function _onTemplateSave() {
    var name = prompt('Nom du template :');
    if (name && saveTemplate(name.trim())) {
      _refreshTemplateList();
      toast('Template "' + name.trim() + '" sauvegardé', 'success');
    }
  }

  function _onTemplateLoad() {
    var sel = document.getElementById('drawTemplateLoad');
    if (!sel || !sel.value) return;
    if (loadTemplate(sel.value)) {
      _refreshTemplateList();
      toast('Template "' + sel.value + '" chargé', 'success');
    }
  }

  function _onTemplateDelete() {
    var sel = document.getElementById('drawTemplateLoad');
    if (!sel || !sel.value) {
      if (typeof toast === 'function') toast('Aucun template selectionne', 'info');
      return;
    }
    if (confirm('Supprimer le template "' + sel.value + '" ?')) {
      deleteTemplate(sel.value);
      _refreshTemplateList();
      if (typeof toast === 'function') toast('Template supprime', 'success');
    }
  }

  function _refreshTemplateList() {
    var sel = document.getElementById('drawTemplateLoad');
    if (!sel) return;
    var current = sel.value;
    sel.innerHTML = '<option value="">— Charger un template —</option>';
    var templates = listTemplates();
    templates.forEach(function (t) {
      var opt = document.createElement('option');
      opt.value = t.name;
      opt.textContent = t.name + ' (' + t.drawings.length + ' dessins)';
      sel.appendChild(opt);
    });
    if (current) sel.value = current;
  }

  function _onCanvasClick(e) {
    if (state.activeTool === 'cursor') return;
    _readOptionsFromUI();
    var rawTp = _toTimePrice(e.clientX, e.clientY);
    if (!rawTp) return;

    var tool = state.activeTool;
    var tp = _snapPoint({ time: rawTp.time, price: rawTp.price }, e.clientX, tool);
    var isOnePoint = (tool === 'horizontal' || tool === 'horizontalray' || tool === 'vertical' || tool === 'text');

    // If editing an existing drawing, clicking elsewhere deselects
    if (state.selectedIndex >= 0 && state.selectedIndex < state.drawings.length) {
      _deselectDrawing();
      // If user clicked on a different drawing, select that one instead
      var hitIdx = _hitTestIndex(rawTp.time, rawTp.price);
      if (hitIdx >= 0 && hitIdx !== state.selectedIndex) {
        _selectDrawing(hitIdx);
        return;
      }
      return;
    }

    // Hit test: clicking on existing drawing enters edit mode
    if (!state.isDrawing) {
      var hitIdx = _hitTestIndex(rawTp.time, rawTp.price);
      if (hitIdx >= 0) {
        _selectDrawing(hitIdx);
        return;
      }
    }

    // Otherwise, creation flow
    if (!state.isDrawing) {
      // First click: start drawing
      state.dragStart = { time: tp.time, price: tp.price };
      state.isDrawing = true;
      state.previewPoint = null;
      // For 1-point tools, finalize immediately
      if (isOnePoint) { _finalizeDrawing(tp); }
    } else {
      // Second click: finalize drawing
      _finalizeDrawing(tp);
    }
  }

  function _selectDrawing(idx) {
    if (idx < 0 || idx >= state.drawings.length) return;
    _cancelDrawing();
    state.selectedIndex = idx;
    var d = state.drawings[idx];
    // Sync tool options to match the selected drawing
    state.toolOptions.color = d.color || '#06b6d4';
    state.toolOptions.fillColor = d.fillColor || '#06b6d4';
    state.toolOptions.lineWidth = d.lineWidth || 1.5;
    state.toolOptions.lineStyle = d.lineStyle || 'solid';
    state.toolOptions.opacity = d.opacity !== undefined ? d.opacity : 0.3;
    state.toolOptions.extendLeft = d.extendLeft || false;
    state.toolOptions.extendRight = d.extendRight !== false;
    state.toolOptions.text = d.text || '';
    state.toolOptions.fibLevels = d.type === 'fibonacci' ? _cloneFibLevels(d.fibLevels) : _defaultFibLevels();
    _syncOptionsUI();
    // Forcer l'affichage du panneau d'options meme en mode curseur
    ['drawOptionsPanel', 'drawOptionsPanelWidget'].forEach(function (id) {
      var panel = document.getElementById(id);
      if (panel) panel.classList.remove('hidden');
    });
    // Sync lock button
    _syncLockButton(d);
    _renderAll();
    if (typeof toast === 'function') toast('Dessin sélectionné — modifie les options en direct', 'info');
  }

  function _deselectDrawing() {
    if (state.selectedIndex < 0) return;
    state.selectedIndex = -1;
    _syncOptionsUI();
    // Reset lock button
    var btn = document.getElementById('drawLockToggle');
    if (btn) { btn.textContent = '🔓'; btn.dataset.locked = 'false'; btn.title = 'Verrouiller le dessin (clic traverse vers le chart)'; }
    _renderAll();
  }

  function _finalizeDrawing(tp) {
    if (!state.dragStart) { _cancelDrawing(); return; }
    var p1 = state.dragStart, p2 = { time: tp.time, price: tp.price };
    var tool = state.activeTool, drawing = null;

    switch (tool) {
      case 'box':
        if (p1.time === p2.time && p1.price === p2.price) { _cancelDrawing(); _renderAll(); return; }
        drawing = _createDrawing('box', [p1, p2]);
        break;
      case 'trendline':
        if (p1.time === p2.time && p1.price === p2.price) { _cancelDrawing(); _renderAll(); return; }
        drawing = _createDrawing('trendline', [p1, p2]);
        break;
      case 'horizontal':
        drawing = _createDrawing('horizontal', [p1]);
        break;
      case 'horizontalray':
        drawing = _createDrawing('horizontalray', [p1]);
        break;
      case 'vertical':
        drawing = _createDrawing('vertical', [p1]);
        break;
      case 'fibonacci':
        if (p1.time === p2.time && p1.price === p2.price) { _cancelDrawing(); _renderAll(); return; }
        drawing = _createDrawing('fibonacci', [p1, p2]);
        break;
      case 'text':
        drawing = _createDrawing('text', [p1]);
        break;
    }

    if (drawing) {
      _pushUndoState();
      state.drawings.push(drawing); _saveDrawings();
    }
    _cancelDrawing();
    _renderAll();

    // Auto-exit to cursor mode
    setActiveTool('cursor');
    // Update toolbar button active state
    var toolbar = document.getElementById('drawToolbar');
    if (toolbar) {
      toolbar.querySelectorAll('.draw-toolbar-btn').forEach(function (b) {
        b.classList.toggle('is-active', b.dataset.tool === 'cursor');
      });
    }
    var widgetToolbar = document.getElementById('drawToolbarWidget');
    if (widgetToolbar) {
      widgetToolbar.querySelectorAll('.draw-toolbar-btn').forEach(function (b) {
        b.classList.toggle('is-active', b.dataset.tool === 'cursor');
      });
    }
  }

  function _onMouseMove(e) {
    if (state.isDrawing && state.dragStart) {
      var tp = _snapPoint(_toTimePrice(e.clientX, e.clientY), e.clientX, state.activeTool);
      if (tp) { state.previewPoint = { time: tp.time, price: tp.price }; _renderAll(); }
    }
    if (state.activeTool === 'cursor') {
      var tp = _toTimePrice(e.clientX, e.clientY);
      if (tp && state.canvas) state.canvas.style.cursor = _hitTest(tp.time, tp.price) ? 'pointer' : '';
    }
    // Stocker la position pour le crosshair canvas en mode dessin
    if (state.activeTool !== 'cursor') {
      state._crosshairPos = _clientToPanePoint(e.clientX, e.clientY);
    }
  }

  function _onMouseLeave() { state.previewPoint = null; state._crosshairPos = null; _renderAll(); }

  function _onDblClick(e) {
    if (state.activeTool !== 'cursor') return;
    var tp = _toTimePrice(e.clientX, e.clientY);
    if (!tp) return;
    var idx = _hitTestIndex(tp.time, tp.price);
    if (idx !== -1) {
      _pushUndoState();
      state.drawings.splice(idx, 1); _saveDrawings(); _renderAll();
    }
  }

  function _cancelDrawing() { state.isDrawing = false; state.dragStart = null; state.previewPoint = null; }

  // ── HIT TEST ──

  function _hitTestIndex(time, price) {
    var pointThreshold = 7;
    var lineThreshold = 5;
    var clickPx = _toPixel(time, price);
    if (!clickPx) return -1;
    var cx = clickPx.x, cy = clickPx.y;
    for (var i = state.drawings.length - 1; i >= 0; i--) {
      var d = state.drawings[i];
      if (!d.points || !d.points[0]) continue;

      // Toujours tester les endpoints (points d'extremite)
      for (var p = 0; p < Math.min(d.points.length, 2); p++) {
        var px = _toPixel(d.points[p].time, d.points[p].price);
        if (!px) continue;
        var dist = Math.sqrt((cx - px.x) * (cx - px.x) + (cy - px.y) * (cy - px.y));
        if (dist < pointThreshold) return i;
      }

      // Si locke : seulement les endpoints, pas les segments/aires
      if (d.locked) continue;

      // Hit-test par type (segments de ligne, aires)
      switch (d.type) {
        case 'box':
          // Unlock: integre (tout le rectangle). Lock: seulement endpoints (deja teste plus haut)
          if (!d.locked && d.points.length >= 2) {
            var p1 = _toPixel(d.points[0].time, d.points[0].price);
            var p2 = _toPixel(d.points[1].time, d.points[1].price);
            if (p1 && p2) {
              var bX1 = Math.min(p1.x, p2.x), bY1 = Math.min(p1.y, p2.y);
              var bX2 = Math.max(p1.x, p2.x), bY2 = Math.max(p1.y, p2.y);
              var onHorizontal = cx >= bX1 - pointThreshold && cx <= bX2 + pointThreshold &&
                (Math.abs(cy - bY1) < lineThreshold || Math.abs(cy - bY2) < lineThreshold);
              var onVertical = cy >= bY1 - pointThreshold && cy <= bY2 + pointThreshold &&
                (Math.abs(cx - bX1) < lineThreshold || Math.abs(cx - bX2) < lineThreshold);
              if (onHorizontal || onVertical) return i;
            }
          }
          break;

        case 'trendline':
          if (d.points.length >= 2) {
            var p1 = _toPixel(d.points[0].time, d.points[0].price);
            var p2 = _toPixel(d.points[1].time, d.points[1].price);
            if (p1 && p2) {
              var cw = state.canvas ? state.canvas.width / (window.devicePixelRatio || 1) : 0;
              var x1 = p1.x, y1 = p1.y, x2 = p2.x, y2 = p2.y;
              if (d.extendLeft) { var tL = (0 - x1) / (x2 - x1 || 1); x1 = 0; y1 = y1 + (y2 - y1) * tL; }
              if (d.extendRight) { var tR = (cw - x1) / (x2 - x1 || 1); x2 = cw; y2 = y1 + (y2 - y1) * tR; }
              if (_distToSegment(cx, cy, x1, y1, x2, y2) < lineThreshold) return i;
            }
          }
          break;

        case 'horizontal':
        case 'horizontalray':
          {
            var px = _toPixel(d.points[0].time, d.points[0].price);
            if (px) {
              var cw = state.canvas ? state.canvas.width / (window.devicePixelRatio || 1) : 0;
              var rx1 = d.type === 'horizontal' ? 0 : px.x;
              var rx2 = cw;
              if (Math.abs(cy - px.y) < lineThreshold && cx >= rx1 - pointThreshold && cx <= rx2 + pointThreshold) return i;
            }
          }
          break;

        case 'vertical':
          {
            var px = _toPixel(d.points[0].time, d.points[0].price);
            if (px) {
              var ch = state.canvas ? state.canvas.height / (window.devicePixelRatio || 1) : 0;
              if (Math.abs(cx - px.x) < lineThreshold && cy >= -pointThreshold && cy <= ch + pointThreshold) return i;
            }
          }
          break;

        case 'fibonacci':
          if (d.points.length >= 2) {
            var p1 = _toPixel(d.points[0].time, d.points[0].price);
            var p2 = _toPixel(d.points[1].time, d.points[1].price);
            if (p1 && p2) {
              var fibThreshold = 5;
              if (_distToSegment(cx, cy, p1.x, p1.y, p2.x, p2.y) < fibThreshold) return i;
              var fibLevels = _normalizeFibLevels(d.fibLevels);
              var cw = state.canvas ? state.canvas.width / (window.devicePixelRatio || 1) : 0;
              var minX = Math.max(0, Math.min(p1.x, p2.x) - 30);
              var maxX = Math.min(cw, Math.max(p1.x, p2.x) + 30);
              for (var f = 0; f < fibLevels.length; f++) {
                var l = fibLevels[f];
                if (l.visible === false) continue;
                var fPrice = _fibLevelPrice(d.points, l.key);
                var fp = _toPixel(d.points[0].time, fPrice);
                if (!fp) continue;
                if (cx >= minX - fibThreshold && cx <= maxX + fibThreshold && Math.abs(cy - fp.y) < fibThreshold) return i;
              }
            }
          }
          break;

        case 'text':
          // Deja teste via endpoints (un seul point)
          break;
      }
    }
    return -1;
  }

  // Distance d'un point (px,py) a un segment (x1,y1)-(x2,y2)
  function _distToSegment(px, py, x1, y1, x2, y2) {
    var dx = x2 - x1, dy = y2 - y1;
    var lenSq = dx * dx + dy * dy;
    if (lenSq === 0) return Math.sqrt((px - x1) * (px - x1) + (py - y1) * (py - y1));
    var t = Math.max(0, Math.min(1, ((px - x1) * dx + (py - y1) * dy) / lenSq));
    var nearX = x1 + t * dx, nearY = y1 + t * dy;
    return Math.sqrt((px - nearX) * (px - nearX) + (py - nearY) * (py - nearY));
  }

  // ── RENDER ──

  function _renderAll() {
    var ctx = state.ctx; if (!ctx || !state.canvas) return;

    // Clear en repere bitmap (pas CSS) pour eviter les artefacts Retina
    var dpr = window.devicePixelRatio || 1;
    ctx.save();
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.clearRect(0, 0, state.canvas.width, state.canvas.height);
    ctx.restore();
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

    _renderSessions();
    for (var i = 0; i < state.drawings.length; i++) { _renderDrawing(state.drawings[i], i); _drawSelectionIndicators(state.drawings[i], i); _drawLockIcon(state.drawings[i], i); _drawLockedDots(state.drawings[i], i); }
    if (state.dragStart && state.previewPoint && state.activeTool !== 'cursor') {
      _renderPreview(state.activeTool, state.dragStart, state.previewPoint);
    }
    // Crosshair en mode dessin : lignes horizontale + verticale
    if (state.activeTool !== 'cursor' && state._crosshairPos) {
      _renderCrosshair(state._crosshairPos);
    }
  }

  function _drawSelectionIndicators(d, index) {
    if (index !== state.selectedIndex || !d.points) return;
    var ctx = state.ctx;
    ctx.save();
    for (var p = 0; p < d.points.length; p++) {
      var px = _toPixel(d.points[p].time, d.points[p].price);
      if (!px) continue;
      // Outer glow ring
      ctx.beginPath(); ctx.arc(px.x, px.y, 6, 0, Math.PI * 2);
      ctx.strokeStyle = '#06b6d4'; ctx.lineWidth = 2;
      ctx.shadowColor = '#06b6d4'; ctx.shadowBlur = 8;
      ctx.stroke();
      // Inner dot
      ctx.beginPath(); ctx.arc(px.x, px.y, 3, 0, Math.PI * 2);
      ctx.fillStyle = '#06b6d4'; ctx.fill();
    }
    ctx.restore();
  }

  function _drawLockIcon(d, index) {
    if (!d.locked || !d.points || !d.points[0]) return;
    var px = _toPixel(d.points[0].time, d.points[0].price);
    if (!px) return;
    var ctx = state.ctx;
    ctx.save();
    ctx.font = '11px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'bottom';
    ctx.fillStyle = '#f59e0b';
    ctx.shadowColor = 'rgba(0,0,0,0.5)';
    ctx.shadowBlur = 4;
    ctx.fillText('🔒', px.x, px.y - 8);
    ctx.restore();
  }

  // Points d'extremite visibles pour les dessins lockes (pour pouvoir les selectionner)
  function _drawLockedDots(d, index) {
    if (!d.locked || !d.points) return;
    if (index === state.selectedIndex) return; // deja dessine par _drawSelectionIndicators
    var ctx = state.ctx;
    ctx.save();
    for (var p = 0; p < Math.min(d.points.length, 2); p++) {
      var px = _toPixel(d.points[p].time, d.points[p].price);
      if (!px) continue;
      ctx.beginPath(); ctx.arc(px.x, px.y, 4, 0, Math.PI * 2);
      ctx.fillStyle = d.color || '#06b6d4';
      ctx.globalAlpha = 0.5;
      ctx.fill();
      ctx.globalAlpha = 1;
    }
    ctx.restore();
  }

  function _renderDrawing(d, index) {
    switch (d.type) {
      case 'box':          _drawBox(d.points, d, index); break;
      case 'trendline':    _drawLine(d.points, d, index); break;
      case 'horizontal':   _drawHorizLine(d.points[0], d, index); break;
      case 'horizontalray':_drawHorizRay(d.points[0], d, index); break;
      case 'vertical':     _drawVertLine(d.points[0], d, index); break;
      case 'fibonacci':    _drawFibonacci(d, index); break;
      case 'text':         _drawText(d.points[0], d, index); break;
    }
  }

  function _renderPreview(tool, p1, p2) {
    var o = state.toolOptions;
    var pd = { color: o.color, fillColor: o.fillColor, lineWidth: 1, lineStyle: 'dashed', opacity: o.opacity, text: o.text, fibLevels: _cloneFibLevels(o.fibLevels) };
    switch (tool) {
      case 'box':          _drawBox([p1, p2], pd); break;
      case 'trendline':    _drawLine([p1, p2], pd); break;
      case 'horizontal':   _drawHorizLine(p1, pd); break;
      case 'horizontalray':_drawHorizRay(p1, pd); break;
      case 'vertical':     _drawVertLine(p1, pd); break;
      case 'fibonacci':    _drawFibonacci({ points: [p1, p2], color: o.color, fibLevels: _cloneFibLevels(o.fibLevels) }); break;
      case 'text':         _drawText(p1, pd); break;
    }
  }

  // ── CROSSHAIR CANVAS (mode dessin) ──

  function _renderCrosshair(pos) {
    var ctx = state.ctx;
    if (!ctx || !state.canvas) return;
    var dpr = window.devicePixelRatio || 1;
    var w = state.canvas.width / dpr;
    var h = state.canvas.height / dpr;
    var px = pos.x;
    var py = pos.y;

    ctx.save();
    ctx.strokeStyle = 'rgba(6, 182, 212, 0.35)';
    ctx.lineWidth = 1;
    ctx.setLineDash([4, 4]);

    // Ligne verticale
    ctx.beginPath();
    ctx.moveTo(px, 0);
    ctx.lineTo(px, h);
    ctx.stroke();

    // Ligne horizontale
    ctx.beginPath();
    ctx.moveTo(0, py);
    ctx.lineTo(w, py);
    ctx.stroke();

    ctx.restore();
  }

  // ── SESSION ZONES ──

  function _renderSessions() {
    var ctx = state.ctx;
    if (!ctx || !state.chart || !state.sessions || !state.sessions.length) return;

    var visibleRange = state.chart.timeScale().getVisibleRange();
    if (!visibleRange || !visibleRange.from || !visibleRange.to) return;

    var from = visibleRange.from; // seconds
    var to = visibleRange.to;

    var ch;
    try { ch = state.canvas.height / (window.devicePixelRatio || 1); } catch(e) { return; }
    if (!ch) return;

    // Day boundaries: floor/ceil to UTC midnight
    var dayStart = Math.floor(from / 86400) * 86400;
    var dayEnd = Math.ceil(to / 86400) * 86400;

    ctx.save();
    ctx.textBaseline = 'top';
    ctx.font = '9px "JetBrains Mono", monospace';

    for (var s = 0; s < state.sessions.length; s++) {
      var session = state.sessions[s];
      if (!session.active) continue;

      for (var t = dayStart; t < dayEnd; t += 86400) {
        // Convertir les horaires locaux en UTC pour ce jour précis
        var range = _getSessionUtcRangeForChartDay(t, session);

        // Clip to visible range
        var clipStart = Math.max(range.startUtcSeconds, from);
        var clipEnd = Math.min(range.endUtcSeconds, to);
        if (clipStart >= clipEnd) continue;

        var x1 = state.chart.timeScale().timeToCoordinate(clipStart);
        var x2 = state.chart.timeScale().timeToCoordinate(clipEnd);
        if (x1 == null || x2 == null || x2 - x1 < 2) continue;

        // Draw fill: keep sessions as context, not as the main visual layer.
        var sessionAlpha = Math.min(parseFloat(session.opacity) || 0.12, 0.045);
        ctx.globalAlpha = sessionAlpha;
        ctx.fillStyle = session.color;
        ctx.fillRect(x1, 0, x2 - x1, ch);
        ctx.globalAlpha = 1;

        // Draw label at top-left of zone
        ctx.fillStyle = session.color;
        ctx.textAlign = 'left';
        ctx.fillText(session.name, x1 + 3, 3);

        // Thin line at session start
        ctx.strokeStyle = session.color;
        ctx.lineWidth = 0.5;
        ctx.globalAlpha = Math.min(0.18, sessionAlpha * 3);
        ctx.beginPath(); ctx.moveTo(x1, 0); ctx.lineTo(x1, ch); ctx.stroke();

        // Thin line at session end
        ctx.beginPath(); ctx.moveTo(x2, 0); ctx.lineTo(x2, ch); ctx.stroke();
        ctx.globalAlpha = 1;
      }
    }

    ctx.restore();
  }

  // ── / SESSION ZONES

  // ── DRAWING PRIMITIVES ──

  function _getDash(style) { for (var i = 0; i < LINE_STYLES.length; i++) { if (LINE_STYLES[i].id === style) return LINE_STYLES[i].dash; } return []; }
  function _getAlpha(d) { var a = parseFloat(d.opacity); return (a >= 0 && a <= 1) ? a : 0.3; }

  function _drawBox(points, d, index) {
    if (points.length < 2) return;
    var ctx = state.ctx;
    var p1 = _toPixel(points[0].time, points[0].price);
    var p2 = _toPixel(points[1].time, points[1].price);
    if (!p1 || !p2) return;

    var x = Math.min(p1.x, p2.x), y = Math.min(p1.y, p2.y);
    var w = Math.abs(p2.x - p1.x), h = Math.abs(p2.y - p1.y);

    ctx.save();
    // Fill
    ctx.globalAlpha = _getAlpha(d);
    ctx.fillStyle = d.fillColor || d.color;
    ctx.fillRect(x, y, w, h);
    ctx.globalAlpha = 1;
    // Border
    ctx.strokeStyle = d.color;
    ctx.lineWidth = d.lineWidth || 1.5;
    ctx.setLineDash(_getDash(d.lineStyle));
    ctx.strokeRect(x, y, w, h);
    // Dots (seulement si selectionne)
    if (index === state.selectedIndex) {
      _drawDot(p1.x, p1.y, d.color);
      _drawDot(p2.x, p2.y, d.color);
    }
    // Label
    if (d.text) _drawLabel(p2.x + 6, p1.y - 4, d.text, d.color);
    ctx.restore();
  }

  function _drawLine(points, d, index) {
    if (points.length < 2) return;
    var ctx = state.ctx;
    var p1 = _toPixel(points[0].time, points[0].price);
    var p2 = _toPixel(points[1].time, points[1].price);
    if (!p1 || !p2) return;
    var cw = state.canvas.width / (window.devicePixelRatio || 1);

    ctx.save();
    ctx.globalAlpha = _getAlpha(d);
    ctx.strokeStyle = d.color;
    ctx.lineWidth = d.lineWidth || 1.5;
    ctx.setLineDash(_getDash(d.lineStyle));

    var x1 = p1.x, y1 = p1.y, x2 = p2.x, y2 = p2.y;
    if (d.extendLeft || d.extendRight) {
      var dx = x2 - x1, dy = y2 - y1;
      if (dx !== 0) {
        if (d.extendLeft) { var tL = (0 - x1) / dx; x1 = 0; y1 = y1 + dy * tL; }
        if (d.extendRight) { var tR = (cw - x1) / dx; x2 = cw; y2 = y1 + dy * tR; }
      }
    }

    ctx.beginPath(); ctx.moveTo(x1, y1); ctx.lineTo(x2, y2); ctx.stroke();
    ctx.globalAlpha = 1;
    if (index === state.selectedIndex) {
      _drawDot(p1.x, p1.y, d.color); _drawDot(p2.x, p2.y, d.color);
    }
    if (d.text) _drawLabel(p2.x + 6, p2.y - 6, d.text, d.color);
    ctx.restore();
  }

  function _drawHorizLine(point, d) {
    var ctx = state.ctx;
    var px = _toPixel(point.time, point.price);
    if (!px) return;
    var cw = state.canvas.width / (window.devicePixelRatio || 1);
    ctx.save();
    ctx.globalAlpha = _getAlpha(d);
    ctx.strokeStyle = d.color; ctx.lineWidth = d.lineWidth || 1.5;
    ctx.setLineDash(_getDash(d.lineStyle));
    ctx.beginPath(); ctx.moveTo(0, px.y); ctx.lineTo(cw, px.y); ctx.stroke();
    ctx.globalAlpha = 1;
    ctx.fillStyle = d.color;
    ctx.font = '10px "JetBrains Mono", monospace';
    ctx.textAlign = 'left'; ctx.textBaseline = 'bottom';
    ctx.fillText(point.price.toFixed(2), 4, px.y - 4);
    if (d.text) { ctx.textAlign = 'right'; ctx.fillText(d.text, cw - 4, px.y - 4); }
    ctx.restore();
  }

  function _drawHorizRay(point, d, index) {
    var ctx = state.ctx;
    var px = _toPixel(point.time, point.price);
    if (!px) return;
    var cw = state.canvas.width / (window.devicePixelRatio || 1);
    ctx.save();
    ctx.globalAlpha = _getAlpha(d);
    ctx.strokeStyle = d.color; ctx.lineWidth = d.lineWidth || 1.5;
    ctx.setLineDash(_getDash(d.lineStyle));
    ctx.beginPath(); ctx.moveTo(px.x, px.y); ctx.lineTo(cw, px.y); ctx.stroke();
    ctx.globalAlpha = 1;
    var as = 8; ctx.beginPath(); ctx.moveTo(cw, px.y); ctx.lineTo(cw - as, px.y - as / 2); ctx.lineTo(cw - as, px.y + as / 2); ctx.closePath(); ctx.fillStyle = d.color; ctx.fill();
    ctx.fillStyle = d.color;
    ctx.font = '10px "JetBrains Mono", monospace';
    ctx.textAlign = 'left'; ctx.textBaseline = 'bottom';
    ctx.fillText(point.price.toFixed(2), px.x + 6, px.y - 6);
    if (d.text) ctx.fillText(d.text, px.x + 6, px.y + 14);
    if (index === state.selectedIndex) _drawDot(px.x, px.y, d.color);
    ctx.restore();
  }

  function _drawVertLine(point, d, index) {
    var ctx = state.ctx;
    var px = _toPixel(point.time, point.price);
    if (!px) return;
    var ch = state.canvas.height / (window.devicePixelRatio || 1);
    ctx.save();
    ctx.globalAlpha = _getAlpha(d);
    ctx.strokeStyle = d.color; ctx.lineWidth = d.lineWidth || 1.5;
    ctx.setLineDash(_getDash(d.lineStyle));
    ctx.beginPath(); ctx.moveTo(px.x, 0); ctx.lineTo(px.x, ch); ctx.stroke();
    ctx.globalAlpha = 1;
    ctx.fillStyle = d.color; ctx.font = '10px "JetBrains Mono", monospace';
    ctx.textAlign = 'center'; ctx.textBaseline = 'bottom';
    ctx.fillText(d.text || '', px.x, ch - 4);
    if (index === state.selectedIndex) _drawDot(px.x, 0, d.color);
    ctx.restore();
  }

  function _drawFibonacci(d, index) {
    var points = d.points;
    if (points.length < 2) return;
    var ctx = state.ctx;
    var p1 = _toPixel(points[0].time, points[0].price);
    var p2 = _toPixel(points[1].time, points[1].price);
    if (!p1 || !p2) return;

    var fibLevels = _normalizeFibLevels(d.fibLevels);

    ctx.save();
    ctx.globalAlpha = _getAlpha(d);
    ctx.strokeStyle = d.color; ctx.lineWidth = 1; ctx.setLineDash([4, 4]);
    ctx.beginPath(); ctx.moveTo(p1.x, p1.y); ctx.lineTo(p2.x, p2.y); ctx.stroke();
    ctx.globalAlpha = 1;

    var cw = state.canvas.width / (window.devicePixelRatio || 1);
    var minX = Math.max(0, Math.min(p1.x, p2.x) - 30);
    var maxX = Math.min(cw, Math.max(p1.x, p2.x) + 30);

    for (var i = 0; i < fibLevels.length; i++) {
      var l = fibLevels[i];
      if (l.visible === false) continue;
      var levelColor = d.color || l.color;
      var price = _fibLevelPrice(points, l.key);
      var py = _toPixel(points[0].time, price);
      if (!py) continue;
      ctx.save();
      ctx.strokeStyle = levelColor; ctx.lineWidth = 1; ctx.setLineDash([4, 3]);
      ctx.beginPath(); ctx.moveTo(minX, py.y); ctx.lineTo(maxX, py.y); ctx.stroke();
      ctx.fillStyle = levelColor; ctx.font = '9px "JetBrains Mono", monospace';
      ctx.textAlign = 'right'; ctx.textBaseline = 'middle';
      ctx.fillText(l.label + '% (' + price.toFixed(2) + ')', maxX - 2, py.y);
      ctx.restore();
    }

    if (index === state.selectedIndex) {
      _drawDot(p1.x, p1.y, d.color); _drawDot(p2.x, p2.y, d.color);
    }
    ctx.restore();
  }

  function _drawText(point, d, index) {
    var ctx = state.ctx;
    var px = _toPixel(point.time, point.price);
    if (!px) return;
    ctx.save();
    ctx.globalAlpha = _getAlpha(d);
    ctx.fillStyle = d.color;
    ctx.font = 'bold 12px "JetBrains Mono", monospace';
    ctx.textAlign = 'left'; ctx.textBaseline = 'bottom';
    ctx.fillText(d.text || 'Texte', px.x + 6, px.y - 6);
    ctx.globalAlpha = 1;
    if (index === state.selectedIndex) _drawDot(px.x, px.y, d.color);
    ctx.restore();
  }

  function _drawLabel(x, y, txt, color) {
    var ctx = state.ctx;
    ctx.save();
    ctx.fillStyle = color;
    ctx.font = 'bold 10px "JetBrains Mono", monospace';
    ctx.textAlign = 'left'; ctx.textBaseline = 'bottom';
    ctx.fillText(txt, x, y);
    ctx.restore();
  }

  function _drawDot(x, y, color) {
    var ctx = state.ctx; if (!ctx) return;
    ctx.save(); ctx.fillStyle = color;
    ctx.beginPath(); ctx.arc(x, y, 3.5, 0, Math.PI * 2); ctx.fill();
    ctx.restore();
  }

  // ── CLEAR ──

  function clearAllDrawings() {
    _pushUndoState();
    state.drawings = []; _saveDrawings(); _renderAll();
  }

  // ── EXPOSED API ──

  window.ChartDrawings = {
    init: initDrawings, destroy: destroyDrawings,
    setTool: setActiveTool, getTool: getActiveTool,
    clearAll: clearAllDrawings, undo: undo, tools: DRAW_TOOLS,
    saveTemplate: saveTemplate, loadTemplate: loadTemplate,
    listTemplates: listTemplates, deleteTemplate: deleteTemplate,
    getDrawings: function () { return state.drawings.slice(); },
    onResize: function () { _resizeCanvas(); _renderAll(); },
    setSnapEnabled: function (v) { state.snapEnabled = !!v; },
    getSnapEnabled: function () { return state.snapEnabled; },
    // Session zones
    getSessionSettings: getSessionSettings,
    updateSessions: updateSessions,
  };

})();

// ---- 065_volume_profile.js ----
// ---------- Hyperliquid Volume Profile - integrated chart overlay ----------
// Source of truth: executed Hyperliquid trades through analytics APIs.

(function () {
  'use strict';

  var STORAGE_KEY = 'chartVolumeProfileSettings';
  var DEFAULTS = {
    active: true,
    metric: 'notional',
    profileType: 'session',
    rowSize: 'auto',
    vaPercent: 70,
    showPOC: true,
    showVAH: true,
    showVAL: true,
    colorPOC: '#f59e0b',
    colorVAH: '#38d3ee',
    colorVAL: '#fb7185',
    colorHvn: '#22c7d8',
    showNodes: true,
    vpPeakN: 9,      // window size %
    vpTroughN: 7,    // window size %
    vpThreshold: 10, // % of max volume
    colorPeak: '#22d3ee',
    colorTrough: '#64748b'
  };

  var state = {
    chart: null,
    series: null,
    container: null,
    canvas: null,
    ctx: null,
    settings: null,
    candles: [],
    coin: 'BTC',
    interval: '3m',
    mode: 'profile',
    data: null,
    requestId: 0,
    resizeObserver: null,
    scaleBound: false,
  };

  function _loadSettings() {
    try {
      var saved = JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}');
      if (saved.bucketSize != null && saved.rowSize == null) saved.rowSize = String(saved.bucketSize);
      if (saved.period != null && saved.profileType == null) saved.profileType = saved.period === 'visible' ? 'visible' : 'session';
      state.settings = Object.assign({}, DEFAULTS, saved);
    } catch (e) {
      state.settings = Object.assign({}, DEFAULTS);
    }
  }

  function _saveSettings() {
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state.settings)); } catch (e) {}
  }

  function _createCanvas() {
    if (!state.container) return;
    if (state.canvas && state.canvas.parentNode) state.canvas.parentNode.removeChild(state.canvas);
    state.canvas = document.createElement('canvas');
    state.canvas.className = 'vp-overlay';
    state.container.appendChild(state.canvas);
    state.ctx = state.canvas.getContext('2d');
    _resize();
  }

  function _paneRect() {
    if (!state.container) return null;
    var parent = state.container.getBoundingClientRect();
    var canvases = state.container.querySelectorAll('#chartCanvas canvas');
    var best = null;
    var area = 0;
    Array.prototype.forEach.call(canvases, function (canvas) {
      var rect = canvas.getBoundingClientRect();
      if (rect.width * rect.height > area) {
        area = rect.width * rect.height;
        best = rect;
      }
    });
    if (!best) return { left: 0, top: 0, width: parent.width, height: parent.height };
    return {
      left: best.left - parent.left,
      top: best.top - parent.top,
      width: best.width,
      height: best.height,
    };
  }

  function _resize() {
    if (!state.canvas || !state.container) return;
    var rect = _paneRect();
    var dpr = window.devicePixelRatio || 1;
    state.canvas.style.left = rect.left + 'px';
    state.canvas.style.top = rect.top + 'px';
    state.canvas.style.width = rect.width + 'px';
    state.canvas.style.height = rect.height + 'px';
    state.canvas.width = Math.round(rect.width * dpr);
    state.canvas.height = Math.round(rect.height * dpr);
    state.ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  }

  function init(chart, series, container) {
    state.chart = chart;
    state.series = series;
    state.container = container;
    if (!state.settings) _loadSettings();
    _createCanvas();
    if (state.resizeObserver) state.resizeObserver.disconnect();
    state.resizeObserver = new ResizeObserver(function () {
      _resize();
      render();
    });
    state.resizeObserver.observe(container);
    if (!state.scaleBound && chart && chart.timeScale()) {
      state.scaleBound = true;
      var schedule = function () {
        render();
        if (state.settings.profileType === 'visible') refresh();
      };
      try { chart.timeScale().subscribeVisibleTimeRangeChange(schedule); } catch (e) {}
    }
    render();
  }

  function destroy() {
    if (state.resizeObserver) state.resizeObserver.disconnect();
    if (state.canvas && state.canvas.parentNode) state.canvas.parentNode.removeChild(state.canvas);
    state.canvas = null;
    state.ctx = null;
    state.data = null;
  }

  function _range() {
    var latest = state.candles.length ? state.candles[state.candles.length - 1].time * 1000 : Date.now();
    var liveEnd = Math.max(latest + 1, Date.now());
    if (state.settings.profileType === 'visible' && state.chart) {
      try {
        var visible = state.chart.timeScale().getVisibleRange();
        if (visible && visible.from && visible.to) {
          return { start: Number(visible.from) * 1000, end: Number(visible.to) * 1000 };
        }
      } catch (e) {}
    }
    if (state.settings.profileType === 'fixed' || state.settings.profileType === 'composite') {
      if (state.candles.length) {
        return { start: state.candles[0].time * 1000, end: latest + 1 };
      }
    }
    var utc = new Date(latest);
    var start = Date.UTC(utc.getUTCFullYear(), utc.getUTCMonth(), utc.getUTCDate());
    return { start: start, end: Math.max(start + 1, liveEnd) };
  }

  function _status(text, className) {
    var el = document.getElementById('chartDataStatus');
    if (!el) return;
    el.className = 'workspace-data-status' + (className ? ' ' + className : '');
    el.textContent = text;
  }

  function refresh() {
    if (!state.settings || !state.settings.active || state.mode !== 'profile') {
      state.data = null;
      render();
      return;
    }
    var range = _range();
    var requestId = ++state.requestId;
    var params = [
      'coin=' + encodeURIComponent(state.coin),
      'startTime=' + Math.floor(range.start),
      'endTime=' + Math.floor(range.end),
      'metric=' + encodeURIComponent(state.settings.metric),
      'rowSize=' + encodeURIComponent(state.settings.rowSize),
      'vaPercent=' + encodeURIComponent(state.settings.vaPercent),
      'profileType=' + encodeURIComponent(state.settings.profileType),
    ].join('&');
    _status('Hyperliquid trades: loading profile', 'partial');
    fetch('/api/hyperliquid/analytics/volume-profile?' + params)
      .then(function (response) {
        if (!response.ok) throw new Error('HTTP ' + response.status);
        return response.json();
      })
      .then(function (data) {
        if (requestId !== state.requestId) return;
        state.data = data;
        if (data.partial) {
          _status('Partial coverage | profile from available trades', 'partial');
        } else {
          _status('Full trade coverage | exact delta', '');
        }
        render();
      })
      .catch(function () {
        if (requestId !== state.requestId) return;
        state.data = null;
        _status('Hyperliquid profile unavailable', 'gap');
        render();
      });
  }

  function setCandles(candles) {
    state.candles = candles || [];
    refresh();
  }

  function setContext(context) {
    context = context || {};
    if (context.coin) state.coin = context.coin;
    if (context.interval) state.interval = context.interval;
    if (context.candles) state.candles = context.candles;
    refresh();
  }

  function setMode(mode) {
    state.mode = mode || 'profile';
    if (state.canvas) state.canvas.style.display = state.mode === 'profile' ? '' : 'none';
    if (state.mode === 'profile') refresh();
  }

  function updateSettings(settings) {
    var normalized = Object.assign({}, settings);
    if (normalized.bucketSize != null) normalized.rowSize = String(normalized.bucketSize);
    if (normalized.period != null) normalized.profileType = normalized.period;
    Object.assign(state.settings, normalized);
    _saveSettings();
    refresh();
  }

  function getSettings() {
    var output = Object.assign({}, state.settings || DEFAULTS);
    output.bucketSize = output.rowSize;
    output.period = output.profileType;
    return output;
  }

  function _priceY(price) {
    try { return state.series && state.series.priceToCoordinate(Number(price)); } catch (e) { return null; }
  }

  function _timeX(timeMs) {
    try { return state.chart && state.chart.timeScale().timeToCoordinate(Number(timeMs) / 1000); } catch (e) { return null; }
  }

  function _label(ctx, x, y, text, color) {
    ctx.font = '700 10px "JetBrains Mono", monospace';
    var width = ctx.measureText(text).width + 12;
    ctx.fillStyle = 'rgba(7, 13, 18, 0.90)';
    ctx.fillRect(x - width, y - 10, width, 18);
    ctx.fillStyle = color;
    ctx.fillText(text, x - width + 6, y + 3);
  }

  function _detectVolumeNodes(levels, maxVolume) {
    var sorted = levels.slice().sort(function (a, b) { return a.price - b.price; });
    var len = sorted.length;
    if (len < 5) return { peaks: [], troughs: [] };

    var peakPercent = state.settings.vpPeakN || 9;
    var troughPercent = state.settings.vpTroughN || 7;
    var threshPercent = state.settings.vpThreshold || 10;

    var peakN = Math.max(1, Math.floor(len * (peakPercent / 100)));
    var troughN = Math.max(1, Math.floor(len * (troughPercent / 100)));
    var minVolThreshold = maxVolume * (threshPercent / 100);

    var peaks = [];
    var troughs = [];

    for (var i = 0; i < len; i++) {
      var vol = sorted[i].totalVolume;

      var isPeak = true;
      var startP = Math.max(0, i - peakN);
      var endP = Math.min(len - 1, i + peakN);
      for (var j = startP; j <= endP; j++) {
        if (sorted[j].totalVolume > vol) {
          isPeak = false;
          break;
        }
      }
      if (isPeak && vol >= minVolThreshold) {
        peaks.push(sorted[i]);
      }

      if (i > troughN && i < len - 1 - troughN) {
        var isTrough = true;
        var startT = Math.max(0, i - troughN);
        var endT = Math.min(len - 1, i + troughN);
        for (var j = startT; j <= endT; j++) {
          if (sorted[j].totalVolume < vol) {
            isTrough = false;
            break;
          }
        }
        if (isTrough) {
          troughs.push(sorted[i]);
        }
      }
    }
    return { peaks: peaks, troughs: troughs };
  }

  function render() {
    if (!state.ctx || !state.canvas) return;
    var dpr = window.devicePixelRatio || 1;
    var width = state.canvas.width / dpr;
    var height = state.canvas.height / dpr;
    var ctx = state.ctx;
    ctx.clearRect(0, 0, width, height);
    if (state.mode !== 'profile' || !state.settings.active || !state.data) return;
    var levels = state.data.levels || [];
    if (!levels.length) {
      ctx.fillStyle = 'rgba(246,195,102,0.8)';
      ctx.font = '11px "JetBrains Mono", monospace';
      ctx.fillText('NO TRADE COVERAGE FOR RANGE', width - 270, 30);
      return;
    }

    var profileWidth = Math.min(265, Math.max(170, width * 0.23));
    var right = width - 44;
    var left = right - profileWidth;
    var maxVolume = Math.max.apply(null, levels.map(function (level) { return level.totalVolume; })) || 1;
    var rowPixels = Math.max(2, Math.min(13, Math.abs((_priceY(levels[0].price + state.data.rowSize) || 0) - (_priceY(levels[0].price) || 0)) || 4));

    ctx.fillStyle = 'rgba(5, 11, 16, 0.42)';
    ctx.fillRect(left - 10, 0, profileWidth + 18, height);
    ctx.fillStyle = 'rgba(132,226,244,0.45)';
    ctx.font = '700 9px "JetBrains Mono", monospace';
    ctx.fillText(state.data.profileType.toUpperCase() + ' VP / ' + state.data.metric.toUpperCase(), left, 16);

    levels.forEach(function (level) {
      var y = _priceY(level.price);
      if (y == null || y < -10 || y > height + 10) return;
      var totalWidth = (level.totalVolume / maxVolume) * profileWidth;
      var sellWidth = level.totalVolume ? totalWidth * level.sellVolume / level.totalVolume : 0;
      var buyWidth = level.totalVolume ? totalWidth * level.buyVolume / level.totalVolume : 0;
      var inValue = level.price >= state.data.val && level.price <= state.data.vah;
      ctx.globalAlpha = inValue ? 0.86 : 0.42;
      ctx.fillStyle = '#fb7185';
      ctx.fillRect(right - totalWidth, y - rowPixels / 2, sellWidth, rowPixels - 1);
      ctx.fillStyle = '#22d3ee';
      ctx.fillRect(right - totalWidth + sellWidth, y - rowPixels / 2, buyWidth, rowPixels - 1);
      if (level.unknownVolume > 0) {
        ctx.fillStyle = 'rgba(148,163,184,0.7)';
        ctx.fillRect(right - totalWidth, y - 1, totalWidth, 1);
      }
    });
    ctx.globalAlpha = 1;

    var developing = state.data.developing || [];
    if (developing.length > 1) {
      ctx.strokeStyle = 'rgba(245,158,11,0.62)';
      ctx.lineWidth = 1;
      ctx.setLineDash([2, 3]);
      ctx.beginPath();
      developing.forEach(function (point, index) {
        var x = _timeX(point.timeMs);
        var y = _priceY(point.poc);
        if (x == null || y == null) return;
        if (index === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      });
      ctx.stroke();
      ctx.setLineDash([]);
    }

    if (state.data.previousLevels) {
      ['poc', 'vah', 'val'].forEach(function (key) {
        var levelY = _priceY(state.data.previousLevels[key]);
        if (levelY == null) return;
        ctx.strokeStyle = 'rgba(148,163,184,0.30)';
        ctx.lineWidth = 1;
        ctx.setLineDash([3, 5]);
        ctx.beginPath();
        ctx.moveTo(left - 60, levelY);
        ctx.lineTo(right, levelY);
        ctx.stroke();
        ctx.setLineDash([]);
      });
    }

    [
      { enabled: state.settings.showPOC, price: state.data.poc, color: state.settings.colorPOC, tag: 'POC', dash: [] },
      { enabled: state.settings.showVAH, price: state.data.vah, color: state.settings.colorVAH, tag: 'VAH', dash: [5, 5] },
      { enabled: state.settings.showVAL, price: state.data.val, color: state.settings.colorVAL, tag: 'VAL', dash: [5, 5] },
    ].forEach(function (line) {
      if (!line.enabled || line.price == null) return;
      var y = _priceY(line.price);
      if (y == null) return;
      ctx.strokeStyle = line.color;
      ctx.lineWidth = line.tag === 'POC' ? 1.6 : 1;
      ctx.globalAlpha = line.tag === 'POC' ? 0.86 : 0.64;
      ctx.setLineDash(line.dash);
      ctx.beginPath();
      ctx.moveTo(line.tag === 'POC' ? 0 : left - 40, y);
      ctx.lineTo(right, y);
      ctx.stroke();
      ctx.globalAlpha = 1;
      ctx.setLineDash([]);
      _label(ctx, right, y, line.tag + ' ' + Number(line.price).toFixed(2), line.color);
    });

    // --- LuxAlgo Node Detection Highlights ---
    if (state.settings.showNodes) {
      var nodes = _detectVolumeNodes(levels, maxVolume);

      // Peaks (HVN)
      nodes.peaks.forEach(function (node) {
        var y = _priceY(node.price);
        if (y == null || y < 0 || y > height) return;

        // Draw Peak line
        ctx.save();
        ctx.strokeStyle = state.settings.colorPeak || '#22d3ee';
        ctx.lineWidth = 1.2;
        ctx.beginPath();
        ctx.moveTo(left, y);
        ctx.lineTo(right, y);
        ctx.stroke();

        // Left marker text
        ctx.font = 'bold 8px "JetBrains Mono", monospace';
        ctx.fillStyle = state.settings.colorPeak || '#22d3ee';
        ctx.textAlign = 'right';
        ctx.fillText('HVN ' + Number(node.price).toFixed(1), left - 5, y + 3);
        ctx.restore();
      });

      // Troughs (LVN)
      nodes.troughs.forEach(function (node) {
        var y = _priceY(node.price);
        if (y == null || y < 0 || y > height) return;

        // Draw Trough line
        ctx.save();
        ctx.strokeStyle = state.settings.colorTrough || '#64748b';
        ctx.lineWidth = 0.8;
        ctx.setLineDash([2, 4]);
        ctx.beginPath();
        ctx.moveTo(left, y);
        ctx.lineTo(right, y);
        ctx.stroke();

        // Left marker text
        ctx.font = '8px "JetBrains Mono", monospace';
        ctx.fillStyle = state.settings.colorTrough || '#64748b';
        ctx.textAlign = 'right';
        ctx.fillText('LVN ' + Number(node.price).toFixed(1), left - 5, y + 3);
        ctx.restore();
      });
    }
  }

  window.VolumeProfile = {
    init: init,
    destroy: destroy,
    setCandles: setCandles,
    setContext: setContext,
    setMode: setMode,
    updateSettings: updateSettings,
    getSettings: getSettings,
    refresh: refresh,
    render: render,
  };
})();

// ---- 070_v6_orderflow_contract.js ----
// ---------- 070_v6_orderflow_contract.js ----------
// Cockpit V6 mock data contract. No live data, no network access.

(function () {
  'use strict';

  var V6OF = window.V6OF = window.V6OF || {};

  /**
   * @typedef {Object} V6Trade
   * @property {string} id
   * @property {string} exchange
   * @property {string} symbol
   * @property {number} tsExchange
   * @property {number} tsLocal
   * @property {number} price
   * @property {number} qty
   * @property {'buy'|'sell'} side
   * @property {number} notional
   */

  /**
   * @typedef {Object} V6OrderBookLevel
   * @property {number} price
   * @property {number} size
   * @property {number} orders
   * @property {number} cumulative
   */

  /**
   * @typedef {Object} V6OrderBookSnapshot
   * @property {string} exchange
   * @property {string} symbol
   * @property {number} tsExchange
   * @property {number} tsLocal
   * @property {V6OrderBookLevel[]} bids
   * @property {V6OrderBookLevel[]} asks
   * @property {number} bestBid
   * @property {number} bestAsk
   * @property {number} spread
   * @property {number} mid
   * @property {number} depth
   * @property {string} source
   */

  /**
   * @typedef {Object} V6DeltaBucket
   * @property {string} exchange
   * @property {string} symbol
   * @property {number} intervalMs
   * @property {number} startTime
   * @property {number} endTime
   * @property {number} buyVol
   * @property {number} sellVol
   * @property {number} delta
   * @property {number} cvd
   * @property {boolean} closed
   */

  /**
   * @typedef {Object} V6VWAPState
   * @property {string} exchange
   * @property {string} symbol
   * @property {string} sessionId
   * @property {number} sessionStart
   * @property {number} coverageStart
   * @property {number} lastUpdateTs
   * @property {number} cumPV
   * @property {number} cumVol
   * @property {number} value
   * @property {string} source
   * @property {boolean} isWarm
   */

  /**
   * @typedef {Object} V6Candle
   * @property {string} symbol
   * @property {string} timeframe
   * @property {number} openTime
   * @property {number} closeTime
   * @property {number} open
   * @property {number} high
   * @property {number} low
   * @property {number} close
   * @property {number} volume
   * @property {number} delta
   */

  /**
   * @typedef {Object} V6HeatmapLevel
   * @property {number} price
   * @property {number} bidSize
   * @property {number} askSize
   * @property {number} totalSize
   * @property {number} intensity
   */

  /**
   * @typedef {Object} V6HeatmapFrame
   * @property {string} exchange
   * @property {string} symbol
   * @property {number} tsExchange
   * @property {number} tsLocal
   * @property {number} mid
   * @property {number} bestBid
   * @property {number} bestAsk
   * @property {number} priceMin
   * @property {number} priceMax
   * @property {number} tickSize
   * @property {V6HeatmapLevel[]} levels
   * @property {string} source
   * @property {number} depth
   */

  /**
   * @typedef {Object} V6FootprintLevel
   * @property {number} price
   * @property {number} buyVol
   * @property {number} sellVol
   * @property {number} delta
   * @property {number} totalVol
   * @property {number} trades
   */

  /**
   * @typedef {Object} V6FootprintCandle
   * @property {string} exchange
   * @property {string} symbol
   * @property {number} intervalMs
   * @property {number} openTime
   * @property {number} closeTime
   * @property {number} open
   * @property {number} high
   * @property {number} low
   * @property {number} close
   * @property {number} volume
   * @property {number} buyVol
   * @property {number} sellVol
   * @property {number} delta
   * @property {number} poc
   * @property {boolean} closed
   * @property {V6FootprintLevel[]} levels
   * @property {string} source
   */

  V6OF.Contract = {
    version: 'v6.orderflow.v1',
    source: 'mock',
    createEmptyState: function () {
      return {
        contractVersion: 'v6.orderflow.v1',
        source: 'mock',
        symbol: 'BTCUSDT',
        timeframe: '1m',
        dataSource: 'binance',
        trades: [],
        orderBook: null,
        lastOrderBookBySymbol: {},
        orderBookCount: 0,
        lastOrderBookTs: 0,
        selectedDomSymbol: '',
        heatmapFrames: [],
        heatmapFrameCount: 0,
        lastHeatmapFrame: null,
        lastHeatmapTs: 0,
        selectedHeatmapSymbol: '',
        footprintCandles: [],
        footprintCandleCount: 0,
        lastFootprintCandle: null,
        lastFootprintTs: 0,
        selectedFootprintSymbol: '',
        candles: [],
        chartCandles: [],
        deltaBuckets: [],
        deltaBucketsByInterval: {},
        latestDeltaByInterval: {},
        vwap: null,
        vwapBySymbol: {},
        _candlesByInterval: {},
        lastMessageAt: 0,
        isStale: false,
        settings: {
          minQty: 0,
          maxRows: 42,
          showTape: true,
          showDOM: true,
          showCVD: true,
          showVwap: true,
          showCandles: true,
          showBubbles: true,
          showHeatmap: false,
          showFootprint: false,
          showLastPrice: true,
          showGrid: true,
          bgColor: '#080b12',
          upColor: '#3ddc97',
          downColor: '#ff5f73',
          chartMode: 'both',
          maxTrades: 500,
          heatmapMaxFrames: 360,
          footprintMaxCandles: 120,
          deltaIntervalMs: 60000,
          domDepth: 20,
          tickSize: 1
        },
        ui: {
          legacyMode: false,
          seed: 42
        }
      };
    },
    isTrade: function (value) {
      return !!value &&
        typeof value.id === 'string' &&
        typeof value.symbol === 'string' &&
        Number.isFinite(value.tsExchange) &&
        Number.isFinite(value.price) &&
        Number.isFinite(value.qty) &&
        (value.side === 'buy' || value.side === 'sell');
    }
  };

  V6OF.escapeHtml = function (value) {
    return String(value == null ? '' : value)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  };

  V6OF.format = {
    price: function (value) {
      if (!Number.isFinite(value)) return '--';
      return value.toLocaleString('en-US', {
        minimumFractionDigits: value >= 1000 ? 1 : 2,
        maximumFractionDigits: value >= 1000 ? 1 : 4
      });
    },
    qty: function (value) {
      if (!Number.isFinite(value)) return '--';
      if (value >= 1000) return (value / 1000).toFixed(1) + 'K';
      if (value >= 100) return value.toFixed(0);
      if (value >= 10) return value.toFixed(1);
      return value.toFixed(3);
    },
    signed: function (value) {
      if (!Number.isFinite(value)) return '--';
      var sign = value > 0 ? '+' : '';
      return sign + V6OF.format.qty(value);
    },
    time: function (ts) {
      if (!Number.isFinite(ts)) return '--:--:--';
      return new Date(ts).toLocaleTimeString([], {
        hour12: false,
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      });
    }
  };
})();

// ---- 071_v6_orderflow_store.js ----
// ---------- 071_v6_orderflow_store.js ----------
// Minimal observable store for the isolated Cockpit V6 mock surface.

(function () {
  'use strict';

  var V6OF = window.V6OF = window.V6OF || {};

  function cloneSettings(settings) {
    return Object.assign({}, settings || {});
  }

  function cloneUi(ui) {
    return Object.assign({}, ui || {});
  }

  function cloneObjectMap(value) {
    return Object.assign({}, value || {});
  }

  function normalizeState(next) {
    var empty = V6OF.Contract.createEmptyState();
    next = next || {};
    next.settings = Object.assign(empty.settings, cloneSettings(next.settings));
    next.ui = Object.assign(empty.ui, cloneUi(next.ui));
    next.trades = Array.isArray(next.trades) ? next.trades : [];
    next.candles = Array.isArray(next.candles) ? next.candles : [];
    next.chartCandles = Array.isArray(next.chartCandles) ? next.chartCandles : [];
    next._candlesByInterval = next._candlesByInterval || {};
    next.deltaBuckets = Array.isArray(next.deltaBuckets) ? next.deltaBuckets : [];
    next.deltaBucketsByInterval = cloneObjectMap(next.deltaBucketsByInterval || empty.deltaBucketsByInterval);
    next.latestDeltaByInterval = cloneObjectMap(next.latestDeltaByInterval || empty.latestDeltaByInterval);
    next.orderBook = next.orderBook || null;
    next.lastOrderBookBySymbol = cloneObjectMap(next.lastOrderBookBySymbol || empty.lastOrderBookBySymbol);
    next.orderBookCount = Number.isFinite(next.orderBookCount) ? next.orderBookCount : 0;
    next.lastOrderBookTs = Number.isFinite(next.lastOrderBookTs) ? next.lastOrderBookTs : 0;
    next.selectedDomSymbol = next.selectedDomSymbol || empty.selectedDomSymbol;
    next.heatmapFrames = Array.isArray(next.heatmapFrames) ? next.heatmapFrames : [];
    next.heatmapFrameCount = Number.isFinite(next.heatmapFrameCount) ? next.heatmapFrameCount : 0;
    next.lastHeatmapFrame = next.lastHeatmapFrame || null;
    next.lastHeatmapTs = Number.isFinite(next.lastHeatmapTs) ? next.lastHeatmapTs : 0;
    next.selectedHeatmapSymbol = next.selectedHeatmapSymbol || empty.selectedHeatmapSymbol;
    next.footprintCandles = Array.isArray(next.footprintCandles) ? next.footprintCandles : [];
    next.footprintCandleCount = Number.isFinite(next.footprintCandleCount) ? next.footprintCandleCount : 0;
    next.lastFootprintCandle = next.lastFootprintCandle || null;
    next.lastFootprintTs = Number.isFinite(next.lastFootprintTs) ? next.lastFootprintTs : 0;
    next.selectedFootprintSymbol = next.selectedFootprintSymbol || empty.selectedFootprintSymbol;
    next.vwap = next.vwap || null;
    next.vwapBySymbol = cloneObjectMap(next.vwapBySymbol || empty.vwapBySymbol);
    next.lastMessageAt = Number.isFinite(next.lastMessageAt) ? next.lastMessageAt : 0;
    next.isStale = !!next.isStale;
    next.contractVersion = next.contractVersion || empty.contractVersion;
    next.source = next.source || empty.source;
    next.symbol = next.symbol || empty.symbol;
    next.timeframe = next.timeframe || empty.timeframe;
    next.depthHistory = Array.isArray(next.depthHistory) ? next.depthHistory : [];
    return next;
  }

  V6OF.createStore = function (initialState) {
    var state = normalizeState(initialState || V6OF.Contract.createEmptyState());
    var listeners = [];

    function notify() {
      listeners.slice().forEach(function (fn) {
        try { fn(state); } catch (err) { console.error('[V6OF] store listener failed', err); }
      });
    }

    return {
      getState: function () {
        return state;
      },
      setState: function (patch, reason) {
        var next = typeof patch === 'function' ? patch(state) : patch;
        if (!next) return state;
        state = normalizeState(Object.assign({}, state, next));
        state.lastUpdateReason = reason || 'setState';
        notify();
        return state;
      },
      updateSettings: function (patch) {
        this.setState({ settings: Object.assign({}, state.settings, patch || {}) }, 'settings');
      },
      updateUi: function (patch) {
        this.setState({ ui: Object.assign({}, state.ui, patch || {}) }, 'ui');
      },
      clearHeatmap: function () {
        this.setState({
          heatmapFrames: [],
          lastHeatmapFrame: null,
          lastHeatmapTs: 0
        }, 'clear-heatmap');
      },
      clearFootprint: function () {
        this.setState({
          footprintCandles: [],
          lastFootprintCandle: null,
          lastFootprintTs: 0
        }, 'clear-footprint');
      },
      clearAllBuffers: function () {
        this.setState({
          trades: [],
          heatmapFrames: [],
          lastHeatmapFrame: null,
          lastHeatmapTs: 0,
          footprintCandles: [],
          lastFootprintCandle: null,
          lastFootprintTs: 0
        }, 'clear-all-buffers');
      },
      subscribe: function (fn) {
        if (typeof fn !== 'function') return function () {};
        listeners.push(fn);
        return function () {
          listeners = listeners.filter(function (item) { return item !== fn; });
        };
      }
    };
  };
})();

// ---- 072_v6_orderflow_mock.js ----
// ---------- 072_v6_orderflow_mock.js ----------
// Deterministic BTC/ETH/SOL mock data. This module does not fetch or stream.

(function () {
  'use strict';

  var V6OF = window.V6OF = window.V6OF || {};

  function makeRng(seed) {
    var s = Math.max(1, seed || 1) % 2147483647;
    return function () {
      s = (s * 16807) % 2147483647;
      return (s - 1) / 2147483646;
    };
  }

  function round(value, digits) {
    var m = Math.pow(10, digits || 0);
    return Math.round(value * m) / m;
  }

  function baseForSymbol(symbol) {
    if (symbol === 'ETHUSDT') return { price: 4200, tick: 0.5, qty: 14 };
    if (symbol === 'SOLUSDT') return { price: 184, tick: 0.05, qty: 240 };
    return { price: 104200, tick: 1, qty: 1.8 };
  }

  function createCandles(symbol, timeframe, now, rng, meta) {
    var candles = [];
    var intervalMs = 60000;
    var price = meta.price;
    var start = now - intervalMs * 47;

    for (var i = 0; i < 48; i++) {
      var open = price;
      var drift = (rng() - 0.47) * meta.tick * 95;
      var close = Math.max(meta.tick, open + drift);
      var wick = meta.tick * (18 + rng() * 55);
      var high = Math.max(open, close) + wick * rng();
      var low = Math.min(open, close) - wick * rng();
      var buyVol = meta.qty * (18 + rng() * 62);
      var sellVol = meta.qty * (18 + rng() * 62);
      var delta = buyVol - sellVol;

      candles.push({
        symbol: symbol,
        timeframe: timeframe,
        openTime: start + i * intervalMs,
        closeTime: start + (i + 1) * intervalMs,
        open: round(open, 4),
        high: round(high, 4),
        low: round(Math.max(meta.tick, low), 4),
        close: round(close, 4),
        volume: round(buyVol + sellVol, 3),
        delta: round(delta, 3)
      });

      price = close;
    }
    return candles;
  }

  function createTrades(symbol, now, rng, candles, meta) {
    var trades = [];
    var idBase = Math.floor(now / 1000);

    for (var i = 0; i < 150; i++) {
      var candle = candles[Math.max(0, candles.length - 1 - Math.floor(i / 4))];
      var side = rng() > 0.48 ? 'buy' : 'sell';
      var qty = meta.qty * (0.08 + Math.pow(rng(), 2) * 8.5);
      if (rng() > 0.94) qty *= 5.5;
      var priceSpan = Math.max(meta.tick, candle.high - candle.low);
      var price = candle.low + priceSpan * rng();
      var ts = now - i * (650 + Math.floor(rng() * 2400));

      trades.push({
        id: 'mock-' + symbol + '-' + (idBase - i),
        exchange: 'mock',
        symbol: symbol,
        tsExchange: ts,
        tsLocal: ts + 12,
        price: round(price, 4),
        qty: round(qty, 4),
        side: side,
        notional: round(price * qty, 2)
      });
    }
    return trades.sort(function (a, b) { return b.tsExchange - a.tsExchange; });
  }

  function createOrderBook(symbol, now, rng, lastPrice, meta) {
    var levels = 14;
    var bids = [];
    var asks = [];
    var bidCum = 0;
    var askCum = 0;
    var spread = meta.tick * 2;
    var bestBid = Math.floor((lastPrice - spread / 2) / meta.tick) * meta.tick;
    var bestAsk = bestBid + spread;

    for (var i = 0; i < levels; i++) {
      var bidSize = meta.qty * (5 + rng() * 48) * (1 + i * 0.09);
      var askSize = meta.qty * (5 + rng() * 48) * (1 + i * 0.09);
      bidCum += bidSize;
      askCum += askSize;
      bids.push({
        price: round(bestBid - i * meta.tick, 4),
        size: round(bidSize, 4),
        orders: 1 + Math.floor(rng() * 8),
        cumulative: round(bidCum, 4)
      });
      asks.push({
        price: round(bestAsk + i * meta.tick, 4),
        size: round(askSize, 4),
        orders: 1 + Math.floor(rng() * 8),
        cumulative: round(askCum, 4)
      });
    }

    return {
      exchange: 'mock',
      symbol: symbol,
      tsExchange: now,
      tsLocal: now + 10,
      bids: bids,
      asks: asks,
      bestBid: round(bestBid, 4),
      bestAsk: round(bestAsk, 4),
      spread: round(bestAsk - bestBid, 4),
      mid: round((bestBid + bestAsk) / 2, 4),
      depth: levels,
      source: 'mock'
    };
  }

  function createDeltaBuckets(symbol, candles) {
    var cvd = 0;
    return candles.map(function (c) {
      var buyVol = Math.max(0, (c.volume + c.delta) / 2);
      var sellVol = Math.max(0, (c.volume - c.delta) / 2);
      cvd += c.delta;
      return {
        symbol: symbol,
        timeframe: c.timeframe,
        startTime: c.openTime,
        endTime: c.closeTime,
        buyVol: round(buyVol, 3),
        sellVol: round(sellVol, 3),
        delta: round(c.delta, 3),
        cvd: round(cvd, 3)
      };
    });
  }

  function createVwap(symbol, now, trades) {
    var cumPV = 0;
    var cumVol = 0;
    trades.forEach(function (trade) {
      cumPV += trade.price * trade.qty;
      cumVol += trade.qty;
    });
    return {
      symbol: symbol,
      sessionId: 'mock-utc-' + new Date(now).toISOString().slice(0, 10),
      sessionStart: Date.UTC(new Date(now).getUTCFullYear(), new Date(now).getUTCMonth(), new Date(now).getUTCDate()),
      ts: now,
      cumPV: round(cumPV, 4),
      cumVol: round(cumVol, 4),
      value: cumVol > 0 ? round(cumPV / cumVol, 4) : 0
    };
  }

  V6OF.Mock = {
    createState: function (opts) {
      opts = opts || {};
      var symbol = opts.symbol || 'BTCUSDT';
      var seed = opts.seed || 42;
      var timeframe = opts.timeframe || '1m';
      var now = opts.now || Date.now();
      var meta = baseForSymbol(symbol);
      var rng = makeRng(seed + symbol.length * 17);
      var candles = createCandles(symbol, timeframe, now, rng, meta);
      var trades = createTrades(symbol, now, rng, candles, meta);
      var last = candles[candles.length - 1] ? candles[candles.length - 1].close : meta.price;

      return Object.assign(V6OF.Contract.createEmptyState(), {
        source: 'mock',
        symbol: symbol,
        timeframe: timeframe,
        trades: trades,
        orderBook: createOrderBook(symbol, now, rng, last, meta),
        candles: candles,
        deltaBuckets: createDeltaBuckets(symbol, candles),
        vwap: createVwap(symbol, now, trades),
        settings: {
          minQty: 0,
          maxRows: 42,
          showVwap: true,
          showHeatmap: true,
          showFootprint: true,
          chartMode: 'both',
          heatmapMaxFrames: 360,
          footprintMaxCandles: 160,
          tickSize: meta.tick
        },
        ui: {
          legacyMode: false,
          seed: seed
        }
      });
    }
  };
})();

